import React, { useState } from 'react';
import { MatchResult, TeamSlot, Role, Player } from '../types';
import { RoleIcons, ROLES_ORDER } from '../constants';
import { Button } from './Button';
import { SpinWheel } from './SpinWheel';
import { PortalTransition } from './PortalTransition';
import { MatchSummary } from './MatchSummary';
import { VictoryCelebration } from './VictoryCelebration';
import { EvaluationScreen } from './EvaluationScreen';

interface MatchDisplayProps {
  match: MatchResult;
  activePlayers: Player[]; 
  onReset: () => void; // For Abort
  onCompleteMatch: (winner: 'azure' | 'crimson' | null, mvpId?: string) => void; // For Finish
  onReroll: (team: 'azure' | 'crimson', role: Role, newPlayer: Player) => void;
}

type ViewState = 'drafting' | 'transition' | 'final' | 'celebration' | 'evaluation';

export const MatchDisplay: React.FC<MatchDisplayProps> = ({ match, activePlayers, onReset, onCompleteMatch, onReroll }) => {
  const [viewState, setViewState] = useState<ViewState>('drafting');
  const [winningTeam, setWinningTeam] = useState<'azure' | 'crimson' | null>(null);

  // Dynamic Role Order: If Coach mode, append Coach to standard order
  const displayRoles = match.isCoachMode ? [...ROLES_ORDER, Role.COACH] : ROLES_ORDER;

  // -1: Not started
  // 0-4: Revealing pairs (0=Clash, ... 4=Roam)
  // 5: Coach (if exists)
  const [currentRoleIndex, setCurrentRoleIndex] = useState(-1);

  // New State for the Modal Wheel
  const [wheelState, setWheelState] = useState<{
    isOpen: boolean;
    type: 'draft' | 'reroll'; // Differentiate between initial draft reveal and manual reroll
    team: 'azure' | 'crimson';
    role: Role;
    winnerName: string;
    winnerPlayer?: Player; // Needed for reroll
    candidates: string[];
  } | null>(null);

  // Tracks which individual cards are visible
  const [revealedCards, setRevealedCards] = useState<Set<string>>(new Set());

  const getPlayerForRole = (team: TeamSlot[], role: Role) => {
    return team.find(slot => slot.role === role);
  };

  const getCardId = (team: 'azure' | 'crimson', role: Role) => `${team}-${role}`;

  const handleNext = () => {
    const nextIndex = currentRoleIndex + 1;
    if (nextIndex >= displayRoles.length) return;

    const roleToReveal = displayRoles[nextIndex];

    // Step 1: Check if Azure is revealed
    const azureId = getCardId('azure', roleToReveal);
    if (!revealedCards.has(azureId)) {
      startWheel('azure', roleToReveal);
      return;
    }

    // Step 2: Check if Crimson is revealed
    const crimsonId = getCardId('crimson', roleToReveal);
    if (!revealedCards.has(crimsonId)) {
      startWheel('crimson', roleToReveal);
      return;
    }
  };

  const handleSkipAll = () => {
    // Debug: Instantly reveal everything
    const allCards = new Set<string>();
    displayRoles.forEach(r => {
      allCards.add(getCardId('azure', r));
      allCards.add(getCardId('crimson', r));
    });
    setRevealedCards(allCards);
    setCurrentRoleIndex(displayRoles.length); // Set to finished state
  };

  const startWheel = (team: 'azure' | 'crimson', role: Role) => {
    const teamSlots = team === 'azure' ? match.azureTeam : match.crimsonTeam;
    const winner = getPlayerForRole(teamSlots, role)?.player;
    if (!winner) return;

    // Get candidates for the wheel
    // If Coach, allow anyone, else restrict to role (though matchmaker already handled this, wheel is visual)
    const candidates = activePlayers
      .filter(p => role === Role.COACH ? true : (p.isAllRoles || p.roles.includes(role)))
      .map(p => p.name);

    setWheelState({
      isOpen: true,
      type: 'draft',
      team,
      role,
      winnerName: winner.name,
      candidates
    });
  };

  // Triggered when user clicks the re-roll button on a card
  const handleRerollClick = (team: 'azure' | 'crimson', role: Role) => {
    // 1. Identify current players in the match to exclude them
    const azureIds = new Set(match.azureTeam.map(s => s.player.id));
    const crimsonIds = new Set(match.crimsonTeam.map(s => s.player.id));

    // 2. Identify available bench players (Active but NOT in match)
    // CRITICAL: This ensures players already in match (even All Role) don't appear in wheel
    const benchPlayers = activePlayers.filter(p => !azureIds.has(p.id) && !crimsonIds.has(p.id));

    if (benchPlayers.length === 0) {
      alert("No available bench players to re-roll with!");
      return;
    }

    // 3. Filter bench players who can play this role
    const candidates = benchPlayers.filter(p => {
       if (role === Role.COACH) return true; // Assuming any bench player can coach
       return p.isAllRoles || p.roles.includes(role);
    });

    if (candidates.length === 0) {
       alert(`No available bench players found for role: ${role}`);
       return;
    }

    // 4. Pick random candidate for the wheel result
    const newPlayer = candidates[Math.floor(Math.random() * candidates.length)];
    const candidateNames = candidates.map(p => p.name);

    // 5. Start Wheel in Reroll mode
    setWheelState({
        isOpen: true,
        type: 'reroll',
        team,
        role,
        winnerName: newPlayer.name,
        winnerPlayer: newPlayer,
        candidates: candidateNames
    });
  };

  const handleWheelComplete = () => {
    if (!wheelState) return;

    if (wheelState.type === 'draft') {
        // Standard Draft Reveal
        const { team, role } = wheelState;
        setRevealedCards(prev => new Set(prev).add(getCardId(team, role)));

        // If we just revealed Crimson, that means the row is done. Increment index.
        if (team === 'crimson') {
           setCurrentRoleIndex(prev => prev + 1);
        }
    } else if (wheelState.type === 'reroll' && wheelState.winnerPlayer) {
        // Apply Reroll
        onReroll(wheelState.team, wheelState.role, wheelState.winnerPlayer);
    }

    setWheelState(null);
  };

  const handleWheelCancel = () => {
    setWheelState(null);
  };

  const handleInitializeBattle = () => {
    setViewState('transition');
  };

  const handleTransitionComplete = () => {
    setViewState('final');
  };

  const handleMatchDecided = (winner: 'azure' | 'crimson' | null) => {
    if (winner) {
      setWinningTeam(winner);
      setViewState('celebration');
    } else {
      // Abort or Draw (No celebration)
      onCompleteMatch(null);
    }
  };

  const handleCelebrationDismiss = () => {
    // Proceed to evaluation instead of finishing
    setViewState('evaluation');
  };

  const handleEvaluationComplete = (mvpId?: string) => {
    onCompleteMatch(winningTeam, mvpId);
  }

  // --- RENDER LOGIC ---

  if (viewState === 'evaluation' && winningTeam) {
    return (
      <EvaluationScreen 
        match={match} 
        winner={winningTeam} 
        onComplete={handleEvaluationComplete} 
      />
    );
  }

  if (viewState === 'celebration' && winningTeam) {
    const winningTeamSlots = winningTeam === 'azure' ? match.azureTeam : match.crimsonTeam;
    return (
      <VictoryCelebration 
        winner={winningTeam} 
        teamSlots={winningTeamSlots}
        onDismiss={handleCelebrationDismiss} 
      />
    );
  }

  if (viewState === 'transition') {
    return (
      <PortalTransition 
        azureTeam={match.azureTeam} 
        crimsonTeam={match.crimsonTeam} 
        onComplete={handleTransitionComplete} 
      />
    );
  }

  if (viewState === 'final') {
    return <MatchSummary match={match} onReset={handleMatchDecided} />;
  }

  // --- DRAFTING VIEW ---

  const renderPlayerCard = (role: Role, roleIndex: number, team: 'azure' | 'crimson') => {
    const teamSlots = team === 'azure' ? match.azureTeam : match.crimsonTeam;
    const player = getPlayerForRole(teamSlots, role)?.player;

    const isRevealed = revealedCards.has(getCardId(team, role));

    // HoK Color Palettes
    const theme = team === 'azure' 
      ? {
          bg: 'bg-[#0a1a2f]',
          border: 'border-hok-cyan',
          glow: 'shadow-[0_0_10px_#00d2ff]',
          text: 'text-hok-cyan',
          gradient: 'from-[#00d2ff]/20 to-transparent'
        } 
      : {
          bg: 'bg-[#1a0505]',
          border: 'border-hok-red',
          glow: 'shadow-[0_0_10px_#ef4444]',
          text: 'text-hok-red',
          gradient: 'from-[#c02d2d]/20 to-transparent'
        };

    // State 1: Hidden
    if (!isRevealed) {
       return (
         <div className="h-24 w-full relative overflow-hidden clip-corner-md border border-[#1e3a5f] bg-[#05090f]/80 flex items-center justify-center opacity-40 group">
            <div className="text-[#1e3a5f] group-hover:text-[#dcb06b]/50 transition-colors duration-500">
               {/* RoleIcons is now text, so we wrap it for sizing */}
               <div className="scale-125 opacity-50">{RoleIcons[role]}</div>
            </div>
            {/* Tech Scanlines */}
            <div className="absolute inset-0 bg-[url('data:image/svg+xml;base64,PHN2ZyB4bWxucz0iaHR0cDovL3d3dy53My5vcmcvMjAwMC9zdmciIHdpZHRoPSI0IiBoZWlnaHQ9IjQiPgo8cmVjdCB3aWR0aD0iNCIgaGVpZ2h0PSI0IiBmaWxsPSIjZmZmIiBmaWxsLW9wYWNpdHk9IjAuMDUiLz4KPHBhdGggZD0iTTAgNEw0IDBaIiBzdHJva2U9IiMwMDAiIHN0cm9rZS13aWR0aD0iMSIvPgo8L3N2Zz4=')] opacity-20"></div>
         </div>
       );
    }

    // State 2: Revealed
    return (
      <div className={`relative h-24 w-full animate-slide-in perspective-container group`}>
        <div className={`
            absolute inset-0 clip-corner-md border-l-4 tilt-card
            ${theme.bg} ${theme.border} 
            ${theme.glow}
            shadow-[0_0_15px_rgba(0,0,0,0.5)]
            transition-all duration-300 hover:brightness-110
        `}>
           <div className="flex items-center h-full relative z-10">
             {/* Icon/Text Section */}
             <div className={`w-24 h-full flex items-center justify-center bg-black/40 ${team === 'crimson' ? 'order-last border-l border-white/10' : 'border-r border-white/10'}`}>
                <div className={`w-full text-center px-1 ${theme.text} transform transition-transform duration-500 hover:scale-110`}>
                  {RoleIcons[role]}
                </div>
             </div>

             {/* Name Section */}
             <div className={`flex-1 px-4 flex flex-col justify-center ${team === 'crimson' ? 'text-right' : 'text-left'}`}>
                <span className={`block text-xl md:text-2xl font-bold text-white truncate font-orbitron drop-shadow-md`}>
                  {player?.name}
                </span>
             </div>

             <div className={`absolute inset-0 bg-gradient-to-r ${theme.gradient} opacity-50 pointer-events-none`}></div>
           </div>

           {/* Decorative Tech Corners */}
           <div className={`absolute top-0 w-8 h-8 border-t border-${team === 'azure' ? 'cyan' : 'red'}-500/50 ${team === 'azure' ? 'left-0' : 'right-0'}`}></div>
           <div className={`absolute bottom-0 w-8 h-8 border-b border-${team === 'azure' ? 'cyan' : 'red'}-500/50 ${team === 'azure' ? 'right-0' : 'left-0'}`}></div>

           {/* Re-roll Button Overlay - Now triggers wheel logic */}
           <button 
             onClick={(e) => { e.stopPropagation(); handleRerollClick(team, role); }}
             className="absolute top-1 right-1 md:top-2 md:right-2 p-1.5 bg-black/50 hover:bg-[#dcb06b] rounded-full transition-colors group-hover:opacity-100 opacity-0 text-white hover:text-black z-50 border border-white/20"
             title="Re-roll this specific slot"
           >
             <svg xmlns="http://www.w3.org/2000/svg" className="h-4 w-4" fill="none" viewBox="0 0 24 24" stroke="currentColor">
               <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M4 4v5h.582m15.356 2A8.001 8.001 0 004.582 9m0 0H9m11 11v-5h-.581m0 0a8.003 8.003 0 01-15.357-2m15.357 2H15" />
             </svg>
           </button>
        </div>
      </div>
    );
  };

  const nextRoleIndex = currentRoleIndex + 1;
  const nextRoleName = nextRoleIndex < displayRoles.length ? displayRoles[nextRoleIndex] : null;
  const isFinished = currentRoleIndex >= displayRoles.length - 1 && revealedCards.size === (match.isCoachMode ? 12 : 10);

  let buttonText = "START DRAFT";
  if (nextRoleName) {
     if (!revealedCards.has(getCardId('azure', nextRoleName))) {
        buttonText = `SELECT AZURE ${nextRoleName.split(' ')[0].toUpperCase()}`;
     } else if (!revealedCards.has(getCardId('crimson', nextRoleName))) {
        buttonText = `SELECT CRIMSON ${nextRoleName.split(' ')[0].toUpperCase()}`;
     } else {
        buttonText = "NEXT LANE";
     }
  }

  // Turret SVG Path
  const TurretIcon = (
    <svg viewBox="0 0 24 24" fill="currentColor" className="w-16 h-16 opacity-30 animate-pulse">
        <path d="M12,2 L2,22 L12,18 L22,22 L12,2 Z" />
        <path d="M12,5 L5,20 L12,17 L19,20 L12,5 Z" fillOpacity="0.5" />
    </svg>
  );

  return (
    <>
      {/* The Spin Wheel Overlay */}
      {wheelState && wheelState.isOpen && (
        <SpinWheel 
          candidates={wheelState.candidates}
          winnerName={wheelState.winnerName}
          team={wheelState.team}
          roleName={wheelState.role}
          onComplete={handleWheelComplete}
          onCancel={handleWheelCancel}
        />
      )}

      <div className="w-full max-w-7xl mx-auto px-4 py-8 pb-32 relative">

        {/* Top Controls: Abort & Instant Result */}
        <div className="absolute top-4 left-4 right-4 z-40 flex justify-between">
           <Button variant="outline" size="sm" onClick={() => onReset()} className="border-red-900/50 text-red-500 hover:bg-red-900/20 text-[10px] px-3">
              <span className="flex items-center gap-2">
                 <svg xmlns="http://www.w3.org/2000/svg" className="h-4 w-4" fill="none" viewBox="0 0 24 24" stroke="currentColor">
                   <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M11 15l-3-3m0 0l3-3m-3 3h8M3 12a9 9 0 1118 0 9 9 0 01-18 0z" />
                 </svg>
                 ABORT DRAFT
              </span>
           </Button>

           {/* Debug / Instant Result Button */}
           {!isFinished && (
             <Button variant="outline" size="sm" onClick={handleSkipAll} className="border-[#dcb06b]/50 text-[#dcb06b] hover:bg-[#dcb06b]/10 text-[10px] px-3">
                <span className="flex items-center gap-2">
                   INSTANT RESULT (DEBUG)
                   <svg xmlns="http://www.w3.org/2000/svg" className="h-4 w-4" fill="none" viewBox="0 0 24 24" stroke="currentColor">
                     <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M13 10V3L4 14h7v7l9-11h-7z" />
                   </svg>
                </span>
             </Button>
           )}
        </div>

        {/* Header Info - PERFECTLY CENTERED */}
        <div className="flex flex-col items-center mb-12 pt-12">
           <div className="flex justify-center w-full mb-8">
              <div className="bg-[#05090f] border border-[#dcb06b]/40 px-8 py-2 clip-diamond relative shadow-[0_0_15px_rgba(220,176,107,0.2)]">
                  <div className="absolute inset-0 bg-[#dcb06b]/5 pointer-events-none"></div>
                  <span className="text-[#dcb06b] font-cinzel font-bold text-sm tracking-widest uppercase block text-center">Room ID</span>
                  <span className="text-2xl font-orbitron font-bold text-white tracking-widest text-center block">{match.roomId}</span>
              </div>
           </div>

           <div className="flex justify-between items-center w-full relative max-w-5xl">
              <div className="w-1/3 text-center relative group">
                 <div className="absolute -inset-4 bg-cyan-500/10 blur-xl rounded-full opacity-50 group-hover:opacity-100 transition-opacity"></div>
                 <div className="absolute -left-10 top-0 text-cyan-500/20">{TurretIcon}</div>
                 <h2 className="relative text-3xl md:text-5xl font-cinzel font-black text-transparent bg-clip-text bg-gradient-to-b from-cyan-200 to-cyan-600 drop-shadow-[0_0_15px_rgba(6,182,212,0.8)]">
                  AZURE
                 </h2>
                 <p className="text-[10px] md:text-xs text-cyan-400 font-orbitron tracking-[0.4em] mt-1 opacity-70">GOLEM TEAM</p>
                 <div className="h-1 w-24 bg-cyan-500 mx-auto mt-2 shadow-[0_0_10px_#00d2ff]"></div>
              </div>

              <div className="w-1/3 flex justify-center items-center z-10">
                <div className="relative w-24 h-24 md:w-32 md:h-32 flex items-center justify-center">
                  <div className="absolute inset-0 border-2 border-[#dcb06b] rotate-45 animate-spin-slow bg-[#05090f]"></div>
                  <div className="absolute inset-2 border border-[#dcb06b]/50 rotate-45"></div>
                  <span className="text-4xl font-black italic text-[#dcb06b] font-orbitron z-10 pr-2 pt-1 animate-pulse-fast">VS</span>
                </div>
              </div>

              <div className="w-1/3 text-center relative group">
                 <div className="absolute -inset-4 bg-red-500/10 blur-xl rounded-full opacity-50 group-hover:opacity-100 transition-opacity"></div>
                 <div className="absolute -right-10 top-0 text-red-500/20 transform scale-x-[-1]">{TurretIcon}</div>
                 <h2 className="relative text-3xl md:text-5xl font-cinzel font-black text-transparent bg-clip-text bg-gradient-to-b from-red-200 to-red-600 drop-shadow-[0_0_15px_rgba(220,45,45,0.8)]">
                  CRIMSON
                 </h2>
                 <p className="text-[10px] md:text-xs text-red-400 font-orbitron tracking-[0.4em] mt-1 opacity-70">GOLEM TEAM</p>
                 <div className="h-1 w-24 bg-red-500 mx-auto mt-2 shadow-[0_0_10px_#ef4444]"></div>
              </div>
           </div>
        </div>

        {/* Matchup Grid */}
        <div className="relative space-y-4 md:space-y-6">
          <div className="absolute left-1/2 top-0 bottom-0 w-[2px] bg-gradient-to-b from-transparent via-[#dcb06b]/30 to-transparent hidden md:block"></div>

          {displayRoles.map((role, idx) => (
            <div key={role} className="grid grid-cols-1 md:grid-cols-2 gap-4 md:gap-16 items-center">
               <div className="order-1 md:order-none">
                  {renderPlayerCard(role, idx, 'azure')}
               </div>
               <div className="order-2 md:order-none">
                  {renderPlayerCard(role, idx, 'crimson')}
               </div>
            </div>
          ))}
        </div>

        {/* Control Bar */}
        <div className="fixed bottom-0 left-0 right-0 p-8 z-50 flex justify-center items-end bg-gradient-to-t from-[#05090f] via-[#05090f]/90 to-transparent pointer-events-none h-48">
           <div className="pointer-events-auto transform transition-all hover:scale-105">
              {!isFinished ? (
                 <div className="flex flex-col items-center">
                    <button 
                      onClick={handleNext}
                      className="
                        group relative w-72 h-16
                        bg-[#0a1a2f] border border-[#dcb06b] 
                        clip-corner-md
                        flex items-center justify-center
                        text-[#dcb06b] font-cinzel font-bold text-xl tracking-widest
                        overflow-hidden
                        hover:bg-[#dcb06b] hover:text-[#05090f]
                        transition-all duration-300
                        shadow-[0_0_20px_rgba(220,176,107,0.2)]
                      "
                    >
                       <span className="relative z-10">
                         {buttonText}
                       </span>
                       <div className="absolute inset-0 w-full h-full bg-white/20 -translate-x-full group-hover:animate-[shimmer_1s_infinite]"></div>
                    </button>
                 </div>
              ) : (
                 <div className="flex flex-col items-center animate-slide-in">
                    <p className="text-[#00d2ff] font-bold mb-4 uppercase tracking-[0.3em] text-sm font-orbitron drop-shadow-[0_0_5px_rgba(0,210,255,0.8)]">
                       Draft Completed
                    </p>
                    <Button 
                      onClick={handleInitializeBattle} 
                      className="px-12 border-[#dcb06b] shadow-[0_0_20px_#dcb06b] animate-pulse"
                    >
                       INITIALIZE BATTLE
                    </Button>
                 </div>
              )}
           </div>
        </div>
      </div>
    </>
  );
};

import React, { useState, useRef } from 'react';
import { Player, MatchResult, Role, MatchHistoryEntry } from './types';
import { PlayerForm } from './components/PlayerForm';
import { PlayerList } from './components/PlayerList';
import { MatchDisplay } from './components/MatchDisplay';
import { EditPlayerModal } from './components/EditPlayerModal';
import { HistoryList } from './components/HistoryList';
import { generateMatch } from './utils/matchmaker';
import { Button } from './components/Button';
import { BackgroundParticles } from './components/BackgroundParticles';

// Quick Fill Data: Honor of Kings Heroes
const HOK_HEROES = [
  { name: "Arthur", roles: [Role.CLASH] },
  { name: "Sun Ce", roles: [Role.CLASH, Role.JUNGLE] },
  { name: "Kaizer", roles: [Role.CLASH, Role.JUNGLE] },
  { name: "Biron", roles: [Role.CLASH] },
  { name: "Li Xin", roles: [Role.CLASH] },
  { name: "Charlotte", roles: [Role.CLASH] },
  { name: "Lam", roles: [Role.JUNGLE] },
  { name: "Prince of Lanling", roles: [Role.JUNGLE, Role.ROAM] },
  { name: "Wukong", roles: [Role.JUNGLE] },
  { name: "Li Bai", roles: [Role.JUNGLE] },
  { name: "Han Xin", roles: [Role.JUNGLE] },
  { name: "Luna", roles: [Role.JUNGLE, Role.MID] },
  { name: "Angela", roles: [Role.MID] },
  { name: "Diaochan", roles: [Role.MID] },
  { name: "Xiao Qiao", roles: [Role.MID] },
  { name: "Mai Shiranui", roles: [Role.MID, Role.JUNGLE] },
  { name: "Lady Zhen", roles: [Role.MID] },
  { name: "Milady", roles: [Role.MID] },
  { name: "Luban No.7", roles: [Role.FARM] },
  { name: "Marco Polo", roles: [Role.FARM] },
  { name: "Hou Yi", roles: [Role.FARM] },
  { name: "Consort Yu", roles: [Role.FARM] },
  { name: "Di Renjie", roles: [Role.FARM] },
  { name: "Arli", roles: [Role.FARM, Role.JUNGLE] },
  { name: "Dolia", roles: [Role.ROAM] },
  { name: "Kui", roles: [Role.ROAM] },
  { name: "Zhuangzi", roles: [Role.ROAM, Role.CLASH] },
  { name: "Zhang Fei", roles: [Role.ROAM] },
  { name: "Da Qiao", roles: [Role.ROAM, Role.MID] },
  { name: "Yaria", roles: [Role.ROAM] }
];

export default function App() {
  const [players, setPlayers] = useState<Player[]>([]);
  const [currentMatch, setCurrentMatch] = useState<MatchResult | null>(null);
  const [matchHistory, setMatchHistory] = useState<MatchHistoryEntry[]>([]);
  const [errorMsg, setErrorMsg] = useState<string | null>(null);
  const [roomId, setRoomId] = useState<string>('');
  const [isCoachMode, setIsCoachMode] = useState(false);

  // Edit State
  const [editingPlayer, setEditingPlayer] = useState<Player | null>(null);
  const [isEditModalOpen, setIsEditModalOpen] = useState(false);

  const rosterFileInputRef = useRef<HTMLInputElement>(null);
  const historyFileInputRef = useRef<HTMLInputElement>(null);

  const addPlayer = (newPlayer: Omit<Player, 'id' | 'isActive' | 'stats'>) => {
    const player: Player = { 
      ...newPlayer, 
      id: crypto.randomUUID(),
      isActive: true, // Default to active when added
      isLastMatchMvp: false,
      stats: {
        matchesPlayed: 0,
        wins: 0,
        currentStreak: 0,
        maxStreak: 0
      }
    };
    setPlayers(prev => [...prev, player]);
    setErrorMsg(null);
  };

  const removePlayer = (id: string) => {
    setPlayers(prev => prev.filter(p => p.id !== id));
  };

  const togglePlayerActive = (id: string) => {
    setPlayers(prev => prev.map(p => 
      p.id === id ? { ...p, isActive: !p.isActive } : p
    ));
  };

  // Edit Handlers
  const handleEditPlayer = (player: Player) => {
    setEditingPlayer(player);
    setIsEditModalOpen(true);
  };

  const handleUpdatePlayer = (updatedPlayer: Player) => {
    setPlayers(prev => prev.map(p => 
      p.id === updatedPlayer.id ? updatedPlayer : p
    ));
    setErrorMsg(null);
  };

  const activePlayers = players.filter(p => p.isActive);

  const handleGenerate = () => {
    if (!roomId.trim()) {
      setErrorMsg("Please enter a Room ID.");
      return;
    }

    const required = isCoachMode ? 12 : 10;
    if (activePlayers.length < required) {
      setErrorMsg(`Need ${required} ACTIVE players for ${isCoachMode ? 'Coach' : 'Standard'} Mode. Current Active: ${activePlayers.length}`);
      return;
    }

    // Only pass active players to the matchmaker
    const result = generateMatch(activePlayers, roomId, isCoachMode);
    if (result) {
      setCurrentMatch(result);
      setErrorMsg(null);
    } else {
      setErrorMsg("Failed to find valid composition. Ensure role coverage.");
    }
  };

  const handleRerollSlot = (team: 'azure' | 'crimson', role: Role, newPlayer: Player) => {
    if (!currentMatch) return;

    // Update Match State with the new player chosen by the wheel
    setCurrentMatch(prev => {
       if (!prev) return null;

       const newAzure = prev.azureTeam.map(slot => {
          if (team === 'azure' && slot.role === role) {
             return { ...slot, player: newPlayer };
          }
          return slot;
       });

       const newCrimson = prev.crimsonTeam.map(slot => {
          if (team === 'crimson' && slot.role === role) {
             return { ...slot, player: newPlayer };
          }
          return slot;
       });

       return {
          ...prev,
          azureTeam: newAzure,
          crimsonTeam: newCrimson
       };
    });
  };

  const handleMatchFinish = (winner: 'azure' | 'crimson' | null, mvpId?: string) => {
    if (!currentMatch) return;

    // 1. Save History
    const historyEntry: MatchHistoryEntry = {
       ...currentMatch,
       id: crypto.randomUUID(),
       winningTeam: winner,
       mvpId: mvpId
    };
    setMatchHistory(prev => [historyEntry, ...prev]);

    // 2. Update Player Stats if there is a winner
    if (winner) {
      const azurePlayerIds = new Set(currentMatch.azureTeam.map(slot => slot.player.id));
      const crimsonPlayerIds = new Set(currentMatch.crimsonTeam.map(slot => slot.player.id));

      setPlayers(prevPlayers => prevPlayers.map(p => {
        let isLastMatchMvp = false;

        // If player matches the manually provided MVP ID, set flag
        if (mvpId && p.id === mvpId) {
          isLastMatchMvp = true;
        }

        if (!azurePlayerIds.has(p.id) && !crimsonPlayerIds.has(p.id)) {
          return { ...p, isLastMatchMvp: false }; // Clear old MVP if they didn't play
        }

        const isAzure = azurePlayerIds.has(p.id);
        const isWinner = (isAzure && winner === 'azure') || (!isAzure && winner === 'crimson');

        const newStats = { ...p.stats };
        newStats.matchesPlayed += 1;

        if (isWinner) {
           newStats.wins += 1;
           newStats.currentStreak += 1;
           if (newStats.currentStreak > newStats.maxStreak) {
             newStats.maxStreak = newStats.currentStreak;
           }
        } else {
           // Reset streak on loss
           newStats.currentStreak = 0;
        }

        return { ...p, stats: newStats, isLastMatchMvp };
      }));
    } else {
      setCurrentMatch(null);
      return; 
    }

    // 3. Clear match
    setCurrentMatch(null);
  };

  const handleAbortMatch = () => setCurrentMatch(null);

  const quickFill = () => {
     const shuffledHeroes = [...HOK_HEROES].sort(() => 0.5 - Math.random());
     const heroesToAdd = shuffledHeroes.slice(0, 15);
     const newPlayers: Player[] = heroesToAdd.map(hero => ({
        id: crypto.randomUUID(),
        name: hero.name,
        isAllRoles: false,
        roles: hero.roles,
        isActive: true,
        isLastMatchMvp: false,
        stats: { matchesPlayed: 0, wins: 0, currentStreak: 0, maxStreak: 0 }
     }));
     // Add some flexible minions/players if needed to ensure we have enough
     for(let i=0; i<5; i++) {
        newPlayers.push({
           id: crypto.randomUUID(),
           name: `Flex Player ${i+1}`,
           isAllRoles: true,
           roles: [],
           isActive: true,
           isLastMatchMvp: false,
           stats: { matchesPlayed: 0, wins: 0, currentStreak: 0, maxStreak: 0 }
        });
     }

     setPlayers(prev => {
        const existingNames = new Set(prev.map(p => p.name));
        const filteredNew = newPlayers.filter(p => !existingNames.has(p.name));
        return [...prev, ...filteredNew].slice(0, 30);
     });

     if(!roomId) setRoomId(Math.floor(1000 + Math.random() * 9000).toString());
  };

  // --- SAVE / LOAD FUNCTIONALITY ---

  const handleExportRoster = () => {
    if (players.length === 0) return;
    const dataStr = "data:text/json;charset=utf-8," + encodeURIComponent(JSON.stringify(players, null, 2));
    const downloadAnchorNode = document.createElement('a');
    downloadAnchorNode.setAttribute("href", dataStr);
    downloadAnchorNode.setAttribute("download", "hok-squad-roster.json");
    document.body.appendChild(downloadAnchorNode);
    downloadAnchorNode.click();
    downloadAnchorNode.remove();
  };

  const handleExportHistory = () => {
    if (matchHistory.length === 0) return;
    const dataStr = "data:text/json;charset=utf-8," + encodeURIComponent(JSON.stringify(matchHistory, null, 2));
    const downloadAnchorNode = document.createElement('a');
    downloadAnchorNode.setAttribute("href", dataStr);
    downloadAnchorNode.setAttribute("download", "hok-match-history.json");
    document.body.appendChild(downloadAnchorNode);
    downloadAnchorNode.click();
    downloadAnchorNode.remove();
  };

  const handleRosterImportClick = () => {
    rosterFileInputRef.current?.click();
  };

  const handleHistoryImportClick = () => {
    historyFileInputRef.current?.click();
  };

  const handleRosterFileChange = (event: React.ChangeEvent<HTMLInputElement>) => {
    const fileObj = event.target.files && event.target.files[0];
    if (!fileObj) return;

    const reader = new FileReader();
    reader.onload = (e) => {
      try {
        const json = e.target?.result;
        if (typeof json === 'string') {
          const parsedData = JSON.parse(json);
          // Basic validation
          if (Array.isArray(parsedData) && parsedData.length > 0 && parsedData[0].name) {
             const importedPlayers: Player[] = parsedData.map((p: any) => ({
               ...p,
               id: crypto.randomUUID(),
               // Ensure properties exist for backward compatibility with old JSONs
               isActive: typeof p.isActive === 'boolean' ? p.isActive : true,
               isLastMatchMvp: typeof p.isLastMatchMvp === 'boolean' ? p.isLastMatchMvp : false,
               stats: p.stats || { matchesPlayed: 0, wins: 0, currentStreak: 0, maxStreak: 0 }
             }));
             setPlayers(importedPlayers);
             setErrorMsg(null);
          } else {
             setErrorMsg("Invalid Roster JSON file format.");
          }
        }
      } catch (err) {
        setErrorMsg("Failed to parse Roster JSON file.");
      }
    };
    reader.readAsText(fileObj);
    event.target.value = '';
  };

  const handleHistoryFileChange = (event: React.ChangeEvent<HTMLInputElement>) => {
    const fileObj = event.target.files && event.target.files[0];
    if (!fileObj) return;

    const reader = new FileReader();
    reader.onload = (e) => {
      try {
        const json = e.target?.result;
        if (typeof json === 'string') {
          const parsedData = JSON.parse(json);
          // Basic validation for match history
          if (Array.isArray(parsedData) && (parsedData.length === 0 || parsedData[0].roomId)) {
             setMatchHistory(parsedData);
             setErrorMsg(null);
          } else {
             setErrorMsg("Invalid History JSON file format.");
          }
        }
      } catch (err) {
        setErrorMsg("Failed to parse History JSON file.");
      }
    };
    reader.readAsText(fileObj);
    event.target.value = '';
  };

  const handleRoomIdChange = (e: React.ChangeEvent<HTMLInputElement>) => {
    const val = e.target.value;
    if (val.length <= 4) {
      setRoomId(val);
    }
  };

  return (
    <div className="min-h-screen text-slate-200 font-inter overflow-x-hidden relative">
      <BackgroundParticles />

      {/* New Background Image (HoK Global Launch) */}
      <div className="fixed inset-0 bg-black -z-10">
         <img 
           src="https://www.levelinfinite.com/wp-content/uploads/2024/03/honor-of-kings-global-launch-pc.jpg" 
           alt="Honor of Kings Background" 
           className="absolute inset-0 w-full h-full object-cover opacity-50"
         />
         <div className="absolute inset-0 bg-gradient-to-b from-[#05090f]/90 via-[#05090f]/60 to-[#05090f] mix-blend-multiply"></div>
         <div className="absolute inset-0 bg-gradient-to-t from-[#05090f] via-transparent to-[#05090f]/80"></div>
      </div>

      {/* Hidden File Inputs */}
      <input 
        type="file" 
        ref={rosterFileInputRef}
        onChange={handleRosterFileChange}
        accept=".json"
        className="hidden"
      />
      <input 
        type="file" 
        ref={historyFileInputRef}
        onChange={handleHistoryFileChange}
        accept=".json"
        className="hidden"
      />

      {/* Edit Modal */}
      {editingPlayer && (
        <EditPlayerModal 
          player={editingPlayer}
          isOpen={isEditModalOpen}
          onClose={() => setIsEditModalOpen(false)}
          onSave={handleUpdatePlayer}
        />
      )}

      {/* Cinematic Header */}
      <header className="relative z-20 h-20 flex items-center justify-center border-b border-[#dcb06b]/20 bg-[#05090f]/60 backdrop-blur-md">
        <div className="absolute inset-0 bg-gradient-to-r from-transparent via-[#dcb06b]/5 to-transparent"></div>
        <div className="flex items-center gap-3 animate-float">
           <div className="w-8 h-8 border-2 border-[#dcb06b] rotate-45 flex items-center justify-center bg-[#0a1a2f]">
              <div className="w-4 h-4 bg-[#dcb06b]"></div>
           </div>
           <h1 className="text-2xl font-cinzel font-black tracking-[0.2em] text-white">
             <span className="hok-gold-text">HONOR</span> OF <span className="hok-gold-text">KINGS</span>
             <span className="block text-[8px] text-[#8a9db8] tracking-[0.5em] font-orbitron mt-0.5">OPEN MABAR CUSTOM FUN MATCH</span>
           </h1>
        </div>
      </header>

      <main className="relative z-10 pt-8 px-4 pb-20">
        {currentMatch ? (
          <MatchDisplay 
            match={currentMatch} 
            activePlayers={activePlayers} 
            onReset={handleAbortMatch}
            onCompleteMatch={handleMatchFinish}
            onReroll={handleRerollSlot}
          />
        ) : (
          <div className="max-w-7xl mx-auto">

            <div className="grid grid-cols-1 lg:grid-cols-12 gap-8">

              {/* Left Panel: Controls */}
              <div className="lg:col-span-4 space-y-6">

                 {/* Room ID & Coach Mode Toggle */}
                 <div className="bg-[#0a1a2f]/80 p-1 clip-corner-sm border border-[#1e3a5f] shadow-[0_0_25px_rgba(220,176,107,0.15)] relative group space-y-2">
                    <div className="absolute -inset-1 bg-gradient-to-r from-transparent via-[#dcb06b]/30 to-transparent blur opacity-0 group-hover:opacity-100 transition-opacity duration-700"></div>

                    <div className="bg-[#05090f] p-4 flex items-center gap-4 clip-corner-sm relative z-10">
                       <label className="text-xs uppercase text-[#dcb06b] font-bold font-orbitron whitespace-nowrap tracking-widest">Room ID</label>
                       <div className="h-8 w-[1px] bg-[#1e3a5f]"></div>
                       <input 
                          type="text" 
                          value={roomId}
                          onChange={handleRoomIdChange}
                          maxLength={4}
                          placeholder="0000"
                          className="bg-transparent text-lg font-orbitron text-white w-full focus:outline-none tracking-widest placeholder-[#1e3a5f]"
                       />
                    </div>
                 </div>

                 <div className="flex items-center justify-between bg-[#0a1a2f]/60 p-4 border border-[#1e3a5f] clip-corner-sm">
                     <span className="text-[#dcb06b] font-cinzel font-bold text-sm tracking-widest flex items-center gap-2">
                        <svg xmlns="http://www.w3.org/2000/svg" className="h-4 w-4" fill="none" viewBox="0 0 24 24" stroke="currentColor">
                           <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M19 11H5m14 0a2 2 0 012 2v6a2 2 0 01-2 2H5a2 2 0 01-2-2v-6a2 2 0 012-2m14 0V9a2 2 0 00-2-2M5 11V9a2 2 0 012-2m0 0V5a2 2 0 012-2h6a2 2 0 012 2v2M7 7h10" />
                        </svg>
                        COACH MODE
                     </span>
                     <label className="relative inline-flex items-center cursor-pointer">
                        <input type="checkbox" className="sr-only peer" checked={isCoachMode} onChange={(e) => setIsCoachMode(e.target.checked)} />
                        <div className="w-11 h-6 bg-[#1e3a5f] peer-focus:outline-none rounded-full peer peer-checked:after:translate-x-full peer-checked:after:border-white after:content-[''] after:absolute after:top-[2px] after:left-[2px] after:bg-white after:border-gray-300 after:border after:rounded-full after:h-5 after:w-5 after:transition-all peer-checked:bg-[#dcb06b]"></div>
                     </label>
                 </div>

                 <PlayerForm onAddPlayer={addPlayer} isCoachMode={isCoachMode} />

                 {/* Status Panel */}
                 <div className="relative p-6 clip-corner-md bg-gradient-to-b from-[#1a2c42] to-[#05090f] border border-[#dcb06b]/20 group hover:border-[#dcb06b]/50 transition-colors duration-500">
                    <div className="absolute top-0 left-0 w-full h-1 bg-gradient-to-r from-transparent via-[#dcb06b] to-transparent opacity-50"></div>

                    <div className="flex justify-between items-end mb-6">
                       <div>
                          <div className="text-[#8a9db8] text-[10px] uppercase tracking-widest font-bold mb-1">Active Players</div>
                          <div className="text-5xl font-orbitron font-bold text-white relative">
                             {activePlayers.length}
                             <span className="text-lg text-[#4a5f78] absolute top-0 -right-12">/ {isCoachMode ? 12 : 10}</span>
                          </div>
                       </div>
                       <div className="text-right">
                          <button onClick={quickFill} className="text-[10px] text-[#dcb06b] border border-[#dcb06b] px-3 py-1 hover:bg-[#dcb06b] hover:text-black transition-colors uppercase tracking-wider">
                             Quick Fill
                          </button>
                       </div>
                    </div>

                    {errorMsg && (
                      <div className="mb-4 p-3 border-l-2 border-red-500 bg-red-900/20 text-red-200 text-xs">
                        {errorMsg}
                      </div>
                    )}

                    <Button 
                      onClick={handleGenerate} 
                      className="w-full text-lg shadow-[0_0_20px_rgba(220,176,107,0.3)]"
                      disabled={activePlayers.length < (isCoachMode ? 12 : 10)}
                    >
                       START MATCHMAKING
                    </Button>
                 </div>
              </div>

              {/* Right Panel: Player Grid & History */}
              <div className="lg:col-span-8">
                 <div className="flex flex-wrap items-center justify-between mb-6 gap-4">
                    <h2 className="text-2xl font-cinzel font-black tracking-[0.2em] uppercase drop-shadow-sm text-[#dcb06b] flex items-center gap-3">
                       <span className="w-2 h-2 bg-[#dcb06b] rotate-45"></span>
                       SQUAD ROSTER
                    </h2>

                    <div className="flex items-center gap-2">
                       {/* Import/Export Controls */}
                       <button 
                         onClick={handleRosterImportClick}
                         className="flex items-center gap-2 px-3 py-1 text-[10px] uppercase font-bold tracking-wider text-[#4a5f78] border border-[#1e3a5f] hover:border-[#dcb06b] hover:text-[#dcb06b] transition-all clip-corner-sm"
                         title="Load Roster JSON"
                       >
                          <svg xmlns="http://www.w3.org/2000/svg" className="h-4 w-4" fill="none" viewBox="0 0 24 24" stroke="currentColor">
                            <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M4 16v1a3 3 0 003 3h10a3 3 0 003-3v-1m-4-8l-4-4m0 0L8 8m4-4v12" />
                          </svg>
                          Load
                       </button>

                       <button 
                         onClick={handleExportRoster}
                         disabled={players.length === 0}
                         className="flex items-center gap-2 px-3 py-1 text-[10px] uppercase font-bold tracking-wider text-[#4a5f78] border border-[#1e3a5f] hover:border-[#dcb06b] hover:text-[#dcb06b] transition-all clip-corner-sm disabled:opacity-30 disabled:cursor-not-allowed"
                         title="Save Roster JSON"
                       >
                          <svg xmlns="http://www.w3.org/2000/svg" className="h-4 w-4" fill="none" viewBox="0 0 24 24" stroke="currentColor">
                            <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M4 16v1a3 3 0 003 3h10a3 3 0 003-3v-1m-4-4l-4 4m0 0l-4-4m4 4V4" />
                          </svg>
                          Save
                       </button>

                       <div className="h-4 w-[1px] bg-[#1e3a5f] mx-2"></div>

                       <button onClick={() => setPlayers([])} className="text-xs text-[#4a5f78] hover:text-red-400 uppercase tracking-widest transition-colors">
                          Clear All
                       </button>
                    </div>
                 </div>

                 <div className="perspective-container tech-border p-6 bg-[#0a1a2f]/40 min-h-[400px] mb-8">
                    <PlayerList 
                      players={players} 
                      onRemove={removePlayer} 
                      onToggleActive={togglePlayerActive}
                      onEdit={handleEditPlayer}
                    />
                 </div>

                 {/* MATCH HISTORY SECTION */}
                 <div className="mt-12">
                     <div className="flex items-center justify-between mb-6">
                        <h2 className="text-2xl font-cinzel font-black tracking-[0.2em] uppercase drop-shadow-sm text-[#dcb06b] flex items-center gap-3">
                           <span className="w-2 h-2 bg-[#dcb06b] rotate-45"></span>
                           BATTLE HISTORY
                        </h2>

                        <div className="flex items-center gap-2">
                           <button 
                             onClick={handleHistoryImportClick}
                             className="flex items-center gap-2 px-3 py-1 text-[10px] uppercase font-bold tracking-wider text-[#4a5f78] border border-[#1e3a5f] hover:border-[#dcb06b] hover:text-[#dcb06b] transition-all clip-corner-sm"
                           >
                              <svg xmlns="http://www.w3.org/2000/svg" className="h-4 w-4" fill="none" viewBox="0 0 24 24" stroke="currentColor">
                                <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M4 16v1a3 3 0 003 3h10a3 3 0 003-3v-1m-4-8l-4-4m0 0L8 8m4-4v12" />
                              </svg>
                              Import
                           </button>

                           <button 
                              onClick={handleExportHistory}
                              disabled={matchHistory.length === 0}
                              className="flex items-center gap-2 px-3 py-1 text-[10px] uppercase font-bold tracking-wider text-[#4a5f78] border border-[#1e3a5f] hover:border-[#dcb06b] hover:text-[#dcb06b] transition-all clip-corner-sm disabled:opacity-30 disabled:cursor-not-allowed"
                           >
                              <svg xmlns="http://www.w3.org/2000/svg" className="h-4 w-4" fill="none" viewBox="0 0 24 24" stroke="currentColor">
                                 <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M12 10v6m0 0l-3-3m3 3l3-3m2 8H7a2 2 0 01-2-2V5a2 2 0 012-2h5.586a1 1 0 01.707.293l5.414 5.414a1 1 0 01.293.707V19a2 2 0 01-2 2z" />
                              </svg>
                              Export
                           </button>
                        </div>
                     </div>

                     <div className="tech-border p-6 bg-[#0a1a2f]/40">
                        <HistoryList history={matchHistory} onClear={() => setMatchHistory([])} />
                     </div>
                 </div>
              </div>

            </div>
          </div>
        )}
      </main>
    </div>
  );
}

import React, { useState, useRef } from 'react';
import { Player, MatchResult, Role, MatchHistoryEntry } from './types';
import { PlayerForm } from './components/PlayerForm';
import { PlayerList } from './components/PlayerList';
import { MatchDisplay } from './components/MatchDisplay';
import { EditPlayerModal } from './components/EditPlayerModal';
import { HistoryList } from './components/HistoryList';
import { generateMatch } from './utils/matchmaker';
import { Button } from './components/Button';
import { BackgroundParticles } from './components/BackgroundParticles';

// Quick Fill Data: Honor of Kings Heroes
const HOK_HEROES = [
  { name: "Arthur", roles: [Role.CLASH] },
  { name: "Sun Ce", roles: [Role.CLASH, Role.JUNGLE] },
  { name: "Kaizer", roles: [Role.CLASH, Role.JUNGLE] },
  { name: "Biron", roles: [Role.CLASH] },
  { name: "Li Xin", roles: [Role.CLASH] },
  { name: "Charlotte", roles: [Role.CLASH] },
  { name: "Lam", roles: [Role.JUNGLE] },
  { name: "Prince of Lanling", roles: [Role.JUNGLE, Role.ROAM] },
  { name: "Wukong", roles: [Role.JUNGLE] },
  { name: "Li Bai", roles: [Role.JUNGLE] },
  { name: "Han Xin", roles: [Role.JUNGLE] },
  { name: "Luna", roles: [Role.JUNGLE, Role.MID] },
  { name: "Angela", roles: [Role.MID] },
  { name: "Diaochan", roles: [Role.MID] },
  { name: "Xiao Qiao", roles: [Role.MID] },
  { name: "Mai Shiranui", roles: [Role.MID, Role.JUNGLE] },
  { name: "Lady Zhen", roles: [Role.MID] },
  { name: "Milady", roles: [Role.MID] },
  { name: "Luban No.7", roles: [Role.FARM] },
  { name: "Marco Polo", roles: [Role.FARM] },
  { name: "Hou Yi", roles: [Role.FARM] },
  { name: "Consort Yu", roles: [Role.FARM] },
  { name: "Di Renjie", roles: [Role.FARM] },
  { name: "Arli", roles: [Role.FARM, Role.JUNGLE] },
  { name: "Dolia", roles: [Role.ROAM] },
  { name: "Kui", roles: [Role.ROAM] },
  { name: "Zhuangzi", roles: [Role.ROAM, Role.CLASH] },
  { name: "Zhang Fei", roles: [Role.ROAM] },
  { name: "Da Qiao", roles: [Role.ROAM, Role.MID] },
  { name: "Yaria", roles: [Role.ROAM] }
];

export default function App() {
  const [players, setPlayers] = useState<Player[]>([]);
  const [currentMatch, setCurrentMatch] = useState<MatchResult | null>(null);
  const [matchHistory, setMatchHistory] = useState<MatchHistoryEntry[]>([]);
  const [errorMsg, setErrorMsg] = useState<string | null>(null);
  const [roomId, setRoomId] = useState<string>('');
  const [isCoachMode, setIsCoachMode] = useState(false);

  // Edit State
  const [editingPlayer, setEditingPlayer] = useState<Player | null>(null);
  const [isEditModalOpen, setIsEditModalOpen] = useState(false);

  const rosterFileInputRef = useRef<HTMLInputElement>(null);
  const historyFileInputRef = useRef<HTMLInputElement>(null);

  const addPlayer = (newPlayer: Omit<Player, 'id' | 'isActive' | 'stats'>) => {
    setPlayers(prev => {
      // Check if player already exists (case-insensitive normalization)
      const normalizedName = newPlayer.name.trim().toLowerCase();
      const existingIndex = prev.findIndex(p => p.name.trim().toLowerCase() === normalizedName);

      if (existingIndex !== -1) {
        // UPDATE Existing Player Logic
        const updatedPlayers = [...prev];
        updatedPlayers[existingIndex] = {
          ...updatedPlayers[existingIndex],
          roles: newPlayer.roles,
          isAllRoles: newPlayer.isAllRoles,
          // We also ensure they are active if they are being updated/re-added
          isActive: true 
        };
        return updatedPlayers;
      }

      // CREATE New Player Logic
      const player: Player = { 
        ...newPlayer, 
        id: crypto.randomUUID(),
        isActive: true, // Default to active when added
        isLastMatchMvp: false,
        stats: {
          matchesPlayed: 0,
          wins: 0,
          currentStreak: 0,
          maxStreak: 0
        }
      };
      return [...prev, player];
    });
    setErrorMsg(null);
  };

  const removePlayer = (id: string) => {
    setPlayers(prev => prev.filter(p => p.id !== id));
  };

  const togglePlayerActive = (id: string) => {
    setPlayers(prev => prev.map(p => 
      p.id === id ? { ...p, isActive: !p.isActive } : p
    ));
  };

  // Edit Handlers
  const handleEditPlayer = (player: Player) => {
    setEditingPlayer(player);
    setIsEditModalOpen(true);
  };

  const handleUpdatePlayer = (updatedPlayer: Player) => {
    setPlayers(prev => prev.map(p => 
      p.id === updatedPlayer.id ? updatedPlayer : p
    ));
    setErrorMsg(null);
  };

  const activePlayers = players.filter(p => p.isActive);

  const handleGenerate = () => {
    if (!roomId.trim()) {
      setErrorMsg("Please enter a Room ID.");
      return;
    }

    const required = isCoachMode ? 12 : 10;
    if (activePlayers.length < required) {
      setErrorMsg(`Need ${required} ACTIVE players for ${isCoachMode ? 'Coach' : 'Standard'} Mode. Current Active: ${activePlayers.length}`);
      return;
    }

    // Only pass active players to the matchmaker
    const result = generateMatch(activePlayers, roomId, isCoachMode);
    if (result) {
      setCurrentMatch(result);
      setErrorMsg(null);
    } else {
      setErrorMsg("Failed to find valid composition. Ensure role coverage.");
    }
  };

  const handleRerollSlot = (team: 'azure' | 'crimson', role: Role, newPlayer: Player) => {
    if (!currentMatch) return;

    // Update Match State with the new player chosen by the wheel
    setCurrentMatch(prev => {
       if (!prev) return null;

       const newAzure = prev.azureTeam.map(slot => {
          if (team === 'azure' && slot.role === role) {
             return { ...slot, player: newPlayer };
          }
          return slot;
       });

       const newCrimson = prev.crimsonTeam.map(slot => {
          if (team === 'crimson' && slot.role === role) {
             return { ...slot, player: newPlayer };
          }
          return slot;
       });

       return {
          ...prev,
          azureTeam: newAzure,
          crimsonTeam: newCrimson
       };
    });
  };

  const handleMatchFinish = (winner: 'azure' | 'crimson' | null, mvpId?: string) => {
    if (!currentMatch) return;

    // 1. Save History
    const historyEntry: MatchHistoryEntry = {
       ...currentMatch,
       id: crypto.randomUUID(),
       winningTeam: winner,
       mvpId: mvpId
    };
    setMatchHistory(prev => [historyEntry, ...prev]);

    // 2. Update Player Stats if there is a winner
    if (winner) {
      const azurePlayerIds = new Set(currentMatch.azureTeam.map(slot => slot.player.id));
      const crimsonPlayerIds = new Set(currentMatch.crimsonTeam.map(slot => slot.player.id));

      setPlayers(prevPlayers => prevPlayers.map(p => {
        let isLastMatchMvp = false;

        // If player matches the manually provided MVP ID, set flag
        if (mvpId && p.id === mvpId) {
          isLastMatchMvp = true;
        }

        if (!azurePlayerIds.has(p.id) && !crimsonPlayerIds.has(p.id)) {
          return { ...p, isLastMatchMvp: false }; // Clear old MVP if they didn't play
        }

        const isAzure = azurePlayerIds.has(p.id);
        const isWinner = (isAzure && winner === 'azure') || (!isAzure && winner === 'crimson');

        const newStats = { ...p.stats };
        newStats.matchesPlayed += 1;

        if (isWinner) {
           newStats.wins += 1;
           newStats.currentStreak += 1;
           if (newStats.currentStreak > newStats.maxStreak) {
             newStats.maxStreak = newStats.currentStreak;
           }
        } else {
           // Reset streak on loss
           newStats.currentStreak = 0;
        }

        return { ...p, stats: newStats, isLastMatchMvp };
      }));
    } else {
      setCurrentMatch(null);
      setRoomId(''); // Reset Room ID even on draw/abandon
      return; 
    }

    // 3. Clear match and Room ID
    setCurrentMatch(null);
    setRoomId('');
  };

  const handleAbortMatch = () => setCurrentMatch(null);

  const quickFill = () => {
     const shuffledHeroes = [...HOK_HEROES].sort(() => 0.5 - Math.random());
     const heroesToAdd = shuffledHeroes.slice(0, 15);
     const newPlayers: Player[] = heroesToAdd.map(hero => ({
        id: crypto.randomUUID(),
        name: hero.name,
        isAllRoles: false,
        roles: hero.roles,
        isActive: true,
        isLastMatchMvp: false,
        stats: { matchesPlayed: 0, wins: 0, currentStreak: 0, maxStreak: 0 }
     }));
     // Add some flexible minions/players if needed to ensure we have enough
     for(let i=0; i<5; i++) {
        newPlayers.push({
           id: crypto.randomUUID(),
           name: `Flex Player ${i+1}`,
           isAllRoles: true,
           roles: [],
           isActive: true,
           isLastMatchMvp: false,
           stats: { matchesPlayed: 0, wins: 0, currentStreak: 0, maxStreak: 0 }
        });
     }

     setPlayers(prev => {
        const existingNames = new Set(prev.map(p => p.name));
        const filteredNew = newPlayers.filter(p => !existingNames.has(p.name));
        return [...prev, ...filteredNew].slice(0, 30);
     });

     if(!roomId) setRoomId(Math.floor(1000 + Math.random() * 9000).toString());
  };

  // --- SAVE / LOAD FUNCTIONALITY ---

  const handleExportRoster = () => {
    if (players.length === 0) return;
    const dataStr = "data:text/json;charset=utf-8," + encodeURIComponent(JSON.stringify(players, null, 2));
    const downloadAnchorNode = document.createElement('a');
    downloadAnchorNode.setAttribute("href", dataStr);
    downloadAnchorNode.setAttribute("download", "hok-squad-roster.json");
    document.body.appendChild(downloadAnchorNode);
    downloadAnchorNode.click();
    downloadAnchorNode.remove();
  };

  const handleExportHistory = () => {
    if (matchHistory.length === 0) return;
    const dataStr = "data:text/json;charset=utf-8," + encodeURIComponent(JSON.stringify(matchHistory, null, 2));
    const downloadAnchorNode = document.createElement('a');
    downloadAnchorNode.setAttribute("href", dataStr);
    downloadAnchorNode.setAttribute("download", "hok-match-history.json");
    document.body.appendChild(downloadAnchorNode);
    downloadAnchorNode.click();
    downloadAnchorNode.remove();
  };

  const handleRosterImportClick = () => {
    rosterFileInputRef.current?.click();
  };

  const handleHistoryImportClick = () => {
    historyFileInputRef.current?.click();
  };

  const handleRosterFileChange = (event: React.ChangeEvent<HTMLInputElement>) => {
    const fileObj = event.target.files && event.target.files[0];
    if (!fileObj) return;

    const reader = new FileReader();
    reader.onload = (e) => {
      try {
        const json = e.target?.result;
        if (typeof json === 'string') {
          const parsedData = JSON.parse(json);
          // Basic validation
          if (Array.isArray(parsedData) && parsedData.length > 0 && parsedData[0].name) {
             const importedPlayers: Player[] = parsedData.map((p: any) => ({
               ...p,
               id: crypto.randomUUID(),
               // Ensure properties exist for backward compatibility with old JSONs
               isActive: typeof p.isActive === 'boolean' ? p.isActive : true,
               isLastMatchMvp: typeof p.isLastMatchMvp === 'boolean' ? p.isLastMatchMvp : false,
               stats: p.stats || { matchesPlayed: 0, wins: 0, currentStreak: 0, maxStreak: 0 }
             }));
             setPlayers(importedPlayers);
             setErrorMsg(null);
          } else {
             setErrorMsg("Invalid Roster JSON file format.");
          }
        }
      } catch (err) {
        setErrorMsg("Failed to parse Roster JSON file.");
      }
    };
    reader.readAsText(fileObj);
    event.target.value = '';
  };

  const handleHistoryFileChange = (event: React.ChangeEvent<HTMLInputElement>) => {
    const fileObj = event.target.files && event.target.files[0];
    if (!fileObj) return;

    const reader = new FileReader();
    reader.onload = (e) => {
      try {
        const json = e.target?.result;
        if (typeof json === 'string') {
          const parsedData = JSON.parse(json);
          // Basic validation for match history
          if (Array.isArray(parsedData) && (parsedData.length === 0 || parsedData[0].roomId)) {
             setMatchHistory(parsedData);
             setErrorMsg(null);
          } else {
             setErrorMsg("Invalid History JSON file format.");
          }
        }
      } catch (err) {
        setErrorMsg("Failed to parse History JSON file.");
      }
    };
    reader.readAsText(fileObj);
    event.target.value = '';
  };

  const handleRoomIdChange = (e: React.ChangeEvent<HTMLInputElement>) => {
    const val = e.target.value;
    if (val.length <= 4) {
      setRoomId(val);
    }
  };

  return (
    <div className="min-h-screen text-slate-200 font-inter overflow-x-hidden relative">
      <BackgroundParticles />

      {/* New Background Image (HoK Global Launch) */}
      <div className="fixed inset-0 bg-black -z-10">
         <img 
           src="https://www.levelinfinite.com/wp-content/uploads/2024/03/honor-of-kings-global-launch-pc.jpg" 
           alt="Honor of Kings Background" 
           className="absolute inset-0 w-full h-full object-cover opacity-50"
         />
         <div className="absolute inset-0 bg-gradient-to-b from-[#05090f]/90 via-[#05090f]/60 to-[#05090f] mix-blend-multiply"></div>
         <div className="absolute inset-0 bg-gradient-to-t from-[#05090f] via-transparent to-[#05090f]/80"></div>
      </div>

      {/* Hidden File Inputs */}
      <input 
        type="file" 
        ref={rosterFileInputRef}
        onChange={handleRosterFileChange}
        accept=".json"
        className="hidden"
      />
      <input 
        type="file" 
        ref={historyFileInputRef}
        onChange={handleHistoryFileChange}
        accept=".json"
        className="hidden"
      />

      {/* Edit Modal */}
      {editingPlayer && (
        <EditPlayerModal 
          player={editingPlayer}
          isOpen={isEditModalOpen}
          onClose={() => setIsEditModalOpen(false)}
          onSave={handleUpdatePlayer}
        />
      )}

      {/* Cinematic Header */}
      <header className="relative z-20 h-20 flex items-center justify-center border-b border-[#dcb06b]/20 bg-[#05090f]/60 backdrop-blur-md">
        <div className="absolute inset-0 bg-gradient-to-r from-transparent via-[#dcb06b]/5 to-transparent"></div>
        <div className="flex items-center gap-3 animate-float">
           <div className="w-8 h-8 border-2 border-[#dcb06b] rotate-45 flex items-center justify-center bg-[#0a1a2f]">
              <div className="w-4 h-4 bg-[#dcb06b]"></div>
           </div>
           <h1 className="text-2xl font-cinzel font-black tracking-[0.2em] text-white">
             <span className="hok-gold-text">HONOR</span> OF <span className="hok-gold-text">KINGS</span>
             <span className="block text-[8px] text-[#8a9db8] tracking-[0.5em] font-orbitron mt-0.5">OPEN MABAR CUSTOM FUN MATCH</span>
           </h1>
        </div>
      </header>

      <main className="relative z-10 pt-8 px-4 pb-20">
        {currentMatch ? (
          <MatchDisplay 
            match={currentMatch} 
            activePlayers={activePlayers} 
            onReset={handleAbortMatch}
            onCompleteMatch={handleMatchFinish}
            onReroll={handleRerollSlot}
          />
        ) : (
          <div className="max-w-7xl mx-auto">

            <div className="grid grid-cols-1 lg:grid-cols-12 gap-8">

              {/* Left Panel: Controls */}
              <div className="lg:col-span-4 space-y-6">

                 {/* Room ID & Coach Mode Toggle */}
                 <div className="bg-[#0a1a2f]/80 p-1 clip-corner-sm border border-[#1e3a5f] shadow-[0_0_25px_rgba(220,176,107,0.15)] relative group space-y-2">
                    <div className="absolute -inset-1 bg-gradient-to-r from-transparent via-[#dcb06b]/30 to-transparent blur opacity-0 group-hover:opacity-100 transition-opacity duration-700"></div>

                    <div className="bg-[#05090f] p-4 flex items-center gap-4 clip-corner-sm relative z-10">
                       <label className="text-xs uppercase text-[#dcb06b] font-bold font-orbitron whitespace-nowrap tracking-widest">Room ID</label>
                       <div className="h-8 w-[1px] bg-[#1e3a5f]"></div>
                       <input 
                          type="text" 
                          value={roomId}
                          onChange={handleRoomIdChange}
                          maxLength={4}
                          placeholder="0000"
                          className="bg-transparent text-lg font-orbitron text-white w-full focus:outline-none tracking-widest placeholder-[#1e3a5f]"
                       />
                    </div>
                 </div>

                 <div className="flex items-center justify-between bg-[#0a1a2f]/60 p-4 border border-[#1e3a5f] clip-corner-sm">
                     <span className="text-[#dcb06b] font-cinzel font-bold text-sm tracking-widest flex items-center gap-2">
                        <svg xmlns="http://www.w3.org/2000/svg" className="h-4 w-4" fill="none" viewBox="0 0 24 24" stroke="currentColor">
                           <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M19 11H5m14 0a2 2 0 012 2v6a2 2 0 01-2 2H5a2 2 0 01-2-2v-6a2 2 0 012-2m14 0V9a2 2 0 00-2-2M5 11V9a2 2 0 012-2m0 0V5a2 2 0 012-2h6a2 2 0 012 2v2M7 7h10" />
                        </svg>
                        COACH MODE
                     </span>
                     <label className="relative inline-flex items-center cursor-pointer">
                        <input type="checkbox" className="sr-only peer" checked={isCoachMode} onChange={(e) => setIsCoachMode(e.target.checked)} />
                        <div className="w-11 h-6 bg-[#1e3a5f] peer-focus:outline-none rounded-full peer peer-checked:after:translate-x-full peer-checked:after:border-white after:content-[''] after:absolute after:top-[2px] after:left-[2px] after:bg-white after:border-gray-300 after:border after:rounded-full after:h-5 after:w-5 after:transition-all peer-checked:bg-[#dcb06b]"></div>
                     </label>
                 </div>

                 <PlayerForm onAddPlayer={addPlayer} isCoachMode={isCoachMode} />

                 {/* Status Panel */}
                 <div className="relative p-6 clip-corner-md bg-gradient-to-b from-[#1a2c42] to-[#05090f] border border-[#dcb06b]/20 group hover:border-[#dcb06b]/50 transition-colors duration-500">
                    <div className="absolute top-0 left-0 w-full h-1 bg-gradient-to-r from-transparent via-[#dcb06b] to-transparent opacity-50"></div>

                    <div className="flex justify-between items-end mb-6">
                       <div>
                          <div className="text-[#8a9db8] text-[10px] uppercase tracking-widest font-bold mb-1">Active Players</div>
                          <div className="text-5xl font-orbitron font-bold text-white relative">
                             {activePlayers.length}
                             <span className="text-lg text-[#4a5f78] absolute top-0 -right-12">/ {isCoachMode ? 12 : 10}</span>
                          </div>
                       </div>
                       <div className="text-right">
                          <button onClick={quickFill} className="text-[10px] text-[#dcb06b] border border-[#dcb06b] px-3 py-1 hover:bg-[#dcb06b] hover:text-black transition-colors uppercase tracking-wider">
                             Quick Fill
                          </button>
                       </div>
                    </div>

                    {errorMsg && (
                      <div className="mb-4 p-3 border-l-2 border-red-500 bg-red-900/20 text-red-200 text-xs">
                        {errorMsg}
                      </div>
                    )}

                    <Button 
                      onClick={handleGenerate} 
                      className="w-full text-lg shadow-[0_0_20px_rgba(220,176,107,0.3)]"
                      disabled={activePlayers.length < (isCoachMode ? 12 : 10)}
                    >
                       START MATCHMAKING
                    </Button>
                 </div>
              </div>

              {/* Right Panel: Player Grid & History */}
              <div className="lg:col-span-8">
                 <div className="flex flex-wrap items-center justify-between mb-6 gap-4">
                    <h2 className="text-2xl font-cinzel font-black tracking-[0.2em] uppercase drop-shadow-sm text-[#dcb06b] flex items-center gap-3">
                       <span className="w-2 h-2 bg-[#dcb06b] rotate-45"></span>
                       SQUAD ROSTER
                    </h2>

                    <div className="flex items-center gap-2">
                       {/* Import/Export Controls */}
                       <button 
                         onClick={handleRosterImportClick}
                         className="flex items-center gap-2 px-3 py-1 text-[10px] uppercase font-bold tracking-wider text-[#4a5f78] border border-[#1e3a5f] hover:border-[#dcb06b] hover:text-[#dcb06b] transition-all clip-corner-sm"
                         title="Load Roster JSON"
                       >
                          <svg xmlns="http://www.w3.org/2000/svg" className="h-4 w-4" fill="none" viewBox="0 0 24 24" stroke="currentColor">
                            <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M4 16v1a3 3 0 003 3h10a3 3 0 003-3v-1m-4-8l-4-4m0 0L8 8m4-4v12" />
                          </svg>
                          Load
                       </button>

                       <button 
                         onClick={handleExportRoster}
                         disabled={players.length === 0}
                         className="flex items-center gap-2 px-3 py-1 text-[10px] uppercase font-bold tracking-wider text-[#4a5f78] border border-[#1e3a5f] hover:border-[#dcb06b] hover:text-[#dcb06b] transition-all clip-corner-sm disabled:opacity-30 disabled:cursor-not-allowed"
                         title="Save Roster JSON"
                       >
                          <svg xmlns="http://www.w3.org/2000/svg" className="h-4 w-4" fill="none" viewBox="0 0 24 24" stroke="currentColor">
                            <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M4 16v1a3 3 0 003 3h10a3 3 0 003-3v-1m-4-4l-4 4m0 0l-4-4m4 4V4" />
                          </svg>
                          Save
                       </button>

                       <div className="h-4 w-[1px] bg-[#1e3a5f] mx-2"></div>

                       <button onClick={() => setPlayers([])} className="text-xs text-[#4a5f78] hover:text-red-400 uppercase tracking-widest transition-colors">
                          Clear All
                       </button>
                    </div>
                 </div>

                 <div className="perspective-container tech-border p-6 bg-[#0a1a2f]/40 min-h-[400px] mb-8">
                    <PlayerList 
                      players={players} 
                      onRemove={removePlayer} 
                      onToggleActive={togglePlayerActive}
                      onEdit={handleEditPlayer}
                    />
                 </div>

                 {/* MATCH HISTORY SECTION */}
                 <div className="mt-12">
                     <div className="flex items-center justify-between mb-6">
                        <h2 className="text-2xl font-cinzel font-black tracking-[0.2em] uppercase drop-shadow-sm text-[#dcb06b] flex items-center gap-3">
                           <span className="w-2 h-2 bg-[#dcb06b] rotate-45"></span>
                           BATTLE HISTORY
                        </h2>

                        <div className="flex items-center gap-2">
                           <button 
                             onClick={handleHistoryImportClick}
                             className="flex items-center gap-2 px-3 py-1 text-[10px] uppercase font-bold tracking-wider text-[#4a5f78] border border-[#1e3a5f] hover:border-[#dcb06b] hover:text-[#dcb06b] transition-all clip-corner-sm"
                           >
                              <svg xmlns="http://www.w3.org/2000/svg" className="h-4 w-4" fill="none" viewBox="0 0 24 24" stroke="currentColor">
                                <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M4 16v1a3 3 0 003 3h10a3 3 0 003-3v-1m-4-8l-4-4m0 0L8 8m4-4v12" />
                              </svg>
                              Import
                           </button>

                           <button 
                              onClick={handleExportHistory}
                              disabled={matchHistory.length === 0}
                              className="flex items-center gap-2 px-3 py-1 text-[10px] uppercase font-bold tracking-wider text-[#4a5f78] border border-[#1e3a5f] hover:border-[#dcb06b] hover:text-[#dcb06b] transition-all clip-corner-sm disabled:opacity-30 disabled:cursor-not-allowed"
                           >
                              <svg xmlns="http://www.w3.org/2000/svg" className="h-4 w-4" fill="none" viewBox="0 0 24 24" stroke="currentColor">
                                 <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M12 10v6m0 0l-3-3m3 3l3-3m2 8H7a2 2 0 01-2-2V5a2 2 0 012-2h5.586a1 1 0 01.707.293l5.414 5.414a1 1 0 01.293.707V19a2 2 0 01-2 2z" />
                              </svg>
                              Export
                           </button>
                        </div>
                     </div>

                     <div className="tech-border p-6 bg-[#0a1a2f]/40">
                        <HistoryList history={matchHistory} onClear={() => setMatchHistory([])} />
                     </div>
                 </div>
              </div>

            </div>
          </div>
        )}
      </main>
    </div>
  );
}

import React, { useState, useEffect } from 'react';
import { Player, Role } from '../types';
import { RoleIcons, ROLES_ORDER } from '../constants';

interface PlayerListProps {
  players: Player[];
  onRemove: (id: string) => void;
  onToggleActive: (id: string) => void;
  onEdit: (player: Player) => void;
}

type FilterType = 'ALL' | 'ACTIVE' | 'BENCH' | Role;

export const PlayerList: React.FC<PlayerListProps> = ({ players, onRemove, onToggleActive, onEdit }) => {
  const [filter, setFilter] = useState<FilterType>('ALL');
  const [menuOpenId, setMenuOpenId] = useState<string | null>(null);

  // Close menu when clicking outside
  useEffect(() => {
    const handleClickOutside = () => setMenuOpenId(null);
    if (menuOpenId) {
      document.addEventListener('click', handleClickOutside);
    }
    return () => {
      document.removeEventListener('click', handleClickOutside);
    };
  }, [menuOpenId]);

  const toggleMenu = (e: React.MouseEvent, id: string) => {
    e.stopPropagation();
    setMenuOpenId(prev => prev === id ? null : id);
  };

  // Filter Logic
  const filteredPlayers = players.filter(p => {
    if (filter === 'ALL') return true;
    if (filter === 'ACTIVE') return p.isActive;
    if (filter === 'BENCH') return !p.isActive;
    // Check for specific Role
    if (Object.values(Role).includes(filter as Role)) {
       // Special handling: if filter is Coach, check exact match or if roles includes it
       return p.roles.includes(filter as Role);
    }
    return true;
  });

  const filters: { label: string; value: FilterType; icon?: React.ReactNode }[] = [
    { label: 'All', value: 'ALL' },
    { label: 'Playing', value: 'ACTIVE' },
    { label: 'Benched', value: 'BENCH' },
    ...ROLES_ORDER.map(r => ({ label: r.split(' ')[0], value: r })),
    { label: 'Coach', value: Role.COACH }
  ];

  if (players.length === 0) {
    return (
      <div className="h-full min-h-[300px] flex flex-col items-center justify-center border border-dashed border-[#1e3a5f] rounded-lg bg-[#0a1a2f]/30 p-8">
        <div className="w-20 h-20 rounded-full bg-[#1e3a5f]/50 flex items-center justify-center mb-4 border border-[#dcb06b]/20">
           <svg xmlns="http://www.w3.org/2000/svg" className="h-8 w-8 text-[#dcb06b]/50" fill="none" viewBox="0 0 24 24" stroke="currentColor"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M12 4.354a4 4 0 110 5.292M15 21H3v-1a6 6 0 0112 0v1zm0 0h6v-1a6 6 0 00-9-5.197M13 7a4 4 0 11-8 0 4 4 0 018 0z" /></svg>
        </div>
        <p className="text-[#8a9db8] font-cinzel tracking-widest text-sm">Waiting for Challengers</p>
      </div>
    );
  }

  return (
    <div>
      {/* FILTER BAR */}
      <div className="mb-6 overflow-x-auto pb-2 scrollbar-hide">
         <div className="flex gap-2 min-w-max">
            {filters.map(f => (
               <button
                 key={f.value}
                 onClick={() => setFilter(f.value)}
                 className={`
                   px-3 py-1.5 text-[10px] uppercase font-bold tracking-wider clip-corner-sm border transition-all
                   ${filter === f.value 
                      ? 'bg-[#dcb06b] text-[#05090f] border-[#dcb06b]' 
                      : 'bg-[#0a1a2f] text-[#8a9db8] border-[#1e3a5f] hover:border-[#dcb06b]/50 hover:text-white'}
                 `}
               >
                 {f.label}
               </button>
            ))}
         </div>
      </div>

      {/* PLAYER GRID */}
      <div className="grid grid-cols-1 sm:grid-cols-2 lg:grid-cols-3 xl:grid-cols-4 gap-6">
        {filteredPlayers.map(player => {
          const isActive = player.isActive;
          const stats = player.stats || { matchesPlayed: 0, wins: 0, currentStreak: 0, maxStreak: 0 };
          const winRate = stats.matchesPlayed > 0 
            ? Math.round((stats.wins / stats.matchesPlayed) * 100) 
            : 0;

          const streak = stats.currentStreak;
          const isHot = streak >= 3;
          const isGodlike = streak >= 6;
          const isMvp = player.isLastMatchMvp;
          const isCoach = player.roles.includes(Role.COACH);

          // Styles for specific states
          let containerGlow = "";
          let borderOverlay = null;

          if (isMvp) {
              containerGlow = "drop-shadow-[0_0_20px_rgba(251,191,36,0.8)]";
              borderOverlay = (
                <div className="absolute -inset-[3px] clip-corner-sm overflow-hidden z-0">
                    <div className="absolute top-[-50%] left-[-50%] w-[200%] h-[200%] animate-spin-slow bg-[conic-gradient(transparent,transparent,#fcd34d,#fbbf24)] opacity-100"></div>
                    <div className="absolute inset-0 bg-yellow-500/10 animate-pulse"></div>
                </div>
              );
          } else if (isActive) {
            if (isCoach) {
              containerGlow = "drop-shadow-[0_0_15px_rgba(255,255,255,0.6)]";
              borderOverlay = (
                <div className="absolute -inset-[2px] clip-corner-sm overflow-hidden z-0">
                    <div className="absolute top-[-50%] left-[-50%] w-[200%] h-[200%] animate-spin-slow bg-[conic-gradient(transparent,transparent,#ffffff)] opacity-100"></div>
                </div>
              );
            } else if (isGodlike) {
              containerGlow = "drop-shadow-[0_0_15px_rgba(239,68,68,0.8)]";
              borderOverlay = (
                <div className="absolute -inset-[2px] clip-corner-sm overflow-hidden z-0">
                    <div className="absolute top-[-50%] left-[-50%] w-[200%] h-[200%] animate-spin-slow bg-[conic-gradient(transparent,transparent,#ef4444)] opacity-100"></div>
                </div>
              );
            } else if (isHot) {
              containerGlow = "drop-shadow-[0_0_10px_rgba(6,182,212,0.6)]";
              borderOverlay = (
                <div className="absolute -inset-[2px] clip-corner-sm overflow-hidden z-0">
                    <div className="absolute top-[-50%] left-[-50%] w-[200%] h-[200%] animate-spin-slow bg-[conic-gradient(transparent,transparent,#06b6d4)] opacity-100"></div>
                </div>
              );
            }
          }

          let bgClass = 'bg-[#05090f]';
          if (isActive && isCoach) bgClass = 'bg-black';

          let borderClass = 'border border-[#1e3a5f]';
          if (isMvp) borderClass = 'border-2 border-yellow-400';
          else if (isActive && (isHot || isGodlike || isCoach)) borderClass = 'border-none';

          return (
            <div key={player.id} className={`relative group ${containerGlow} tilt-card`}>

              {borderOverlay}

              <div 
                className={`
                  relative z-10 p-3 pb-12 clip-corner-sm h-full flex flex-col
                  ${bgClass} ${borderClass}
                  ${!isActive ? 'opacity-60 grayscale hover:opacity-100' : 'hover:border-[#dcb06b]/50'}
                `}
                style={isActive && (isHot || isGodlike || isCoach) && !isMvp ? { margin: '1px' } : {}}
              >

                {/* Header Row: Name & Menu */}
                <div className={`flex justify-between items-start mb-3 border-b pb-2 ${isMvp ? 'border-yellow-400/50' : isGodlike ? 'border-red-900' : isHot ? 'border-cyan-900' : isCoach ? 'border-white/30' : 'border-[#1e3a5f]'} group-hover:border-[#dcb06b]/30`}>
                  <div className="flex items-center gap-2 flex-1 min-w-0 mr-1">
                      {isMvp && (
                        <div className="relative group/mvp shrink-0">
                          <div className="text-[10px] font-black bg-gradient-to-r from-yellow-300 to-yellow-600 text-[#05090f] px-1 rounded-sm shadow-[0_0_10px_#fbbf24] animate-pulse">MVP</div>
                        </div>
                      )}

                      {!isMvp && isHot && isActive && !isCoach && (
                        <div className="relative group/flame shrink-0">
                          <svg xmlns="http://www.w3.org/2000/svg" viewBox="0 0 24 24" fill="currentColor" className={`w-4 h-4 animate-pulse ${isGodlike ? 'text-red-500' : 'text-cyan-400'}`}>
                            <path fillRule="evenodd" d="M12.963 2.286a.75.75 0 00-1.071-.136 9.742 9.742 0 00-3.539 6.177 7.547 7.547 0 01-1.705-1.715.75.75 0 00-1.152-.082A9 9 0 1015.68 4.534a7.46 7.46 0 01-2.717-2.248zM15.75 14.25a3.75 3.75 0 11-7.5 0 3.75 3.75 0 017.5 0z" clipRule="evenodd" />
                          </svg>
                        </div>
                      )}

                      {isCoach && (
                          <div className="text-[10px] font-black bg-white text-black px-1 rounded-sm shadow-[0_0_10px_#ffffff] shrink-0">COACH</div>
                      )}

                      <div 
                        className={`font-bold font-orbitron tracking-wide leading-tight truncate w-full ${isMvp ? 'text-yellow-400' : isCoach ? 'text-white' : isActive ? 'text-[#f0f4f8] group-hover:text-[#dcb06b]' : 'text-[#4a5f78]'}`}
                        title={player.name}
                      >
                          {player.name}
                      </div>
                  </div>

                  {/* Three-Dot Menu */}
                  <div className="relative shrink-0">
                    <button 
                       onClick={(e) => toggleMenu(e, player.id)}
                       className="p-1 text-[#4a5f78] hover:text-[#dcb06b] transition-colors"
                    >
                       <svg xmlns="http://www.w3.org/2000/svg" className="h-5 w-5" fill="none" viewBox="0 0 24 24" stroke="currentColor">
                         <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M12 5v.01M12 12v.01M12 19v.01M12 6a1 1 0 110-2 1 1 0 010 2zm0 7a1 1 0 110-2 1 1 0 010 2zm0 7a1 1 0 110-2 1 1 0 010 2z" />
                       </svg>
                    </button>

                    {/* Dropdown Content */}
                    {menuOpenId === player.id && (
                       <div className="absolute right-0 top-full mt-1 w-32 bg-[#05090f] border border-[#dcb06b] z-50 shadow-[0_0_20px_rgba(0,0,0,0.8)] clip-corner-sm flex flex-col animate-slide-in">
                          <button 
                            onClick={(e) => { e.stopPropagation(); onToggleActive(player.id); setMenuOpenId(null); }}
                            className="px-3 py-2 text-left text-[10px] uppercase font-bold text-[#f0f4f8] hover:bg-[#dcb06b] hover:text-[#05090f] transition-colors"
                          >
                             {isActive ? 'Bench Player' : 'Activate'}
                          </button>
                          <button 
                            onClick={(e) => { e.stopPropagation(); onEdit(player); setMenuOpenId(null); }}
                            className="px-3 py-2 text-left text-[10px] uppercase font-bold text-[#f0f4f8] hover:bg-[#dcb06b] hover:text-[#05090f] transition-colors"
                          >
                             Edit Details
                          </button>
                          <div className="h-[1px] bg-[#1e3a5f] w-full"></div>
                          <button 
                            onClick={(e) => { e.stopPropagation(); onRemove(player.id); setMenuOpenId(null); }}
                            className="px-3 py-2 text-left text-[10px] uppercase font-bold text-red-500 hover:bg-red-500 hover:text-white transition-colors"
                          >
                             Remove
                          </button>
                       </div>
                    )}
                  </div>
                </div>

                {/* Roles */}
                <div className="w-full mb-3 flex-grow">
                  {player.isAllRoles ? (
                    <div className={`w-full flex items-center justify-center gap-2 py-1.5 border clip-corner-sm ${isActive ? 'bg-[#dcb06b]/10 text-[#dcb06b] border-[#dcb06b]/30' : 'bg-[#1e3a5f]/20 text-[#4a5f78] border-[#1e3a5f]/30'}`}>
                      <span className="w-1.5 h-1.5 bg-current rounded-full animate-pulse"></span>
                      <span className="text-[9px] font-bold uppercase tracking-widest">All Roles</span>
                      <span className="w-1.5 h-1.5 bg-current rounded-full animate-pulse"></span>
                    </div>
                  ) : (
                    <div className="flex flex-wrap gap-1.5">
                        {player.roles.length === 0 && (
                          <span className="text-[9px] text-red-400 italic">No role selected</span>
                        )}
                        {player.roles.map(role => (
                          <div key={role} className={`
                              flex items-center justify-center px-2 py-1 gap-1.5 
                              clip-corner-sm border transition-colors flex-grow sm:flex-grow-0
                              ${isActive ? 'bg-[#1e3a5f]/50 text-[#8a9db8] border-transparent' : 'bg-[#0f223d]/50 text-[#4a5f78] border-transparent'}
                          `}>
                              <span className="text-[8px] uppercase font-bold tracking-wider leading-none whitespace-nowrap">
                                {role === Role.COACH ? 'COACH' : role.split(' ')[0]}
                              </span>
                          </div>
                        ))}
                    </div>
                  )}
                </div>

                {/* Stats Footer */}
                <div className={`absolute bottom-0 left-0 right-0 h-8 flex items-center justify-between px-3 text-[10px] font-mono border-t border-[#1e3a5f] bg-[#05090f]/50 ${isActive ? 'opacity-100' : 'opacity-50'}`}>
                  <div className="flex items-center gap-2">
                    <span className="text-[#4a5f78]">Matches:</span>
                    <span className="text-[#f0f4f8]">{stats.matchesPlayed}</span>
                  </div>

                  {stats.matchesPlayed > 0 && (
                      <div className="flex items-center gap-2">
                        <span className="text-[#4a5f78]">WR:</span>
                        <span className={`font-bold ${winRate >= 60 ? 'text-[#dcb06b]' : winRate >= 50 ? 'text-[#f0f4f8]' : 'text-red-400'}`}>
                          {winRate}%
                        </span>
                      </div>
                  )}
                </div>

                {/* Status Indicator Text for Inactive */}
                {!isActive && (
                  <div className="absolute inset-0 flex items-center justify-center pointer-events-none z-10">
                    <span className="text-[#0a1a2f] font-black text-2xl -rotate-12 opacity-40 uppercase tracking-widest select-none bg-[#dcb06b] px-2 mix-blend-screen">Benched</span>
                  </div>
                )}

                {/* Decorative Corner for Active Players */}
                {isActive && (
                  <>
                    <div className={`absolute top-0 left-0 w-2 h-2 border-t border-l ${isMvp ? 'border-yellow-400' : isCoach ? 'border-white' : 'border-[#dcb06b]'} opacity-0 group-hover:opacity-100 transition-opacity`}></div>
                    <div className={`absolute bottom-8 right-0 w-2 h-2 border-b border-r ${isMvp ? 'border-yellow-400' : isCoach ? 'border-white' : 'border-[#dcb06b]'} opacity-0 group-hover:opacity-100 transition-opacity`}></div>
                  </>
                )}
              </div>
            </div>
          );
        })}
      </div>
    </div>
  );
};

import React, { useState, useRef } from 'react';
import { Player, MatchResult, Role, MatchHistoryEntry } from './types';
import { PlayerForm } from './components/PlayerForm';
import { PlayerList } from './components/PlayerList';
import { MatchDisplay } from './components/MatchDisplay';
import { EditPlayerModal } from './components/EditPlayerModal';
import { HistoryList } from './components/HistoryList';
import { generateMatch } from './utils/matchmaker';
import { Button } from './components/Button';
import { BackgroundParticles } from './components/BackgroundParticles';

// Quick Fill Data: Honor of Kings Heroes
const HOK_HEROES = [
  { name: "Arthur", roles: [Role.CLASH] },
  { name: "Sun Ce", roles: [Role.CLASH, Role.JUNGLE] },
  { name: "Kaizer", roles: [Role.CLASH, Role.JUNGLE] },
  { name: "Biron", roles: [Role.CLASH] },
  { name: "Li Xin", roles: [Role.CLASH] },
  { name: "Charlotte", roles: [Role.CLASH] },
  { name: "Lam", roles: [Role.JUNGLE] },
  { name: "Prince of Lanling", roles: [Role.JUNGLE, Role.ROAM] },
  { name: "Wukong", roles: [Role.JUNGLE] },
  { name: "Li Bai", roles: [Role.JUNGLE] },
  { name: "Han Xin", roles: [Role.JUNGLE] },
  { name: "Luna", roles: [Role.JUNGLE, Role.MID] },
  { name: "Angela", roles: [Role.MID] },
  { name: "Diaochan", roles: [Role.MID] },
  { name: "Xiao Qiao", roles: [Role.MID] },
  { name: "Mai Shiranui", roles: [Role.MID, Role.JUNGLE] },
  { name: "Lady Zhen", roles: [Role.MID] },
  { name: "Milady", roles: [Role.MID] },
  { name: "Luban No.7", roles: [Role.FARM] },
  { name: "Marco Polo", roles: [Role.FARM] },
  { name: "Hou Yi", roles: [Role.FARM] },
  { name: "Consort Yu", roles: [Role.FARM] },
  { name: "Di Renjie", roles: [Role.FARM] },
  { name: "Arli", roles: [Role.FARM, Role.JUNGLE] },
  { name: "Dolia", roles: [Role.ROAM] },
  { name: "Kui", roles: [Role.ROAM] },
  { name: "Zhuangzi", roles: [Role.ROAM, Role.CLASH] },
  { name: "Zhang Fei", roles: [Role.ROAM] },
  { name: "Da Qiao", roles: [Role.ROAM, Role.MID] },
  { name: "Yaria", roles: [Role.ROAM] }
];

export default function App() {
  const [players, setPlayers] = useState<Player[]>([]);
  const [currentMatch, setCurrentMatch] = useState<MatchResult | null>(null);
  const [matchHistory, setMatchHistory] = useState<MatchHistoryEntry[]>([]);
  const [errorMsg, setErrorMsg] = useState<string | null>(null);
  const [roomId, setRoomId] = useState<string>('');
  const [isCoachMode, setIsCoachMode] = useState(false);

  // Edit State
  const [editingPlayer, setEditingPlayer] = useState<Player | null>(null);
  const [isEditModalOpen, setIsEditModalOpen] = useState(false);

  const rosterFileInputRef = useRef<HTMLInputElement>(null);
  const historyFileInputRef = useRef<HTMLInputElement>(null);

  const addPlayer = (newPlayer: Omit<Player, 'id' | 'isActive' | 'stats'>) => {
    setPlayers(prev => {
      // Check if player already exists (case-insensitive normalization)
      const normalizedName = newPlayer.name.trim().toLowerCase();
      const existingIndex = prev.findIndex(p => p.name.trim().toLowerCase() === normalizedName);

      if (existingIndex !== -1) {
        // UPDATE Existing Player Logic
        const updatedPlayers = [...prev];
        updatedPlayers[existingIndex] = {
          ...updatedPlayers[existingIndex],
          roles: newPlayer.roles,
          isAllRoles: newPlayer.isAllRoles,
          // We also ensure they are active if they are being updated/re-added
          isActive: true 
        };
        return updatedPlayers;
      }

      // CREATE New Player Logic
      const player: Player = { 
        ...newPlayer, 
        id: crypto.randomUUID(),
        isActive: true, // Default to active when added
        isLastMatchMvp: false,
        stats: {
          matchesPlayed: 0,
          wins: 0,
          currentStreak: 0,
          maxStreak: 0
        }
      };
      return [...prev, player];
    });
    setErrorMsg(null);
  };

  const removePlayer = (id: string) => {
    setPlayers(prev => prev.filter(p => p.id !== id));
  };

  const togglePlayerActive = (id: string) => {
    setPlayers(prev => prev.map(p => 
      p.id === id ? { ...p, isActive: !p.isActive } : p
    ));
  };

  // Edit Handlers
  const handleEditPlayer = (player: Player) => {
    setEditingPlayer(player);
    setIsEditModalOpen(true);
  };

  const handleUpdatePlayer = (updatedPlayer: Player) => {
    setPlayers(prev => prev.map(p => 
      p.id === updatedPlayer.id ? updatedPlayer : p
    ));
    setErrorMsg(null);
  };

  const activePlayers = players.filter(p => p.isActive);

  const handleGenerate = () => {
    if (!roomId.trim()) {
      setErrorMsg("Please enter a Room ID.");
      return;
    }

    const required = isCoachMode ? 12 : 10;
    if (activePlayers.length < required) {
      setErrorMsg(`Need ${required} ACTIVE players for ${isCoachMode ? 'Coach' : 'Standard'} Mode. Current Active: ${activePlayers.length}`);
      return;
    }

    // COACH MODE VALIDATION
    if (isCoachMode) {
       // Check if there are at least 2 players who can be Coach
       // This means: Has Role.COACH explicitly OR isAllRoles
       const coachCandidates = activePlayers.filter(p => p.isAllRoles || p.roles.includes(Role.COACH));

       if (coachCandidates.length < 2) {
         setErrorMsg(`Coach Mode requires at least 2 players capable of Coaching (Selected 'Coach' role or 'All Roles'). Found: ${coachCandidates.length}`);
         return;
       }
    }

    // Only pass active players to the matchmaker
    const result = generateMatch(activePlayers, roomId, isCoachMode);
    if (result) {
      setCurrentMatch(result);
      setErrorMsg(null);
    } else {
      setErrorMsg("Failed to find valid composition. Ensure role coverage.");
    }
  };

  const handleRerollSlot = (team: 'azure' | 'crimson', role: Role, newPlayer: Player) => {
    if (!currentMatch) return;

    // Update Match State with the new player chosen by the wheel
    setCurrentMatch(prev => {
       if (!prev) return null;

       const newAzure = prev.azureTeam.map(slot => {
          if (team === 'azure' && slot.role === role) {
             return { ...slot, player: newPlayer };
          }
          return slot;
       });

       const newCrimson = prev.crimsonTeam.map(slot => {
          if (team === 'crimson' && slot.role === role) {
             return { ...slot, player: newPlayer };
          }
          return slot;
       });

       return {
          ...prev,
          azureTeam: newAzure,
          crimsonTeam: newCrimson
       };
    });
  };

  const handleMatchFinish = (winner: 'azure' | 'crimson' | null, mvpId?: string) => {
    if (!currentMatch) return;

    // 1. Save History
    const historyEntry: MatchHistoryEntry = {
       ...currentMatch,
       id: crypto.randomUUID(),
       winningTeam: winner,
       mvpId: mvpId
    };
    setMatchHistory(prev => [historyEntry, ...prev]);

    // 2. Update Player Stats if there is a winner
    if (winner) {
      const azurePlayerIds = new Set(currentMatch.azureTeam.map(slot => slot.player.id));
      const crimsonPlayerIds = new Set(currentMatch.crimsonTeam.map(slot => slot.player.id));

      setPlayers(prevPlayers => prevPlayers.map(p => {
        let isLastMatchMvp = false;

        // If player matches the manually provided MVP ID, set flag
        if (mvpId && p.id === mvpId) {
          isLastMatchMvp = true;
        }

        if (!azurePlayerIds.has(p.id) && !crimsonPlayerIds.has(p.id)) {
          return { ...p, isLastMatchMvp: false }; // Clear old MVP if they didn't play
        }

        const isAzure = azurePlayerIds.has(p.id);
        const isWinner = (isAzure && winner === 'azure') || (!isAzure && winner === 'crimson');

        const newStats = { ...p.stats };
        newStats.matchesPlayed += 1;

        if (isWinner) {
           newStats.wins += 1;
           newStats.currentStreak += 1;
           if (newStats.currentStreak > newStats.maxStreak) {
             newStats.maxStreak = newStats.currentStreak;
           }
        } else {
           // Reset streak on loss
           newStats.currentStreak = 0;
        }

        return { ...p, stats: newStats, isLastMatchMvp };
      }));
    } else {
      setCurrentMatch(null);
      setRoomId(''); // Reset Room ID even on draw/abandon
      return; 
    }

    // 3. Clear match and Room ID
    setCurrentMatch(null);
    setRoomId('');
  };

  const handleAbortMatch = () => setCurrentMatch(null);

  const quickFill = () => {
     const shuffledHeroes = [...HOK_HEROES].sort(() => 0.5 - Math.random());
     const heroesToAdd = shuffledHeroes.slice(0, 15);
     const newPlayers: Player[] = heroesToAdd.map(hero => ({
        id: crypto.randomUUID(),
        name: hero.name,
        isAllRoles: false,
        roles: hero.roles,
        isActive: true,
        isLastMatchMvp: false,
        stats: { matchesPlayed: 0, wins: 0, currentStreak: 0, maxStreak: 0 }
     }));
     // Add some flexible minions/players if needed to ensure we have enough
     for(let i=0; i<5; i++) {
        newPlayers.push({
           id: crypto.randomUUID(),
           name: `Flex Player ${i+1}`,
           isAllRoles: true,
           roles: [],
           isActive: true,
           isLastMatchMvp: false,
           stats: { matchesPlayed: 0, wins: 0, currentStreak: 0, maxStreak: 0 }
        });
     }

     setPlayers(prev => {
        const existingNames = new Set(prev.map(p => p.name));
        const filteredNew = newPlayers.filter(p => !existingNames.has(p.name));
        return [...prev, ...filteredNew].slice(0, 30);
     });

     if(!roomId) setRoomId(Math.floor(1000 + Math.random() * 9000).toString());
  };

  // --- SAVE / LOAD FUNCTIONALITY ---

  const handleExportRoster = () => {
    if (players.length === 0) return;
    const dataStr = "data:text/json;charset=utf-8," + encodeURIComponent(JSON.stringify(players, null, 2));
    const downloadAnchorNode = document.createElement('a');
    downloadAnchorNode.setAttribute("href", dataStr);
    downloadAnchorNode.setAttribute("download", "hok-squad-roster.json");
    document.body.appendChild(downloadAnchorNode);
    downloadAnchorNode.click();
    downloadAnchorNode.remove();
  };

  const handleExportHistory = () => {
    if (matchHistory.length === 0) return;
    const dataStr = "data:text/json;charset=utf-8," + encodeURIComponent(JSON.stringify(matchHistory, null, 2));
    const downloadAnchorNode = document.createElement('a');
    downloadAnchorNode.setAttribute("href", dataStr);
    downloadAnchorNode.setAttribute("download", "hok-match-history.json");
    document.body.appendChild(downloadAnchorNode);
    downloadAnchorNode.click();
    downloadAnchorNode.remove();
  };

  const handleRosterImportClick = () => {
    rosterFileInputRef.current?.click();
  };

  const handleHistoryImportClick = () => {
    historyFileInputRef.current?.click();
  };

  const handleRosterFileChange = (event: React.ChangeEvent<HTMLInputElement>) => {
    const fileObj = event.target.files && event.target.files[0];
    if (!fileObj) return;

    const reader = new FileReader();
    reader.onload = (e) => {
      try {
        const json = e.target?.result;
        if (typeof json === 'string') {
          const parsedData = JSON.parse(json);
          // Basic validation
          if (Array.isArray(parsedData) && parsedData.length > 0 && parsedData[0].name) {
             const importedPlayers: Player[] = parsedData.map((p: any) => ({
               ...p,
               id: crypto.randomUUID(),
               // Ensure properties exist for backward compatibility with old JSONs
               isActive: typeof p.isActive === 'boolean' ? p.isActive : true,
               isLastMatchMvp: typeof p.isLastMatchMvp === 'boolean' ? p.isLastMatchMvp : false,
               stats: p.stats || { matchesPlayed: 0, wins: 0, currentStreak: 0, maxStreak: 0 }
             }));
             setPlayers(importedPlayers);
             setErrorMsg(null);
          } else {
             setErrorMsg("Invalid Roster JSON file format.");
          }
        }
      } catch (err) {
        setErrorMsg("Failed to parse Roster JSON file.");
      }
    };
    reader.readAsText(fileObj);
    event.target.value = '';
  };

  const handleHistoryFileChange = (event: React.ChangeEvent<HTMLInputElement>) => {
    const fileObj = event.target.files && event.target.files[0];
    if (!fileObj) return;

    const reader = new FileReader();
    reader.onload = (e) => {
      try {
        const json = e.target?.result;
        if (typeof json === 'string') {
          const parsedData = JSON.parse(json);
          // Basic validation for match history
          if (Array.isArray(parsedData) && (parsedData.length === 0 || parsedData[0].roomId)) {
             setMatchHistory(parsedData);
             setErrorMsg(null);
          } else {
             setErrorMsg("Invalid History JSON file format.");
          }
        }
      } catch (err) {
        setErrorMsg("Failed to parse History JSON file.");
      }
    };
    reader.readAsText(fileObj);
    event.target.value = '';
  };

  const handleRoomIdChange = (e: React.ChangeEvent<HTMLInputElement>) => {
    const val = e.target.value;
    if (val.length <= 4) {
      setRoomId(val);
    }
  };

  return (
    <div className="min-h-screen text-slate-200 font-inter overflow-x-hidden relative">
      <BackgroundParticles />

      {/* New Background Image (HoK Global Launch) */}
      <div className="fixed inset-0 bg-black -z-10">
         <img 
           src="https://www.levelinfinite.com/wp-content/uploads/2024/03/honor-of-kings-global-launch-pc.jpg" 
           alt="Honor of Kings Background" 
           className="absolute inset-0 w-full h-full object-cover opacity-50"
         />
         <div className="absolute inset-0 bg-gradient-to-b from-[#05090f]/90 via-[#05090f]/60 to-[#05090f] mix-blend-multiply"></div>
         <div className="absolute inset-0 bg-gradient-to-t from-[#05090f] via-transparent to-[#05090f]/80"></div>
      </div>

      {/* Hidden File Inputs */}
      <input 
        type="file" 
        ref={rosterFileInputRef}
        onChange={handleRosterFileChange}
        accept=".json"
        className="hidden"
      />
      <input 
        type="file" 
        ref={historyFileInputRef}
        onChange={handleHistoryFileChange}
        accept=".json"
        className="hidden"
      />

      {/* Edit Modal */}
      {editingPlayer && (
        <EditPlayerModal 
          player={editingPlayer}
          isOpen={isEditModalOpen}
          onClose={() => setIsEditModalOpen(false)}
          onSave={handleUpdatePlayer}
        />
      )}

      {/* Cinematic Header */}
      <header className="relative z-20 h-20 flex items-center justify-center border-b border-[#dcb06b]/20 bg-[#05090f]/60 backdrop-blur-md">
        <div className="absolute inset-0 bg-gradient-to-r from-transparent via-[#dcb06b]/5 to-transparent"></div>
        <div className="flex items-center gap-3 animate-float">
           <div className="w-8 h-8 border-2 border-[#dcb06b] rotate-45 flex items-center justify-center bg-[#0a1a2f]">
              <div className="w-4 h-4 bg-[#dcb06b]"></div>
           </div>
           <h1 className="text-2xl font-cinzel font-black tracking-[0.2em] text-white">
             <span className="hok-gold-text">HONOR</span> OF <span className="hok-gold-text">KINGS</span>
             <span className="block text-[8px] text-[#8a9db8] tracking-[0.5em] font-orbitron mt-0.5">OPEN MABAR CUSTOM FUN MATCH</span>
           </h1>
        </div>
      </header>

      <main className="relative z-10 pt-8 px-4 pb-20">
        {currentMatch ? (
          <MatchDisplay 
            match={currentMatch} 
            activePlayers={activePlayers} 
            onReset={handleAbortMatch}
            onCompleteMatch={handleMatchFinish}
            onReroll={handleRerollSlot}
          />
        ) : (
          <div className="max-w-7xl mx-auto">

            <div className="grid grid-cols-1 lg:grid-cols-12 gap-8">

              {/* Left Panel: Controls */}
              <div className="lg:col-span-4 space-y-6">

                 {/* Room ID & Coach Mode Toggle */}
                 <div className="bg-[#0a1a2f]/80 p-1 clip-corner-sm border border-[#1e3a5f] shadow-[0_0_25px_rgba(220,176,107,0.15)] relative group space-y-2">
                    <div className="absolute -inset-1 bg-gradient-to-r from-transparent via-[#dcb06b]/30 to-transparent blur opacity-0 group-hover:opacity-100 transition-opacity duration-700"></div>

                    <div className="bg-[#05090f] p-4 flex items-center gap-4 clip-corner-sm relative z-10">
                       <label className="text-xs uppercase text-[#dcb06b] font-bold font-orbitron whitespace-nowrap tracking-widest">Room ID</label>
                       <div className="h-8 w-[1px] bg-[#1e3a5f]"></div>
                       <input 
                          type="text" 
                          value={roomId}
                          onChange={handleRoomIdChange}
                          maxLength={4}
                          placeholder="0000"
                          className="bg-transparent text-lg font-orbitron text-white w-full focus:outline-none tracking-widest placeholder-[#1e3a5f]"
                       />
                    </div>
                 </div>

                 <div className="flex items-center justify-between bg-[#0a1a2f]/60 p-4 border border-[#1e3a5f] clip-corner-sm">
                     <span className="text-[#dcb06b] font-cinzel font-bold text-sm tracking-widest flex items-center gap-2">
                        <svg xmlns="http://www.w3.org/2000/svg" className="h-4 w-4" fill="none" viewBox="0 0 24 24" stroke="currentColor">
                           <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M19 11H5m14 0a2 2 0 012 2v6a2 2 0 01-2 2H5a2 2 0 01-2-2v-6a2 2 0 012-2m14 0V9a2 2 0 00-2-2M5 11V9a2 2 0 012-2m0 0V5a2 2 0 012-2h6a2 2 0 012 2v2M7 7h10" />
                        </svg>
                        COACH MODE
                     </span>
                     <label className="relative inline-flex items-center cursor-pointer">
                        <input type="checkbox" className="sr-only peer" checked={isCoachMode} onChange={(e) => setIsCoachMode(e.target.checked)} />
                        <div className="w-11 h-6 bg-[#1e3a5f] peer-focus:outline-none rounded-full peer peer-checked:after:translate-x-full peer-checked:after:border-white after:content-[''] after:absolute after:top-[2px] after:left-[2px] after:bg-white after:border-gray-300 after:border after:rounded-full after:h-5 after:w-5 after:transition-all peer-checked:bg-[#dcb06b]"></div>
                     </label>
                 </div>

                 <PlayerForm onAddPlayer={addPlayer} isCoachMode={isCoachMode} />

                 {/* Status Panel */}
                 <div className="relative p-6 clip-corner-md bg-gradient-to-b from-[#1a2c42] to-[#05090f] border border-[#dcb06b]/20 group hover:border-[#dcb06b]/50 transition-colors duration-500">
                    <div className="absolute top-0 left-0 w-full h-1 bg-gradient-to-r from-transparent via-[#dcb06b] to-transparent opacity-50"></div>

                    <div className="flex justify-between items-end mb-6">
                       <div>
                          <div className="text-[#8a9db8] text-[10px] uppercase tracking-widest font-bold mb-1">Active Players</div>
                          <div className="text-5xl font-orbitron font-bold text-white relative">
                             {activePlayers.length}
                             <span className="text-lg text-[#4a5f78] absolute top-0 -right-12">/ {isCoachMode ? 12 : 10}</span>
                          </div>
                       </div>
                       <div className="text-right">
                          <button onClick={quickFill} className="text-[10px] text-[#dcb06b] border border-[#dcb06b] px-3 py-1 hover:bg-[#dcb06b] hover:text-black transition-colors uppercase tracking-wider">
                             Quick Fill
                          </button>
                       </div>
                    </div>

                    {errorMsg && (
                      <div className="mb-4 p-3 border-l-2 border-red-500 bg-red-900/20 text-red-200 text-xs">
                        {errorMsg}
                      </div>
                    )}

                    <Button 
                      onClick={handleGenerate} 
                      className="w-full text-lg shadow-[0_0_20px_rgba(220,176,107,0.3)]"
                      disabled={activePlayers.length < (isCoachMode ? 12 : 10)}
                    >
                       START MATCHMAKING
                    </Button>
                 </div>
              </div>

              {/* Right Panel: Player Grid & History */}
              <div className="lg:col-span-8">
                 <div className="flex flex-wrap items-center justify-between mb-6 gap-4">
                    <h2 className="text-2xl font-cinzel font-black tracking-[0.2em] uppercase drop-shadow-sm text-[#dcb06b] flex items-center gap-3">
                       <span className="w-2 h-2 bg-[#dcb06b] rotate-45"></span>
                       SQUAD ROSTER
                    </h2>

                    <div className="flex items-center gap-2">
                       {/* Import/Export Controls */}
                       <button 
                         onClick={handleRosterImportClick}
                         className="flex items-center gap-2 px-3 py-1 text-[10px] uppercase font-bold tracking-wider text-[#4a5f78] border border-[#1e3a5f] hover:border-[#dcb06b] hover:text-[#dcb06b] transition-all clip-corner-sm"
                         title="Load Roster JSON"
                       >
                          <svg xmlns="http://www.w3.org/2000/svg" className="h-4 w-4" fill="none" viewBox="0 0 24 24" stroke="currentColor">
                            <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M4 16v1a3 3 0 003 3h10a3 3 0 003-3v-1m-4-8l-4-4m0 0L8 8m4-4v12" />
                          </svg>
                          Load
                       </button>

                       <button 
                         onClick={handleExportRoster}
                         disabled={players.length === 0}
                         className="flex items-center gap-2 px-3 py-1 text-[10px] uppercase font-bold tracking-wider text-[#4a5f78] border border-[#1e3a5f] hover:border-[#dcb06b] hover:text-[#dcb06b] transition-all clip-corner-sm disabled:opacity-30 disabled:cursor-not-allowed"
                         title="Save Roster JSON"
                       >
                          <svg xmlns="http://www.w3.org/2000/svg" className="h-4 w-4" fill="none" viewBox="0 0 24 24" stroke="currentColor">
                            <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M4 16v1a3 3 0 003 3h10a3 3 0 003-3v-1m-4-4l-4 4m0 0l-4-4m4 4V4" />
                          </svg>
                          Save
                       </button>

                       <div className="h-4 w-[1px] bg-[#1e3a5f] mx-2"></div>

                       <button onClick={() => setPlayers([])} className="text-xs text-[#4a5f78] hover:text-red-400 uppercase tracking-widest transition-colors">
                          Clear All
                       </button>
                    </div>
                 </div>

                 <div className="perspective-container tech-border p-6 bg-[#0a1a2f]/40 min-h-[400px] mb-8">
                    <PlayerList 
                      players={players} 
                      onRemove={removePlayer} 
                      onToggleActive={togglePlayerActive}
                      onEdit={handleEditPlayer}
                    />
                 </div>

                 {/* MATCH HISTORY SECTION */}
                 <div className="mt-12">
                     <div className="flex items-center justify-between mb-6">
                        <h2 className="text-2xl font-cinzel font-black tracking-[0.2em] uppercase drop-shadow-sm text-[#dcb06b] flex items-center gap-3">
                           <span className="w-2 h-2 bg-[#dcb06b] rotate-45"></span>
                           BATTLE HISTORY
                        </h2>

                        <div className="flex items-center gap-2">
                           <button 
                             onClick={handleHistoryImportClick}
                             className="flex items-center gap-2 px-3 py-1 text-[10px] uppercase font-bold tracking-wider text-[#4a5f78] border border-[#1e3a5f] hover:border-[#dcb06b] hover:text-[#dcb06b] transition-all clip-corner-sm"
                           >
                              <svg xmlns="http://www.w3.org/2000/svg" className="h-4 w-4" fill="none" viewBox="0 0 24 24" stroke="currentColor">
                                <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M4 16v1a3 3 0 003 3h10a3 3 0 003-3v-1m-4-8l-4-4m0 0L8 8m4-4v12" />
                              </svg>
                              Import
                           </button>

                           <button 
                              onClick={handleExportHistory}
                              disabled={matchHistory.length === 0}
                              className="flex items-center gap-2 px-3 py-1 text-[10px] uppercase font-bold tracking-wider text-[#4a5f78] border border-[#1e3a5f] hover:border-[#dcb06b] hover:text-[#dcb06b] transition-all clip-corner-sm disabled:opacity-30 disabled:cursor-not-allowed"
                           >
                              <svg xmlns="http://www.w3.org/2000/svg" className="h-4 w-4" fill="none" viewBox="0 0 24 24" stroke="currentColor">
                                 <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M12 10v6m0 0l-3-3m3 3l3-3m2 8H7a2 2 0 01-2-2V5a2 2 0 012-2h5.586a1 1 0 01.707.293l5.414 5.414a1 1 0 01.293.707V19a2 2 0 01-2 2z" />
                              </svg>
                              Export
                           </button>
                        </div>
                     </div>

                     <div className="tech-border p-6 bg-[#0a1a2f]/40">
                        <HistoryList history={matchHistory} onClear={() => setMatchHistory([])} />
                     </div>
                 </div>
              </div>

            </div>
          </div>
        )}
      </main>
    </div>
  );
}

import React, { useState } from 'react';
import { MatchResult, TeamSlot, Role, Player } from '../types';
import { RoleIcons, ROLES_ORDER } from '../constants';
import { Button } from './Button';
import { SpinWheel } from './SpinWheel';
import { PortalTransition } from './PortalTransition';
import { MatchSummary } from './MatchSummary';
import { VictoryCelebration } from './VictoryCelebration';
import { EvaluationScreen } from './EvaluationScreen';

interface MatchDisplayProps {
  match: MatchResult;
  activePlayers: Player[]; 
  onReset: () => void; // For Abort
  onCompleteMatch: (winner: 'azure' | 'crimson' | null, mvpId?: string) => void; // For Finish
  onReroll: (team: 'azure' | 'crimson', role: Role, newPlayer: Player) => void;
}

type ViewState = 'drafting' | 'transition' | 'final' | 'celebration' | 'evaluation';

export const MatchDisplay: React.FC<MatchDisplayProps> = ({ match, activePlayers, onReset, onCompleteMatch, onReroll }) => {
  const [viewState, setViewState] = useState<ViewState>('drafting');
  const [winningTeam, setWinningTeam] = useState<'azure' | 'crimson' | null>(null);

  // Dynamic Role Order: If Coach mode, append Coach to standard order
  const displayRoles = match.isCoachMode ? [...ROLES_ORDER, Role.COACH] : ROLES_ORDER;

  // -1: Not started
  // 0-4: Revealing pairs (0=Clash, ... 4=Roam)
  // 5: Coach (if exists)
  const [currentRoleIndex, setCurrentRoleIndex] = useState(-1);

  // New State for the Modal Wheel
  const [wheelState, setWheelState] = useState<{
    isOpen: boolean;
    type: 'draft' | 'reroll'; // Differentiate between initial draft reveal and manual reroll
    team: 'azure' | 'crimson';
    role: Role;
    winnerName: string;
    winnerPlayer?: Player; // Needed for reroll
    candidates: string[];
  } | null>(null);

  // Tracks which individual cards are visible
  const [revealedCards, setRevealedCards] = useState<Set<string>>(new Set());

  const getPlayerForRole = (team: TeamSlot[], role: Role) => {
    return team.find(slot => slot.role === role);
  };

  const getCardId = (team: 'azure' | 'crimson', role: Role) => `${team}-${role}`;

  const handleNext = () => {
    const nextIndex = currentRoleIndex + 1;
    if (nextIndex >= displayRoles.length) return;

    const roleToReveal = displayRoles[nextIndex];

    // Step 1: Check if Azure is revealed
    const azureId = getCardId('azure', roleToReveal);
    if (!revealedCards.has(azureId)) {
      startWheel('azure', roleToReveal);
      return;
    }

    // Step 2: Check if Crimson is revealed
    const crimsonId = getCardId('crimson', roleToReveal);
    if (!revealedCards.has(crimsonId)) {
      startWheel('crimson', roleToReveal);
      return;
    }
  };

  const handleSkipAll = () => {
    // Debug: Instantly reveal everything
    const allCards = new Set<string>();
    displayRoles.forEach(r => {
      allCards.add(getCardId('azure', r));
      allCards.add(getCardId('crimson', r));
    });
    setRevealedCards(allCards);
    setCurrentRoleIndex(displayRoles.length); // Set to finished state
  };

  const startWheel = (team: 'azure' | 'crimson', role: Role) => {
    const teamSlots = team === 'azure' ? match.azureTeam : match.crimsonTeam;
    const winner = getPlayerForRole(teamSlots, role)?.player;
    if (!winner) return;

    // Get candidates for the wheel
    const candidates = activePlayers
      .filter(p => role === Role.COACH ? true : (p.isAllRoles || p.roles.includes(role)))
      .map(p => p.name);

    setWheelState({
      isOpen: true,
      type: 'draft',
      team,
      role,
      winnerName: winner.name,
      candidates
    });
  };

  // Triggered when user clicks the re-roll button on a card
  const handleRerollClick = (team: 'azure' | 'crimson', role: Role) => {
    const azureIds = new Set(match.azureTeam.map(s => s.player.id));
    const crimsonIds = new Set(match.crimsonTeam.map(s => s.player.id));

    // CRITICAL: This ensures players already in match (even All Role) don't appear in wheel
    const benchPlayers = activePlayers.filter(p => !azureIds.has(p.id) && !crimsonIds.has(p.id));

    if (benchPlayers.length === 0) {
      alert("No available bench players to re-roll with!");
      return;
    }

    const candidates = benchPlayers.filter(p => {
       if (role === Role.COACH) return true; 
       return p.isAllRoles || p.roles.includes(role);
    });

    if (candidates.length === 0) {
       alert(`No available bench players found for role: ${role}`);
       return;
    }

    const newPlayer = candidates[Math.floor(Math.random() * candidates.length)];
    const candidateNames = candidates.map(p => p.name);

    setWheelState({
        isOpen: true,
        type: 'reroll',
        team,
        role,
        winnerName: newPlayer.name,
        winnerPlayer: newPlayer,
        candidates: candidateNames
    });
  };

  const handleWheelComplete = () => {
    if (!wheelState) return;

    if (wheelState.type === 'draft') {
        const { team, role } = wheelState;
        setRevealedCards(prev => new Set(prev).add(getCardId(team, role)));
        if (team === 'crimson') {
           setCurrentRoleIndex(prev => prev + 1);
        }
    } else if (wheelState.type === 'reroll' && wheelState.winnerPlayer) {
        onReroll(wheelState.team, wheelState.role, wheelState.winnerPlayer);
    }

    setWheelState(null);
  };

  const handleWheelCancel = () => {
    setWheelState(null);
  };

  const handleInitializeBattle = () => {
    setViewState('transition');
  };

  const handleTransitionComplete = () => {
    setViewState('final');
  };

  const handleMatchDecided = (winner: 'azure' | 'crimson' | null) => {
    if (winner) {
      setWinningTeam(winner);
      setViewState('celebration');
    } else {
      onCompleteMatch(null);
    }
  };

  const handleCelebrationDismiss = () => {
    setViewState('evaluation');
  };

  const handleEvaluationComplete = (mvpId?: string) => {
    onCompleteMatch(winningTeam, mvpId);
  }

  // --- RENDER LOGIC ---

  if (viewState === 'evaluation' && winningTeam) {
    return (
      <EvaluationScreen 
        match={match} 
        winner={winningTeam} 
        onComplete={handleEvaluationComplete} 
      />
    );
  }

  if (viewState === 'celebration' && winningTeam) {
    const winningTeamSlots = winningTeam === 'azure' ? match.azureTeam : match.crimsonTeam;
    return (
      <VictoryCelebration 
        winner={winningTeam} 
        teamSlots={winningTeamSlots}
        onDismiss={handleCelebrationDismiss} 
      />
    );
  }

  if (viewState === 'transition') {
    return (
      <PortalTransition 
        azureTeam={match.azureTeam} 
        crimsonTeam={match.crimsonTeam} 
        onComplete={handleTransitionComplete} 
      />
    );
  }

  if (viewState === 'final') {
    return <MatchSummary match={match} onReset={handleMatchDecided} />;
  }

  // --- DRAFTING VIEW ---

  const renderPlayerCard = (role: Role, roleIndex: number, team: 'azure' | 'crimson') => {
    const teamSlots = team === 'azure' ? match.azureTeam : match.crimsonTeam;
    const player = getPlayerForRole(teamSlots, role)?.player;
    const isRevealed = revealedCards.has(getCardId(team, role));

    // HoK Color Palettes
    const theme = team === 'azure' 
      ? {
          bg: 'bg-[#0a1a2f]',
          border: 'border-hok-cyan',
          glow: 'shadow-[0_0_10px_#00d2ff]',
          text: 'text-hok-cyan',
          gradient: 'from-[#00d2ff]/20 to-transparent'
        } 
      : {
          bg: 'bg-[#1a0505]',
          border: 'border-hok-red',
          glow: 'shadow-[0_0_10px_#ef4444]',
          text: 'text-hok-red',
          gradient: 'from-[#c02d2d]/20 to-transparent'
        };

    // State 1: Hidden
    if (!isRevealed) {
       return (
         <div className="h-24 w-full relative overflow-hidden clip-corner-md border border-[#1e3a5f] bg-[#05090f]/80 flex flex-col items-center justify-center opacity-40 group">
            <div className="text-[#1e3a5f] group-hover:text-[#dcb06b]/50 transition-colors duration-500 transform scale-90 opacity-50">
               {RoleIcons[role]}
            </div>
            {/* Tech Scanlines */}
            <div className="absolute inset-0 bg-[url('data:image/svg+xml;base64,PHN2ZyB4bWxucz0iaHR0cDovL3d3dy53My5vcmcvMjAwMC9zdmciIHdpZHRoPSI0IiBoZWlnaHQ9IjQiPgo8cmVjdCB3aWR0aD0iNCIgaGVpZ2h0PSI0IiBmaWxsPSIjZmZmIiBmaWxsLW9wYWNpdHk9IjAuMDUiLz4KPHBhdGggZD0iTTAgNEw0IDBaIiBzdHJva2U9IiMwMDAiIHN0cm9rZS13aWR0aD0iMSIvPgo8L3N2Zz4=')] opacity-20"></div>
         </div>
       );
    }

    // State 2: Revealed (UPDATED LAYOUT FOR TEXT ROLES)
    return (
      <div className={`relative h-24 w-full animate-slide-in perspective-container group`}>
        <div className={`
            absolute inset-0 clip-corner-md border-l-4 tilt-card
            ${theme.bg} ${theme.border} 
            ${theme.glow}
            shadow-[0_0_15px_rgba(0,0,0,0.5)]
            transition-all duration-300 hover:brightness-110
        `}>
           <div className={`flex flex-col h-full relative z-10 px-4 py-2 justify-center ${team === 'crimson' ? 'items-end text-right' : 'items-start text-left'}`}>

             {/* Text Role Label (Top) */}
             <div className={`mb-1 px-2 py-0.5 rounded-sm bg-black/40 border border-white/10 ${theme.text} transform transition-transform duration-500 w-auto inline-block`}>
                {RoleIcons[role]}
             </div>

             {/* Name Section */}
             <span className={`block text-xl md:text-2xl font-bold text-white truncate font-orbitron drop-shadow-md w-full`}>
                {player?.name}
             </span>

             <div className={`absolute inset-0 bg-gradient-to-r ${theme.gradient} opacity-50 pointer-events-none`}></div>
           </div>

           {/* Decorative Tech Corners */}
           <div className={`absolute top-0 w-8 h-8 border-t border-${team === 'azure' ? 'cyan' : 'red'}-500/50 ${team === 'azure' ? 'left-0' : 'right-0'}`}></div>
           <div className={`absolute bottom-0 w-8 h-8 border-b border-${team === 'azure' ? 'cyan' : 'red'}-500/50 ${team === 'azure' ? 'right-0' : 'left-0'}`}></div>

           {/* Re-roll Button Overlay */}
           <button 
             onClick={(e) => { e.stopPropagation(); handleRerollClick(team, role); }}
             className="absolute top-1 right-1 md:top-2 md:right-2 p-1.5 bg-black/50 hover:bg-[#dcb06b] rounded-full transition-colors group-hover:opacity-100 opacity-0 text-white hover:text-black z-50 border border-white/20"
             title="Re-roll this specific slot"
           >
             <svg xmlns="http://www.w3.org/2000/svg" className="h-4 w-4" fill="none" viewBox="0 0 24 24" stroke="currentColor">
               <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M4 4v5h.582m15.356 2A8.001 8.001 0 004.582 9m0 0H9m11 11v-5h-.581m0 0a8.003 8.003 0 01-15.357-2m15.357 2H15" />
             </svg>
           </button>
        </div>
      </div>
    );
  };

  const nextRoleIndex = currentRoleIndex + 1;
  const nextRoleName = nextRoleIndex < displayRoles.length ? displayRoles[nextRoleIndex] : null;
  const isFinished = currentRoleIndex >= displayRoles.length - 1 && revealedCards.size === (match.isCoachMode ? 12 : 10);

  let buttonText = "START DRAFT";
  if (nextRoleName) {
     if (!revealedCards.has(getCardId('azure', nextRoleName))) {
        buttonText = `SELECT AZURE ${nextRoleName.split(' ')[0].toUpperCase()}`;
     } else if (!revealedCards.has(getCardId('crimson', nextRoleName))) {
        buttonText = `SELECT CRIMSON ${nextRoleName.split(' ')[0].toUpperCase()}`;
     } else {
        buttonText = "NEXT LANE";
     }
  }

  // Turret SVG Path
  const TurretIcon = (
    <svg viewBox="0 0 24 24" fill="currentColor" className="w-16 h-16 opacity-30 animate-pulse">
        <path d="M12,2 L2,22 L12,18 L22,22 L12,2 Z" />
        <path d="M12,5 L5,20 L12,17 L19,20 L12,5 Z" fillOpacity="0.5" />
    </svg>
  );

  return (
    <>
      {/* The Spin Wheel Overlay */}
      {wheelState && wheelState.isOpen && (
        <SpinWheel 
          candidates={wheelState.candidates}
          winnerName={wheelState.winnerName}
          team={wheelState.team}
          roleName={wheelState.role}
          onComplete={handleWheelComplete}
          onCancel={handleWheelCancel}
        />
      )}

      <div className="w-full max-w-7xl mx-auto px-4 py-8 pb-32 relative">

        {/* Top Controls: Abort & Instant Result */}
        <div className="absolute top-4 left-4 right-4 z-40 flex justify-between">
           <Button variant="outline" size="sm" onClick={() => onReset()} className="border-red-900/50 text-red-500 hover:bg-red-900/20 text-[10px] px-3">
              <span className="flex items-center gap-2">
                 <svg xmlns="http://www.w3.org/2000/svg" className="h-4 w-4" fill="none" viewBox="0 0 24 24" stroke="currentColor">
                   <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M11 15l-3-3m0 0l3-3m-3 3h8M3 12a9 9 0 1118 0 9 9 0 01-18 0z" />
                 </svg>
                 ABORT DRAFT
              </span>
           </Button>

           {/* Debug / Instant Result Button */}
           {!isFinished && (
             <Button variant="outline" size="sm" onClick={handleSkipAll} className="border-[#dcb06b]/50 text-[#dcb06b] hover:bg-[#dcb06b]/10 text-[10px] px-3">
                <span className="flex items-center gap-2">
                   INSTANT RESULT (DEBUG)
                   <svg xmlns="http://www.w3.org/2000/svg" className="h-4 w-4" fill="none" viewBox="0 0 24 24" stroke="currentColor">
                     <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M13 10V3L4 14h7v7l9-11h-7z" />
                   </svg>
                </span>
             </Button>
           )}
        </div>

        {/* Header Info - PERFECTLY CENTERED */}
        <div className="flex flex-col items-center mb-12 pt-12">
           <div className="flex justify-center w-full mb-8">
              <div className="bg-[#05090f] border border-[#dcb06b]/40 px-8 py-2 clip-diamond relative shadow-[0_0_15px_rgba(220,176,107,0.2)]">
                  <div className="absolute inset-0 bg-[#dcb06b]/5 pointer-events-none"></div>
                  <span className="text-[#dcb06b] font-cinzel font-bold text-sm tracking-widest uppercase block text-center">Room ID</span>
                  <span className="text-2xl font-orbitron font-bold text-white tracking-widest text-center block">{match.roomId}</span>
              </div>
           </div>

           <div className="flex justify-between items-center w-full relative max-w-5xl">
              <div className="w-1/3 text-center relative group">
                 <div className="absolute -inset-4 bg-cyan-500/10 blur-xl rounded-full opacity-50 group-hover:opacity-100 transition-opacity"></div>
                 <div className="absolute -left-10 top-0 text-cyan-500/20">{TurretIcon}</div>
                 <h2 className="relative text-3xl md:text-5xl font-cinzel font-black text-transparent bg-clip-text bg-gradient-to-b from-cyan-200 to-cyan-600 drop-shadow-[0_0_15px_rgba(6,182,212,0.8)]">
                  AZURE
                 </h2>
                 <p className="text-[10px] md:text-xs text-cyan-400 font-orbitron tracking-[0.4em] mt-1 opacity-70">GOLEM TEAM</p>
                 <div className="h-1 w-24 bg-cyan-500 mx-auto mt-2 shadow-[0_0_10px_#00d2ff]"></div>
              </div>

              <div className="w-1/3 flex justify-center items-center z-10">
                <div className="relative w-24 h-24 md:w-32 md:h-32 flex items-center justify-center">
                  <div className="absolute inset-0 border-2 border-[#dcb06b] rotate-45 animate-spin-slow bg-[#05090f]"></div>
                  <div className="absolute inset-2 border border-[#dcb06b]/50 rotate-45"></div>
                  <span className="text-4xl font-black italic text-[#dcb06b] font-orbitron z-10 pr-2 pt-1 animate-pulse-fast">VS</span>
                </div>
              </div>

              <div className="w-1/3 text-center relative group">
                 <div className="absolute -inset-4 bg-red-500/10 blur-xl rounded-full opacity-50 group-hover:opacity-100 transition-opacity"></div>
                 <div className="absolute -right-10 top-0 text-red-500/20 transform scale-x-[-1]">{TurretIcon}</div>
                 <h2 className="relative text-3xl md:text-5xl font-cinzel font-black text-transparent bg-clip-text bg-gradient-to-b from-red-200 to-red-600 drop-shadow-[0_0_15px_rgba(220,45,45,0.8)]">
                  CRIMSON
                 </h2>
                 <p className="text-[10px] md:text-xs text-red-400 font-orbitron tracking-[0.4em] mt-1 opacity-70">GOLEM TEAM</p>
                 <div className="h-1 w-24 bg-red-500 mx-auto mt-2 shadow-[0_0_10px_#ef4444]"></div>
              </div>
           </div>
        </div>

        {/* Matchup Grid */}
        <div className="relative space-y-4 md:space-y-6">
          <div className="absolute left-1/2 top-0 bottom-0 w-[2px] bg-gradient-to-b from-transparent via-[#dcb06b]/30 to-transparent hidden md:block"></div>

          {displayRoles.map((role, idx) => (
            <div key={role} className="grid grid-cols-1 md:grid-cols-2 gap-4 md:gap-16 items-center">
               <div className="order-1 md:order-none">
                  {renderPlayerCard(role, idx, 'azure')}
               </div>
               <div className="order-2 md:order-none">
                  {renderPlayerCard(role, idx, 'crimson')}
               </div>
            </div>
          ))}
        </div>

        {/* Control Bar */}
        <div className="fixed bottom-0 left-0 right-0 p-8 z-50 flex justify-center items-end bg-gradient-to-t from-[#05090f] via-[#05090f]/90 to-transparent pointer-events-none h-48">
           <div className="pointer-events-auto transform transition-all hover:scale-105">
              {!isFinished ? (
                 <div className="flex flex-col items-center">
                    <button 
                      onClick={handleNext}
                      className="
                        group relative w-72 h-16
                        bg-[#0a1a2f] border border-[#dcb06b] 
                        clip-corner-md
                        flex items-center justify-center
                        text-[#dcb06b] font-cinzel font-bold text-xl tracking-widest
                        overflow-hidden
                        hover:bg-[#dcb06b] hover:text-[#05090f]
                        transition-all duration-300
                        shadow-[0_0_20px_rgba(220,176,107,0.2)]
                      "
                    >
                       <span className="relative z-10">
                         {buttonText}
                       </span>
                       <div className="absolute inset-0 w-full h-full bg-white/20 -translate-x-full group-hover:animate-[shimmer_1s_infinite]"></div>
                    </button>
                 </div>
              ) : (
                 <div className="flex flex-col items-center animate-slide-in">
                    <p className="text-[#00d2ff] font-bold mb-4 uppercase tracking-[0.3em] text-sm font-orbitron drop-shadow-[0_0_5px_rgba(0,210,255,0.8)]">
                       Draft Completed
                    </p>
                    <Button 
                      onClick={handleInitializeBattle} 
                      className="px-12 border-[#dcb06b] shadow-[0_0_20px_#dcb06b] animate-pulse"
                    >
                       INITIALIZE BATTLE
                    </Button>
                 </div>
              )}
           </div>
        </div>
      </div>
    </>
  );
};

import React from 'react';
import { MatchResult, TeamSlot, Role } from '../types';
import { ROLES_ORDER, RoleIcons } from '../constants';
import { Button } from './Button';

interface MatchSummaryProps {
  match: MatchResult;
  onReset: (winner: 'azure' | 'crimson' | null) => void;
}

export const MatchSummary: React.FC<MatchSummaryProps> = ({ match, onReset }) => {
  const getPlayer = (slots: TeamSlot[], role: Role) => slots.find(s => s.role === role)?.player;

  return (
    <div className="min-h-screen bg-[url('https://wallpaperaccess.com/full/3739268.jpg')] bg-cover bg-center bg-no-repeat bg-fixed relative flex flex-col items-center justify-center p-4">
       {/* Dark Overlay */}
       <div className="absolute inset-0 bg-[#05090f]/90 backdrop-blur-sm z-0"></div>

       <div className="relative z-10 w-full max-w-7xl animate-slide-in">

          {/* Header */}
          <div className="text-center mb-10">
             <h1 className="text-4xl md:text-6xl font-cinzel font-black text-transparent bg-clip-text bg-gradient-to-b from-[#f3dcb1] to-[#dcb06b] drop-shadow-[0_4px_10px_rgba(0,0,0,0.8)]">
                BATTLE READY
             </h1>
             <p className="text-[#8a9db8] font-orbitron tracking-[0.3em] mt-2">ROOM ID: {match.roomId}</p>
          </div>

