import React, { useEffect, useState } from 'react';
import { TeamSlot } from '../types';
import { Button } from './Button';
import { RoleIcons } from '../constants';

interface PortalTransitionProps {
  onComplete: () => void;
  azureTeam: TeamSlot[];
  crimsonTeam: TeamSlot[];
}

export const PortalTransition: React.FC<PortalTransitionProps> = ({ onComplete, azureTeam, crimsonTeam }) => {
  const [stage, setStage] = useState(0);
  const [elapsedSeconds, setElapsedSeconds] = useState(0);

  useEffect(() => {
    // Sequence:
    // 0ms: Start (Empty)
    // 100ms: Slide In (Stage 1)
    // 800ms: Impact/Shake (Stage 2) - Rosters Fade In

    const t1 = setTimeout(() => setStage(1), 100);
    const t2 = setTimeout(() => setStage(2), 800);

    // Timer Interval
    const interval = setInterval(() => {
       setElapsedSeconds(prev => prev + 1);
    }, 1000);

    return () => {
        clearTimeout(t1);
        clearTimeout(t2);
        clearInterval(interval);
    };
  }, []);

  const handleNext = () => {
    setStage(3); // Fade out
    setTimeout(() => {
        onComplete();
    }, 500);
  };

  const formatTime = (totalSeconds: number) => {
    const mins = Math.floor(totalSeconds / 60);
    const secs = totalSeconds % 60;
    return `${mins.toString().padStart(2, '0')}:${secs.toString().padStart(2, '0')}`;
  };

  return (
    <div className="fixed inset-0 z-[100] bg-black flex items-center justify-center overflow-hidden font-inter">

        {/* Background Flash on Impact */}
        <div className={`
            absolute inset-0 bg-white pointer-events-none z-50
            ${stage === 2 ? 'animate-[impact-flash_0.5s_ease-out_forwards]' : 'opacity-0'}
        `}></div>

        {/* Shake Container */}
        <div className={`
            absolute inset-0 flex items-center justify-center w-full h-full
            ${stage === 2 ? 'animate-[clash-shake_0.5s_ease-in-out]' : ''}
            transition-opacity duration-500
            ${stage === 3 ? 'opacity-0' : 'opacity-100'}
        `}>

            {/* LEFT SIDE - AZURE GOLEM */}
            <div className={`
                absolute left-0 top-0 bottom-0 w-1/2 
                bg-gradient-to-r from-[#0a1a2f] to-[#00d2ff]/30
                flex flex-col items-end justify-center
                border-r-4 border-[#00d2ff]
                pr-8 md:pr-48
                transform transition-all duration-700 ease-in
                ${stage >= 1 ? 'translate-x-0' : '-translate-x-full'}
            `}>
                <div className="text-right w-full max-w-xl">
                    <div className="text-[#00d2ff] font-cinzel font-black text-3xl md:text-5xl tracking-[0.1em] drop-shadow-[0_0_20px_#00d2ff] whitespace-nowrap mb-8 relative">
                        AZURE GOLEM
                        <div className="absolute -bottom-2 right-0 w-1/2 h-1 bg-[#00d2ff] shadow-[0_0_10px_#00d2ff]"></div>
                    </div>

                    {/* Azure Roster List - Enhanced */}
                    <div className="space-y-4">
                        {azureTeam.map((slot, idx) => (
                          <div 
                            key={idx} 
                            className={`
                              flex items-center justify-end gap-4 transition-all duration-500 transform
                              ${stage >= 2 ? 'translate-x-0 opacity-100' : '-translate-x-10 opacity-0'}
                            `}
                            style={{ transitionDelay: `${800 + (idx * 100)}ms` }}
                          >
                             {/* Name Card */}
                             <div className="bg-[#00d2ff]/10 border-r-2 border-[#00d2ff] pl-8 pr-4 py-2 clip-corner-sm relative group overflow-hidden min-w-[200px] text-right">
                                <div className="absolute inset-0 bg-gradient-to-l from-[#00d2ff]/20 to-transparent opacity-0 group-hover:opacity-100 transition-opacity"></div>
                                <span className="relative z-10 text-white font-orbitron font-bold text-lg md:text-xl drop-shadow-md tracking-wide">
                                  {slot.player.name}
                                </span>
                             </div>

                             {/* Role Icon/Badge */}
                             <div className="relative">
                               <div className="px-2 py-2 flex items-center justify-center bg-[#0a1a2f] border border-[#00d2ff] text-[#00d2ff] clip-corner-sm shadow-[0_0_10px_#00d2ff] min-w-[3rem]">
                                  <div className="scale-75">{RoleIcons[slot.role]}</div>
                               </div>
                             </div>
                          </div>
                        ))}
                    </div>
                </div>
            </div>

            {/* RIGHT SIDE - CRIMSON GOLEM */}
            <div className={`
                absolute right-0 top-0 bottom-0 w-1/2 
                bg-gradient-to-l from-[#1a0505] to-[#ef4444]/30
                flex flex-col items-start justify-center
                border-l-4 border-[#ef4444]
                pl-8 md:pl-48
                transform transition-all duration-700 ease-in
                ${stage >= 1 ? 'translate-x-0' : 'translate-x-full'}
            `}>
                <div className="text-left w-full max-w-xl">
                    <div className="text-[#ef4444] font-cinzel font-black text-3xl md:text-5xl tracking-[0.1em] drop-shadow-[0_0_20px_#ef4444] whitespace-nowrap mb-8 relative">
                        CRIMSON GOLEM
                        <div className="absolute -bottom-2 left-0 w-1/2 h-1 bg-[#ef4444] shadow-[0_0_10px_#ef4444]"></div>
                    </div>

                    {/* Crimson Roster List - Enhanced */}
                    <div className="space-y-4">
                        {crimsonTeam.map((slot, idx) => (
                          <div 
                            key={idx} 
                            className={`
                              flex items-center justify-start gap-4 transition-all duration-500 transform
                              ${stage >= 2 ? 'translate-x-0 opacity-100' : 'translate-x-10 opacity-0'}
                            `}
                            style={{ transitionDelay: `${800 + (idx * 100)}ms` }}
                          >
                             {/* Role Icon/Badge */}
                             <div className="relative">
                               <div className="px-2 py-2 flex items-center justify-center bg-[#1a0505] border border-[#ef4444] text-[#ef4444] clip-corner-sm shadow-[0_0_10px_#ef4444] min-w-[3rem]">
                                  <div className="scale-75">{RoleIcons[slot.role]}</div>
                               </div>
                             </div>

                             {/* Name Card */}
                             <div className="bg-[#ef4444]/10 border-l-2 border-[#ef4444] pr-8 pl-4 py-2 clip-corner-sm relative group overflow-hidden min-w-[200px] text-left">
                                <div className="absolute inset-0 bg-gradient-to-r from-[#ef4444]/20 to-transparent opacity-0 group-hover:opacity-100 transition-opacity"></div>
                                <span className="relative z-10 text-white font-orbitron font-bold text-lg md:text-xl drop-shadow-md tracking-wide">
                                  {slot.player.name}
                                </span>
                             </div>
                          </div>
                        ))}
                    </div>
                </div>
            </div>

            {/* CENTER VS & Loading State */}
            <div className={`
                absolute z-40 flex flex-col items-center justify-center transform transition-all duration-300
                ${stage >= 2 ? 'scale-100 opacity-100' : 'scale-0 opacity-0'}
            `}>
                <div className="relative w-24 h-24 md:w-32 md:h-32 flex items-center justify-center mb-8">
                    <div className="absolute inset-0 bg-[#dcb06b] rotate-45 animate-pulse"></div>
                    <div className="absolute inset-1 bg-black rotate-45"></div>
                    <span className="relative z-10 text-[#dcb06b] font-orbitron font-black text-4xl md:text-5xl italic">VS</span>
                </div>

                {/* Loading / Timer UI */}
                <div className="flex flex-col items-center gap-2 mb-8 bg-black/50 p-4 rounded-lg backdrop-blur-sm border border-[#dcb06b]/30">
                    <div className="flex items-center gap-2">
                        <div className="w-4 h-4 border-2 border-[#dcb06b] border-t-transparent rounded-full animate-spin"></div>
                        <span className="text-[#dcb06b] text-xs font-orbitron tracking-widest uppercase animate-pulse">Match in Progress</span>
                    </div>
                    <div className="text-white font-mono text-2xl tracking-widest font-bold">
                       {formatTime(elapsedSeconds)}
                    </div>
                </div>

                <Button onClick={handleNext} className="px-8 border-[#dcb06b] shadow-[0_0_15px_#dcb06b] hover:scale-110">
                    ENTER BATTLEFIELD
                </Button>
            </div>

        </div>

        {/* Particles / Debris (Simple CSS) */}
        {stage >= 2 && (
            <div className="absolute inset-0 pointer-events-none overflow-hidden">
                <div className="absolute top-1/2 left-1/2 w-1 h-20 bg-[#dcb06b] rotate-45 animate-[fly-out_0.5s_ease-out_forwards]"></div>
            </div>
        )}
    </div>
  );
};

import React, { useEffect, useState } from 'react';
import { MatchResult, Role } from '../types';
import { ROLES_ORDER, RoleIcons } from '../constants';
import { Button } from './Button';

interface EvaluationScreenProps {
  match: MatchResult;
  winner: 'azure' | 'crimson';
  onComplete: (mvpId?: string) => void;
}

export const EvaluationScreen: React.FC<EvaluationScreenProps> = ({ match, winner, onComplete }) => {
  const [mvpId, setMvpId] = useState<string>('');
  const [isLoading, setIsLoading] = useState(true);

  // Rating State: Map of player ID to 'up' or 'down' or null
  const [ratings, setRatings] = useState<Record<string, 'up' | 'down' | null>>({});

  useEffect(() => {
    // Simulate Calculation Loading
    const timer = setTimeout(() => {
        setIsLoading(false);
    }, 2500); // 2.5s loading time

    return () => clearTimeout(timer);
  }, [match, winner]);

  // Handle Drag Start for MVP Badge
  const handleDragStart = (e: React.DragEvent) => {
    e.dataTransfer.setData("type", "mvp-token");
    e.dataTransfer.effectAllowed = "move";
  };

  const handleDragOver = (e: React.DragEvent) => {
    e.preventDefault(); // Necessary to allow dropping
    e.dataTransfer.dropEffect = "move";
  };

  const handleDrop = (e: React.DragEvent, playerId: string) => {
     e.preventDefault();
     const type = e.dataTransfer.getData("type");
     if (type === "mvp-token") {
        setMvpId(playerId);
     }
  };

  const toggleRating = (playerId: string, type: 'up' | 'down') => {
     setRatings(prev => {
        const current = prev[playerId];
        if (current === type) {
            // Toggle off if clicking same
            const newState = { ...prev };
            delete newState[playerId];
            return newState;
        }
        return { ...prev, [playerId]: type };
     });
  };

  if (isLoading) {
    return (
        <div className="fixed inset-0 z-[100] bg-[#05090f] flex flex-col items-center justify-center">
            <div className="w-16 h-16 border-4 border-[#1e3a5f] border-t-[#dcb06b] rounded-full animate-spin mb-6"></div>
            <h2 className="text-[#dcb06b] font-orbitron text-xl tracking-[0.2em] animate-pulse">CALCULATING BATTLE DATA</h2>
            <div className="w-64 h-1 bg-[#1e3a5f] mt-4 rounded overflow-hidden">
                <div className="h-full bg-[#dcb06b] animate-[loading-bar_2s_ease-in-out_infinite]"></div>
            </div>
            <style>{`
                @keyframes loading-bar {
                    0% { width: 0%; transform: translateX(-100%); }
                    50% { width: 100%; transform: translateX(0); }
                    100% { width: 0%; transform: translateX(100%); }
                }
            `}</style>
        </div>
    );
  }

  // MVP Draggable Token Component
  const MVPToken = () => (
    <div 
      draggable 
      onDragStart={handleDragStart}
      className="cursor-grab active:cursor-grabbing hover:scale-110 transition-transform"
      title="Drag me to the MVP player!"
    >
       <div className="w-12 h-12 bg-gradient-to-br from-yellow-300 to-yellow-600 rounded-full flex items-center justify-center shadow-[0_0_15px_#fbbf24] border-2 border-white animate-pulse">
           <span className="font-black italic text-[#05090f] text-xs">MVP</span>
       </div>
    </div>
  );

  const winningTeam = winner === 'azure' ? match.azureTeam : match.crimsonTeam;
  const losingTeam = winner === 'azure' ? match.crimsonTeam : match.azureTeam;

  const renderTeamColumn = (teamSlots: typeof winningTeam, teamName: string, isWinner: boolean, teamColor: 'cyan' | 'red') => {
      const borderColor = teamColor === 'cyan' ? 'border-[#00d2ff]' : 'border-[#ef4444]';
      const bgColor = teamColor === 'cyan' ? 'bg-[#00d2ff]/10' : 'bg-[#ef4444]/10';
      const textColor = teamColor === 'cyan' ? 'text-cyan-400' : 'text-red-500';

      return (
        <div className={`flex-1 w-full border ${borderColor} ${bgColor} p-0 clip-corner-md transition-all`}>
            <div className={`p-4 bg-opacity-30 border-b border-white/10 flex justify-between items-center ${teamColor === 'cyan' ? 'bg-[#00d2ff]' : 'bg-[#ef4444]'}`}>
                <div className="flex items-center gap-2">
                    <div className={`w-1 h-6 ${teamColor === 'cyan' ? 'bg-cyan-500' : 'bg-red-500'}`}></div>
                    <h3 className={`${textColor} font-cinzel font-bold text-xl`}>{teamName}</h3>
                </div>
                {isWinner && <span className="text-[#dcb06b] font-bold uppercase tracking-widest text-xs border border-[#dcb06b] px-2 py-1 rounded">Victory</span>}
            </div>

            <div className="p-4 space-y-2">
                {ROLES_ORDER.map(role => {
                    const slot = teamSlots.find(s => s.role === role);
                    if(!slot) return null;
                    const isMvp = slot.player.id === mvpId;
                    const rating = ratings[slot.player.id];

                    return (
                        <div 
                            key={role} 
                            onDragOver={handleDragOver}
                            onDrop={(e) => handleDrop(e, slot.player.id)}
                            className={`
                                flex items-center justify-between bg-[#0a1a2f]/50 p-3 rounded border relative overflow-hidden group transition-all
                                ${isMvp ? 'border-yellow-400 shadow-[0_0_15px_rgba(251,191,36,0.3)]' : 'border-white/5 hover:border-white/20'}
                            `}
                        >
                            {/* MVP Background Highlight */}
                            {isMvp && (
                                <div className="absolute inset-0 bg-gradient-to-r from-yellow-500/10 to-transparent pointer-events-none"></div>
                            )}

                            <div className="flex items-center gap-4 relative z-10 flex-1 min-w-0">
                                <div className={`shrink-0 ${teamColor === 'cyan' ? 'text-cyan-500/50' : 'text-red-500/50'}`}>
                                    {RoleIcons[role]}
                                </div>
                                <div className="min-w-0 flex-1">
                                    <div className={`text-lg font-orbitron truncate ${isMvp ? 'text-[#dcb06b]' : 'text-white'}`}>{slot.player.name}</div>
                                </div>
                            </div>

                            {/* Right Side: Arrows & MVP Status */}
                            <div className="flex items-center gap-4 relative z-10 shrink-0">

                                {/* Performance Arrows */}
                                <div className="flex flex-col gap-1 mr-2">
                                    <button 
                                        onClick={() => toggleRating(slot.player.id, 'up')}
                                        className={`p-1 rounded hover:bg-white/10 transition-colors ${rating === 'up' ? 'text-green-400 drop-shadow-[0_0_5px_lime]' : 'text-gray-600'}`}
                                    >
                                        <svg xmlns="http://www.w3.org/2000/svg" className="h-4 w-4" fill="none" viewBox="0 0 24 24" stroke="currentColor" strokeWidth={3}>
                                            <path strokeLinecap="round" strokeLinejoin="round" d="M5 15l7-7 7 7" />
                                        </svg>
                                    </button>
                                    <button 
                                        onClick={() => toggleRating(slot.player.id, 'down')}
                                        className={`p-1 rounded hover:bg-white/10 transition-colors ${rating === 'down' ? 'text-red-500 drop-shadow-[0_0_5px_red]' : 'text-gray-600'}`}
                                    >
                                        <svg xmlns="http://www.w3.org/2000/svg" className="h-4 w-4" fill="none" viewBox="0 0 24 24" stroke="currentColor" strokeWidth={3}>
                                            <path strokeLinecap="round" strokeLinejoin="round" d="M19 9l-7 7-7-7" />
                                        </svg>
                                    </button>
                                </div>

                                {/* MVP Badge Drop Zone / Display */}
                                <div className="w-12 h-12 flex items-center justify-center">
                                    {isMvp ? (
                                        <div className="w-10 h-10 bg-gradient-to-br from-yellow-300 to-yellow-600 rounded-full flex items-center justify-center shadow-[0_0_10px_#fbbf24] animate-[pop_0.3s_ease-out]">
                                            <span className="font-black italic text-[#05090f] text-[10px]">MVP</span>
                                        </div>
                                    ) : (
                                        <div className="w-10 h-10 border-2 border-dashed border-white/10 rounded-full flex items-center justify-center text-[8px] text-white/20 opacity-0 group-hover:opacity-100 transition-opacity">
                                            DROP
                                        </div>
                                    )}
                                </div>
                            </div>
                        </div>
                    );
                })}
            </div>
        </div>
      );
  }

  return (
    <div className="min-h-screen bg-[url('https://wallpaperaccess.com/full/3739268.jpg')] bg-cover bg-center fixed inset-0 z-[50] flex flex-col items-center justify-center p-4">
       <div className="absolute inset-0 bg-[#05090f]/90 backdrop-blur-md"></div>

       <div className="relative z-10 w-full max-w-6xl animate-slide-in h-full overflow-y-auto py-8">

          <div className="text-center mb-6">
             <div className="flex items-center justify-center gap-3 mb-2">
                 <div className="w-2 h-2 bg-[#dcb06b] rounded-full"></div>
                 <h2 className="text-[#dcb06b] font-cinzel font-bold text-xl tracking-[0.3em] uppercase">Battle Report</h2>
                 <div className="w-2 h-2 bg-[#dcb06b] rounded-full"></div>
             </div>
             <h1 className="text-3xl md:text-5xl font-orbitron font-black text-white uppercase drop-shadow-[0_0_15px_rgba(255,255,255,0.5)]">
                Evaluation
             </h1>
          </div>

          {/* MVP Drag Source Area */}
          <div className="flex flex-col items-center justify-center mb-8 p-4 bg-[#0a1a2f]/50 border border-[#dcb06b]/30 rounded-lg max-w-md mx-auto">
             <div className="text-[#8a9db8] text-[10px] uppercase tracking-widest mb-3 font-bold">
                 {!mvpId ? "Drag MVP Badge to Player" : "MVP Assigned"}
             </div>
             {!mvpId ? (
                <MVPToken />
             ) : (
                <div className="flex items-center gap-2">
                     <button onClick={() => setMvpId('')} className="text-xs text-red-400 underline">Reset Selection</button>
                </div>
             )}
          </div>

          <div className="flex flex-col md:flex-row gap-8 items-start justify-center">

             {/* Left Column (Azure) */}
             {renderTeamColumn(match.azureTeam, "AZURE GOLEM", winner === 'azure', 'cyan')}

             {/* Right Column (Crimson) */}
             {renderTeamColumn(match.crimsonTeam, "CRIMSON GOLEM", winner === 'crimson', 'red')}

          </div>

          <div className="mt-12 flex justify-center pb-8">
             <Button onClick={() => onComplete(mvpId)} className="px-16 py-4 text-xl shadow-[0_0_20px_#dcb06b]">
                CONTINUE TO LOBBY
             </Button>
