import React, { useState } from 'react';
import { MatchHistoryEntry, Role } from '../types';
import { ROLES_ORDER, RoleIcons } from '../constants';

interface HistoryListProps {
  history: MatchHistoryEntry[];
  onClear: () => void;
}

export const HistoryList: React.FC<HistoryListProps> = ({ history, onClear }) => {
  const [expandedId, setExpandedId] = useState<string | null>(null);

  if (history.length === 0) {
    return (
      <div className="p-8 text-center border border-[#1e3a5f] bg-[#0a1a2f]/40 rounded">
        <p className="text-[#8a9db8] font-cinzel tracking-widest text-sm">No match history recorded yet.</p>
      </div>
    );
  }

  const toggleExpand = (id: string) => {
    setExpandedId(expandedId === id ? null : id);
  };

  const formatDate = (ts: number) => {
    return new Date(ts).toLocaleString();
  };

  return (
    <div className="space-y-4">
       <div className="flex justify-between items-center mb-4">
          <h3 className="text-[#dcb06b] font-cinzel text-lg tracking-widest">Recent Matches</h3>
          <button onClick={onClear} className="text-[10px] text-red-400 hover:text-red-200 uppercase tracking-wider">
             Clear History
          </button>
       </div>

       <div className="space-y-3">
         {history.map((match) => {
            const isAzureWin = match.winningTeam === 'azure';
            const isCrimsonWin = match.winningTeam === 'crimson';
            const isDraw = !match.winningTeam;

            return (
              <div key={match.id} className="border border-[#1e3a5f] bg-[#05090f] clip-corner-sm transition-all hover:border-[#dcb06b]/30">
                {/* Header Summary */}
                <div 
                  className="p-4 flex items-center justify-between cursor-pointer hover:bg-[#1e3a5f]/20 transition-colors"
                  onClick={() => toggleExpand(match.id)}
                >
                   <div className="flex items-center gap-4">
                      <div className={`
                         w-2 h-12 skew-x-[-12deg]
                         ${isAzureWin ? 'bg-cyan-500 shadow-[0_0_10px_#06b6d4]' : isCrimsonWin ? 'bg-red-500 shadow-[0_0_10px_#ef4444]' : 'bg-gray-500'}
                      `}></div>
                      <div>
                         <div className="text-xs text-[#8a9db8] font-orbitron tracking-widest mb-1">
                            ROOM: {match.roomId}
                         </div>
                         <div className={`font-cinzel font-bold text-lg ${isAzureWin ? 'text-cyan-400' : isCrimsonWin ? 'text-red-500' : 'text-gray-400'}`}>
                            {isAzureWin ? 'AZURE VICTORY' : isCrimsonWin ? 'CRIMSON VICTORY' : 'MATCH ENDED'}
                         </div>
                         <div className="text-[10px] text-[#4a5f78]">{formatDate(match.timestamp)}</div>
                      </div>
                   </div>

                   <div className={`transform transition-transform duration-300 ${expandedId === match.id ? 'rotate-180' : ''}`}>
                      <svg xmlns="http://www.w3.org/2000/svg" className="h-5 w-5 text-[#dcb06b]" fill="none" viewBox="0 0 24 24" stroke="currentColor">
                        <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M19 9l-7 7-7-7" />
                      </svg>
                   </div>
                </div>

                {/* Details Accordion */}
                {expandedId === match.id && (
                  <div className="border-t border-[#1e3a5f] p-4 bg-[#0a1a2f]/30">
                     <div className="grid grid-cols-1 md:grid-cols-2 gap-8">
                        {/* Azure Roster */}
                        <div>
                           <h4 className="text-cyan-500 font-cinzel text-xs tracking-widest mb-3 border-b border-cyan-500/20 pb-1">AZURE TEAM</h4>
                           <div className="space-y-2">
                              {ROLES_ORDER.map(role => {
                                 const p = match.azureTeam.find(s => s.role === role)?.player;
                                 return (
                                    <div key={role} className="flex items-center justify-between text-sm">
                                       <span className="flex items-center gap-2 text-[#8a9db8]">
                                          <div className="text-cyan-500/70">{RoleIcons[role]}</div>
                                       </span>
                                       <span className="text-white font-orbitron">{p?.name}</span>
                                    </div>
                                 );
                              })}
                           </div>
                        </div>

                        {/* Crimson Roster */}
                        <div>
                           <h4 className="text-red-500 font-cinzel text-xs tracking-widest mb-3 border-b border-red-500/20 pb-1">CRIMSON TEAM</h4>
                           <div className="space-y-2">
                              {ROLES_ORDER.map(role => {
                                 const p = match.crimsonTeam.find(s => s.role === role)?.player;
                                 return (
                                    <div key={role} className="flex items-center justify-between text-sm">
                                       <span className="flex items-center gap-2 text-[#8a9db8]">
                                          <div className="text-red-500/70">{RoleIcons[role]}</div>
                                       </span>
                                       <span className="text-white font-orbitron">{p?.name}</span>
                                    </div>
                                 );
                              })}
                           </div>
                        </div>
                     </div>
                  </div>
                )}
              </div>
            );
         })}
       </div>
    </div>
  );
};

import React, { useState, useEffect } from 'react';
import { Player, Role } from '../types';
import { RoleIcons, ROLES_ORDER } from '../constants';

interface PlayerListProps {
  players: Player[];
  onRemove: (id: string) => void;
  onToggleActive: (id: string) => void;
  onEdit: (player: Player) => void;
}

type FilterType = 'ALL' | 'ACTIVE' | 'BENCH' | Role;

export const PlayerList: React.FC<PlayerListProps> = ({ players, onRemove, onToggleActive, onEdit }) => {
  const [filter, setFilter] = useState<FilterType>('ALL');
  const [menuOpenId, setMenuOpenId] = useState<string | null>(null);

  // Close menu when clicking outside
  useEffect(() => {
    const handleClickOutside = () => setMenuOpenId(null);
    if (menuOpenId) {
      document.addEventListener('click', handleClickOutside);
    }
    return () => {
      document.removeEventListener('click', handleClickOutside);
    };
  }, [menuOpenId]);

  const toggleMenu = (e: React.MouseEvent, id: string) => {
    e.stopPropagation();
    setMenuOpenId(prev => prev === id ? null : id);
  };

  // Filter Logic
  const filteredPlayers = players.filter(p => {
    if (filter === 'ALL') return true;
    if (filter === 'ACTIVE') return p.isActive;
    if (filter === 'BENCH') return !p.isActive;
    // Check for specific Role
    if (Object.values(Role).includes(filter as Role)) {
       // Special handling: if filter is Coach, check exact match or if roles includes it
       return p.roles.includes(filter as Role);
    }
    return true;
  });

  const filters: { label: string; value: FilterType; icon?: React.ReactNode }[] = [
    { label: 'All', value: 'ALL' },
    { label: 'Playing', value: 'ACTIVE' },
    { label: 'Benched', value: 'BENCH' },
    ...ROLES_ORDER.map(r => ({ label: r.split(' ')[0], value: r })),
    { label: 'Coach', value: Role.COACH }
  ];

  if (players.length === 0) {
    return (
      <div className="h-full min-h-[300px] flex flex-col items-center justify-center border border-dashed border-[#1e3a5f] rounded-lg bg-[#0a1a2f]/30 p-8">
        <div className="w-20 h-20 rounded-full bg-[#1e3a5f]/50 flex items-center justify-center mb-4 border border-[#dcb06b]/20">
           <svg xmlns="http://www.w3.org/2000/svg" className="h-8 w-8 text-[#dcb06b]/50" fill="none" viewBox="0 0 24 24" stroke="currentColor"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M12 4.354a4 4 0 110 5.292M15 21H3v-1a6 6 0 0112 0v1zm0 0h6v-1a6 6 0 00-9-5.197M13 7a4 4 0 11-8 0 4 4 0 018 0z" /></svg>
        </div>
        <p className="text-[#8a9db8] font-cinzel tracking-widest text-sm">Waiting for Challengers</p>
      </div>
    );
  }

  return (
    <div>
      {/* FILTER BAR */}
      <div className="mb-6 overflow-x-auto pb-2 scrollbar-hide">
         <div className="flex gap-2 min-w-max">
            {filters.map(f => (
               <button
                 key={f.value}
                 onClick={() => setFilter(f.value)}
                 className={`
                   px-3 py-1.5 text-[10px] uppercase font-bold tracking-wider clip-corner-sm border transition-all
                   ${filter === f.value 
                      ? 'bg-[#dcb06b] text-[#05090f] border-[#dcb06b]' 
                      : 'bg-[#0a1a2f] text-[#8a9db8] border-[#1e3a5f] hover:border-[#dcb06b]/50 hover:text-white'}
                 `}
               >
                 {f.label}
               </button>
            ))}
         </div>
      </div>

      {/* PLAYER GRID: 3 Columns max now (lg:grid-cols-3) to allow wider cards */}
      <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 gap-4">
        {filteredPlayers.map(player => {
          const isActive = player.isActive;
          const stats = player.stats || { matchesPlayed: 0, wins: 0, currentStreak: 0, maxStreak: 0 };
          const winRate = stats.matchesPlayed > 0 
            ? Math.round((stats.wins / stats.matchesPlayed) * 100) 
            : 0;

          const streak = stats.currentStreak;
          const isHot = streak >= 3;
          const isGodlike = streak >= 6;
          const isMvp = player.isLastMatchMvp;
          const isCoach = player.roles.includes(Role.COACH);

          // Styles for specific states
          let containerGlow = "";
          let borderOverlay = null;

          if (isMvp) {
              containerGlow = "drop-shadow-[0_0_20px_rgba(251,191,36,0.6)]";
              borderOverlay = (
                <div className="absolute -inset-[3px] clip-corner-sm overflow-hidden z-0 pointer-events-none">
                    <div className="absolute top-[-50%] left-[-50%] w-[200%] h-[200%] animate-spin-slow bg-[conic-gradient(transparent,transparent,#fcd34d,#fbbf24)] opacity-100"></div>
                    <div className="absolute inset-0 bg-yellow-500/10 animate-pulse"></div>
                </div>
              );
          } else if (isActive) {
            if (isCoach) {
              containerGlow = "drop-shadow-[0_0_15px_rgba(255,255,255,0.4)]";
              borderOverlay = (
                <div className="absolute -inset-[2px] clip-corner-sm overflow-hidden z-0 pointer-events-none">
                    <div className="absolute top-[-50%] left-[-50%] w-[200%] h-[200%] animate-spin-slow bg-[conic-gradient(transparent,transparent,#ffffff)] opacity-100"></div>
                </div>
              );
            } else if (isGodlike) {
              containerGlow = "drop-shadow-[0_0_15px_rgba(239,68,68,0.6)]";
              borderOverlay = (
                <div className="absolute -inset-[2px] clip-corner-sm overflow-hidden z-0 pointer-events-none">
                    <div className="absolute top-[-50%] left-[-50%] w-[200%] h-[200%] animate-spin-slow bg-[conic-gradient(transparent,transparent,#ef4444)] opacity-100"></div>
                </div>
              );
            } else if (isHot) {
              containerGlow = "drop-shadow-[0_0_10px_rgba(6,182,212,0.4)]";
              borderOverlay = (
                <div className="absolute -inset-[2px] clip-corner-sm overflow-hidden z-0 pointer-events-none">
                    <div className="absolute top-[-50%] left-[-50%] w-[200%] h-[200%] animate-spin-slow bg-[conic-gradient(transparent,transparent,#06b6d4)] opacity-100"></div>
                </div>
              );
            }
          }

          let bgClass = 'bg-[#05090f]';
          if (isActive && isCoach) bgClass = 'bg-black';

          let borderClass = 'border border-[#1e3a5f]';
          if (isMvp) borderClass = 'border-2 border-yellow-400';
          else if (isActive && (isHot || isGodlike || isCoach)) borderClass = 'border-none';

          return (
            <div key={player.id} className={`relative group ${containerGlow} tilt-card`}>

              {borderOverlay}

              <div 
                className={`
                  relative z-10 p-3 pb-8 clip-corner-sm h-full flex flex-col justify-between min-h-[140px]
                  ${bgClass} ${borderClass}
                  ${!isActive ? 'opacity-60 grayscale hover:opacity-100' : 'hover:border-[#dcb06b]/50'}
                `}
                style={isActive && (isHot || isGodlike || isCoach) && !isMvp ? { margin: '1px' } : {}}
              >

                {/* TOP ROW: Roles & Menu (Swapped position to give Name more room below) */}
                <div className="flex justify-between items-start mb-2">

                   {/* Roles Container - Compact */}
                   <div className="flex flex-wrap gap-1 max-w-[85%]">
                      {player.isAllRoles ? (
                        <div className={`flex items-center gap-1.5 px-2 py-0.5 border clip-corner-sm ${isActive ? 'bg-[#dcb06b]/10 text-[#dcb06b] border-[#dcb06b]/30' : 'bg-[#1e3a5f]/20 text-[#4a5f78] border-[#1e3a5f]/30'}`}>
                           <span className="text-[9px] font-bold uppercase tracking-widest whitespace-nowrap">All Roles</span>
                        </div>
                      ) : (
                        <>
                           {player.roles.length === 0 && <span className="text-[9px] text-red-400 italic">No Roles</span>}
                           {player.roles.map(role => (
                              <div key={role} className={`
                                  flex items-center px-2 py-0.5
                                  clip-corner-sm border transition-colors
                                  ${isActive ? 'bg-[#1e3a5f]/50 text-[#8a9db8] border-transparent' : 'bg-[#0f223d]/50 text-[#4a5f78] border-transparent'}
                              `}>
                                  <span className="text-[8px] uppercase font-bold tracking-wider leading-none whitespace-nowrap">
                                    {role === Role.COACH ? 'COACH' : role.split(' ')[0]}
                                  </span>
                              </div>
                           ))}
                        </>
                      )}
                   </div>

                   {/* Three-Dot Menu */}
                   <div className="relative">
                      <button 
                         onClick={(e) => toggleMenu(e, player.id)}
                         className="p-1 text-[#4a5f78] hover:text-[#dcb06b] transition-colors"
                      >
                         <svg xmlns="http://www.w3.org/2000/svg" className="h-5 w-5" fill="none" viewBox="0 0 24 24" stroke="currentColor">
                           <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M12 5v.01M12 12v.01M12 19v.01M12 6a1 1 0 110-2 1 1 0 010 2zm0 7a1 1 0 110-2 1 1 0 010 2zm0 7a1 1 0 110-2 1 1 0 010 2z" />
                         </svg>
                      </button>

                      {menuOpenId === player.id && (
                         <div className="absolute right-0 top-full mt-1 w-32 bg-[#05090f] border border-[#dcb06b] z-50 shadow-[0_0_20px_rgba(0,0,0,0.8)] clip-corner-sm flex flex-col animate-slide-in">
                            <button 
                              onClick={(e) => { e.stopPropagation(); onToggleActive(player.id); setMenuOpenId(null); }}
                              className="px-3 py-2 text-left text-[10px] uppercase font-bold text-[#f0f4f8] hover:bg-[#dcb06b] hover:text-[#05090f] transition-colors"
                            >
                               {isActive ? 'Bench Player' : 'Activate'}
                            </button>
                            <button 
                              onClick={(e) => { e.stopPropagation(); onEdit(player); setMenuOpenId(null); }}
                              className="px-3 py-2 text-left text-[10px] uppercase font-bold text-[#f0f4f8] hover:bg-[#dcb06b] hover:text-[#05090f] transition-colors"
                            >
                               Edit Details
                            </button>
                            <div className="h-[1px] bg-[#1e3a5f] w-full"></div>
                            <button 
                              onClick={(e) => { e.stopPropagation(); onRemove(player.id); setMenuOpenId(null); }}
                              className="px-3 py-2 text-left text-[10px] uppercase font-bold text-red-500 hover:bg-red-500 hover:text-white transition-colors"
                            >
                               Remove
                            </button>
                         </div>
                      )}
                   </div>
                </div>

                {/* MIDDLE: NAME & Badges */}
                <div className="flex flex-col mb-4 px-1">
                   {/* Special Badges Row */}
                   <div className="flex gap-2 mb-1 h-4">
                      {isMvp && (
                         <div className="text-[9px] font-black bg-gradient-to-r from-yellow-300 to-yellow-600 text-[#05090f] px-1 rounded-sm shadow-[0_0_5px_#fbbf24] animate-pulse">MVP</div>
                      )}
                      {isCoach && (
                          <div className="text-[9px] font-black bg-white text-black px-1 rounded-sm shadow-[0_0_5px_#ffffff]">COACH</div>
                      )}
                      {!isMvp && isHot && isActive && !isCoach && (
                         <div className={`text-[9px] font-bold uppercase flex items-center gap-1 ${isGodlike ? 'text-red-500' : 'text-cyan-400'}`}>
                            <span className="animate-pulse">🔥</span> {isGodlike ? 'GODLIKE' : 'HOT'}
                         </div>
                      )}
                   </div>

                   {/* Large Name */}
                   <div 
                      className={`text-xl font-bold font-orbitron tracking-wide leading-tight truncate w-full ${isMvp ? 'text-yellow-400' : isCoach ? 'text-white' : isActive ? 'text-[#f0f4f8] group-hover:text-[#dcb06b]' : 'text-[#4a5f78]'}`}
                      title={player.name}
                   >
                      {player.name}
                   </div>
                </div>

                {/* BOTTOM: Stats Footer */}
                <div className={`absolute bottom-0 left-0 right-0 h-8 flex items-center justify-between px-3 text-[10px] font-mono border-t border-[#1e3a5f] bg-[#05090f]/50 ${isActive ? 'opacity-100' : 'opacity-50'}`}>
                  <div className="flex items-center gap-2">
                    <span className="text-[#4a5f78]">Matches:</span>
                    <span className="text-[#f0f4f8]">{stats.matchesPlayed}</span>
                  </div>

                  {stats.matchesPlayed > 0 && (
                      <div className="flex items-center gap-2">
                        <span className="text-[#4a5f78]">WR:</span>
                        <span className={`font-bold ${winRate >= 60 ? 'text-[#dcb06b]' : winRate >= 50 ? 'text-[#f0f4f8]' : 'text-red-400'}`}>
                          {winRate}%
                        </span>
                      </div>
                  )}
                </div>

                {/* Benched Overlay */}
                {!isActive && (
                  <div className="absolute inset-0 flex items-center justify-center pointer-events-none z-10">
                    <span className="text-[#0a1a2f] font-black text-2xl -rotate-12 opacity-40 uppercase tracking-widest select-none bg-[#dcb06b] px-2 mix-blend-screen">Benched</span>
                  </div>
                )}

                {/* Corner Accents */}
                {isActive && (
                  <>
                    <div className={`absolute top-0 left-0 w-2 h-2 border-t border-l ${isMvp ? 'border-yellow-400' : isCoach ? 'border-white' : 'border-[#dcb06b]'} opacity-0 group-hover:opacity-100 transition-opacity`}></div>
                    <div className={`absolute bottom-8 right-0 w-2 h-2 border-b border-r ${isMvp ? 'border-yellow-400' : isCoach ? 'border-white' : 'border-[#dcb06b]'} opacity-0 group-hover:opacity-100 transition-opacity`}></div>
                  </>
                )}
              </div>
            </div>
          );
        })}
      </div>
    </div>
  );
};

import React, { useState } from 'react';
import { MatchResult, TeamSlot, Role, Player } from '../types';
import { RoleIcons, ROLES_ORDER } from '../constants';
import { Button } from './Button';
import { SpinWheel } from './SpinWheel';
import { PortalTransition } from './PortalTransition';
import { MatchSummary } from './MatchSummary';
import { VictoryCelebration } from './VictoryCelebration';
import { EvaluationScreen } from './EvaluationScreen';

interface MatchDisplayProps {
  match: MatchResult;
  activePlayers: Player[]; 
  onReset: () => void; // For Abort
  onCompleteMatch: (winner: 'azure' | 'crimson' | null, mvpId?: string) => void; // For Finish
  onReroll: (team: 'azure' | 'crimson', role: Role, newPlayer: Player) => void;
}

type ViewState = 'drafting' | 'transition' | 'final' | 'celebration' | 'evaluation';

export const MatchDisplay: React.FC<MatchDisplayProps> = ({ match, activePlayers, onReset, onCompleteMatch, onReroll }) => {
  const [viewState, setViewState] = useState<ViewState>('drafting');
  const [winningTeam, setWinningTeam] = useState<'azure' | 'crimson' | null>(null);

  // Dynamic Role Order: If Coach mode, append Coach to standard order
  const displayRoles = match.isCoachMode ? [...ROLES_ORDER, Role.COACH] : ROLES_ORDER;

  // -1: Not started
  // 0-4: Revealing pairs (0=Clash, ... 4=Roam)
  // 5: Coach (if exists)
  const [currentRoleIndex, setCurrentRoleIndex] = useState(-1);

  // New State for the Modal Wheel
  const [wheelState, setWheelState] = useState<{
    isOpen: boolean;
    type: 'draft' | 'reroll'; // Differentiate between initial draft reveal and manual reroll
    team: 'azure' | 'crimson';
    role: Role;
    winnerName: string;
    winnerPlayer?: Player; // Needed for reroll
    candidates: string[];
  } | null>(null);

  // Tracks which individual cards are visible
  const [revealedCards, setRevealedCards] = useState<Set<string>>(new Set());

  const getPlayerForRole = (team: TeamSlot[], role: Role) => {
    return team.find(slot => slot.role === role);
  };

  const getCardId = (team: 'azure' | 'crimson', role: Role) => `${team}-${role}`;

  const handleNext = () => {
    const nextIndex = currentRoleIndex + 1;
    if (nextIndex >= displayRoles.length) return;

    const roleToReveal = displayRoles[nextIndex];

    // Step 1: Check if Azure is revealed
    const azureId = getCardId('azure', roleToReveal);
    if (!revealedCards.has(azureId)) {
      startWheel('azure', roleToReveal);
      return;
    }

    // Step 2: Check if Crimson is revealed
    const crimsonId = getCardId('crimson', roleToReveal);
    if (!revealedCards.has(crimsonId)) {
      startWheel('crimson', roleToReveal);
      return;
    }
  };

  const handleSkipAll = () => {
    // Debug: Instantly reveal everything
    const allCards = new Set<string>();
    displayRoles.forEach(r => {
      allCards.add(getCardId('azure', r));
      allCards.add(getCardId('crimson', r));
    });
    setRevealedCards(allCards);
    setCurrentRoleIndex(displayRoles.length); // Set to finished state
  };

  const startWheel = (team: 'azure' | 'crimson', role: Role) => {
    const teamSlots = team === 'azure' ? match.azureTeam : match.crimsonTeam;
    const winner = getPlayerForRole(teamSlots, role)?.player;
    if (!winner) return;

    // Get candidates for the wheel
    // STRICT COACH LOGIC: If role is Coach, ONLY allow players with Coach role.
    const candidates = activePlayers
      .filter(p => {
          if (role === Role.COACH) {
              return p.roles.includes(Role.COACH);
          }
          return p.isAllRoles || p.roles.includes(role);
      })
      .map(p => p.name);

    setWheelState({
      isOpen: true,
      type: 'draft',
      team,
      role,
      winnerName: winner.name,
      candidates
    });
  };

  // Triggered when user clicks the re-roll button on a card
  const handleRerollClick = (team: 'azure' | 'crimson', role: Role) => {
    const azureIds = new Set(match.azureTeam.map(s => s.player.id));
    const crimsonIds = new Set(match.crimsonTeam.map(s => s.player.id));

    // CRITICAL: This ensures players already in match (even All Role) don't appear in wheel
    const benchPlayers = activePlayers.filter(p => !azureIds.has(p.id) && !crimsonIds.has(p.id));

    if (benchPlayers.length === 0) {
      alert("No available bench players to re-roll with!");
      return;
    }

    // STRICT COACH LOGIC for Reroll
    const candidates = benchPlayers.filter(p => {
       if (role === Role.COACH) {
          return p.roles.includes(Role.COACH);
       }
       return p.isAllRoles || p.roles.includes(role);
    });

    if (candidates.length === 0) {
       alert(`No available bench players found for role: ${role}`);
       return;
    }

    const newPlayer = candidates[Math.floor(Math.random() * candidates.length)];
    const candidateNames = candidates.map(p => p.name);

    setWheelState({
        isOpen: true,
        type: 'reroll',
        team,
        role,
        winnerName: newPlayer.name,
        winnerPlayer: newPlayer,
        candidates: candidateNames
    });
  };

  const handleWheelComplete = () => {
    if (!wheelState) return;

    if (wheelState.type === 'draft') {
        const { team, role } = wheelState;
        setRevealedCards(prev => new Set(prev).add(getCardId(team, role)));
        if (team === 'crimson') {
           setCurrentRoleIndex(prev => prev + 1);
        }
    } else if (wheelState.type === 'reroll' && wheelState.winnerPlayer) {
        onReroll(wheelState.team, wheelState.role, wheelState.winnerPlayer);
    }

    setWheelState(null);
  };

  const handleWheelCancel = () => {
    setWheelState(null);
  };

  const handleInitializeBattle = () => {
    setViewState('transition');
  };

  const handleTransitionComplete = () => {
    setViewState('final');
  };

  const handleMatchDecided = (winner: 'azure' | 'crimson' | null) => {
    if (winner) {
      setWinningTeam(winner);
      setViewState('celebration');
    } else {
      onCompleteMatch(null);
    }
  };

  const handleCelebrationDismiss = () => {
    setViewState('evaluation');
  };

  const handleEvaluationComplete = (mvpId?: string) => {
    onCompleteMatch(winningTeam, mvpId);
  }

  // --- RENDER LOGIC ---

  if (viewState === 'evaluation' && winningTeam) {
    return (
      <EvaluationScreen 
        match={match} 
        winner={winningTeam} 
        onComplete={handleEvaluationComplete} 
      />
    );
  }

  if (viewState === 'celebration' && winningTeam) {
    const winningTeamSlots = winningTeam === 'azure' ? match.azureTeam : match.crimsonTeam;
    return (
      <VictoryCelebration 
        winner={winningTeam} 
        teamSlots={winningTeamSlots}
        onDismiss={handleCelebrationDismiss} 
      />
    );
  }

  if (viewState === 'transition') {
    return (
      <PortalTransition 
        azureTeam={match.azureTeam} 
        crimsonTeam={match.crimsonTeam} 
        onComplete={handleTransitionComplete} 
      />
    );
  }

  if (viewState === 'final') {
    return <MatchSummary match={match} onReset={handleMatchDecided} />;
  }

  // --- DRAFTING VIEW ---

  const renderPlayerCard = (role: Role, roleIndex: number, team: 'azure' | 'crimson') => {
    const teamSlots = team === 'azure' ? match.azureTeam : match.crimsonTeam;
    const player = getPlayerForRole(teamSlots, role)?.player;
    const isRevealed = revealedCards.has(getCardId(team, role));

    // HoK Color Palettes
    const theme = team === 'azure' 
      ? {
          bg: 'bg-[#0a1a2f]',
          border: 'border-hok-cyan',
          glow: 'shadow-[0_0_10px_#00d2ff]',
          text: 'text-hok-cyan',
          gradient: 'from-[#00d2ff]/20 to-transparent'
        } 
      : {
          bg: 'bg-[#1a0505]',
          border: 'border-hok-red',
          glow: 'shadow-[0_0_10px_#ef4444]',
          text: 'text-hok-red',
          gradient: 'from-[#c02d2d]/20 to-transparent'
        };

    // State 1: Hidden
    if (!isRevealed) {
       return (
         <div className="h-24 w-full relative overflow-hidden clip-corner-md border border-[#1e3a5f] bg-[#05090f]/80 flex flex-col items-center justify-center opacity-40 group">
            <div className="text-[#1e3a5f] group-hover:text-[#dcb06b]/50 transition-colors duration-500 transform scale-90 opacity-50">
               {RoleIcons[role]}
            </div>
            {/* Tech Scanlines */}
            <div className="absolute inset-0 bg-[url('data:image/svg+xml;base64,PHN2ZyB4bWxucz0iaHR0cDovL3d3dy53My5vcmcvMjAwMC9zdmciIHdpZHRoPSI0IiBoZWlnaHQ9IjQiPgo8cmVjdCB3aWR0aD0iNCIgaGVpZ2h0PSI0IiBmaWxsPSIjZmZmIiBmaWxsLW9wYWNpdHk9IjAuMDUiLz4KPHBhdGggZD0iTTAgNEw0IDBaIiBzdHJva2U9IiMwMDAiIHN0cm9rZS13aWR0aD0iMSIvPgo8L3N2Zz4=')] opacity-20"></div>
         </div>
       );
    }

    // State 2: Revealed (UPDATED LAYOUT FOR TEXT ROLES)
    return (
      <div className={`relative h-24 w-full animate-slide-in perspective-container group`}>
        <div className={`
            absolute inset-0 clip-corner-md border-l-4 tilt-card
            ${theme.bg} ${theme.border} 
            ${theme.glow}
            shadow-[0_0_15px_rgba(0,0,0,0.5)]
            transition-all duration-300 hover:brightness-110
        `}>
           <div className={`flex flex-col h-full relative z-10 px-4 py-2 justify-center ${team === 'crimson' ? 'items-end text-right' : 'items-start text-left'}`}>

             {/* Text Role Label (Top) */}
             <div className={`mb-1 px-2 py-0.5 rounded-sm bg-black/40 border border-white/10 ${theme.text} transform transition-transform duration-500 w-auto inline-block`}>
                {RoleIcons[role]}
             </div>

             {/* Name Section */}
             <span className={`block text-xl md:text-2xl font-bold text-white truncate font-orbitron drop-shadow-md w-full`}>
                {player?.name}
             </span>

             <div className={`absolute inset-0 bg-gradient-to-r ${theme.gradient} opacity-50 pointer-events-none`}></div>
           </div>

           {/* Decorative Tech Corners */}
           <div className={`absolute top-0 w-8 h-8 border-t border-${team === 'azure' ? 'cyan' : 'red'}-500/50 ${team === 'azure' ? 'left-0' : 'right-0'}`}></div>
           <div className={`absolute bottom-0 w-8 h-8 border-b border-${team === 'azure' ? 'cyan' : 'red'}-500/50 ${team === 'azure' ? 'right-0' : 'left-0'}`}></div>

           {/* Re-roll Button Overlay */}
           <button 
             onClick={(e) => { e.stopPropagation(); handleRerollClick(team, role); }}
             className="absolute top-1 right-1 md:top-2 md:right-2 p-1.5 bg-black/50 hover:bg-[#dcb06b] rounded-full transition-colors group-hover:opacity-100 opacity-0 text-white hover:text-black z-50 border border-white/20"
             title="Re-roll this specific slot"
           >
             <svg xmlns="http://www.w3.org/2000/svg" className="h-4 w-4" fill="none" viewBox="0 0 24 24" stroke="currentColor">
               <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M4 4v5h.582m15.356 2A8.001 8.001 0 004.582 9m0 0H9m11 11v-5h-.581m0 0a8.003 8.003 0 01-15.357-2m15.357 2H15" />
             </svg>
           </button>
        </div>
      </div>
    );
  };

  const nextRoleIndex = currentRoleIndex + 1;
  const nextRoleName = nextRoleIndex < displayRoles.length ? displayRoles[nextRoleIndex] : null;
  const isFinished = currentRoleIndex >= displayRoles.length - 1 && revealedCards.size === (match.isCoachMode ? 12 : 10);

  let buttonText = "START DRAFT";
  if (nextRoleName) {
     if (!revealedCards.has(getCardId('azure', nextRoleName))) {
        buttonText = `SELECT AZURE ${nextRoleName.split(' ')[0].toUpperCase()}`;
     } else if (!revealedCards.has(getCardId('crimson', nextRoleName))) {
        buttonText = `SELECT CRIMSON ${nextRoleName.split(' ')[0].toUpperCase()}`;
     } else {
        buttonText = "NEXT LANE";
     }
  }

  // Turret SVG Path
  const TurretIcon = (
    <svg viewBox="0 0 24 24" fill="currentColor" className="w-16 h-16 opacity-30 animate-pulse">
        <path d="M12,2 L2,22 L12,18 L22,22 L12,2 Z" />
        <path d="M12,5 L5,20 L12,17 L19,20 L12,5 Z" fillOpacity="0.5" />
    </svg>
  );

  return (
    <>
      {/* The Spin Wheel Overlay */}
      {wheelState && wheelState.isOpen && (
        <SpinWheel 
          candidates={wheelState.candidates}
          winnerName={wheelState.winnerName}
          team={wheelState.team}
          roleName={wheelState.role}
          onComplete={handleWheelComplete}
          onCancel={handleWheelCancel}
        />
      )}

      <div className="w-full max-w-7xl mx-auto px-4 py-8 pb-32 relative">

        {/* Top Controls: Abort & Instant Result */}
        <div className="absolute top-4 left-4 right-4 z-40 flex justify-between">
           <Button variant="outline" size="sm" onClick={() => onReset()} className="border-red-900/50 text-red-500 hover:bg-red-900/20 text-[10px] px-3">
              <span className="flex items-center gap-2">
                 <svg xmlns="http://www.w3.org/2000/svg" className="h-4 w-4" fill="none" viewBox="0 0 24 24" stroke="currentColor">
                   <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M11 15l-3-3m0 0l3-3m-3 3h8M3 12a9 9 0 1118 0 9 9 0 01-18 0z" />
                 </svg>
                 ABORT DRAFT
              </span>
           </Button>

           {/* Debug / Instant Result Button */}
           {!isFinished && (
             <Button variant="outline" size="sm" onClick={handleSkipAll} className="border-[#dcb06b]/50 text-[#dcb06b] hover:bg-[#dcb06b]/10 text-[10px] px-3">
                <span className="flex items-center gap-2">
                   INSTANT RESULT (DEBUG)
                   <svg xmlns="http://www.w3.org/2000/svg" className="h-4 w-4" fill="none" viewBox="0 0 24 24" stroke="currentColor">
                     <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M13 10V3L4 14h7v7l9-11h-7z" />
                   </svg>
                </span>
             </Button>
           )}
        </div>

        {/* Header Info - PERFECTLY CENTERED */}
        <div className="flex flex-col items-center mb-12 pt-12">
           <div className="flex justify-center w-full mb-8">
              <div className="bg-[#05090f] border border-[#dcb06b]/40 px-8 py-2 clip-diamond relative shadow-[0_0_15px_rgba(220,176,107,0.2)]">
                  <div className="absolute inset-0 bg-[#dcb06b]/5 pointer-events-none"></div>
                  <span className="text-[#dcb06b] font-cinzel font-bold text-sm tracking-widest uppercase block text-center">Room ID</span>
                  <span className="text-2xl font-orbitron font-bold text-white tracking-widest text-center block">{match.roomId}</span>
              </div>
           </div>

           <div className="flex justify-between items-center w-full relative max-w-5xl">
              <div className="w-1/3 text-center relative group">
                 <div className="absolute -inset-4 bg-cyan-500/10 blur-xl rounded-full opacity-50 group-hover:opacity-100 transition-opacity"></div>
                 <div className="absolute -left-10 top-0 text-cyan-500/20">{TurretIcon}</div>
                 <h2 className="relative text-3xl md:text-5xl font-cinzel font-black text-transparent bg-clip-text bg-gradient-to-b from-cyan-200 to-cyan-600 drop-shadow-[0_0_15px_rgba(6,182,212,0.8)]">
                  AZURE
                 </h2>
                 <p className="text-[10px] md:text-xs text-cyan-400 font-orbitron tracking-[0.4em] mt-1 opacity-70">GOLEM TEAM</p>
                 <div className="h-1 w-24 bg-cyan-500 mx-auto mt-2 shadow-[0_0_10px_#00d2ff]"></div>
              </div>

              <div className="w-1/3 flex justify-center items-center z-10">
                <div className="relative w-24 h-24 md:w-32 md:h-32 flex items-center justify-center">
                  <div className="absolute inset-0 border-2 border-[#dcb06b] rotate-45 animate-spin-slow bg-[#05090f]"></div>
                  <div className="absolute inset-2 border border-[#dcb06b]/50 rotate-45"></div>
                  <span className="text-4xl font-black italic text-[#dcb06b] font-orbitron z-10 pr-2 pt-1 animate-pulse-fast">VS</span>
                </div>
              </div>

              <div className="w-1/3 text-center relative group">
