export default function App() {
  const [players, setPlayers] = useState<Player[]>([]);
  const [currentMatch, setCurrentMatch] = useState<MatchResult | null>(null);
  const [matchHistory, setMatchHistory] = useState<MatchHistoryEntry[]>([]);
  const [errorMsg, setErrorMsg] = useState<string | null>(null);
  const [roomId, setRoomId] = useState<string>('');
  const [isCoachMode, setIsCoachMode] = useState(false);
  const [isSidebarOpen, setIsSidebarOpen] = useState(true);

  // Edit State
  const [editingPlayer, setEditingPlayer] = useState<Player | null>(null);
  const [isEditModalOpen, setIsEditModalOpen] = useState(false);

  const rosterFileInputRef = useRef<HTMLInputElement>(null);
  const historyFileInputRef = useRef<HTMLInputElement>(null);

  const addPlayer = (newPlayer: Omit<Player, 'id' | 'isActive' | 'stats'>) => {
    setPlayers(prev => {
      // Check if player already exists (case-insensitive normalization)
      const normalizedName = newPlayer.name.trim().toLowerCase();
      const existingIndex = prev.findIndex(p => p.name.trim().toLowerCase() === normalizedName);

      if (existingIndex !== -1) {
        // UPDATE Existing Player Logic
        const updatedPlayers = [...prev];
        updatedPlayers[existingIndex] = {
          ...updatedPlayers[existingIndex],
          roles: newPlayer.roles,
          isAllRoles: newPlayer.isAllRoles,
          // We also ensure they are active if they are being updated/re-added
          isActive: true 
        };
        return updatedPlayers;
      }

      // CREATE New Player Logic
      const player: Player = { 
        ...newPlayer, 
        id: crypto.randomUUID(),
        isActive: true, // Default to active when added
        isLastMatchMvp: false,
        stats: {
          matchesPlayed: 0,
          wins: 0,
          currentStreak: 0,
          maxStreak: 0
        }
      };
      return [...prev, player];
    });
    setErrorMsg(null);
  };

  const removePlayer = (id: string) => {
    setPlayers(prev => prev.filter(p => p.id !== id));
  };

  const togglePlayerActive = (id: string) => {
    setPlayers(prev => prev.map(p => 
      p.id === id ? { ...p, isActive: !p.isActive } : p
    ));
  };

  // Edit Handlers
  const handleEditPlayer = (player: Player) => {
    setEditingPlayer(player);
    setIsEditModalOpen(true);
  };

  const handleUpdatePlayer = (updatedPlayer: Player) => {
    setPlayers(prev => prev.map(p => 
      p.id === updatedPlayer.id ? updatedPlayer : p
    ));
    setErrorMsg(null);
  };

  const activePlayers = players.filter(p => p.isActive);

  const handleGenerate = () => {
    if (!roomId.trim()) {
      setErrorMsg("Please enter a Room ID.");
      return;
    }

    const required = isCoachMode ? 12 : 10;
    if (activePlayers.length < required) {
      setErrorMsg(`Need ${required} ACTIVE players for ${isCoachMode ? 'Coach' : 'Standard'} Mode. Current Active: ${activePlayers.length}`);
      return;
    }

    // COACH MODE VALIDATION
    if (isCoachMode) {
       // STRICT: Only players with the explicit COACH role can be coach. 
       // All Roles/Fill does NOT count for coach slots.
       const coachCandidates = activePlayers.filter(p => p.roles.includes(Role.COACH));

       if (coachCandidates.length < 2) {
         setErrorMsg(`Coach Mode requires at least 2 players with the specific 'COACH' role. Found: ${coachCandidates.length}`);
         return;
       }
    }

    // Only pass active players to the matchmaker
    const result = generateMatch(activePlayers, roomId, isCoachMode);
    if (result) {
      setCurrentMatch(result);
      setErrorMsg(null);
    } else {
      setErrorMsg("Failed to find valid composition. Ensure role coverage.");
    }
  };

  const handleRerollSlot = (team: 'azure' | 'crimson', role: Role, newPlayer: Player) => {
    if (!currentMatch) return;

    // Update Match State with the new player chosen by the wheel
    setCurrentMatch(prev => {
       if (!prev) return null;

       const newAzure = prev.azureTeam.map(slot => {
          if (team === 'azure' && slot.role === role) {
             return { ...slot, player: newPlayer };
          }
          return slot;
       });

       const newCrimson = prev.crimsonTeam.map(slot => {
          if (team === 'crimson' && slot.role === role) {
             return { ...slot, player: newPlayer };
          }
          return slot;
       });

       return {
          ...prev,
          azureTeam: newAzure,
          crimsonTeam: newCrimson
       };
    });
  };

  const handleMatchFinish = (winner: 'azure' | 'crimson' | null, mvpId?: string) => {
    if (!currentMatch) return;

    // 1. Save History
    const historyEntry: MatchHistoryEntry = {
       ...currentMatch,
       id: crypto.randomUUID(),
       winningTeam: winner,
       mvpId: mvpId
    };
    setMatchHistory(prev => [historyEntry, ...prev]);

    // 2. Update Player Stats if there is a winner
    if (winner) {
      const azurePlayerIds = new Set(currentMatch.azureTeam.map(slot => slot.player.id));
      const crimsonPlayerIds = new Set(currentMatch.crimsonTeam.map(slot => slot.player.id));

      setPlayers(prevPlayers => prevPlayers.map(p => {
        let isLastMatchMvp = false;

        // If player matches the manually provided MVP ID, set flag
        if (mvpId && p.id === mvpId) {
          isLastMatchMvp = true;
        }

        if (!azurePlayerIds.has(p.id) && !crimsonPlayerIds.has(p.id)) {
          return { ...p, isLastMatchMvp: false }; // Clear old MVP if they didn't play
        }

        const isAzure = azurePlayerIds.has(p.id);
        const isWinner = (isAzure && winner === 'azure') || (!isAzure && winner === 'crimson');

        const newStats = { ...p.stats };
        newStats.matchesPlayed += 1;

        if (isWinner) {
           newStats.wins += 1;
           newStats.currentStreak += 1;
           if (newStats.currentStreak > newStats.maxStreak) {
             newStats.maxStreak = newStats.currentStreak;
           }
        } else {
           // Reset streak on loss
           newStats.currentStreak = 0;
        }

        return { ...p, stats: newStats, isLastMatchMvp };
      }));
    }

    // 3. Clear match and Room ID (Reset ID)
    setCurrentMatch(null);
    setRoomId(''); 
  };

  const handleAbortMatch = () => setCurrentMatch(null);

  const quickFill = () => {
     const shuffledHeroes = [...HOK_HEROES].sort(() => 0.5 - Math.random());
     const heroesToAdd = shuffledHeroes.slice(0, 15);
     const newPlayers: Player[] = heroesToAdd.map(hero => ({
        id: crypto.randomUUID(),
        name: hero.name,
        isAllRoles: false,
        roles: hero.roles,
        isActive: true,
        isLastMatchMvp: false,
        stats: { matchesPlayed: 0, wins: 0, currentStreak: 0, maxStreak: 0 }
     }));
     // Add some flexible minions/players if needed to ensure we have enough
     for(let i=0; i<5; i++) {
        newPlayers.push({
           id: crypto.randomUUID(),
           name: `Flex Player ${i+1}`,
           isAllRoles: true,
           roles: [],
           isActive: true,
           isLastMatchMvp: false,
           stats: { matchesPlayed: 0, wins: 0, currentStreak: 0, maxStreak: 0 }
        });
     }

     setPlayers(prev => {
        const existingNames = new Set(prev.map(p => p.name));
        const filteredNew = newPlayers.filter(p => !existingNames.has(p.name));
        return [...prev, ...filteredNew].slice(0, 30);
     });

     // Random Room ID
     if(!roomId) setRoomId(Math.floor(1000 + Math.random() * 9000).toString());
  };

  // --- SAVE / LOAD FUNCTIONALITY ---

  const handleExportRoster = () => {
    if (players.length === 0) return;
    const dataStr = "data:text/json;charset=utf-8," + encodeURIComponent(JSON.stringify(players, null, 2));
    const downloadAnchorNode = document.createElement('a');
    downloadAnchorNode.setAttribute("href", dataStr);
    downloadAnchorNode.setAttribute("download", "hok-squad-roster.json");
    document.body.appendChild(downloadAnchorNode);
    downloadAnchorNode.click();
    downloadAnchorNode.remove();
  };

  const handleExportHistory = () => {
    if (matchHistory.length === 0) return;
    const dataStr = "data:text/json;charset=utf-8," + encodeURIComponent(JSON.stringify(matchHistory, null, 2));
    const downloadAnchorNode = document.createElement('a');
    downloadAnchorNode.setAttribute("href", dataStr);
    downloadAnchorNode.setAttribute("download", "hok-match-history.json");
    document.body.appendChild(downloadAnchorNode);
    downloadAnchorNode.click();
    downloadAnchorNode.remove();
  };

  const handleRosterImportClick = () => {
    rosterFileInputRef.current?.click();
  };

  const handleHistoryImportClick = () => {
    historyFileInputRef.current?.click();
  };

  const handleRosterFileChange = (event: React.ChangeEvent<HTMLInputElement>) => {
    const fileObj = event.target.files && event.target.files[0];
    if (!fileObj) return;

    const reader = new FileReader();
    reader.onload = (e) => {
      try {
        const json = e.target?.result;
        if (typeof json === 'string') {
          const parsedData = JSON.parse(json);
          // Basic validation
          if (Array.isArray(parsedData) && parsedData.length > 0 && parsedData[0].name) {
             const importedPlayers: Player[] = parsedData.map((p: any) => ({
               ...p,
               id: crypto.randomUUID(),
               // Ensure properties exist for backward compatibility with old JSONs
               isActive: typeof p.isActive === 'boolean' ? p.isActive : true,
               isLastMatchMvp: typeof p.isLastMatchMvp === 'boolean' ? p.isLastMatchMvp : false,
               stats: p.stats || { matchesPlayed: 0, wins: 0, currentStreak: 0, maxStreak: 0 }
             }));
             setPlayers(importedPlayers);
             setErrorMsg(null);
          } else {
             setErrorMsg("Invalid Roster JSON file format.");
          }
        }
      } catch (err) {
        setErrorMsg("Failed to parse Roster JSON file.");
      }
    };
    reader.readAsText(fileObj);
    event.target.value = '';
  };

  const handleHistoryFileChange = (event: React.ChangeEvent<HTMLInputElement>) => {
    const fileObj = event.target.files && event.target.files[0];
    if (!fileObj) return;

    const reader = new FileReader();
    reader.onload = (e) => {
      try {
        const json = e.target?.result;
        if (typeof json === 'string') {
          const parsedData = JSON.parse(json);
          // Basic validation for match history
          if (Array.isArray(parsedData) && (parsedData.length === 0 || parsedData[0].roomId)) {
             setMatchHistory(parsedData);
             setErrorMsg(null);
          } else {
             setErrorMsg("Invalid History JSON file format.");
          }
        }
      } catch (err) {
        setErrorMsg("Failed to parse History JSON file.");
      }
    };
    reader.readAsText(fileObj);
    event.target.value = '';
  };

  const handleRoomIdChange = (e: React.ChangeEvent<HTMLInputElement>) => {
    const val = e.target.value;
    if (val.length <= 4) {
      setRoomId(val);
    }
  };

  return (
    <div className="min-h-screen text-slate-200 font-inter overflow-x-hidden relative">
      <BackgroundParticles />

      {/* New Background Image (HoK Global Launch) */}
      <div className="fixed inset-0 bg-black -z-10">
         <img 
           src="https://www.levelinfinite.com/wp-content/uploads/2024/03/honor-of-kings-global-launch-pc.jpg" 
           alt="Honor of Kings Background" 
           className="absolute inset-0 w-full h-full object-cover opacity-50"
         />
         <div className="absolute inset-0 bg-gradient-to-b from-[#05090f]/90 via-[#05090f]/60 to-[#05090f] mix-blend-multiply"></div>
         <div className="absolute inset-0 bg-gradient-to-t from-[#05090f] via-transparent to-[#05090f]/80"></div>
      </div>

      {/* Hidden File Inputs */}
      <input 
        type="file" 
        ref={rosterFileInputRef}
        onChange={handleRosterFileChange}
        accept=".json"
        className="hidden"
      />
      <input 
        type="file" 
        ref={historyFileInputRef}
        onChange={handleHistoryFileChange}
        accept=".json"
        className="hidden"
      />

      {/* Edit Modal */}
      {editingPlayer && (
        <EditPlayerModal 
          player={editingPlayer}
          isOpen={isEditModalOpen}
          onClose={() => setIsEditModalOpen(false)}
          onSave={handleUpdatePlayer}
        />
      )}

      {/* Cinematic Header */}
      <header className="relative z-20 h-20 flex items-center justify-center border-b border-[#dcb06b]/20 bg-[#05090f]/60 backdrop-blur-md">
        <div className="absolute inset-0 bg-gradient-to-r from-transparent via-[#dcb06b]/5 to-transparent"></div>
        <div className="flex items-center gap-3 animate-float">
           <div className="w-8 h-8 border-2 border-[#dcb06b] rotate-45 flex items-center justify-center bg-[#0a1a2f]">
              <div className="w-4 h-4 bg-[#dcb06b]"></div>
           </div>
           <h1 className="text-2xl font-cinzel font-black tracking-[0.2em] text-white">
             <span className="hok-gold-text">HONOR</span> OF <span className="hok-gold-text">KINGS</span>
             <span className="block text-[8px] text-[#8a9db8] tracking-[0.5em] font-orbitron mt-0.5">OPEN MABAR CUSTOM FUN MATCH</span>
           </h1>
        </div>
      </header>

      <main className="relative z-10 pt-8 px-4 pb-20">
        {currentMatch ? (
          <MatchDisplay 
            match={currentMatch} 
            activePlayers={activePlayers} 
            onReset={handleAbortMatch}
            onCompleteMatch={handleMatchFinish}
            onReroll={handleRerollSlot}
          />
        ) : (
          <div className="max-w-7xl mx-auto">

            <div className="grid grid-cols-1 lg:grid-cols-12 gap-8 relative transition-all duration-500">

              {/* Left Panel: Controls (Collapsible) */}
              <div className={`
                 lg:col-span-4 space-y-6 transition-all duration-500 ease-in-out
                 ${isSidebarOpen ? 'opacity-100 translate-x-0' : 'hidden opacity-0 -translate-x-full lg:col-span-0'}
              `}>

                 {/* Room ID & Coach Mode Toggle */}
                 <div className="bg-[#0a1a2f]/80 p-1 clip-corner-sm border border-[#1e3a5f] shadow-[0_0_25px_rgba(220,176,107,0.15)] relative group space-y-2">
                    <div className="absolute -inset-1 bg-gradient-to-r from-transparent via-[#dcb06b]/30 to-transparent blur opacity-0 group-hover:opacity-100 transition-opacity duration-700"></div>

                    <div className="bg-[#05090f] p-4 flex items-center gap-4 clip-corner-sm relative z-10">
                       <label className="text-xs uppercase text-[#dcb06b] font-bold font-orbitron whitespace-nowrap tracking-widest">Room ID</label>
                       <div className="h-8 w-[1px] bg-[#1e3a5f]"></div>
                       <input 
                          type="text" 
                          value={roomId}
                          onChange={handleRoomIdChange}
                          maxLength={4}
                          placeholder="0000"
                          className="bg-transparent text-lg font-orbitron text-white w-full focus:outline-none tracking-widest placeholder-[#1e3a5f]"
                       />
                    </div>
                 </div>

                 <div className="flex items-center justify-between bg-[#0a1a2f]/60 p-4 border border-[#1e3a5f] clip-corner-sm">
                     <span className="text-[#dcb06b] font-cinzel font-bold text-sm tracking-widest flex items-center gap-2">
                        <svg xmlns="http://www.w3.org/2000/svg" className="h-4 w-4" fill="none" viewBox="0 0 24 24" stroke="currentColor">
                           <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M19 11H5m14 0a2 2 0 012 2v6a2 2 0 01-2 2H5a2 2 0 01-2-2v-6a2 2 0 012-2m14 0V9a2 2 0 00-2-2M5 11V9a2 2 0 012-2m0 0V5a2 2 0 012-2h6a2 2 0 012 2v2M7 7h10" />
                        </svg>
                        COACH MODE
                     </span>
                     <label className="relative inline-flex items-center cursor-pointer">
                        <input type="checkbox" className="sr-only peer" checked={isCoachMode} onChange={(e) => setIsCoachMode(e.target.checked)} />
                        <div className="w-11 h-6 bg-[#1e3a5f] peer-focus:outline-none rounded-full peer peer-checked:after:translate-x-full peer-checked:after:border-white after:content-[''] after:absolute after:top-[2px] after:left-[2px] after:bg-white after:border-gray-300 after:border after:rounded-full after:h-5 after:w-5 after:transition-all peer-checked:bg-[#dcb06b]"></div>
                     </label>
                 </div>

                 <PlayerForm onAddPlayer={addPlayer} isCoachMode={isCoachMode} />

                 {/* Status Panel */}
                 <div className="relative p-6 clip-corner-md bg-gradient-to-b from-[#1a2c42] to-[#05090f] border border-[#dcb06b]/20 group hover:border-[#dcb06b]/50 transition-colors duration-500">
                    <div className="absolute top-0 left-0 w-full h-1 bg-gradient-to-r from-transparent via-[#dcb06b] to-transparent opacity-50"></div>

                    <div className="flex justify-between items-end mb-6">
                       <div>
                          <div className="text-[#8a9db8] text-[10px] uppercase tracking-widest font-bold mb-1">Active Players</div>
                          <div className="text-5xl font-orbitron font-bold text-white relative">
                             {activePlayers.length}
                             <span className="text-lg text-[#4a5f78] absolute top-0 -right-12">/ {isCoachMode ? 12 : 10}</span>
                          </div>
                       </div>
                       <div className="text-right">
                          <button onClick={quickFill} className="text-[10px] text-[#dcb06b] border border-[#dcb06b] px-3 py-1 hover:bg-[#dcb06b] hover:text-black transition-colors uppercase tracking-wider">
                             Quick Fill
                          </button>
                       </div>
                    </div>

                    {errorMsg && (
                      <div className="mb-4 p-3 border-l-2 border-red-500 bg-red-900/20 text-red-200 text-xs">
                        {errorMsg}
                      </div>
                    )}

                    <Button 
                      onClick={handleGenerate} 
                      className="w-full text-lg shadow-[0_0_20px_rgba(220,176,107,0.3)]"
                      disabled={activePlayers.length < (isCoachMode ? 12 : 10)}
                    >
                       START MATCHMAKING
                    </Button>
                 </div>
              </div>

              {/* Right Panel: Player Grid & History */}
              <div className={`transition-all duration-500 ${isSidebarOpen ? 'lg:col-span-8' : 'lg:col-span-12'}`}>
                 <div className="flex flex-wrap items-center justify-between mb-6 gap-4">

                    {/* Header with Expand Button */}
                    <div className="flex items-center gap-4">
                        <button 
                           onClick={() => setIsSidebarOpen(!isSidebarOpen)} 
                           className="p-2 border border-[#1e3a5f] hover:border-[#dcb06b] text-[#dcb06b] clip-corner-sm transition-all bg-[#0a1a2f]/50"
                           title={isSidebarOpen ? "Maximize List" : "Show Controls"}
                        >
                           {isSidebarOpen ? (
                              <svg xmlns="http://www.w3.org/2000/svg" className="h-5 w-5" fill="none" viewBox="0 0 24 24" stroke="currentColor">
                                <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M4 8V4m0 0h4M4 4l5 5m11-1V4m0 0h-4m4 0l-5 5M4 16v4m0 0h4m-4 0l5-5m11 5l-5-5m5 5v-4m0 4h-4" />
                              </svg>
                           ) : (
                              <svg xmlns="http://www.w3.org/2000/svg" className="h-5 w-5" fill="none" viewBox="0 0 24 24" stroke="currentColor">
                                 <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M4 6h16M4 12h16M4 18h16" />
                              </svg>
                           )}
                        </button>

                        <h2 className="text-2xl font-cinzel font-black tracking-[0.2em] uppercase drop-shadow-sm text-[#dcb06b] flex items-center gap-3">
                           <span className="w-2 h-2 bg-[#dcb06b] rotate-45"></span>
                           SQUAD ROSTER
                        </h2>
                    </div>

                    <div className="flex items-center gap-2">
                       {/* Import/Export Controls */}
                       <button 
                         onClick={handleRosterImportClick}
                         className="flex items-center gap-2 px-3 py-1 text-[10px] uppercase font-bold tracking-wider text-[#4a5f78] border border-[#1e3a5f] hover:border-[#dcb06b] hover:text-[#dcb06b] transition-all clip-corner-sm"
                         title="Load Roster JSON"
                       >
                          <svg xmlns="http://www.w3.org/2000/svg" className="h-4 w-4" fill="none" viewBox="0 0 24 24" stroke="currentColor">
                            <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M4 16v1a3 3 0 003 3h10a3 3 0 003-3v-1m-4-8l-4-4m0 0L8 8m4-4v12" />
                          </svg>
                          Load
                       </button>

                       <button 
                         onClick={handleExportRoster}
                         disabled={players.length === 0}
                         className="flex items-center gap-2 px-3 py-1 text-[10px] uppercase font-bold tracking-wider text-[#4a5f78] border border-[#1e3a5f] hover:border-[#dcb06b] hover:text-[#dcb06b] transition-all clip-corner-sm disabled:opacity-30 disabled:cursor-not-allowed"
                         title="Save Roster JSON"
                       >
                          <svg xmlns="http://www.w3.org/2000/svg" className="h-4 w-4" fill="none" viewBox="0 0 24 24" stroke="currentColor">
                            <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M4 16v1a3 3 0 003 3h10a3 3 0 003-3v-1m-4-4l-4 4m0 0l-4-4m4 4V4" />
                          </svg>
                          Save
                       </button>

                       <div className="h-4 w-[1px] bg-[#1e3a5f] mx-2"></div>

                       <button onClick={() => setPlayers([])} className="text-xs text-[#4a5f78] hover:text-red-400 uppercase tracking-widest transition-colors">
                          Clear All
                       </button>
                    </div>
                 </div>

                 <div className="perspective-container tech-border p-6 bg-[#0a1a2f]/40 min-h-[400px] mb-8">
                    <PlayerList 
                      players={players} 
                      onRemove={removePlayer} 
                      onToggleActive={togglePlayerActive}
                      onEdit={handleEditPlayer}
                      isSidebarOpen={isSidebarOpen}
                    />
                 </div>

                 {/* MATCH HISTORY SECTION */}
                 <div className="mt-12">
                     <div className="flex items-center justify-between mb-6">
                        <h2 className="text-2xl font-cinzel font-black tracking-[0.2em] uppercase drop-shadow-sm text-[#dcb06b] flex items-center gap-3">
                           <span className="w-2 h-2 bg-[#dcb06b] rotate-45"></span>
                           BATTLE HISTORY
                        </h2>

                        <div className="flex items-center gap-2">
                           <button 
                             onClick={handleHistoryImportClick}
                             className="flex items-center gap-2 px-3 py-1 text-[10px] uppercase font-bold tracking-wider text-[#4a5f78] border border-[#1e3a5f] hover:border-[#dcb06b] hover:text-[#dcb06b] transition-all clip-corner-sm"
                           >
                              <svg xmlns="http://www.w3.org/2000/svg" className="h-4 w-4" fill="none" viewBox="0 0 24 24" stroke="currentColor">
                                <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M4 16v1a3 3 0 003 3h10a3 3 0 003-3v-1m-4-8l-4-4m0 0L8 8m4-4v12" />
                              </svg>
                              Import
                           </button>

                           <button 
                              onClick={handleExportHistory}
                              disabled={matchHistory.length === 0}
                              className="flex items-center gap-2 px-3 py-1 text-[10px] uppercase font-bold tracking-wider text-[#4a5f78] border border-[#1e3a5f] hover:border-[#dcb06b] hover:text-[#dcb06b] transition-all clip-corner-sm disabled:opacity-30 disabled:cursor-not-allowed"
                           >
                              <svg xmlns="http://www.w3.org/2000/svg" className="h-4 w-4" fill="none" viewBox="0 0 24 24" stroke="currentColor">
                                 <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M12 10v6m0 0l-3-3m3 3l3-3m2 8H7a2 2 0 01-2-2V5a2 2 0 012-2h5.586a1 1 0 01.707.293l5.414 5.414a1 1 0 01.293.707V19a2 2 0 01-2 2z" />
                              </svg>
                              Export
                           </button>
                        </div>
                     </div>

                     <div className="tech-border p-6 bg-[#0a1a2f]/40">
                        <HistoryList history={matchHistory} onClear={() => setMatchHistory([])} />
                     </div>
                 </div>
              </div>

            </div>
          </div>
        )}
      </main>
    </div>
  );
}

import React, { useState, useEffect } from 'react';
import { Player, Role } from '../types';
import { RoleIcons, ROLES_ORDER } from '../constants';

interface PlayerListProps {
  players: Player[];
  onRemove: (id: string) => void;
  onToggleActive: (id: string) => void;
  onEdit: (player: Player) => void;
  isSidebarOpen?: boolean;
}

type FilterType = 'ALL' | 'ACTIVE' | 'BENCH' | Role;

export const PlayerList: React.FC<PlayerListProps> = ({ players, onRemove, onToggleActive, onEdit, isSidebarOpen = true }) => {
  const [filter, setFilter] = useState<FilterType>('ALL');
  const [searchQuery, setSearchQuery] = useState('');
  const [menuOpenId, setMenuOpenId] = useState<string | null>(null);

  // Close menu when clicking outside
  useEffect(() => {
    const handleClickOutside = () => setMenuOpenId(null);
    if (menuOpenId) {
      document.addEventListener('click', handleClickOutside);
    }
    return () => {
      document.removeEventListener('click', handleClickOutside);
    };
  }, [menuOpenId]);

  const toggleMenu = (e: React.MouseEvent, id: string) => {
    e.stopPropagation();
    setMenuOpenId(prev => prev === id ? null : id);
  };

  // Filter Logic
  const filteredPlayers = players.filter(p => {
    // 1. Filter by Category
    let matchesCategory = true;
    if (filter === 'ACTIVE') matchesCategory = p.isActive;
    else if (filter === 'BENCH') matchesCategory = !p.isActive;
    else if (Object.values(Role).includes(filter as Role)) {
       matchesCategory = p.roles.includes(filter as Role);
    }

    // 2. Filter by Search (Name Include)
    const matchesSearch = p.name.toLowerCase().includes(searchQuery.toLowerCase());

    return matchesCategory && matchesSearch;
  });

  const filters: { label: string; value: FilterType; icon?: React.ReactNode }[] = [
    { label: 'All', value: 'ALL' },
    { label: 'Playing', value: 'ACTIVE' },
    { label: 'Benched', value: 'BENCH' },
    ...ROLES_ORDER.map(r => ({ label: r.split(' ')[0], value: r })),
    { label: 'Coach', value: Role.COACH }
  ];

  // --- HELPER: Role Color Logic ---
  const getRoleStyle = (player: Player, isActive: boolean) => {
      if (!isActive) return { text: 'text-[#4a5f78]', border: 'border-[#1e3a5f]', bg: 'bg-[#05090f]' };

      if (player.isAllRoles) {
          return { text: 'text-purple-400', border: 'border-purple-500/50', bg: 'bg-[#05090f]', glow: 'shadow-purple-500/20' };
      }

      // Priority Order for coloring if multiple roles: Coach > Clash > Jungle > Mid > Farm > Roam
      // Using user requested colors:
      // Clash: Orange
      // Jungle: Green (Emerald/Green)
      // Mid: Blue
      // Farm: Gold
      // Roam: Cyan/Teal

      const roles = player.roles;

      if (roles.includes(Role.COACH)) {
          return { text: 'text-white', border: 'border-white', bg: 'bg-black', glow: 'shadow-white/30' };
      }
      if (roles.includes(Role.CLASH)) {
          return { text: 'text-orange-400', border: 'border-orange-500/60', bg: 'bg-[#05090f]', glow: 'shadow-orange-500/20' };
      }
      if (roles.includes(Role.JUNGLE)) {
          return { text: 'text-emerald-400', border: 'border-emerald-500/60', bg: 'bg-[#05090f]', glow: 'shadow-emerald-500/20' };
      }
      if (roles.includes(Role.MID)) {
          return { text: 'text-blue-400', border: 'border-blue-500/60', bg: 'bg-[#05090f]', glow: 'shadow-blue-500/20' };
      }
      if (roles.includes(Role.FARM)) {
          return { text: 'text-yellow-400', border: 'border-yellow-500/60', bg: 'bg-[#05090f]', glow: 'shadow-yellow-500/20' };
      }
      if (roles.includes(Role.ROAM)) {
          return { text: 'text-cyan-400', border: 'border-cyan-500/60', bg: 'bg-[#05090f]', glow: 'shadow-cyan-500/20' };
      }

      // Default fallback
      return { text: 'text-[#f0f4f8]', border: 'border-[#dcb06b]/50', bg: 'bg-[#05090f]', glow: 'shadow-[#dcb06b]/20' };
  };


  if (players.length === 0) {
    return (
      <div className="h-full min-h-[300px] flex flex-col items-center justify-center border border-dashed border-[#1e3a5f] rounded-lg bg-[#0a1a2f]/30 p-8">
        <div className="w-20 h-20 rounded-full bg-[#1e3a5f]/50 flex items-center justify-center mb-4 border border-[#dcb06b]/20">
           <svg xmlns="http://www.w3.org/2000/svg" className="h-8 w-8 text-[#dcb06b]/50" fill="none" viewBox="0 0 24 24" stroke="currentColor"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M12 4.354a4 4 0 110 5.292M15 21H3v-1a6 6 0 0112 0v1zm0 0h6v-1a6 6 0 00-9-5.197M13 7a4 4 0 11-8 0 4 4 0 018 0z" /></svg>
        </div>
        <p className="text-[#8a9db8] font-cinzel tracking-widest text-sm">Waiting for Challengers</p>
      </div>
    );
  }

  // Responsive Grid Logic: More columns when sidebar is closed (screen expanded)
  const gridClasses = isSidebarOpen
      ? "grid-cols-1 md:grid-cols-2 lg:grid-cols-3 xl:grid-cols-4" // Sidebar Open (Less space)
      : "grid-cols-1 md:grid-cols-3 lg:grid-cols-4 xl:grid-cols-5 2xl:grid-cols-6"; // Sidebar Closed (More space)

  return (
    <div>
      {/* FILTER & SEARCH BAR */}
      <div className="mb-6 flex flex-col md:flex-row gap-4 items-start md:items-center justify-between">
         {/* Role Filters */}
         <div className="overflow-x-auto pb-2 scrollbar-hide w-full md:w-auto">
            <div className="flex gap-2 min-w-max">
                {filters.map(f => (
                  <button
                    key={f.value}
                    onClick={() => setFilter(f.value)}
                    className={`
                      px-3 py-1.5 text-[10px] uppercase font-bold tracking-wider clip-corner-sm border transition-all
                      ${filter === f.value 
                          ? 'bg-[#dcb06b] text-[#05090f] border-[#dcb06b]' 
                          : 'bg-[#0a1a2f] text-[#8a9db8] border-[#1e3a5f] hover:border-[#dcb06b]/50 hover:text-white'}
                    `}
                  >
                    {f.label}
                  </button>
                ))}
            </div>
         </div>

         {/* Search Box */}
         <div className="relative w-full md:w-64">
             <input 
               type="text" 
               placeholder="Find Player..." 
               value={searchQuery}
               onChange={(e) => setSearchQuery(e.target.value)}
               className="w-full bg-[#05090f] border border-[#1e3a5f] px-3 py-1.5 pl-8 text-xs text-[#f0f4f8] focus:outline-none focus:border-[#dcb06b] clip-corner-sm font-orbitron placeholder-[#4a5f78]"
             />
             <svg xmlns="http://www.w3.org/2000/svg" className="h-4 w-4 absolute left-2 top-1.5 text-[#4a5f78]" fill="none" viewBox="0 0 24 24" stroke="currentColor">
               <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M21 21l-6-6m2-5a7 7 0 11-14 0 7 7 0 0114 0z" />
             </svg>
         </div>
      </div>

      {/* PLAYER GRID: Dynamic Resizing */}
      <div className={`grid gap-3 transition-all duration-500 ${gridClasses}`}>
        {filteredPlayers.map(player => {
          const isActive = player.isActive;
          const stats = player.stats || { matchesPlayed: 0, wins: 0, currentStreak: 0, maxStreak: 0 };
          const winRate = stats.matchesPlayed > 0 
            ? Math.round((stats.wins / stats.matchesPlayed) * 100) 
            : 0;

          const streak = stats.currentStreak;
          const isHot = streak >= 3;
          const isGodlike = streak >= 6;
          const isMvp = player.isLastMatchMvp;
          const isCoach = player.roles.includes(Role.COACH);

          const style = getRoleStyle(player, isActive);

          // Container Glow Animation Logic
          let containerGlow = "";
          let borderOverlay = null;

          if (isMvp) {
              containerGlow = "drop-shadow-[0_0_15px_rgba(251,191,36,0.5)]";
              borderOverlay = (
                <div className="absolute -inset-[2px] clip-corner-sm overflow-hidden z-0 pointer-events-none">
                    <div className="absolute inset-0 bg-yellow-500/10 animate-pulse"></div>
                    <div className="absolute top-0 left-0 w-full h-[1px] bg-yellow-500/50 animate-[shimmer_2s_infinite]"></div>
                </div>
              );
          } else if (isActive) {
            // "Breathing" Glow effect
            containerGlow = `${style.glow} drop-shadow-[0_0_5px_currentColor]`; 
            if (isCoach) {
               // Special Coach Animation
               borderOverlay = (
                  <div className="absolute -inset-[2px] clip-corner-sm overflow-hidden z-0 pointer-events-none">
                     <div className="absolute inset-0 bg-white/5 animate-pulse"></div>
                  </div>
               );
            } else if (isHot || isGodlike) {
               borderOverlay = (
                 <div className="absolute -inset-[2px] clip-corner-sm overflow-hidden z-0 pointer-events-none">
                     <div className={`absolute inset-0 ${isGodlike ? 'bg-red-500/10' : 'bg-cyan-400/10'} animate-pulse`}></div>
                 </div>
               );
            }
          }

          let borderClass = 'border border-[#1e3a5f]';
          if (isActive) {
             if (isMvp) borderClass = 'border-2 border-yellow-400';
             else borderClass = `border ${style.border}`;
          }

          return (
            <div key={player.id} className={`relative group ${containerGlow} tilt-card h-full transition-all duration-300`}>

              {borderOverlay}

              <div 
                className={`
                  relative z-10 p-2 clip-corner-sm h-full flex flex-col gap-1
                  ${style.bg} ${borderClass}
                  ${!isActive ? 'opacity-60 grayscale hover:opacity-100' : 'hover:brightness-110'}
                  transition-all
                `}
              >

                {/* ROW 1: Name, Roles, Menu - TIGHT */}
                <div className="flex justify-between items-start gap-2">

                   <div className="flex-1 min-w-0">

                      {/* Name */}
                      <div className="flex items-center gap-2 mb-1">
                          <div 
                              className={`text-lg font-bold font-orbitron tracking-wide leading-none truncate ${isMvp ? 'text-yellow-400' : style.text}`}
                              title={player.name}
                          >
                              {player.name}
                          </div>

                          {/* Mini Badges Inline */}
                          {isMvp && <div className="text-[8px] font-black bg-yellow-500 text-black px-1 rounded-sm shadow-[0_0_5px_yellow]">MVP</div>}
                          {isCoach && <div className="text-[8px] font-black bg-white text-black px-1 rounded-sm shadow-[0_0_5px_white]">COACH</div>}
                          {!isMvp && isHot && isActive && !isCoach && (
                            <span className="text-[8px] animate-pulse">🔥</span>
                          )}
                      </div>

                      {/* Roles */}
                      <div className="flex flex-wrap gap-1">
                          {player.isAllRoles ? (
                            <div className={`px-1.5 py-0.5 border clip-corner-sm bg-purple-900/20 text-purple-400 border-purple-500/30`}>
                              <span className="text-[8px] font-bold uppercase whitespace-nowrap">All Roles</span>
                            </div>
                          ) : (
                            player.roles.map(role => (
                                <div key={role} className={`px-1.5 py-0.5 clip-corner-sm ${isActive ? 'bg-white/5' : 'bg-[#0f223d]/50'} ${style.text}`}>
                                    <span className="text-[7px] uppercase font-bold leading-none whitespace-nowrap opacity-90">
                                        {role === Role.COACH ? 'COACH' : role.split(' ')[0]}
                                    </span>
                                </div>
                            ))
                          )}
                      </div>
                   </div>

                   {/* Menu Button */}
                   <div className="relative shrink-0">
                      <button 
                         onClick={(e) => toggleMenu(e, player.id)}
                         className={`p-1 ${isActive ? style.text : 'text-[#4a5f78]'} hover:brightness-150 transition-colors`}
                      >
                         <svg xmlns="http://www.w3.org/2000/svg" className="h-4 w-4" fill="none" viewBox="0 0 24 24" stroke="currentColor">
                           <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M12 5v.01M12 12v.01M12 19v.01M12 6a1 1 0 110-2 1 1 0 010 2zm0 7a1 1 0 110-2 1 1 0 010 2zm0 7a1 1 0 110-2 1 1 0 010 2z" />
                         </svg>
                      </button>

                      {menuOpenId === player.id && (
                         <div className="absolute right-0 top-6 w-32 bg-[#05090f] border border-[#dcb06b] z-50 shadow-lg clip-corner-sm flex flex-col animate-slide-in">
                            <button 
                              onClick={(e) => { e.stopPropagation(); onToggleActive(player.id); setMenuOpenId(null); }}
                              className="px-3 py-2 text-left text-[10px] uppercase font-bold text-[#f0f4f8] hover:bg-[#dcb06b] hover:text-[#05090f] transition-colors"
                            >
                               {isActive ? 'Bench Player' : 'Activate'}
                            </button>
                            <button 
                              onClick={(e) => { e.stopPropagation(); onEdit(player); setMenuOpenId(null); }}
                              className="px-3 py-2 text-left text-[10px] uppercase font-bold text-[#f0f4f8] hover:bg-[#dcb06b] hover:text-[#05090f] transition-colors"
                            >
                               Edit Details
                            </button>
                            <div className="h-[1px] bg-[#1e3a5f] w-full"></div>
                            <button 
                              onClick={(e) => { e.stopPropagation(); onRemove(player.id); setMenuOpenId(null); }}
                              className="px-3 py-2 text-left text-[10px] uppercase font-bold text-red-500 hover:bg-red-500 hover:text-white transition-colors"
                            >
                               Remove
                            </button>
                         </div>
                      )}
                   </div>
                </div>

                {/* ROW 2: Stats - TIGHT under name */}
                {stats.matchesPlayed > 0 && (
                  <div className={`flex items-center gap-3 text-[9px] font-mono mt-1 ${isActive ? 'text-gray-400' : 'text-[#4a5f78]/50'}`}>
                      <div>
                        Match: <span className="text-[#f0f4f8]">{stats.matchesPlayed}</span>
                      </div>
                      <div>
                        WR: <span className={`${winRate >= 60 ? 'text-[#dcb06b]' : winRate >= 50 ? 'text-[#f0f4f8]' : 'text-red-400'}`}>{winRate}%</span>
                      </div>
                  </div>
                )}

                {/* Benched Overlay */}
                {!isActive && (
                  <div className="absolute inset-0 flex items-center justify-center pointer-events-none z-10">
                    <span className="text-[#0a1a2f] font-black text-xl -rotate-12 opacity-40 uppercase tracking-widest select-none bg-[#dcb06b] px-1 mix-blend-screen">Benched</span>
                  </div>
                )}
              </div>
            </div>
          );
        })}
      </div>
    </div>
  );
};

import React, { useState, useEffect } from 'react';
import { Player, Role } from '../types';
import { ROLES_ORDER } from '../constants';

interface PlayerListProps {
  players: Player[];
  onRemove: (id: string) => void;
  onToggleActive: (id: string) => void;
  onEdit: (player: Player) => void;
  isSidebarOpen?: boolean;
}

type FilterType = 'ALL' | 'ACTIVE' | 'BENCH' | Role;

export const PlayerList: React.FC<PlayerListProps> = ({ players, onRemove, onToggleActive, onEdit, isSidebarOpen = true }) => {
  const [filter, setFilter] = useState<FilterType>('ALL');
  const [searchQuery, setSearchQuery] = useState('');
  const [menuOpenId, setMenuOpenId] = useState<string | null>(null);

  // Close menu when clicking outside
  useEffect(() => {
    const handleClickOutside = () => setMenuOpenId(null);
    if (menuOpenId) {
      document.addEventListener('click', handleClickOutside);
    }
    return () => {
      document.removeEventListener('click', handleClickOutside);
    };
  }, [menuOpenId]);

  const toggleMenu = (e: React.MouseEvent, id: string) => {
    e.stopPropagation();
    setMenuOpenId(prev => prev === id ? null : id);
  };

  // Filter Logic
  const filteredPlayers = players.filter(p => {
    let matchesCategory = true;
    if (filter === 'ACTIVE') matchesCategory = p.isActive;
    else if (filter === 'BENCH') matchesCategory = !p.isActive;
    else if (Object.values(Role).includes(filter as Role)) {
       matchesCategory = p.roles.includes(filter as Role);
    }
    const matchesSearch = p.name.toLowerCase().includes(searchQuery.toLowerCase());
    return matchesCategory && matchesSearch;
  });

  const filters: { label: string; value: FilterType; icon?: React.ReactNode }[] = [
    { label: 'All', value: 'ALL' },
    { label: 'Playing', value: 'ACTIVE' },
    { label: 'Benched', value: 'BENCH' },
    ...ROLES_ORDER.map(r => ({ label: r.split(' ')[0], value: r })),
    { label: 'Coach', value: Role.COACH }
  ];

  // --- HELPER: Role Badge Color Logic (Strictly for the Role Label) ---
  const getRoleBadgeStyle = (role: Role) => {
      switch (role) {
          case Role.COACH: return 'text-white border-white bg-white/10';
          case Role.CLASH: return 'text-orange-400 border-orange-500/50 bg-orange-900/20'; // Clash: Orange
          case Role.JUNGLE: return 'text-emerald-400 border-emerald-500/50 bg-emerald-900/20'; // Jungle: Green/Emerald
          case Role.MID: return 'text-blue-400 border-blue-500/50 bg-blue-900/20'; // Mid: Blue
          case Role.FARM: return 'text-yellow-400 border-yellow-500/50 bg-yellow-900/20'; // Farm: Gold
          case Role.ROAM: return 'text-cyan-400 border-cyan-500/50 bg-cyan-900/20'; // Roam: Cyan
          default: return 'text-gray-400 border-gray-600 bg-gray-800/30';
      }
  };

  if (players.length === 0) {
    return (
      <div className="h-full min-h-[300px] flex flex-col items-center justify-center border border-dashed border-[#1e3a5f] rounded-lg bg-[#0a1a2f]/30 p-8">
        <div className="w-20 h-20 rounded-full bg-[#1e3a5f]/50 flex items-center justify-center mb-4 border border-[#dcb06b]/20">
           <svg xmlns="http://www.w3.org/2000/svg" className="h-8 w-8 text-[#dcb06b]/50" fill="none" viewBox="0 0 24 24" stroke="currentColor"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M12 4.354a4 4 0 110 5.292M15 21H3v-1a6 6 0 0112 0v1zm0 0h6v-1a6 6 0 00-9-5.197M13 7a4 4 0 11-8 0 4 4 0 018 0z" /></svg>
        </div>
        <p className="text-[#8a9db8] font-cinzel tracking-widest text-sm">Waiting for Challengers</p>
      </div>
    );
  }

  // Responsive Grid Logic
  const gridClasses = isSidebarOpen
      ? "grid-cols-1 md:grid-cols-2 lg:grid-cols-3 xl:grid-cols-4"
      : "grid-cols-1 md:grid-cols-3 lg:grid-cols-4 xl:grid-cols-5 2xl:grid-cols-6";

  return (
    <div>
      {/* FILTER & SEARCH BAR */}
      <div className="mb-6 flex flex-col md:flex-row gap-4 items-start md:items-center justify-between">
         <div className="overflow-x-auto pb-2 scrollbar-hide w-full md:w-auto">
            <div className="flex gap-2 min-w-max">
                {filters.map(f => (
                  <button
                    key={f.value}
                    onClick={() => setFilter(f.value)}
                    className={`
                      px-3 py-1.5 text-[10px] uppercase font-bold tracking-wider clip-corner-sm border transition-all
                      ${filter === f.value 
                          ? 'bg-[#dcb06b] text-[#05090f] border-[#dcb06b]' 
                          : 'bg-[#0a1a2f] text-[#8a9db8] border-[#1e3a5f] hover:border-[#dcb06b]/50 hover:text-white'}
                    `}
                  >
                    {f.label}
                  </button>
                ))}
            </div>
         </div>

         <div className="relative w-full md:w-64">
             <input 
               type="text" 
               placeholder="Find Player..." 
               value={searchQuery}
               onChange={(e) => setSearchQuery(e.target.value)}
               className="w-full bg-[#05090f] border border-[#1e3a5f] px-3 py-1.5 pl-8 text-xs text-[#f0f4f8] focus:outline-none focus:border-[#dcb06b] clip-corner-sm font-orbitron placeholder-[#4a5f78]"
             />
             <svg xmlns="http://www.w3.org/2000/svg" className="h-4 w-4 absolute left-2 top-1.5 text-[#4a5f78]" fill="none" viewBox="0 0 24 24" stroke="currentColor">
               <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M21 21l-6-6m2-5a7 7 0 11-14 0 7 7 0 0114 0z" />
             </svg>
         </div>
      </div>

      {/* PLAYER GRID */}
      <div className={`grid gap-3 transition-all duration-500 ${gridClasses}`}>
        {filteredPlayers.map(player => {
          const isActive = player.isActive;
          const stats = player.stats || { matchesPlayed: 0, wins: 0, currentStreak: 0, maxStreak: 0 };
          const winRate = stats.matchesPlayed > 0 
            ? Math.round((stats.wins / stats.matchesPlayed) * 100) 
            : 0;

          const streak = stats.currentStreak;
          const isHot = streak >= 3 && streak < 6;
          const isGodlike = streak >= 6;
          const isMvp = player.isLastMatchMvp;
          const isCoach = player.roles.includes(Role.COACH);

          // --- ANIMATED BORDER LOGIC ---
          let animationLayer = null;
          let glowClass = "";

          if (isActive) {
              if (isMvp) {
                  // MVP: Golden Rotating Glow
                  glowClass = "drop-shadow-[0_0_15px_rgba(251,191,36,0.6)]";
                  animationLayer = (
                      <div className="absolute inset-[-50%] bg-[conic-gradient(from_0deg,transparent_0deg,#fbbf24_90deg,transparent_180deg,#fbbf24_270deg,transparent_360deg)] animate-[spin_4s_linear_infinite] opacity-100"></div>
                  );
              } else if (isCoach) {
                  // Coach: White Rotating Glow
                  glowClass = "drop-shadow-[0_0_10px_rgba(255,255,255,0.5)]";
                  animationLayer = (
                      <div className="absolute inset-[-50%] bg-[conic-gradient(from_0deg,transparent_0deg,#ffffff_90deg,transparent_180deg,#ffffff_270deg,transparent_360deg)] animate-[spin_6s_linear_infinite] opacity-80"></div>
                  );
              } else if (isGodlike) {
                  // Godlike (6+): Red Lightning/Blood Rotating Glow (Fast)
                  glowClass = "drop-shadow-[0_0_20px_rgba(239,68,68,0.8)]";
                  animationLayer = (
                      <div className="absolute inset-[-50%] bg-[conic-gradient(from_0deg,transparent_0deg,#ef4444_60deg,#7f1d1d_120deg,transparent_180deg,#ef4444_240deg,transparent_360deg)] animate-[spin_2s_linear_infinite] opacity-100"></div>
                  );
              } else if (isHot) {
                  // Hot (3-5): Blue/Cyan Flame Rotating Glow
                  glowClass = "drop-shadow-[0_0_10px_rgba(6,182,212,0.6)]";
                  animationLayer = (
                      <div className="absolute inset-[-50%] bg-[conic-gradient(from_0deg,transparent_0deg,#06b6d4_90deg,transparent_180deg,#06b6d4_270deg,transparent_360deg)] animate-[spin_3s_linear_infinite] opacity-100"></div>
                  );
              }
          }

          // Background Logic for the Inner Card
          const cardBg = isActive && isCoach ? 'bg-[#000000]' : 'bg-[#05090f]';

          return (
            <div key={player.id} className={`relative group ${glowClass} tilt-card h-full transition-all duration-300`}>

              {/* This div handles the shape and the rotating border behind content */}
              <div className="absolute inset-0 clip-corner-sm overflow-hidden z-0">
                  {/* Default Border (Static) for everyone else */}
                  <div className="absolute inset-0 bg-[#1e3a5f]"></div>

                  {/* The Animated Layer (Overwrites default if active) */}
                  {animationLayer}
              </div>

              {/* Inner Content Card (Slightly smaller to reveal the animated border) */}
              <div 
                className={`
                  absolute inset-[1px] clip-corner-sm z-10 flex flex-col gap-1 p-2
                  ${cardBg}
                  ${!isActive ? 'opacity-50 grayscale hover:opacity-80 transition-opacity' : ''}
                `}
              >

                {/* ROW 1: Name, Roles, Menu - TIGHT */}
                <div className="flex justify-between items-start gap-2">

                   <div className="flex-1 min-w-0">

                      {/* Name - Standard Color unless MVP */}
                      <div className="flex items-center gap-2 mb-1">
                          <div 
                              className={`text-lg font-bold font-orbitron tracking-wide leading-none truncate ${isMvp ? 'text-yellow-400' : 'text-[#e2e8f0]'}`}
                              title={player.name}
                          >
                              {player.name}
                          </div>

                          {/* Mini Badges Inline */}
                          {isMvp && <div className="text-[8px] font-black bg-gradient-to-r from-yellow-400 to-yellow-600 text-black px-1.5 py-0.5 rounded-sm shadow-[0_0_10px_#fbbf24] animate-pulse">MVP</div>}
                          {isCoach && <div className="text-[8px] font-black bg-white text-black px-1.5 py-0.5 rounded-sm shadow-[0_0_10px_white]">COACH</div>}
                          {!isMvp && isGodlike && isActive && (
                             <span className="text-[8px] text-red-500 animate-pulse font-black">GODLIKE</span>
                          )}
                          {!isMvp && !isGodlike && isHot && isActive && (
                             <span className="text-[8px] text-cyan-400 animate-pulse">🔥</span>
                          )}
                      </div>

                      {/* Roles - Colored Badges */}
                      <div className="flex flex-wrap gap-1">
                          {player.isAllRoles ? (
                            <div className={`px-1.5 py-0.5 border clip-corner-sm bg-purple-900/20 text-purple-400 border-purple-500/30`}>
                              <span className="text-[8px] font-bold uppercase whitespace-nowrap">All Roles</span>
                            </div>
                          ) : (
                            player.roles.map(role => (
                                <div key={role} className={`px-1.5 py-0.5 border clip-corner-sm ${getRoleBadgeStyle(role)}`}>
                                    <span className="text-[7px] uppercase font-bold leading-none whitespace-nowrap opacity-100">
                                        {role === Role.COACH ? 'COACH' : role.split(' ')[0]}
                                    </span>
                                </div>
                            ))
                          )}
                      </div>
                   </div>

                   {/* Menu Button */}
                   <div className="relative shrink-0">
                      <button 
                         onClick={(e) => toggleMenu(e, player.id)}
                         className={`p-1 text-[#4a5f78] hover:text-[#dcb06b] hover:bg-white/5 transition-colors rounded`}
                      >
                         <svg xmlns="http://www.w3.org/2000/svg" className="h-4 w-4" fill="none" viewBox="0 0 24 24" stroke="currentColor">
                           <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M12 5v.01M12 12v.01M12 19v.01M12 6a1 1 0 110-2 1 1 0 010 2zm0 7a1 1 0 110-2 1 1 0 010 2zm0 7a1 1 0 110-2 1 1 0 010 2z" />
                         </svg>
                      </button>

                      {menuOpenId === player.id && (
                         <div className="absolute right-0 top-6 w-32 bg-[#05090f] border border-[#dcb06b] z-50 shadow-lg clip-corner-sm flex flex-col animate-slide-in">
                            <button 
                              onClick={(e) => { e.stopPropagation(); onToggleActive(player.id); setMenuOpenId(null); }}
                              className="px-3 py-2 text-left text-[10px] uppercase font-bold text-[#f0f4f8] hover:bg-[#dcb06b] hover:text-[#05090f] transition-colors"
                            >
                               {isActive ? 'Bench Player' : 'Activate'}
                            </button>
                            <button 
                              onClick={(e) => { e.stopPropagation(); onEdit(player); setMenuOpenId(null); }}
                              className="px-3 py-2 text-left text-[10px] uppercase font-bold text-[#f0f4f8] hover:bg-[#dcb06b] hover:text-[#05090f] transition-colors"
                            >
                               Edit Details
                            </button>
                            <div className="h-[1px] bg-[#1e3a5f] w-full"></div>
                            <button 
                              onClick={(e) => { e.stopPropagation(); onRemove(player.id); setMenuOpenId(null); }}
                              className="px-3 py-2 text-left text-[10px] uppercase font-bold text-red-500 hover:bg-red-500 hover:text-white transition-colors"
                            >
                               Remove
                            </button>
                         </div>
                      )}
                   </div>
                </div>

                {/* ROW 2: Stats - TIGHT under name */}
                {stats.matchesPlayed > 0 && (
                  <div className={`flex items-center gap-3 text-[9px] font-mono mt-auto pt-2 border-t border-white/5 ${isActive ? 'text-gray-400' : 'text-[#4a5f78]/50'}`}>
                      <div>
                        Match: <span className="text-[#f0f4f8]">{stats.matchesPlayed}</span>
                      </div>
                      <div>
                        WR: <span className={`${winRate >= 60 ? 'text-[#dcb06b]' : winRate >= 50 ? 'text-[#f0f4f8]' : 'text-red-400'}`}>{winRate}%</span>
                      </div>
                      {streak > 1 && (
                        <div className="ml-auto">
                            <span className={`${isGodlike ? 'text-red-500 font-black animate-pulse' : isHot ? 'text-cyan-400 font-bold' : 'text-gray-400'}`}>
                                {streak} Win Streak
                            </span>
                        </div>
                      )}
                  </div>
                )}

                {/* Benched Overlay */}
                {!isActive && (
                  <div className="absolute inset-0 flex items-center justify-center pointer-events-none z-10">
                    <span className="text-[#0a1a2f] font-black text-xl -rotate-12 opacity-40 uppercase tracking-widest select-none bg-[#dcb06b] px-1 mix-blend-screen">Benched</span>
                  </div>
                )}
              </div>

              {/* Invisible spacer to maintain height if needed, though absolute positioning handles it mostly. 
                  We add a min-height via class to ensure consistent look even with no stats. 
              */}
              <div className="invisible p-2 flex flex-col gap-1 min-h-[72px]">
                 <div className="text-lg">Placeholder</div>
                 <div className="text-[7px]">Roles</div>
              </div>
            </div>
          );
        })}
      </div>
    </div>
  );
};

import React, { useState, useEffect } from 'react';
import { createPortal } from 'react-dom';
import { Player, Role } from '../types';
import { ROLES_ORDER } from '../constants';

interface PlayerListProps {
  players: Player[];
  onRemove: (id: string) => void;
  onToggleActive: (id: string) => void;
  onEdit: (player: Player) => void;
  isSidebarOpen?: boolean;
}

type FilterType = 'ALL' | 'ACTIVE' | 'BENCH' | Role;

export const PlayerList: React.FC<PlayerListProps> = ({ players, onRemove, onToggleActive, onEdit, isSidebarOpen = true }) => {
  const [filter, setFilter] = useState<FilterType>('ALL');
  const [searchQuery, setSearchQuery] = useState('');

  // Menu State
  const [menuOpenId, setMenuOpenId] = useState<string | null>(null);
  const [menuPosition, setMenuPosition] = useState<{ top: number; left: number }>({ top: 0, left: 0 });

  // Close menu when clicking outside
  useEffect(() => {
    const handleClickOutside = () => setMenuOpenId(null);
    const handleScroll = () => setMenuOpenId(null); // Close on scroll to avoid floating menu issues

    if (menuOpenId) {
      document.addEventListener('click', handleClickOutside);
      window.addEventListener('scroll', handleScroll, true);
    }
    return () => {
      document.removeEventListener('click', handleClickOutside);
      window.removeEventListener('scroll', handleScroll, true);
    };
  }, [menuOpenId]);

  const toggleMenu = (e: React.MouseEvent, id: string) => {
    e.stopPropagation();
    if (menuOpenId === id) {
        setMenuOpenId(null);
    } else {
        // Calculate position relative to the viewport
        const rect = e.currentTarget.getBoundingClientRect();
        setMenuPosition({
            top: rect.bottom + 5,
            left: rect.right - 128 // Align right edge (128px is w-32)
        });
        setMenuOpenId(id);
    }
  };

  // Filter Logic
  const filteredPlayers = players.filter(p => {
    let matchesCategory = true;
    if (filter === 'ACTIVE') matchesCategory = p.isActive;
    else if (filter === 'BENCH') matchesCategory = !p.isActive;
    else if (Object.values(Role).includes(filter as Role)) {
       matchesCategory = p.roles.includes(filter as Role);
    }
    const matchesSearch = p.name.toLowerCase().includes(searchQuery.toLowerCase());
    return matchesCategory && matchesSearch;
  });

  const filters: { label: string; value: FilterType; icon?: React.ReactNode }[] = [
    { label: 'All', value: 'ALL' },
    { label: 'Playing', value: 'ACTIVE' },
    { label: 'Benched', value: 'BENCH' },
    ...ROLES_ORDER.map(r => ({ label: r.split(' ')[0], value: r })),
    { label: 'Coach', value: Role.COACH }
  ];

  // --- HELPER: Role Badge Color Logic (Strictly for the Role Label) ---
  const getRoleBadgeStyle = (role: Role) => {
      switch (role) {
          case Role.COACH: return 'text-white border-white bg-white/10';
          case Role.CLASH: return 'text-orange-400 border-orange-500/50 bg-orange-900/20'; // Clash: Orange
          case Role.JUNGLE: return 'text-emerald-400 border-emerald-500/50 bg-emerald-900/20'; // Jungle: Green/Emerald
          case Role.MID: return 'text-blue-400 border-blue-500/50 bg-blue-900/20'; // Mid: Blue
          case Role.FARM: return 'text-yellow-400 border-yellow-500/50 bg-yellow-900/20'; // Farm: Gold
          case Role.ROAM: return 'text-cyan-400 border-cyan-500/50 bg-cyan-900/20'; // Roam: Cyan
          default: return 'text-gray-400 border-gray-600 bg-gray-800/30';
      }
  };

  if (players.length === 0) {
    return (
      <div className="h-full min-h-[300px] flex flex-col items-center justify-center border border-dashed border-[#1e3a5f] rounded-lg bg-[#0a1a2f]/30 p-8">
        <div className="w-20 h-20 rounded-full bg-[#1e3a5f]/50 flex items-center justify-center mb-4 border border-[#dcb06b]/20">
           <svg xmlns="http://www.w3.org/2000/svg" className="h-8 w-8 text-[#dcb06b]/50" fill="none" viewBox="0 0 24 24" stroke="currentColor"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M12 4.354a4 4 0 110 5.292M15 21H3v-1a6 6 0 0112 0v1zm0 0h6v-1a6 6 0 00-9-5.197M13 7a4 4 0 11-8 0 4 4 0 018 0z" /></svg>
        </div>
        <p className="text-[#8a9db8] font-cinzel tracking-widest text-sm">Waiting for Challengers</p>
      </div>
    );
  }

  // Responsive Grid Logic
  const gridClasses = isSidebarOpen
      ? "grid-cols-1 md:grid-cols-2 lg:grid-cols-3 xl:grid-cols-4"
      : "grid-cols-1 md:grid-cols-3 lg:grid-cols-4 xl:grid-cols-5 2xl:grid-cols-6";

  return (
    <div>
      {/* FILTER & SEARCH BAR */}
      <div className="mb-6 flex flex-col md:flex-row gap-4 items-start md:items-center justify-between">
         <div className="overflow-x-auto pb-2 scrollbar-hide w-full md:w-auto">
            <div className="flex gap-2 min-w-max">
                {filters.map(f => (
                  <button
                    key={f.value}
                    onClick={() => setFilter(f.value)}
                    className={`
                      px-3 py-1.5 text-[10px] uppercase font-bold tracking-wider clip-corner-sm border transition-all
                      ${filter === f.value 
                          ? 'bg-[#dcb06b] text-[#05090f] border-[#dcb06b]' 
                          : 'bg-[#0a1a2f] text-[#8a9db8] border-[#1e3a5f] hover:border-[#dcb06b]/50 hover:text-white'}
                    `}
                  >
                    {f.label}
                  </button>
                ))}
            </div>
         </div>

         <div className="relative w-full md:w-64">
             <input 
               type="text" 
               placeholder="Find Player..." 
               value={searchQuery}
               onChange={(e) => setSearchQuery(e.target.value)}
               className="w-full bg-[#05090f] border border-[#1e3a5f] px-3 py-1.5 pl-8 text-xs text-[#f0f4f8] focus:outline-none focus:border-[#dcb06b] clip-corner-sm font-orbitron placeholder-[#4a5f78]"
             />
             <svg xmlns="http://www.w3.org/2000/svg" className="h-4 w-4 absolute left-2 top-1.5 text-[#4a5f78]" fill="none" viewBox="0 0 24 24" stroke="currentColor">
               <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M21 21l-6-6m2-5a7 7 0 11-14 0 7 7 0 0114 0z" />
             </svg>
         </div>
      </div>

      {/* PLAYER GRID */}
      <div className={`grid gap-3 transition-all duration-500 ${gridClasses}`}>
        {filteredPlayers.map(player => {
          const isActive = player.isActive;
          const stats = player.stats || { matchesPlayed: 0, wins: 0, currentStreak: 0, maxStreak: 0 };
          const winRate = stats.matchesPlayed > 0 
            ? Math.round((stats.wins / stats.matchesPlayed) * 100) 
            : 0;

          const streak = stats.currentStreak;
          const isHot = streak >= 3 && streak < 6;
          const isGodlike = streak >= 6;
          const isMvp = player.isLastMatchMvp;
          const isCoach = player.roles.includes(Role.COACH);

          // --- ANIMATED BORDER LOGIC ---
          let animationLayer = null;
          let glowClass = "";

          if (isActive) {
              if (isMvp) {
                  glowClass = "drop-shadow-[0_0_15px_rgba(251,191,36,0.6)]";
                  animationLayer = (
                      <div className="absolute inset-[-50%] bg-[conic-gradient(from_0deg,transparent_0deg,#fbbf24_90deg,transparent_180deg,#fbbf24_270deg,transparent_360deg)] animate-[spin_4s_linear_infinite] opacity-100"></div>
                  );
              } else if (isCoach) {
                  glowClass = "drop-shadow-[0_0_10px_rgba(255,255,255,0.5)]";
                  animationLayer = (
                      <div className="absolute inset-[-50%] bg-[conic-gradient(from_0deg,transparent_0deg,#ffffff_90deg,transparent_180deg,#ffffff_270deg,transparent_360deg)] animate-[spin_6s_linear_infinite] opacity-80"></div>
                  );
              } else if (isGodlike) {
                  glowClass = "drop-shadow-[0_0_20px_rgba(239,68,68,0.8)]";
                  animationLayer = (
                      <div className="absolute inset-[-50%] bg-[conic-gradient(from_0deg,transparent_0deg,#ef4444_60deg,#7f1d1d_120deg,transparent_180deg,#ef4444_240deg,transparent_360deg)] animate-[spin_2s_linear_infinite] opacity-100"></div>
                  );
              } else if (isHot) {
                  glowClass = "drop-shadow-[0_0_10px_rgba(6,182,212,0.6)]";
                  animationLayer = (
                      <div className="absolute inset-[-50%] bg-[conic-gradient(from_0deg,transparent_0deg,#06b6d4_90deg,transparent_180deg,#06b6d4_270deg,transparent_360deg)] animate-[spin_3s_linear_infinite] opacity-100"></div>
                  );
              }
          }

          const cardBg = isActive && isCoach ? 'bg-[#000000]' : 'bg-[#05090f]';

          return (
            <React.Fragment key={player.id}>
              {/* Dropdown Menu Portal - Renders outside the card to avoid clipping */}
              {menuOpenId === player.id && createPortal(
                <div 
                   className="fixed z-[9999] w-32 bg-[#05090f] border border-[#dcb06b] shadow-[0_0_20px_rgba(0,0,0,0.9)] clip-corner-sm flex flex-col animate-slide-in"
                   style={{ 
                      top: menuPosition.top, 
                      left: menuPosition.left 
                   }}
                   onClick={(e) => e.stopPropagation()}
                >
                    <button 
                      onClick={(e) => { e.stopPropagation(); onToggleActive(player.id); setMenuOpenId(null); }}
                      className="px-3 py-3 text-left text-[10px] uppercase font-bold text-[#f0f4f8] hover:bg-[#dcb06b] hover:text-[#05090f] transition-colors"
                    >
                       {isActive ? 'Bench Player' : 'Activate'}
                    </button>
                    <button 
                      onClick={(e) => { e.stopPropagation(); onEdit(player); setMenuOpenId(null); }}
                      className="px-3 py-3 text-left text-[10px] uppercase font-bold text-[#f0f4f8] hover:bg-[#dcb06b] hover:text-[#05090f] transition-colors"
                    >
                       Edit Details
                    </button>
                    <div className="h-[1px] bg-[#1e3a5f] w-full"></div>
                    <button 
                      onClick={(e) => { e.stopPropagation(); onRemove(player.id); setMenuOpenId(null); }}
                      className="px-3 py-3 text-left text-[10px] uppercase font-bold text-red-500 hover:bg-red-500 hover:text-white transition-colors"
                    >
                       Remove
                    </button>
                 </div>,
                 document.body
              )}

              <div className={`relative group ${glowClass} tilt-card h-full transition-all duration-300`}>

                {/* Border Animation Layer */}
                <div className="absolute inset-0 clip-corner-sm overflow-hidden z-0">
                    <div className="absolute inset-0 bg-[#1e3a5f]"></div>
                    {animationLayer}
                </div>

                {/* Content Card */}
                <div 
                  className={`
                    absolute inset-[1px] clip-corner-sm z-10 flex flex-col gap-1 p-2
                    ${cardBg}
                    ${!isActive ? 'opacity-50 grayscale hover:opacity-80 transition-opacity' : ''}
                  `}
                >

                  {/* Name, Roles, Menu */}
                  <div className="flex justify-between items-start gap-2">

                     <div className="flex-1 min-w-0">
                        {/* Name */}
                        <div className="flex items-center gap-2 mb-1">
                            <div 
                                className={`text-lg font-bold font-orbitron tracking-wide leading-none truncate ${isMvp ? 'text-yellow-400' : 'text-[#e2e8f0]'}`}
                                title={player.name}
                            >
                                {player.name}
                            </div>

                            {/* Badges */}
                            {isMvp && <div className="text-[8px] font-black bg-gradient-to-r from-yellow-400 to-yellow-600 text-black px-1.5 py-0.5 rounded-sm shadow-[0_0_10px_#fbbf24] animate-pulse">MVP</div>}
                            {isCoach && <div className="text-[8px] font-black bg-white text-black px-1.5 py-0.5 rounded-sm shadow-[0_0_10px_white]">COACH</div>}
                            {!isMvp && isGodlike && isActive && (
                               <span className="text-[8px] text-red-500 animate-pulse font-black">GODLIKE</span>
                            )}
                            {!isMvp && !isGodlike && isHot && isActive && (
                               <span className="text-[8px] text-cyan-400 animate-pulse">🔥</span>
                            )}
                        </div>

                        {/* Roles */}
                        <div className="flex flex-wrap gap-1">
                            {player.isAllRoles ? (
                              <div className={`px-1.5 py-0.5 border clip-corner-sm bg-purple-900/20 text-purple-400 border-purple-500/30`}>
                                <span className="text-[8px] font-bold uppercase whitespace-nowrap">All Roles</span>
                              </div>
                            ) : (
                              player.roles.map(role => (
                                  <div key={role} className={`px-1.5 py-0.5 border clip-corner-sm ${getRoleBadgeStyle(role)}`}>
                                      <span className="text-[7px] uppercase font-bold leading-none whitespace-nowrap opacity-100">
                                          {role === Role.COACH ? 'COACH' : role.split(' ')[0]}
                                      </span>
                                  </div>
                              ))
                            )}
                        </div>
                     </div>

                     {/* Menu Button */}
                     <div className="relative shrink-0">
                        <button 
                           onClick={(e) => toggleMenu(e, player.id)}
                           className={`p-1 text-[#4a5f78] hover:text-[#dcb06b] hover:bg-white/5 transition-colors rounded`}
                        >
                           <svg xmlns="http://www.w3.org/2000/svg" className="h-4 w-4" fill="none" viewBox="0 0 24 24" stroke="currentColor">
                             <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M12 5v.01M12 12v.01M12 19v.01M12 6a1 1 0 110-2 1 1 0 010 2zm0 7a1 1 0 110-2 1 1 0 010 2zm0 7a1 1 0 110-2 1 1 0 010 2z" />
                           </svg>
                        </button>
                     </div>
                  </div>

                  {/* Stats */}
                  {stats.matchesPlayed > 0 && (
                    <div className={`flex items-center gap-3 text-[9px] font-mono mt-auto pt-2 border-t border-white/5 ${isActive ? 'text-gray-400' : 'text-[#4a5f78]/50'}`}>
                        <div>
                          Match: <span className="text-[#f0f4f8]">{stats.matchesPlayed}</span>
                        </div>
                        <div>
                          WR: <span className={`${winRate >= 60 ? 'text-[#dcb06b]' : winRate >= 50 ? 'text-[#f0f4f8]' : 'text-red-400'}`}>{winRate}%</span>
                        </div>
                        {streak > 1 && (
                          <div className="ml-auto">
                              <span className={`${isGodlike ? 'text-red-500 font-black animate-pulse' : isHot ? 'text-cyan-400 font-bold' : 'text-gray-400'}`}>
                                  {streak} Win Streak
                              </span>
                          </div>
                        )}
                    </div>
                  )}

                  {/* Benched Overlay */}
                  {!isActive && (
                    <div className="absolute inset-0 flex items-center justify-center pointer-events-none z-10">
                      <span className="text-[#0a1a2f] font-black text-xl -rotate-12 opacity-40 uppercase tracking-widest select-none bg-[#dcb06b] px-1 mix-blend-screen">Benched</span>
                    </div>
                  )}
                </div>

                {/* Invisible spacer to maintain height */}
                <div className="invisible p-2 flex flex-col gap-1 min-h-[72px]">
                   <div className="text-lg">Placeholder</div>
                   <div className="text-[7px]">Roles</div>
                </div>
              </div>
            </React.Fragment>
          );
        })}
      </div>
    </div>
  );
};

import React, { useState, useRef } from 'react';
import { Player, MatchResult, Role, MatchHistoryEntry } from './types';
import { PlayerForm } from './components/PlayerForm';
import { PlayerList } from './components/PlayerList';
