import React, { useState, useEffect, useRef } from 'react';
import { Button } from './Button';

interface SpinWheelProps {
  candidates: string[];
  winnerName: string;
  onComplete: () => void;
  onCancel: () => void;
  team: 'azure' | 'crimson';
  roleName: string;
}

export const SpinWheel: React.FC<SpinWheelProps> = ({ candidates, winnerName, onComplete, onCancel, team, roleName }) => {
  const [status, setStatus] = useState<'idle' | 'scrolling' | 'completed'>('idle');
  const [scrollPosition, setScrollPosition] = useState(0);

  // Ref for the scroll container
  const reelRef = useRef<HTMLDivElement>(null);

  // Configuration
  const ITEM_HEIGHT = 80; 
  const VISIBLE_ITEMS = 5; 
  const TOTAL_DURATION = 8000; 
  const WINNER_INDEX = 150; 

  const [reelItems, setReelItems] = useState<string[]>([]);

  useEffect(() => {
    const items: string[] = [];
    const uniqueCandidates = Array.from(new Set(candidates)) as string[];

    // If we only have 1 candidate (or 0), we can't avoid duplicates
    if (uniqueCandidates.length <= 1) {
       for (let i = 0; i < WINNER_INDEX + VISIBLE_ITEMS + 5; i++) {
          if (i === WINNER_INDEX) {
            items.push(winnerName);
          } else {
            items.push(uniqueCandidates[0] || winnerName);
          }
       }
       setReelItems(items);
       return;
    }

    let previousName = '';

    for (let i = 0; i < WINNER_INDEX + VISIBLE_ITEMS + 5; i++) {
       if (i === WINNER_INDEX) {
         items.push(winnerName);
         previousName = winnerName;
       } else {
         // Filter available candidates to exclude the one we just added (previousName)
         // This guarantees no immediate duplicates (e.g. A, B, A, C, B) instead of (A, A, B, B)
         const availableCandidates = uniqueCandidates.filter(name => name !== previousName);

         // Fallback if filter empties list (shouldn't happen if uniqueCandidates > 1)
         const pool = availableCandidates.length > 0 ? availableCandidates : uniqueCandidates;

         const randomName = pool[Math.floor(Math.random() * pool.length)];
         items.push(randomName);
         previousName = randomName;
       }
    }
    setReelItems(items);
  }, [candidates, winnerName]);

  const handleLock = () => {
    if (status !== 'idle') return;
    setStatus('scrolling');

    const containerHeight = ITEM_HEIGHT * VISIBLE_ITEMS;
    const centerOffset = (containerHeight / 2) - (ITEM_HEIGHT / 2);
    const targetY = -(WINNER_INDEX * ITEM_HEIGHT) + centerOffset;

    setScrollPosition(targetY);

    setTimeout(() => {
       setStatus('completed');
       setTimeout(() => {
         onComplete();
       }, 1000);
    }, TOTAL_DURATION);
  };

  const handleSkip = () => {
     // Instantly jump to end
     setStatus('completed');
     const containerHeight = ITEM_HEIGHT * VISIBLE_ITEMS;
     const centerOffset = (containerHeight / 2) - (ITEM_HEIGHT / 2);
     const targetY = -(WINNER_INDEX * ITEM_HEIGHT) + centerOffset;
     setScrollPosition(targetY);
     setTimeout(() => {
         onComplete();
     }, 500);
  };

  const themeColor = team === 'azure' ? '#00d2ff' : '#ef4444';

  return (
    <div className="fixed inset-0 z-[60] flex flex-col items-center justify-center bg-black/90 backdrop-blur-xl animate-slide-in">

      {/* Controls: Skip & Abort */}
      <div className="absolute top-6 right-6 z-50 flex gap-4">
        {/* Skip Animation (Debug) */}
        {status === 'scrolling' && (
           <button 
             onClick={handleSkip}
             className="px-4 py-2 bg-[#dcb06b]/20 border border-[#dcb06b] text-[#dcb06b] font-orbitron font-bold text-xs uppercase tracking-widest hover:bg-[#dcb06b] hover:text-black transition-colors"
           >
             Fast Forward
           </button>
        )}

        {/* Cancel Button */}
        {status === 'idle' && (
          <button 
            onClick={onCancel}
            className="group flex items-center gap-2 text-[#4a5f78] hover:text-white transition-colors"
          >
            <span className="text-xs uppercase tracking-widest font-bold opacity-0 group-hover:opacity-100 transition-opacity">Abort</span>
            <div className="w-10 h-10 rounded-full border border-[#1e3a5f] group-hover:border-red-500 flex items-center justify-center bg-[#05090f]">
              <svg xmlns="http://www.w3.org/2000/svg" className="h-5 w-5" fill="none" viewBox="0 0 24 24" stroke="currentColor">
                <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M6 18L18 6M6 6l12 12" />
              </svg>
            </div>
          </button>
        )}
      </div>

      <div className="mb-8 text-center relative z-10 pointer-events-none select-none">
        <h3 className="text-[#dcb06b] font-cinzel text-xl tracking-[0.3em] uppercase mb-2">
          Targeting Candidate
        </h3>
        <h2 className="text-4xl md:text-5xl font-black font-orbitron text-white uppercase drop-shadow-[0_0_15px_rgba(255,255,255,0.5)]">
          <span style={{ color: themeColor }}>{team}</span> {roleName}
        </h2>
      </div>

      {/* Scroller Container */}
      <div className="relative">

         <div 
            className="relative overflow-hidden bg-[#05090f] border-x-2 border-[#dcb06b]/30 shadow-[0_0_50px_rgba(0,0,0,0.8)]"
            style={{ 
              width: '320px', 
              height: `${ITEM_HEIGHT * VISIBLE_ITEMS}px`
            }}
         >
            <div 
              ref={reelRef}
              className="w-full flex flex-col items-center will-change-transform"
              style={{
                transform: `translateY(${scrollPosition}px)`,
                transition: status === 'scrolling' 
                   ? `transform ${TOTAL_DURATION}ms cubic-bezier(0.1, 0, 0.1, 1)` 
                   : 'none',
              }}
            >
               {status === 'idle' && (
                  <div className="absolute inset-0 flex flex-col items-center animate-[scrollFast_0.5s_linear_infinite]">
                     {reelItems.slice(0, 20).map((name, i) => (
                        <div 
                          key={`idle-${i}`} 
                          className="flex items-center justify-center w-full text-[#4a5f78] font-orbitron font-bold text-2xl uppercase opacity-50"
                          style={{ height: `${ITEM_HEIGHT}px`, flexShrink: 0 }}
                        >
                          {name}
                        </div>
                     ))}
                  </div>
               )}

               {status !== 'idle' && reelItems.map((name, index) => (
                  <div 
                    key={index}
                    className={`
                      flex items-center justify-center w-full transition-colors duration-300
                      ${(index === WINNER_INDEX && status === 'completed') 
                          ? 'text-[#dcb06b] text-3xl drop-shadow-[0_0_10px_#dcb06b]' 
                          : 'text-[#f0f4f8] text-2xl opacity-80'}
                      font-orbitron font-bold uppercase tracking-wider
                    `}
                    style={{ height: `${ITEM_HEIGHT}px`, flexShrink: 0 }}
                  >
                     {name}
                  </div>
               ))}
            </div>

            <div className="absolute top-0 left-0 right-0 h-24 bg-gradient-to-b from-[#05090f] to-transparent z-10 pointer-events-none"></div>
            <div className="absolute bottom-0 left-0 right-0 h-24 bg-gradient-to-t from-[#05090f] to-transparent z-10 pointer-events-none"></div>

            <div className="absolute top-1/2 left-1/2 -translate-x-1/2 -translate-y-1/2 w-full h-[80px] z-20 pointer-events-none flex items-center justify-between px-2">
               <div className={`h-full w-4 border-l-4 border-t-4 border-b-4 ${status === 'completed' ? 'border-[#dcb06b] animate-pulse' : 'border-[#4a5f78]'}`}></div>
               <div className="absolute inset-0 bg-[#dcb06b]/5 border-y border-[#dcb06b]/20"></div>
               <div className={`h-full w-4 border-r-4 border-t-4 border-b-4 ${status === 'completed' ? 'border-[#dcb06b] animate-pulse' : 'border-[#4a5f78]'}`}></div>
            </div>

            <div className="absolute inset-0 bg-[linear-gradient(rgba(18,16,16,0)_50%,rgba(0,0,0,0.25)_50%),linear-gradient(90deg,rgba(255,0,0,0.06),rgba(0,255,0,0.02),rgba(0,0,255,0.06))] z-30 pointer-events-none bg-[length:100%_4px,6px_100%]"></div>
         </div>
      </div>

      <div className="mt-12 h-24 flex items-center justify-center">
         {status === 'idle' ? (
            <Button 
               onClick={handleLock}
               className="px-12 py-4 text-xl border-2 border-[#dcb06b] shadow-[0_0_20px_#dcb06b] animate-pulse"
            >
               LOCK TARGET
            </Button>
         ) : status === 'scrolling' ? (
            <div className="text-[#dcb06b] font-orbitron text-sm uppercase tracking-[0.5em] animate-pulse">
               Acquiring Target...
            </div>
         ) : (
             <div className="text-white font-orbitron text-sm uppercase tracking-[0.5em] animate-[bounce_1s_infinite]">
               Target Locked
            </div>
         )}
      </div>

      <style>{`
        @keyframes scrollFast {
          0% { transform: translateY(0); }
          100% { transform: translateY(-50%); }
        }
      `}</style>
    </div>
  );
};

import React, { useState, useEffect } from 'react';
import { createPortal } from 'react-dom';
import { Player, Role } from '../types';
import { ROLES_ORDER } from '../constants';

interface PlayerListProps {
  players: Player[];
  onRemove: (id: string) => void;
  onToggleActive: (id: string) => void;
  onEdit: (player: Player) => void;
  isSidebarOpen?: boolean;
}

type FilterType = 'ALL' | 'ACTIVE' | 'BENCH' | Role;

export const PlayerList: React.FC<PlayerListProps> = ({ players, onRemove, onToggleActive, onEdit, isSidebarOpen = true }) => {
  const [filter, setFilter] = useState<FilterType>('ALL');
  const [searchQuery, setSearchQuery] = useState('');
  const [showFilters, setShowFilters] = useState(false);

  // Menu State
  const [menuOpenId, setMenuOpenId] = useState<string | null>(null);
  const [menuPosition, setMenuPosition] = useState<{ top: number; left: number }>({ top: 0, left: 0 });

  // Close menu when clicking outside
  useEffect(() => {
    const handleClickOutside = () => setMenuOpenId(null);
    const handleScroll = () => setMenuOpenId(null); 

    if (menuOpenId) {
      document.addEventListener('click', handleClickOutside);
      window.addEventListener('scroll', handleScroll, true);
    }
    return () => {
      document.removeEventListener('click', handleClickOutside);
      window.removeEventListener('scroll', handleScroll, true);
    };
  }, [menuOpenId]);

  const toggleMenu = (e: React.MouseEvent, id: string) => {
    e.stopPropagation();
    if (menuOpenId === id) {
        setMenuOpenId(null);
    } else {
        const rect = e.currentTarget.getBoundingClientRect();
        setMenuPosition({
            top: rect.bottom + 5,
            left: rect.right - 128
        });
        setMenuOpenId(id);
    }
  };

  const filteredPlayers = players.filter(p => {
    let matchesCategory = true;
    if (filter === 'ACTIVE') matchesCategory = p.isActive;
    else if (filter === 'BENCH') matchesCategory = !p.isActive;
    else if (Object.values(Role).includes(filter as Role)) {
       matchesCategory = p.roles.includes(filter as Role);
    }
    const matchesSearch = p.name.toLowerCase().includes(searchQuery.toLowerCase());
    return matchesCategory && matchesSearch;
  });

  const filters: { label: string; value: FilterType; icon?: React.ReactNode }[] = [
    { label: 'All', value: 'ALL' },
    { label: 'Playing', value: 'ACTIVE' },
    { label: 'Benched', value: 'BENCH' },
    ...ROLES_ORDER.map(r => ({ label: r.split(' ')[0], value: r })),
    { label: 'Coach', value: Role.COACH }
  ];

  const getRoleBadgeStyle = (role: Role) => {
      switch (role) {
          case Role.COACH: return 'text-white border-white bg-white/10 shadow-[0_0_10px_rgba(255,255,255,0.5)]'; // Added glow for list view
          case Role.CLASH: return 'text-orange-400 border-orange-500/50 bg-orange-900/20'; 
          case Role.JUNGLE: return 'text-emerald-400 border-emerald-500/50 bg-emerald-900/20'; 
          case Role.MID: return 'text-blue-400 border-blue-500/50 bg-blue-900/20'; 
          case Role.FARM: return 'text-yellow-400 border-yellow-500/50 bg-yellow-900/20'; 
          case Role.ROAM: return 'text-cyan-400 border-cyan-500/50 bg-cyan-900/20'; 
          default: return 'text-gray-400 border-gray-600 bg-gray-800/30';
      }
  };

  if (players.length === 0) {
    return (
      <div className="h-full min-h-[300px] flex flex-col items-center justify-center border border-dashed border-[#1e3a5f] rounded-lg bg-[#0a1a2f]/30 p-8">
        <div className="w-20 h-20 rounded-full bg-[#1e3a5f]/50 flex items-center justify-center mb-4 border border-[#dcb06b]/20">
           <svg xmlns="http://www.w3.org/2000/svg" className="h-8 w-8 text-[#dcb06b]/50" fill="none" viewBox="0 0 24 24" stroke="currentColor"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M12 4.354a4 4 0 110 5.292M15 21H3v-1a6 6 0 0112 0v1zm0 0h6v-1a6 6 0 00-9-5.197M13 7a4 4 0 11-8 0 4 4 0 018 0z" /></svg>
        </div>
        <p className="text-[#8a9db8] font-cinzel tracking-widest text-sm">Waiting for Challengers</p>
      </div>
    );
  }

  // Adjusted Grid Logic: 3xN when Sidebar Open
  const gridClasses = isSidebarOpen
      ? "grid-cols-1 md:grid-cols-2 lg:grid-cols-3" 
      : "grid-cols-1 md:grid-cols-3 lg:grid-cols-4 xl:grid-cols-5 2xl:grid-cols-6";

  return (
    <div>
      {/* FILTER & SEARCH BAR */}
      <div className="mb-6 flex flex-col md:flex-row gap-4 items-start md:items-center justify-between">

         {/* Collapsible Filter Menu */}
         <div className="relative w-full md:w-auto z-20">
             <button 
               onClick={() => setShowFilters(!showFilters)}
               className="flex items-center gap-2 px-4 py-2 bg-[#05090f] border border-[#1e3a5f] text-[#dcb06b] clip-corner-sm hover:bg-[#1e3a5f]/50 transition-colors uppercase font-bold text-xs tracking-wider"
             >
                <svg xmlns="http://www.w3.org/2000/svg" className="h-4 w-4" fill="none" viewBox="0 0 24 24" stroke="currentColor">
                   <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M3 4a1 1 0 011-1h16a1 1 0 011 1v2.586a1 1 0 01-.293.707l-6.414 6.414a1 1 0 00-.293.707V17l-4 4v-6.586a1 1 0 00-.293-.707L3.293 7.293A1 1 0 013 6.586V4z" />
                </svg>
                {filter === 'ALL' ? 'Filter Roles' : filter}
                <svg xmlns="http://www.w3.org/2000/svg" className={`h-3 w-3 transition-transform ${showFilters ? 'rotate-180' : ''}`} fill="none" viewBox="0 0 24 24" stroke="currentColor">
                   <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M19 9l-7 7-7-7" />
                </svg>
             </button>

             {showFilters && (
                <div className="absolute top-full left-0 mt-2 w-48 bg-[#05090f] border border-[#dcb06b] clip-corner-sm shadow-xl p-2 flex flex-col gap-1 animate-slide-in">
                    {filters.map(f => (
                      <button
                        key={f.value}
                        onClick={() => { setFilter(f.value); setShowFilters(false); }}
                        className={`
                          text-left px-3 py-2 text-[10px] uppercase font-bold tracking-wider clip-corner-sm border transition-all
                          ${filter === f.value 
                              ? 'bg-[#dcb06b] text-[#05090f] border-[#dcb06b]' 
                              : 'bg-transparent text-[#8a9db8] border-transparent hover:border-[#1e3a5f] hover:text-white hover:bg-[#1e3a5f]/30'}
                        `}
                      >
                        {f.label}
                      </button>
                    ))}
                </div>
             )}
         </div>

         <div className="relative w-full md:w-64">
             <input 
               type="text" 
               placeholder="Find Player..." 
               value={searchQuery}
               onChange={(e) => setSearchQuery(e.target.value)}
               className="w-full bg-[#05090f] border border-[#1e3a5f] px-3 py-1.5 pl-8 text-xs text-[#f0f4f8] focus:outline-none focus:border-[#dcb06b] clip-corner-sm font-orbitron placeholder-[#4a5f78]"
             />
             <svg xmlns="http://www.w3.org/2000/svg" className="h-4 w-4 absolute left-2 top-1.5 text-[#4a5f78]" fill="none" viewBox="0 0 24 24" stroke="currentColor">
               <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M21 21l-6-6m2-5a7 7 0 11-14 0 7 7 0 0114 0z" />
             </svg>
         </div>
      </div>

      {/* PLAYER GRID */}
      <div className={`grid gap-3 transition-all duration-500 ${gridClasses}`}>
        {filteredPlayers.map(player => {
          const isActive = player.isActive;
          const stats = player.stats || { matchesPlayed: 0, wins: 0, currentStreak: 0, maxStreak: 0 };
          const winRate = stats.matchesPlayed > 0 
            ? Math.round((stats.wins / stats.matchesPlayed) * 100) 
            : 0;

          const streak = stats.currentStreak;
          const isHot = streak >= 3 && streak < 6; 
          const isGodlike = streak >= 6;
          const isMvp = player.isLastMatchMvp;
          const hasCoachRole = player.roles.includes(Role.COACH);

          // --- ANIMATED BORDER LOGIC ---
          let animationLayer = null;
          let glowClass = "";

          if (isActive) {
              if (isMvp) {
                  glowClass = "drop-shadow-[0_0_15px_rgba(251,191,36,0.6)]";
                  animationLayer = (
                      <div className="absolute inset-[-50%] bg-[conic-gradient(from_0deg,transparent_0deg,#fbbf24_90deg,transparent_180deg,#fbbf24_270deg,transparent_360deg)] animate-[spin_4s_linear_infinite] opacity-100"></div>
                  );
              } else if (hasCoachRole) {
                  glowClass = "drop-shadow-[0_0_10px_rgba(255,255,255,0.5)]";
                  animationLayer = (
                      <div className="absolute inset-[-50%] bg-[conic-gradient(from_0deg,transparent_0deg,#ffffff_90deg,transparent_180deg,#ffffff_270deg,transparent_360deg)] animate-[spin_6s_linear_infinite] opacity-80"></div>
                  );
              } else if (isGodlike) {
                  glowClass = "drop-shadow-[0_0_20px_rgba(239,68,68,0.8)]";
                  animationLayer = (
                      <div className="absolute inset-[-50%] bg-[conic-gradient(from_0deg,transparent_0deg,#ef4444_60deg,#7f1d1d_120deg,transparent_180deg,#ef4444_240deg,transparent_360deg)] animate-[spin_2s_linear_infinite] opacity-100"></div>
                  );
              } else if (isHot) {
                  glowClass = "drop-shadow-[0_0_10px_rgba(6,182,212,0.6)]";
                  animationLayer = (
                      <div className="absolute inset-[-50%] bg-[conic-gradient(from_0deg,transparent_0deg,#06b6d4_90deg,transparent_180deg,#06b6d4_270deg,transparent_360deg)] animate-[spin_3s_linear_infinite] opacity-100"></div>
                  );
              }
          }

          const cardBg = isActive && hasCoachRole ? 'bg-[#000000]' : 'bg-[#05090f]';

          return (
            <React.Fragment key={player.id}>
              {menuOpenId === player.id && createPortal(
                <div 
                   className="fixed z-[9999] w-32 bg-[#05090f] border border-[#dcb06b] shadow-[0_0_20px_rgba(0,0,0,0.9)] clip-corner-sm flex flex-col animate-slide-in"
                   style={{ 
                      top: menuPosition.top, 
                      left: menuPosition.left 
                   }}
                   onClick={(e) => e.stopPropagation()}
                >
                    <button 
                      onClick={(e) => { e.stopPropagation(); onToggleActive(player.id); setMenuOpenId(null); }}
                      className="px-3 py-3 text-left text-[10px] uppercase font-bold text-[#f0f4f8] hover:bg-[#dcb06b] hover:text-[#05090f] transition-colors"
                    >
                       {isActive ? 'Bench Player' : 'Activate'}
                    </button>
                    <button 
                      onClick={(e) => { e.stopPropagation(); onEdit(player); setMenuOpenId(null); }}
                      className="px-3 py-3 text-left text-[10px] uppercase font-bold text-[#f0f4f8] hover:bg-[#dcb06b] hover:text-[#05090f] transition-colors"
                    >
                       Edit Details
                    </button>
                    <div className="h-[1px] bg-[#1e3a5f] w-full"></div>
                    <button 
                      onClick={(e) => { e.stopPropagation(); onRemove(player.id); setMenuOpenId(null); }}
                      className="px-3 py-3 text-left text-[10px] uppercase font-bold text-red-500 hover:bg-red-500 hover:text-white transition-colors"
                    >
                       Remove
                    </button>
                 </div>,
                 document.body
              )}

              <div className={`relative group ${glowClass} tilt-card h-full transition-all duration-300`}>

                <div className="absolute inset-0 clip-corner-sm overflow-hidden z-0">
                    <div className="absolute inset-0 bg-[#1e3a5f]"></div>
                    {animationLayer}
                </div>

                <div 
                  className={`
                    absolute inset-[1px] clip-corner-sm z-10 flex flex-col gap-1 p-2
                    ${cardBg}
                    ${!isActive ? 'opacity-50 grayscale hover:opacity-80 transition-opacity' : ''}
                  `}
                >

                  <div className="flex justify-between items-start gap-2">

                     <div className="flex-1 min-w-0">
                        {/* Name */}
                        <div className="flex items-center gap-2 mb-1">
                            <div 
                                className={`text-lg font-bold font-orbitron tracking-wide leading-none truncate ${isMvp ? 'text-yellow-400' : 'text-[#e2e8f0]'}`}
                                title={player.name}
                            >
                                {player.name}
                            </div>

                            {/* Badges */}
                            {isMvp && <div className="text-[8px] font-black bg-gradient-to-r from-yellow-400 to-yellow-600 text-black px-1.5 py-0.5 rounded-sm shadow-[0_0_10px_#fbbf24] animate-pulse">MVP</div>}
                            {/* Removed redundant text COACH badge since we use a special role badge now, but keeping MVP/Godlike logic */}
                            {!isMvp && isGodlike && isActive && (
                               <span className="text-[8px] text-red-500 animate-pulse font-black">GODLIKE</span>
                            )}
                        </div>

                        <div className="flex flex-wrap gap-1">
                            {hasCoachRole ? (
                                // Exclusive Coach Badge - If player is Coach, ONLY show this.
                                <div className={`px-1.5 py-0.5 border clip-corner-sm ${getRoleBadgeStyle(Role.COACH)}`}>
                                    <span className="text-[7px] uppercase font-bold leading-none whitespace-nowrap opacity-100">
                                        COACH
                                    </span>
                                </div>
                            ) : (
                                // Standard Role Rendering
                                player.isAllRoles ? (
                                  <div className={`px-1.5 py-0.5 border clip-corner-sm bg-purple-900/20 text-purple-400 border-purple-500/30`}>
                                    <span className="text-[8px] font-bold uppercase whitespace-nowrap">All Roles</span>
                                  </div>
                                ) : (
                                  player.roles.map(role => (
                                      <div key={role} className={`px-1.5 py-0.5 border clip-corner-sm ${getRoleBadgeStyle(role)}`}>
                                          <span className="text-[7px] uppercase font-bold leading-none whitespace-nowrap opacity-100">
                                              {role.split(' ')[0]}
                                          </span>
                                      </div>
                                  ))
                                )
                            )}
                        </div>
                     </div>

                     <div className="relative shrink-0">
                        <button 
                           onClick={(e) => toggleMenu(e, player.id)}
                           className={`p-1 text-[#4a5f78] hover:text-[#dcb06b] hover:bg-white/5 transition-colors rounded`}
                        >
                           <svg xmlns="http://www.w3.org/2000/svg" className="h-4 w-4" fill="none" viewBox="0 0 24 24" stroke="currentColor">
                             <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M12 5v.01M12 12v.01M12 19v.01M12 6a1 1 0 110-2 1 1 0 010 2zm0 7a1 1 0 110-2 1 1 0 010 2zm0 7a1 1 0 110-2 1 1 0 010 2z" />
                           </svg>
                        </button>
                     </div>
                  </div>

                  {/* Stats - Added Flex Wrap for dynamic adjustment */}
                  {stats.matchesPlayed > 0 && (
                    <div className={`flex flex-wrap items-center gap-x-3 gap-y-1 text-[9px] font-mono mt-auto pt-2 border-t border-white/5 ${isActive ? 'text-gray-400' : 'text-[#4a5f78]/50'}`}>
                        <div className="whitespace-nowrap">
                          Match: <span className="text-[#f0f4f8]">{stats.matchesPlayed}</span>
                        </div>
                        <div className="whitespace-nowrap">
                          WR: <span className={`${winRate >= 60 ? 'text-[#dcb06b]' : winRate >= 50 ? 'text-[#f0f4f8]' : 'text-red-400'}`}>{winRate}%</span>
                        </div>
                        {streak > 1 && (
                          <div className="whitespace-nowrap ml-auto">
                              <span className={`${isGodlike ? 'text-red-500 font-black animate-pulse' : isHot ? 'text-cyan-400 font-bold' : 'text-gray-400'}`}>
                                  {streak} Win Streak
                              </span>
                          </div>
                        )}
                    </div>
                  )}

                  {!isActive && (
                    <div className="absolute inset-0 flex items-center justify-center pointer-events-none z-10">
                      <span className="text-[#0a1a2f] font-black text-xl -rotate-12 opacity-40 uppercase tracking-widest select-none bg-[#dcb06b] px-1 mix-blend-screen">Benched</span>
                    </div>
                  )}
                </div>

                <div className="invisible p-2 flex flex-col gap-1 min-h-[72px]">
                   <div className="text-lg">Placeholder</div>
                   <div className="text-[7px]">Roles</div>
                </div>
              </div>
            </React.Fragment>
          );
        })}
      </div>
    </div>
  );
};

import React, { useState } from 'react';
import { MatchResult, TeamSlot, Role, Player } from '../types';
import { RoleIcons, ROLES_ORDER } from '../constants';
import { Button } from './Button';
import { SpinWheel } from './SpinWheel';
import { PortalTransition } from './PortalTransition';
import { MatchSummary } from './MatchSummary';
import { VictoryCelebration } from './VictoryCelebration';
import { EvaluationScreen } from './EvaluationScreen';

interface MatchDisplayProps {
  match: MatchResult;
  activePlayers: Player[]; 
  onReset: () => void; // For Abort
  onCompleteMatch: (winner: 'azure' | 'crimson' | null, mvpId?: string) => void; // For Finish
  onReroll: (team: 'azure' | 'crimson', role: Role, newPlayer: Player) => void;
}

type ViewState = 'drafting' | 'transition' | 'final' | 'celebration' | 'evaluation';

export const MatchDisplay: React.FC<MatchDisplayProps> = ({ match, activePlayers, onReset, onCompleteMatch, onReroll }) => {
  const [viewState, setViewState] = useState<ViewState>('drafting');
  const [winningTeam, setWinningTeam] = useState<'azure' | 'crimson' | null>(null);

  // Dynamic Role Order: If Coach mode, append Coach to standard order
  const displayRoles = match.isCoachMode ? [...ROLES_ORDER, Role.COACH] : ROLES_ORDER;

  // -1: Not started
  // 0-4: Revealing pairs (0=Clash, ... 4=Roam)
  // 5: Coach (if exists)
  const [currentRoleIndex, setCurrentRoleIndex] = useState(-1);

  // New State for the Modal Wheel
  const [wheelState, setWheelState] = useState<{
    isOpen: boolean;
    type: 'draft' | 'reroll'; // Differentiate between initial draft reveal and manual reroll
    team: 'azure' | 'crimson';
    role: Role;
    winnerName: string;
    winnerPlayer?: Player; // Needed for reroll
    candidates: string[];
  } | null>(null);

  // Tracks which individual cards are visible
  const [revealedCards, setRevealedCards] = useState<Set<string>>(new Set());

  const getPlayerForRole = (team: TeamSlot[], role: Role) => {
    return team.find(slot => slot.role === role);
  };

  const getCardId = (team: 'azure' | 'crimson', role: Role) => `${team}-${role}`;

  const handleNext = () => {
    const nextIndex = currentRoleIndex + 1;
    if (nextIndex >= displayRoles.length) return;

    const roleToReveal = displayRoles[nextIndex];

    // Step 1: Check if Azure is revealed
    const azureId = getCardId('azure', roleToReveal);
    if (!revealedCards.has(azureId)) {
      startWheel('azure', roleToReveal);
      return;
    }

    // Step 2: Check if Crimson is revealed
    const crimsonId = getCardId('crimson', roleToReveal);
    if (!revealedCards.has(crimsonId)) {
      startWheel('crimson', roleToReveal);
      return;
    }
  };

  const handleSkipAll = () => {
    // Debug: Instantly reveal everything
    const allCards = new Set<string>();
    displayRoles.forEach(r => {
      allCards.add(getCardId('azure', r));
      allCards.add(getCardId('crimson', r));
    });
    setRevealedCards(allCards);
    setCurrentRoleIndex(displayRoles.length); // Set to finished state
  };

  const startWheel = (team: 'azure' | 'crimson', role: Role) => {
    const teamSlots = team === 'azure' ? match.azureTeam : match.crimsonTeam;
    const winner = getPlayerForRole(teamSlots, role)?.player;
    if (!winner) return;

    // Get candidates for the wheel
    // STRICT COACH LOGIC: If role is Coach, ONLY allow players with Coach role.
    const candidates = activePlayers
      .filter(p => {
          if (role === Role.COACH) {
              return p.roles.includes(Role.COACH);
          }
          return p.isAllRoles || p.roles.includes(role);
      })
      .map(p => p.name);

    setWheelState({
      isOpen: true,
      type: 'draft',
      team,
      role,
      winnerName: winner.name,
      candidates
    });
  };

  // Triggered when user clicks the re-roll button on a card
  const handleRerollClick = (team: 'azure' | 'crimson', role: Role) => {
    const azureIds = new Set(match.azureTeam.map(s => s.player.id));
    const crimsonIds = new Set(match.crimsonTeam.map(s => s.player.id));

    const benchPlayers = activePlayers.filter(p => !azureIds.has(p.id) && !crimsonIds.has(p.id));

    if (benchPlayers.length === 0) {
      alert("No available bench players to re-roll with!");
      return;
    }

    const candidates = benchPlayers.filter(p => {
       if (role === Role.COACH) {
          return p.roles.includes(Role.COACH);
       }
       return p.isAllRoles || p.roles.includes(role);
    });

    if (candidates.length === 0) {
       alert(`No available bench players found for role: ${role}`);
       return;
    }

    const newPlayer = candidates[Math.floor(Math.random() * candidates.length)];
    const candidateNames = candidates.map(p => p.name);

    setWheelState({
        isOpen: true,
        type: 'reroll',
        team,
        role,
        winnerName: newPlayer.name,
        winnerPlayer: newPlayer,
        candidates: candidateNames
    });
  };

  const handleWheelComplete = () => {
    if (!wheelState) return;

    if (wheelState.type === 'draft') {
        const { team, role } = wheelState;
        setRevealedCards(prev => new Set(prev).add(getCardId(team, role)));
        if (team === 'crimson') {
           setCurrentRoleIndex(prev => prev + 1);
        }
    } else if (wheelState.type === 'reroll' && wheelState.winnerPlayer) {
        onReroll(wheelState.team, wheelState.role, wheelState.winnerPlayer);
    }

    setWheelState(null);
  };

  const handleWheelCancel = () => {
    setWheelState(null);
  };

  const handleInitializeBattle = () => {
    setViewState('transition');
  };

  const handleTransitionComplete = () => {
    setViewState('final');
  };

  const handleMatchDecided = (winner: 'azure' | 'crimson' | null) => {
    if (winner) {
      setWinningTeam(winner);
      setViewState('celebration');
    } else {
      onCompleteMatch(null);
    }
  };

  const handleCelebrationDismiss = () => {
    setViewState('evaluation');
  };

  const handleEvaluationComplete = (mvpId?: string) => {
    onCompleteMatch(winningTeam, mvpId);
  }

  // --- RENDER LOGIC ---

  if (viewState === 'evaluation' && winningTeam) {
    return (
      <EvaluationScreen 
        match={match} 
        winner={winningTeam} 
        onComplete={handleEvaluationComplete} 
      />
    );
  }

  if (viewState === 'celebration' && winningTeam) {
    const winningTeamSlots = winningTeam === 'azure' ? match.azureTeam : match.crimsonTeam;
    return (
      <VictoryCelebration 
        winner={winningTeam} 
        teamSlots={winningTeamSlots}
        onDismiss={handleCelebrationDismiss} 
      />
    );
  }

  if (viewState === 'transition') {
    return (
      <PortalTransition 
        azureTeam={match.azureTeam} 
        crimsonTeam={match.crimsonTeam} 
        onComplete={handleTransitionComplete} 
      />
    );
  }

  if (viewState === 'final') {
    return <MatchSummary match={match} onReset={handleMatchDecided} />;
  }

  // --- DRAFTING VIEW ---

  const renderPlayerCard = (role: Role, roleIndex: number, team: 'azure' | 'crimson') => {
    const teamSlots = team === 'azure' ? match.azureTeam : match.crimsonTeam;
    const player = getPlayerForRole(teamSlots, role)?.player;
    const isRevealed = revealedCards.has(getCardId(team, role));
    const isCoach = role === Role.COACH;

    // HoK Color Palettes
    // If Coach, override with Special White/Silver Theme
    let theme;
    if (isCoach) {
        theme = {
            bg: 'bg-[#1a1a1a]',
            border: 'border-white',
            glow: 'shadow-[0_0_20px_rgba(255,255,255,0.8)]',
            text: 'text-white',
            gradient: 'from-white/20 to-transparent'
        };
    } else {
        theme = team === 'azure' 
          ? {
              bg: 'bg-[#0a1a2f]',
              border: 'border-hok-cyan',
              glow: 'shadow-[0_0_10px_#00d2ff]',
              text: 'text-hok-cyan',
              gradient: 'from-[#00d2ff]/20 to-transparent'
            } 
          : {
              bg: 'bg-[#1a0505]',
              border: 'border-hok-red',
              glow: 'shadow-[0_0_10px_#ef4444]',
              text: 'text-hok-red',
              gradient: 'from-[#c02d2d]/20 to-transparent'
            };
    }

    // State 1: Hidden
    if (!isRevealed) {
       return (
         <div className="h-16 w-full relative overflow-hidden clip-corner-md border border-[#1e3a5f] bg-[#05090f]/80 flex flex-col items-center justify-center opacity-40 group">
            <div className="text-[#1e3a5f] group-hover:text-[#dcb06b]/50 transition-colors duration-500 transform scale-90 opacity-50">
               {RoleIcons[role]}
            </div>
            {/* Tech Scanlines */}
            <div className="absolute inset-0 bg-[url('data:image/svg+xml;base64,PHN2ZyB4bWxucz0iaHR0cDovL3d3dy53My5vcmcvMjAwMC9zdmciIHdpZHRoPSI0IiBoZWlnaHQ9IjQiPgo8cmVjdCB3aWR0aD0iNCIgaGVpZ2h0PSI0IiBmaWxsPSIjZmZmIiBmaWxsLW9wYWNpdHk9IjAuMDUiLz4KPHBhdGggZD0iTTAgNEw0IDBaIiBzdHJva2U9IiMwMDAiIHN0cm9rZS13aWR0aD0iMSIvPgo8L3N2Zz4=')] opacity-20"></div>
         </div>
       );
    }

    // State 2: Revealed (UPDATED LAYOUT FOR TEXT ROLES & MIRRORING)
    return (
      <div className={`relative h-16 w-full animate-slide-in perspective-container group`}>
        <div className={`
            absolute inset-0 clip-corner-md border-l-4 tilt-card
            ${theme.bg} ${theme.border} 
            ${theme.glow}
            shadow-[0_0_15px_rgba(0,0,0,0.5)]
            transition-all duration-300 hover:brightness-110
        `}>
           <div className={`flex flex-col h-full relative z-10 px-4 py-1 justify-center ${team === 'crimson' ? 'items-end text-right' : 'items-start text-left'}`}>

             {/* Text Role Label (Top) */}
             <div className={`mb-0.5 px-2 py-0.5 rounded-sm bg-black/40 border border-white/10 ${theme.text} transform transition-transform duration-500 w-auto inline-block scale-90 origin-${team === 'crimson' ? 'right' : 'left'}`}>
                {RoleIcons[role]}
             </div>

             {/* Name Section */}
             <span className={`block text-lg md:text-xl font-bold text-white truncate font-orbitron drop-shadow-md w-full`}>
                {player?.name}
             </span>

             <div className={`absolute inset-0 bg-gradient-to-r ${theme.gradient} opacity-50 pointer-events-none`}></div>
           </div>

           {/* Decorative Tech Corners */}
           <div className={`absolute top-0 w-8 h-8 border-t border-${isCoach ? 'white' : (team === 'azure' ? 'cyan' : 'red')}-500/50 ${team === 'azure' ? 'left-0' : 'right-0'}`}></div>
           <div className={`absolute bottom-0 w-8 h-8 border-b border-${isCoach ? 'white' : (team === 'azure' ? 'cyan' : 'red')}-500/50 ${team === 'azure' ? 'right-0' : 'left-0'}`}></div>

           {/* Re-roll Button Overlay - Mirrored Position */}
           {/* If Azure (Left Align): Button on Right. If Crimson (Right Align): Button on Left */}
           <button 
             onClick={(e) => { e.stopPropagation(); handleRerollClick(team, role); }}
             className={`absolute top-1 p-1.5 bg-black/50 hover:bg-[#dcb06b] rounded-full transition-colors group-hover:opacity-100 opacity-0 text-white hover:text-black z-50 border border-white/20
                ${team === 'azure' ? 'right-2' : 'left-2'}
             `}
             title="Re-roll this specific slot"
           >
             <svg xmlns="http://www.w3.org/2000/svg" className="h-4 w-4" fill="none" viewBox="0 0 24 24" stroke="currentColor">
               <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M4 4v5h.582m15.356 2A8.001 8.001 0 004.582 9m0 0H9m11 11v-5h-.581m0 0a8.003 8.003 0 01-15.357-2m15.357 2H15" />
             </svg>
           </button>
        </div>
      </div>
    );
  };

  const nextRoleIndex = currentRoleIndex + 1;
  const nextRoleName = nextRoleIndex < displayRoles.length ? displayRoles[nextRoleIndex] : null;
  const isFinished = currentRoleIndex >= displayRoles.length - 1 && revealedCards.size === (match.isCoachMode ? 12 : 10);

  let buttonText = "START DRAFT";
  if (nextRoleName) {
     if (!revealedCards.has(getCardId('azure', nextRoleName))) {
        buttonText = `SELECT AZURE ${nextRoleName.split(' ')[0].toUpperCase()}`;
     } else if (!revealedCards.has(getCardId('crimson', nextRoleName))) {
        buttonText = `SELECT CRIMSON ${nextRoleName.split(' ')[0].toUpperCase()}`;
     } else {
        buttonText = "NEXT LANE";
     }
  }

  // Turret SVG Path
  const TurretIcon = (
    <svg viewBox="0 0 24 24" fill="currentColor" className="w-16 h-16 opacity-30 animate-pulse">
        <path d="M12,2 L2,22 L12,18 L22,22 L12,2 Z" />
        <path d="M12,5 L5,20 L12,17 L19,20 L12,5 Z" fillOpacity="0.5" />
    </svg>
  );

  return (
    <>
      {/* The Spin Wheel Overlay */}
      {wheelState && wheelState.isOpen && (
        <SpinWheel 
          candidates={wheelState.candidates}
          winnerName={wheelState.winnerName}
          team={wheelState.team}
          roleName={wheelState.role}
          onComplete={handleWheelComplete}
          onCancel={handleWheelCancel}
        />
      )}

      <div className="w-full max-w-7xl mx-auto px-4 py-8 pb-32 relative">

        {/* Top Controls: Abort & Instant Result */}
        <div className="absolute top-4 left-4 right-4 z-40 flex justify-between">
           <Button variant="outline" size="sm" onClick={() => onReset()} className="border-red-900/50 text-red-500 hover:bg-red-900/20 text-[10px] px-3">
              <span className="flex items-center gap-2">
                 <svg xmlns="http://www.w3.org/2000/svg" className="h-4 w-4" fill="none" viewBox="0 0 24 24" stroke="currentColor">
                   <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M11 15l-3-3m0 0l3-3m-3 3h8M3 12a9 9 0 1118 0 9 9 0 01-18 0z" />
                 </svg>
                 ABORT DRAFT
              </span>
           </Button>

           {/* Debug / Instant Result Button */}
           {!isFinished && (
             <Button variant="outline" size="sm" onClick={handleSkipAll} className="border-[#dcb06b]/50 text-[#dcb06b] hover:bg-[#dcb06b]/10 text-[10px] px-3">
                <span className="flex items-center gap-2">
                   INSTANT RESULT (DEBUG)
                   <svg xmlns="http://www.w3.org/2000/svg" className="h-4 w-4" fill="none" viewBox="0 0 24 24" stroke="currentColor">
                     <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M13 10V3L4 14h7v7l9-11h-7z" />
                   </svg>
                </span>
             </Button>
           )}
        </div>

        {/* Header Info - PERFECTLY CENTERED */}
        <div className="flex flex-col items-center mb-6 pt-8">
           <div className="flex justify-center w-full mb-4">
              <div className="bg-[#05090f] border border-[#dcb06b]/40 px-8 py-2 clip-diamond relative shadow-[0_0_15px_rgba(220,176,107,0.2)]">
                  <div className="absolute inset-0 bg-[#dcb06b]/5 pointer-events-none"></div>
                  <span className="text-[#dcb06b] font-cinzel font-bold text-xs tracking-widest uppercase block text-center">Room ID</span>
                  <span className="text-xl font-orbitron font-bold text-white tracking-widest text-center block">{match.roomId}</span>
              </div>
           </div>

           <div className="flex justify-between items-center w-full relative max-w-5xl">
              <div className="w-1/3 text-center relative group">
                 <div className="absolute -inset-4 bg-cyan-500/10 blur-xl rounded-full opacity-50 group-hover:opacity-100 transition-opacity"></div>
                 <div className="absolute -left-10 top-0 text-cyan-500/20">{TurretIcon}</div>
                 <h2 className="relative text-2xl md:text-4xl font-cinzel font-black text-transparent bg-clip-text bg-gradient-to-b from-cyan-200 to-cyan-600 drop-shadow-[0_0_15px_rgba(6,182,212,0.8)]">
                  AZURE
                 </h2>
                 <p className="text-[10px] md:text-xs text-cyan-400 font-orbitron tracking-[0.4em] mt-1 opacity-70">GOLEM TEAM</p>
                 <div className="h-1 w-24 bg-cyan-500 mx-auto mt-2 shadow-[0_0_10px_#00d2ff]"></div>
              </div>

              <div className="w-1/3 flex justify-center items-center z-10">
                <div className="relative w-20 h-20 md:w-28 md:h-28 flex items-center justify-center">
                  <div className="absolute inset-0 border-2 border-[#dcb06b] rotate-45 animate-spin-slow bg-[#05090f]"></div>
                  <div className="absolute inset-2 border border-[#dcb06b]/50 rotate-45"></div>
                  <span className="text-3xl font-black italic text-[#dcb06b] font-orbitron z-10 pr-2 pt-1 animate-pulse-fast">VS</span>
                </div>
              </div>

              <div className="w-1/3 text-center relative group">
                 <div className="absolute -inset-4 bg-red-500/10 blur-xl rounded-full opacity-50 group-hover:opacity-100 transition-opacity"></div>
                 <div className="absolute -right-10 top-0 text-red-500/20 transform scale-x-[-1]">{TurretIcon}</div>
                 <h2 className="relative text-2xl md:text-4xl font-cinzel font-black text-transparent bg-clip-text bg-gradient-to-b from-red-200 to-red-600 drop-shadow-[0_0_15px_rgba(220,45,45,0.8)]">
                  CRIMSON
                 </h2>
                 <p className="text-[10px] md:text-xs text-red-400 font-orbitron tracking-[0.4em] mt-1 opacity-70">GOLEM TEAM</p>
                 <div className="h-1 w-24 bg-red-500 mx-auto mt-2 shadow-[0_0_10px_#ef4444]"></div>
              </div>
           </div>
        </div>

        {/* Matchup Grid - Compact Gaps */}
        <div className="relative space-y-2 md:space-y-3">
          <div className="absolute left-1/2 top-0 bottom-0 w-[2px] bg-gradient-to-b from-transparent via-[#dcb06b]/30 to-transparent hidden md:block"></div>

          {displayRoles.map((role, idx) => (
            <div key={role} className="grid grid-cols-1 md:grid-cols-2 gap-2 md:gap-8 items-center">
               <div className="order-1 md:order-none">
                  {renderPlayerCard(role, idx, 'azure')}
               </div>
               <div className="order-2 md:order-none">
                  {renderPlayerCard(role, idx, 'crimson')}
               </div>
            </div>
          ))}
        </div>

        {/* Control Bar */}
        <div className="fixed bottom-0 left-0 right-0 p-8 z-50 flex justify-center items-end bg-gradient-to-t from-[#05090f] via-[#05090f]/90 to-transparent pointer-events-none h-48">
           <div className="pointer-events-auto transform transition-all hover:scale-105">
              {!isFinished ? (
                 <div className="flex flex-col items-center">
                    <button 
                      onClick={handleNext}
                      className="
                        group relative w-72 h-16
                        bg-[#0a1a2f] border border-[#dcb06b] 
                        clip-corner-md
                        flex items-center justify-center
                        text-[#dcb06b] font-cinzel font-bold text-xl tracking-widest
                        overflow-hidden
                        hover:bg-[#dcb06b] hover:text-[#05090f]
                        transition-all duration-300
                        shadow-[0_0_20px_rgba(220,176,107,0.2)]
                      "
                    >
                       <span className="relative z-10">
                         {buttonText}
                       </span>
                       <div className="absolute inset-0 w-full h-full bg-white/20 -translate-x-full group-hover:animate-[shimmer_1s_infinite]"></div>
                    </button>
                 </div>
              ) : (
                 <div className="flex flex-col items-center animate-slide-in">
                    <p className="text-[#00d2ff] font-bold mb-4 uppercase tracking-[0.3em] text-sm font-orbitron drop-shadow-[0_0_5px_rgba(0,210,255,0.8)]">
                       Draft Completed
                    </p>
                    <Button 
                      onClick={handleInitializeBattle} 
                      className="px-12 border-[#dcb06b] shadow-[0_0_20px_#dcb06b] animate-pulse"
                    >
                       INITIALIZE BATTLE
                    </Button>
                 </div>
              )}
           </div>
        </div>
      </div>
    </>
  );
};

import React, { useState, useEffect } from 'react';
import { createPortal } from 'react-dom';
import { Player, Role } from '../types';
import { ROLES_ORDER } from '../constants';

interface PlayerListProps {
  players: Player[];
  onRemove: (id: string) => void;
  onToggleActive: (id: string) => void;
  onEdit: (player: Player) => void;
  isSidebarOpen?: boolean;
}

type FilterType = 'ALL' | 'ACTIVE' | 'BENCH' | Role;

export const PlayerList: React.FC<PlayerListProps> = ({ players, onRemove, onToggleActive, onEdit, isSidebarOpen = true }) => {
  const [filter, setFilter] = useState<FilterType>('ALL');
  const [searchQuery, setSearchQuery] = useState('');
  const [showFilters, setShowFilters] = useState(false);

  // Menu State
  const [menuOpenId, setMenuOpenId] = useState<string | null>(null);
  const [menuPosition, setMenuPosition] = useState<{ top: number; left: number }>({ top: 0, left: 0 });

  // Close menu when clicking outside
  useEffect(() => {
    const handleClickOutside = (e: MouseEvent) => {
        // Don't close if clicking inside the filter container
        if ((e.target as Element).closest('.filter-container')) return;

        setMenuOpenId(null);
        setShowFilters(false);
    };
    const handleScroll = () => {
        setMenuOpenId(null);
        // We might not want to close filters on scroll to allow "show off" while scrolling
    }; 

    if (menuOpenId || showFilters) {
      document.addEventListener('click', handleClickOutside);
      window.addEventListener('scroll', handleScroll, true);
    }
    return () => {
      document.removeEventListener('click', handleClickOutside);
      window.removeEventListener('scroll', handleScroll, true);
    };
  }, [menuOpenId, showFilters]);

  const toggleMenu = (e: React.MouseEvent, id: string) => {
    e.stopPropagation();
    if (menuOpenId === id) {
        setMenuOpenId(null);
    } else {
        const rect = e.currentTarget.getBoundingClientRect();
        setMenuPosition({
            top: rect.bottom + 5,
            left: rect.right - 128
        });
        setMenuOpenId(id);
    }
  };

  const filteredPlayers = players.filter(p => {
    let matchesCategory = true;
    if (filter === 'ACTIVE') matchesCategory = p.isActive;
    else if (filter === 'BENCH') matchesCategory = !p.isActive;
    else if (Object.values(Role).includes(filter as Role)) {
       matchesCategory = p.roles.includes(filter as Role);
    }
    const matchesSearch = p.name.toLowerCase().includes(searchQuery.toLowerCase());
    return matchesCategory && matchesSearch;
  });

  const filters: { label: string; value: FilterType; icon?: React.ReactNode }[] = [
    { label: 'All', value: 'ALL' },
    { label: 'Playing', value: 'ACTIVE' },
    { label: 'Benched', value: 'BENCH' },
    ...ROLES_ORDER.map(r => ({ label: r.split(' ')[0], value: r })),
    { label: 'Coach', value: Role.COACH }
  ];

  const getRoleBadgeStyle = (role: Role) => {
      switch (role) {
          case Role.COACH: return 'text-white border-white bg-white/10 shadow-[0_0_10px_rgba(255,255,255,0.5)]';
          case Role.CLASH: return 'text-orange-400 border-orange-500/50 bg-orange-900/20'; 
          case Role.JUNGLE: return 'text-emerald-400 border-emerald-500/50 bg-emerald-900/20'; 
          case Role.MID: return 'text-blue-400 border-blue-500/50 bg-blue-900/20'; 
          case Role.FARM: return 'text-yellow-400 border-yellow-500/50 bg-yellow-900/20'; 
          case Role.ROAM: return 'text-cyan-400 border-cyan-500/50 bg-cyan-900/20'; 
          default: return 'text-gray-400 border-gray-600 bg-gray-800/30';
      }
  };

  if (players.length === 0) {
    return (
      <div className="h-full min-h-[300px] flex flex-col items-center justify-center border border-dashed border-[#1e3a5f] rounded-lg bg-[#0a1a2f]/30 p-8">
        <div className="w-20 h-20 rounded-full bg-[#1e3a5f]/50 flex items-center justify-center mb-4 border border-[#dcb06b]/20">
           <svg xmlns="http://www.w3.org/2000/svg" className="h-8 w-8 text-[#dcb06b]/50" fill="none" viewBox="0 0 24 24" stroke="currentColor"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M12 4.354a4 4 0 110 5.292M15 21H3v-1a6 6 0 0112 0v1zm0 0h6v-1a6 6 0 00-9-5.197M13 7a4 4 0 11-8 0 4 4 0 018 0z" /></svg>
        </div>
        <p className="text-[#8a9db8] font-cinzel tracking-widest text-sm">Waiting for Challengers</p>
      </div>
    );
  }

  // Adjusted Grid Logic: 3xN when Sidebar Open
  const gridClasses = isSidebarOpen
      ? "grid-cols-1 md:grid-cols-2 lg:grid-cols-3" 
      : "grid-cols-1 md:grid-cols-3 lg:grid-cols-4 xl:grid-cols-5 2xl:grid-cols-6";

  return (
    <div>
      {/* FILTER & SEARCH BAR */}
      <div className="mb-6 flex flex-col md:flex-row gap-4 items-start md:items-center justify-between">

         {/* Filter Menu Container - identified by class for click-outside logic */}
         <div className="relative w-full md:w-auto z-20 filter-container">
             <button 
               onClick={(e) => { e.stopPropagation(); setShowFilters(!showFilters); }}
               className={`
                  flex items-center gap-2 px-4 py-2 border clip-corner-sm transition-all uppercase font-bold text-xs tracking-wider
                  ${showFilters ? 'bg-[#dcb06b] text-[#05090f] border-[#dcb06b]' : 'bg-[#05090f] border-[#1e3a5f] text-[#dcb06b] hover:bg-[#1e3a5f]/50'}
               `}
             >
                <svg xmlns="http://www.w3.org/2000/svg" className="h-4 w-4" fill="none" viewBox="0 0 24 24" stroke="currentColor">
                   <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M3 4a1 1 0 011-1h16a1 1 0 011 1v2.586a1 1 0 01-.293.707l-6.414 6.414a1 1 0 00-.293.707V17l-4 4v-6.586a1 1 0 00-.293-.707L3.293 7.293A1 1 0 013 6.586V4z" />
                </svg>
                {filter === 'ALL' ? 'Filter Roles' : filter}
                <svg xmlns="http://www.w3.org/2000/svg" className={`h-3 w-3 transition-transform ${showFilters ? 'rotate-180' : ''}`} fill="none" viewBox="0 0 24 24" stroke="currentColor">
                   <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M19 9l-7 7-7-7" />
                </svg>
             </button>

             {showFilters && (
                <div className="absolute top-full left-0 mt-2 w-[280px] md:w-[400px] bg-[#05090f]/95 backdrop-blur-md border border-[#dcb06b] clip-corner-sm shadow-[0_10px_40px_rgba(0,0,0,0.8)] p-3 animate-slide-in grid grid-cols-2 md:grid-cols-3 gap-2 z-50">
                    <div className="absolute -top-1 left-6 w-2 h-2 bg-[#dcb06b] rotate-45 border-l border-t border-[#dcb06b] bg-[#05090f]"></div>
                    {filters.map(f => (
                      <button
                        key={f.value}
                        onClick={(e) => { 
                            e.stopPropagation(); 
                            setFilter(f.value); 
                            // Intentionally NOT closing showFilters here to allow rapid switching
                        }}
                        className={`
                          flex items-center justify-center text-center px-3 py-2 text-[10px] uppercase font-bold tracking-wider clip-corner-sm border transition-all
                          ${filter === f.value 
                              ? 'bg-[#dcb06b] text-[#05090f] border-[#dcb06b] shadow-[0_0_10px_#dcb06b]' 
                              : 'bg-transparent text-[#8a9db8] border-[#1e3a5f] hover:border-[#dcb06b] hover:text-white hover:bg-[#1e3a5f]/30'}
                        `}
                      >
                        {f.label}
                      </button>
                    ))}
                </div>
             )}
         </div>

         <div className="relative w-full md:w-64">
             <input 
               type="text" 
               placeholder="Find Player..." 
               value={searchQuery}
               onChange={(e) => setSearchQuery(e.target.value)}
               className="w-full bg-[#05090f] border border-[#1e3a5f] px-3 py-1.5 pl-8 text-xs text-[#f0f4f8] focus:outline-none focus:border-[#dcb06b] clip-corner-sm font-orbitron placeholder-[#4a5f78]"
             />
             <svg xmlns="http://www.w3.org/2000/svg" className="h-4 w-4 absolute left-2 top-1.5 text-[#4a5f78]" fill="none" viewBox="0 0 24 24" stroke="currentColor">
               <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M21 21l-6-6m2-5a7 7 0 11-14 0 7 7 0 0114 0z" />
             </svg>
         </div>
      </div>

      {/* PLAYER GRID */}
      <div className={`grid gap-3 transition-all duration-500 ${gridClasses}`}>
        {filteredPlayers.map(player => {
          const isActive = player.isActive;
          const stats = player.stats || { matchesPlayed: 0, wins: 0, currentStreak: 0, maxStreak: 0 };
          const winRate = stats.matchesPlayed > 0 
            ? Math.round((stats.wins / stats.matchesPlayed) * 100) 
            : 0;

          const streak = stats.currentStreak;
          const isHot = streak >= 3 && streak < 6; 
          const isGodlike = streak >= 6;
          const isMvp = player.isLastMatchMvp;
          const hasCoachRole = player.roles.includes(Role.COACH);

          // --- ANIMATED BORDER LOGIC ---
          let animationLayer = null;
          let glowClass = "";

          if (isActive) {
              if (isMvp) {
                  glowClass = "drop-shadow-[0_0_15px_rgba(251,191,36,0.6)]";
                  animationLayer = (
                      <div className="absolute inset-[-50%] bg-[conic-gradient(from_0deg,transparent_0deg,#fbbf24_90deg,transparent_180deg,#fbbf24_270deg,transparent_360deg)] animate-[spin_4s_linear_infinite] opacity-100"></div>
                  );
              } else if (hasCoachRole) {
                  glowClass = "drop-shadow-[0_0_10px_rgba(255,255,255,0.5)]";
                  animationLayer = (
                      <div className="absolute inset-[-50%] bg-[conic-gradient(from_0deg,transparent_0deg,#ffffff_90deg,transparent_180deg,#ffffff_270deg,transparent_360deg)] animate-[spin_6s_linear_infinite] opacity-80"></div>
                  );
              } else if (isGodlike) {
                  glowClass = "drop-shadow-[0_0_20px_rgba(239,68,68,0.8)]";
                  animationLayer = (
                      <div className="absolute inset-[-50%] bg-[conic-gradient(from_0deg,transparent_0deg,#ef4444_60deg,#7f1d1d_120deg,transparent_180deg,#ef4444_240deg,transparent_360deg)] animate-[spin_2s_linear_infinite] opacity-100"></div>
                  );
              } else if (isHot) {
                  glowClass = "drop-shadow-[0_0_10px_rgba(6,182,212,0.6)]";
                  animationLayer = (
                      <div className="absolute inset-[-50%] bg-[conic-gradient(from_0deg,transparent_0deg,#06b6d4_90deg,transparent_180deg,#06b6d4_270deg,transparent_360deg)] animate-[spin_3s_linear_infinite] opacity-100"></div>
                  );
              }
          }

          const cardBg = isActive && hasCoachRole ? 'bg-[#000000]' : 'bg-[#05090f]';

          return (
            <React.Fragment key={player.id}>
              {menuOpenId === player.id && createPortal(
                <div 
                   className="fixed z-[9999] w-32 bg-[#05090f] border border-[#dcb06b] shadow-[0_0_20px_rgba(0,0,0,0.9)] clip-corner-sm flex flex-col animate-slide-in"
                   style={{ 
                      top: menuPosition.top, 
                      left: menuPosition.left 
                   }}
                   onClick={(e) => e.stopPropagation()}
                >
                    <button 
                      onClick={(e) => { e.stopPropagation(); onToggleActive(player.id); setMenuOpenId(null); }}
                      className="px-3 py-3 text-left text-[10px] uppercase font-bold text-[#f0f4f8] hover:bg-[#dcb06b] hover:text-[#05090f] transition-colors"
                    >
                       {isActive ? 'Bench Player' : 'Activate'}
                    </button>
                    <button 
                      onClick={(e) => { e.stopPropagation(); onEdit(player); setMenuOpenId(null); }}
                      className="px-3 py-3 text-left text-[10px] uppercase font-bold text-[#f0f4f8] hover:bg-[#dcb06b] hover:text-[#05090f] transition-colors"
                    >
                       Edit Details
                    </button>
                    <div className="h-[1px] bg-[#1e3a5f] w-full"></div>
                    <button 
                      onClick={(e) => { e.stopPropagation(); onRemove(player.id); setMenuOpenId(null); }}
                      className="px-3 py-3 text-left text-[10px] uppercase font-bold text-red-500 hover:bg-red-500 hover:text-white transition-colors"
                    >
                       Remove
                    </button>
                 </div>,
                 document.body
              )}

              <div className={`relative group ${glowClass} tilt-card h-full transition-all duration-300`}>

                <div className="absolute inset-0 clip-corner-sm overflow-hidden z-0">
                    <div className="absolute inset-0 bg-[#1e3a5f]"></div>
                    {animationLayer}
                </div>

                <div 
                  className={`
                    absolute inset-[1px] clip-corner-sm z-10 flex flex-col gap-1 p-2
                    ${cardBg}
                    ${!isActive ? 'opacity-50 grayscale hover:opacity-80 transition-opacity' : ''}
                  `}
                >

                  <div className="flex justify-between items-start gap-2">

                     <div className="flex-1 min-w-0">
                        {/* Name */}
                        <div className="flex items-center gap-2 mb-1">
                            <div 
                                className={`text-lg font-bold font-orbitron tracking-wide leading-none truncate ${isMvp ? 'text-yellow-400' : 'text-[#e2e8f0]'}`}
                                title={player.name}
                            >
                                {player.name}
                            </div>

                            {/* Badges */}
                            {isMvp && <div className="text-[8px] font-black bg-gradient-to-r from-yellow-400 to-yellow-600 text-black px-1.5 py-0.5 rounded-sm shadow-[0_0_10px_#fbbf24] animate-pulse">MVP</div>}

                            {!isMvp && isGodlike && isActive && (
                               <span className="text-[8px] text-red-500 animate-pulse font-black">GODLIKE</span>
                            )}
                        </div>

                        <div className="flex flex-wrap gap-1">
                            {hasCoachRole ? (
                                // Exclusive Coach Badge - If player is Coach, ONLY show this.
                                <div className={`px-1.5 py-0.5 border clip-corner-sm ${getRoleBadgeStyle(Role.COACH)}`}>
                                    <span className="text-[7px] uppercase font-bold leading-none whitespace-nowrap opacity-100">
                                        COACH
                                    </span>
                                </div>
                            ) : (
                                // Standard Role Rendering
                                player.isAllRoles ? (
                                  <div className={`px-1.5 py-0.5 border clip-corner-sm bg-purple-900/20 text-purple-400 border-purple-500/30`}>
                                    <span className="text-[8px] font-bold uppercase whitespace-nowrap">All Roles</span>
                                  </div>
                                ) : (
                                  player.roles.map(role => (
                                      <div key={role} className={`px-1.5 py-0.5 border clip-corner-sm ${getRoleBadgeStyle(role)}`}>
                                          <span className="text-[7px] uppercase font-bold leading-none whitespace-nowrap opacity-100">
                                              {role.split(' ')[0]}
                                          </span>
                                      </div>
                                  ))
                                )
                            )}
                        </div>
                     </div>

                     <div className="relative shrink-0">
                        <button 
                           onClick={(e) => toggleMenu(e, player.id)}
                           className={`p-1 text-[#4a5f78] hover:text-[#dcb06b] hover:bg-white/5 transition-colors rounded`}
                        >
                           <svg xmlns="http://www.w3.org/2000/svg" className="h-4 w-4" fill="none" viewBox="0 0 24 24" stroke="currentColor">
                             <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M12 5v.01M12 12v.01M12 19v.01M12 6a1 1 0 110-2 1 1 0 010 2zm0 7a1 1 0 110-2 1 1 0 010 2zm0 7a1 1 0 110-2 1 1 0 010 2z" />
                           </svg>
                        </button>
                     </div>
                  </div>

                  {/* Stats - Added Flex Wrap for dynamic adjustment */}
                  {stats.matchesPlayed > 0 && (
                    <div className={`flex flex-wrap items-center gap-x-3 gap-y-1 text-[9px] font-mono mt-auto pt-2 border-t border-white/5 ${isActive ? 'text-gray-400' : 'text-[#4a5f78]/50'}`}>
                        <div className="whitespace-nowrap">
                          Match: <span className="text-[#f0f4f8]">{stats.matchesPlayed}</span>
                        </div>
                        <div className="whitespace-nowrap">
                          WR: <span className={`${winRate >= 60 ? 'text-[#dcb06b]' : winRate >= 50 ? 'text-[#f0f4f8]' : 'text-red-400'}`}>{winRate}%</span>
                        </div>
                        {streak > 1 && (
                          <div className="whitespace-nowrap ml-auto">
                              <span className={`${isGodlike ? 'text-red-500 font-black animate-pulse' : isHot ? 'text-cyan-400 font-bold' : 'text-gray-400'}`}>
                                  {streak} Win Streak
                              </span>
                          </div>
                        )}
                    </div>
                  )}

                  {!isActive && (
                    <div className="absolute inset-0 flex items-center justify-center pointer-events-none z-10">
                      <span className="text-[#0a1a2f] font-black text-xl -rotate-12 opacity-40 uppercase tracking-widest select-none bg-[#dcb06b] px-1 mix-blend-screen">Benched</span>
                    </div>
                  )}
                </div>

                <div className="invisible p-2 flex flex-col gap-1 min-h-[72px]">
                   <div className="text-lg">Placeholder</div>
                   <div className="text-[7px]">Roles</div>
                </div>
              </div>
            </React.Fragment>
          );
        })}
      </div>
    </div>
  );
};

import React, { useState, useEffect } from 'react';
import { createPortal } from 'react-dom';
import { Player, Role } from '../types';
import { ROLES_ORDER } from '../constants';

interface PlayerListProps {
  players: Player[];
  onRemove: (id: string) => void;
  onToggleActive: (id: string) => void;
  onEdit: (player: Player) => void;
  isSidebarOpen?: boolean;
}

type FilterType = 'ALL' | 'ACTIVE' | 'BENCH' | Role;

export const PlayerList: React.FC<PlayerListProps> = ({ players, onRemove, onToggleActive, onEdit, isSidebarOpen = true }) => {
  const [filter, setFilter] = useState<FilterType>('ALL');
  const [searchQuery, setSearchQuery] = useState('');
  const [showFilters, setShowFilters] = useState(false);

  // Menu State
  const [menuOpenId, setMenuOpenId] = useState<string | null>(null);
  const [menuPosition, setMenuPosition] = useState<{ top: number; left: number }>({ top: 0, left: 0 });

  // Close menu when clicking outside
  useEffect(() => {
    const handleClickOutside = (e: MouseEvent) => {
        // Don't close if clicking inside the filter container
        if ((e.target as Element).closest('.filter-container')) return;

        setMenuOpenId(null);
        setShowFilters(false);
    };
    const handleScroll = () => {
        setMenuOpenId(null);
        // We might not want to close filters on scroll to allow "show off" while scrolling
    }; 

    if (menuOpenId || showFilters) {
      document.addEventListener('click', handleClickOutside);
      window.addEventListener('scroll', handleScroll, true);
    }
    return () => {
      document.removeEventListener('click', handleClickOutside);
      window.removeEventListener('scroll', handleScroll, true);
    };
  }, [menuOpenId, showFilters]);

  const toggleMenu = (e: React.MouseEvent, id: string) => {
    e.stopPropagation();
    if (menuOpenId === id) {
        setMenuOpenId(null);
    } else {
        const rect = e.currentTarget.getBoundingClientRect();
        setMenuPosition({
            top: rect.bottom + 5,
            left: rect.right - 128
        });
        setMenuOpenId(id);
    }
  };

  const filteredPlayers = players.filter(p => {
    let matchesCategory = true;
    if (filter === 'ACTIVE') matchesCategory = p.isActive;
    else if (filter === 'BENCH') matchesCategory = !p.isActive;
    else if (Object.values(Role).includes(filter as Role)) {
       matchesCategory = p.roles.includes(filter as Role);
    }
    const matchesSearch = p.name.toLowerCase().includes(searchQuery.toLowerCase());
    return matchesCategory && matchesSearch;
  });

  const filters: { label: string; value: FilterType; icon?: React.ReactNode }[] = [
    { label: 'All', value: 'ALL' },
    { label: 'Playing', value: 'ACTIVE' },
    { label: 'Benched', value: 'BENCH' },
    ...ROLES_ORDER.map(r => ({ label: r.split(' ')[0], value: r })),
    { label: 'Coach', value: Role.COACH }
  ];

  const getRoleBadgeStyle = (role: Role) => {
      switch (role) {
          case Role.COACH: return 'text-white border-white bg-white/10 shadow-[0_0_10px_rgba(255,255,255,0.5)]';
          case Role.CLASH: return 'text-orange-400 border-orange-500/50 bg-orange-900/20'; 
          case Role.JUNGLE: return 'text-emerald-400 border-emerald-500/50 bg-emerald-900/20'; 
          case Role.MID: return 'text-blue-400 border-blue-500/50 bg-blue-900/20'; 
          case Role.FARM: return 'text-yellow-400 border-yellow-500/50 bg-yellow-900/20'; 
          case Role.ROAM: return 'text-cyan-400 border-cyan-500/50 bg-cyan-900/20'; 
          default: return 'text-gray-400 border-gray-600 bg-gray-800/30';
      }
  };

  if (players.length === 0) {
    return (
      <div className="h-full min-h-[300px] flex flex-col items-center justify-center border border-dashed border-[#1e3a5f] rounded-lg bg-[#0a1a2f]/30 p-8">
        <div className="w-20 h-20 rounded-full bg-[#1e3a5f]/50 flex items-center justify-center mb-4 border border-[#dcb06b]/20">
           <svg xmlns="http://www.w3.org/2000/svg" className="h-8 w-8 text-[#dcb06b]/50" fill="none" viewBox="0 0 24 24" stroke="currentColor"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M12 4.354a4 4 0 110 5.292M15 21H3v-1a6 6 0 0112 0v1zm0 0h6v-1a6 6 0 00-9-5.197M13 7a4 4 0 11-8 0 4 4 0 018 0z" /></svg>
        </div>
        <p className="text-[#8a9db8] font-cinzel tracking-widest text-sm">Waiting for Challengers</p>
      </div>
    );
  }

  // Adjusted Grid Logic: 3xN when Sidebar Open
  const gridClasses = isSidebarOpen
      ? "grid-cols-1 md:grid-cols-2 lg:grid-cols-3" 
      : "grid-cols-1 md:grid-cols-3 lg:grid-cols-4 xl:grid-cols-5 2xl:grid-cols-6";

  return (
    <div>
      {/* FILTER & SEARCH BAR */}
      <div className="mb-6 flex flex-col md:flex-row gap-4 items-start md:items-center justify-between">

         {/* Filter Menu Container - identified by class for click-outside logic */}
         <div className="relative w-full md:w-auto z-20 filter-container">
             <button 
               onClick={(e) => { e.stopPropagation(); setShowFilters(!showFilters); }}
               className={`
                  flex items-center gap-2 px-4 py-2 border clip-corner-sm transition-all uppercase font-bold text-xs tracking-wider
                  ${showFilters ? 'bg-[#dcb06b] text-[#05090f] border-[#dcb06b]' : 'bg-[#05090f] border-[#1e3a5f] text-[#dcb06b] hover:bg-[#1e3a5f]/50'}
               `}
             >
                <svg xmlns="http://www.w3.org/2000/svg" className="h-4 w-4" fill="none" viewBox="0 0 24 24" stroke="currentColor">
                   <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M3 4a1 1 0 011-1h16a1 1 0 011 1v2.586a1 1 0 01-.293.707l-6.414 6.414a1 1 0 00-.293.707V17l-4 4v-6.586a1 1 0 00-.293-.707L3.293 7.293A1 1 0 013 6.586V4z" />
                </svg>
                {filter === 'ALL' ? 'Filter Roles' : filter}
                <svg xmlns="http://www.w3.org/2000/svg" className={`h-3 w-3 transition-transform ${showFilters ? 'rotate-180' : ''}`} fill="none" viewBox="0 0 24 24" stroke="currentColor">
                   <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M19 9l-7 7-7-7" />
                </svg>
             </button>

             {showFilters && (
                <div className="absolute top-full left-0 mt-2 w-[280px] md:w-[400px] bg-[#05090f]/95 backdrop-blur-md border border-[#dcb06b] clip-corner-sm shadow-[0_10px_40px_rgba(0,0,0,0.8)] p-3 animate-slide-in grid grid-cols-2 md:grid-cols-3 gap-2 z-50">
                    <div className="absolute -top-1 left-6 w-2 h-2 bg-[#dcb06b] rotate-45 border-l border-t border-[#dcb06b] bg-[#05090f]"></div>
                    {filters.map(f => (
                      <button
                        key={f.value}
                        onClick={(e) => { 
                            e.stopPropagation(); 
                            setFilter(f.value); 
                            // Intentionally NOT closing showFilters here to allow rapid switching
                        }}
                        className={`
                          flex items-center justify-center text-center px-3 py-2 text-[10px] uppercase font-bold tracking-wider clip-corner-sm border transition-all
                          ${filter === f.value 
                              ? 'bg-[#dcb06b] text-[#05090f] border-[#dcb06b] shadow-[0_0_10px_#dcb06b]' 
                              : 'bg-transparent text-[#8a9db8] border-[#1e3a5f] hover:border-[#dcb06b] hover:text-white hover:bg-[#1e3a5f]/30'}
                        `}
                      >
                        {f.label}
                      </button>
                    ))}
                </div>
             )}
         </div>

         <div className="relative w-full md:w-64">
             <input 
               type="text" 
               placeholder="Find Player..." 
               value={searchQuery}
               onChange={(e) => setSearchQuery(e.target.value)}
               className="w-full bg-[#05090f] border border-[#1e3a5f] px-3 py-1.5 pl-8 text-xs text-[#f0f4f8] focus:outline-none focus:border-[#dcb06b] clip-corner-sm font-orbitron placeholder-[#4a5f78]"
             />
             <svg xmlns="http://www.w3.org/2000/svg" className="h-4 w-4 absolute left-2 top-1.5 text-[#4a5f78]" fill="none" viewBox="0 0 24 24" stroke="currentColor">
               <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M21 21l-6-6m2-5a7 7 0 11-14 0 7 7 0 0114 0z" />
             </svg>
         </div>
      </div>

      {/* PLAYER GRID */}
      <div className={`grid gap-3 transition-all duration-500 ${gridClasses}`}>
        {filteredPlayers.map(player => {
          const isActive = player.isActive;
          const stats = player.stats || { matchesPlayed: 0, wins: 0, currentStreak: 0, maxStreak: 0 };
          const winRate = stats.matchesPlayed > 0 
            ? Math.round((stats.wins / stats.matchesPlayed) * 100) 
            : 0;

          const streak = stats.currentStreak;
          const isHot = streak >= 3 && streak < 6; 
          const isGodlike = streak >= 6;
          const isMvp = player.isLastMatchMvp;
          const hasCoachRole = player.roles.includes(Role.COACH);

          // --- ANIMATED BORDER LOGIC ---
          let animationLayer = null;
          let glowClass = "";

          if (isActive) {
              if (isMvp) {
                  glowClass = "drop-shadow-[0_0_15px_rgba(251,191,36,0.6)]";
                  animationLayer = (
                      <div className="absolute inset-[-50%] bg-[conic-gradient(from_0deg,transparent_0deg,#fbbf24_90deg,transparent_180deg,#fbbf24_270deg,transparent_360deg)] animate-[spin_4s_linear_infinite] opacity-100"></div>
                  );
              } else if (hasCoachRole) {
                  glowClass = "drop-shadow-[0_0_10px_rgba(255,255,255,0.5)]";
                  animationLayer = (
                      <div className="absolute inset-[-50%] bg-[conic-gradient(from_0deg,transparent_0deg,#ffffff_90deg,transparent_180deg,#ffffff_270deg,transparent_360deg)] animate-[spin_6s_linear_infinite] opacity-80"></div>
                  );
              } else if (isGodlike) {
                  glowClass = "drop-shadow-[0_0_20px_rgba(239,68,68,0.8)]";
                  animationLayer = (
                      <div className="absolute inset-[-50%] bg-[conic-gradient(from_0deg,transparent_0deg,#ef4444_60deg,#7f1d1d_120deg,transparent_180deg,#ef4444_240deg,transparent_360deg)] animate-[spin_2s_linear_infinite] opacity-100"></div>
                  );
              } else if (isHot) {
                  glowClass = "drop-shadow-[0_0_10px_rgba(6,182,212,0.6)]";
                  animationLayer = (
                      <div className="absolute inset-[-50%] bg-[conic-gradient(from_0deg,transparent_0deg,#06b6d4_90deg,transparent_180deg,#06b6d4_270deg,transparent_360deg)] animate-[spin_3s_linear_infinite] opacity-100"></div>
                  );
              }
          }

          const cardBg = isActive && hasCoachRole ? 'bg-[#000000]' : 'bg-[#05090f]';

          return (
            <React.Fragment key={player.id}>
              {menuOpenId === player.id && createPortal(
                <div 
                   className="fixed z-[9999] w-32 bg-[#05090f] border border-[#dcb06b] shadow-[0_0_20px_rgba(0,0,0,0.9)] clip-corner-sm flex flex-col animate-slide-in"
                   style={{ 
                      top: menuPosition.top, 
                      left: menuPosition.left 
                   }}
                   onClick={(e) => e.stopPropagation()}
                >
                    <button 
                      onClick={(e) => { e.stopPropagation(); onToggleActive(player.id); setMenuOpenId(null); }}
                      className="px-3 py-3 text-left text-[10px] uppercase font-bold text-[#f0f4f8] hover:bg-[#dcb06b] hover:text-[#05090f] transition-colors"
                    >
                       {isActive ? 'Bench Player' : 'Activate'}
                    </button>
                    <button 
                      onClick={(e) => { e.stopPropagation(); onEdit(player); setMenuOpenId(null); }}
                      className="px-3 py-3 text-left text-[10px] uppercase font-bold text-[#f0f4f8] hover:bg-[#dcb06b] hover:text-[#05090f] transition-colors"
                    >
                       Edit Details
                    </button>
                    <div className="h-[1px] bg-[#1e3a5f] w-full"></div>
                    <button 
                      onClick={(e) => { e.stopPropagation(); onRemove(player.id); setMenuOpenId(null); }}
                      className="px-3 py-3 text-left text-[10px] uppercase font-bold text-red-500 hover:bg-red-500 hover:text-white transition-colors"
                    >
                       Remove
                    </button>
                 </div>,
                 document.body
              )}

              <div className={`relative group ${glowClass} tilt-card h-full transition-all duration-300`}>

                <div className="absolute inset-0 clip-corner-sm overflow-hidden z-0">
                    <div className="absolute inset-0 bg-[#1e3a5f]"></div>
                    {animationLayer}
                </div>

                <div 
                  className={`
                    absolute inset-[1px] clip-corner-sm z-10 flex flex-col gap-1 p-2
                    ${cardBg}
                    ${!isActive ? 'opacity-50 grayscale hover:opacity-80 transition-opacity' : ''}
                  `}
                >

                  <div className="flex justify-between items-start gap-2">

                     <div className="flex-1 min-w-0">
                        {/* Name */}
                        <div className="flex items-center gap-2 mb-1">
                            <div 
                                className={`text-lg font-bold font-orbitron tracking-wide leading-none truncate ${isMvp ? 'text-yellow-400' : 'text-[#e2e8f0]'}`}
                                title={player.name}
                            >
                                {player.name}
                            </div>

                            {/* Badges */}
                            {isMvp && <div className="text-[8px] font-black bg-gradient-to-r from-yellow-400 to-yellow-600 text-black px-1.5 py-0.5 rounded-sm shadow-[0_0_10px_#fbbf24] animate-pulse">MVP</div>}

                            {!isMvp && isGodlike && isActive && (
                               <span className="text-[8px] text-red-500 animate-pulse font-black">GODLIKE</span>
                            )}
                        </div>

                        <div className="flex flex-wrap gap-1">
                            {hasCoachRole ? (
                                // Exclusive Coach Badge - If player is Coach, ONLY show this.
                                <div className={`px-1.5 py-0.5 border clip-corner-sm ${getRoleBadgeStyle(Role.COACH)}`}>
                                    <span className="text-[7px] uppercase font-bold leading-none whitespace-nowrap opacity-100">
                                        COACH
                                    </span>
                                </div>
                            ) : (
                                // Standard Role Rendering
                                player.isAllRoles ? (
                                  <div className={`px-1.5 py-0.5 border clip-corner-sm bg-purple-900/20 text-purple-400 border-purple-500/30`}>
                                    <span className="text-[8px] font-bold uppercase whitespace-nowrap">All Roles</span>
                                  </div>
                                ) : (
                                  player.roles.map(role => (
                                      <div key={role} className={`px-1.5 py-0.5 border clip-corner-sm ${getRoleBadgeStyle(role)}`}>
                                          <span className="text-[7px] uppercase font-bold leading-none whitespace-nowrap opacity-100">
                                              {role.split(' ')[0]}
                                          </span>
                                      </div>
                                  ))
                                )
                            )}
                        </div>
                     </div>

                     <div className="relative shrink-0">
                        <button 
                           onClick={(e) => toggleMenu(e, player.id)}
                           className={`p-1 text-[#4a5f78] hover:text-[#dcb06b] hover:bg-white/5 transition-colors rounded`}
                        >
                           <svg xmlns="http://www.w3.org/2000/svg" className="h-4 w-4" fill="none" viewBox="0 0 24 24" stroke="currentColor">
                             <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M12 5v.01M12 12v.01M12 19v.01M12 6a1 1 0 110-2 1 1 0 010 2zm0 7a1 1 0 110-2 1 1 0 010 2zm0 7a1 1 0 110-2 1 1 0 010 2z" />
                           </svg>
                        </button>
                     </div>
                  </div>

                  {/* Stats - ALWAYS Visible */}
                  <div className={`flex flex-wrap items-center gap-x-3 gap-y-1 text-[9px] font-mono mt-auto pt-2 border-t border-white/5 ${isActive ? 'text-gray-400' : 'text-[#4a5f78]/50'}`}>
                      <div className="whitespace-nowrap">
                        Match: <span className="text-[#f0f4f8]">{stats.matchesPlayed}</span>
                      </div>
                      <div className="whitespace-nowrap">
                        WR: <span className={`${winRate >= 60 ? 'text-[#dcb06b]' : winRate >= 50 ? 'text-[#f0f4f8]' : 'text-red-400'}`}>{winRate}%</span>
                      </div>
                      {streak > 1 && (
                        <div className="whitespace-nowrap ml-auto">
                            <span className={`${isGodlike ? 'text-red-500 font-black animate-pulse' : isHot ? 'text-cyan-400 font-bold' : 'text-gray-400'}`}>
                                {streak} Win Streak
                            </span>
                        </div>
                      )}
                  </div>

                  {!isActive && (
                    <div className="absolute inset-0 flex items-center justify-center pointer-events-none z-10">
                      <span className="text-[#0a1a2f] font-black text-xl -rotate-12 opacity-40 uppercase tracking-widest select-none bg-[#dcb06b] px-1 mix-blend-screen">Benched</span>
                    </div>
                  )}
                </div>

                <div className="invisible p-2 flex flex-col gap-1 min-h-[72px]">
                   <div className="text-lg">Placeholder</div>
                   <div className="text-[7px]">Roles</div>
                </div>
              </div>
            </React.Fragment>
          );
        })}
      </div>
    </div>
  );
};

import React, { useEffect, useState } from 'react';
import { TeamSlot, Role } from '../types';
import { Button } from './Button';
import { RoleIcons } from '../constants';

interface PortalTransitionProps {
  onComplete: () => void;
  azureTeam: TeamSlot[];
  crimsonTeam: TeamSlot[];
}

export const PortalTransition: React.FC<PortalTransitionProps> = ({ onComplete, azureTeam, crimsonTeam }) => {
  const [stage, setStage] = useState(0);
  const [elapsedSeconds, setElapsedSeconds] = useState(0);

  useEffect(() => {
    // Sequence:
    // 0ms: Start (Empty)
    // 100ms: Slide In (Stage 1)
    // 800ms: Impact/Shake (Stage 2) - Rosters Fade In

    const t1 = setTimeout(() => setStage(1), 100);
    const t2 = setTimeout(() => setStage(2), 800);

    // Timer Interval
    const interval = setInterval(() => {
       setElapsedSeconds(prev => prev + 1);
    }, 1000);

    return () => {
        clearTimeout(t1);
        clearTimeout(t2);
        clearInterval(interval);
    };
  }, []);

  const handleNext = () => {
    setStage(3); // Fade out
    setTimeout(() => {
        onComplete();
    }, 500);
  };

  const formatTime = (totalSeconds: number) => {
    const mins = Math.floor(totalSeconds / 60);
    const secs = totalSeconds % 60;
    return `${mins.toString().padStart(2, '0')}:${secs.toString().padStart(2, '0')}`;
  };

  const renderTeamSection = (teamSlots: TeamSlot[], alignment: 'left' | 'right') => {
      // Separate Coach from Players
      const coachSlot = teamSlots.find(s => s.role === Role.COACH);
      const playerSlots = teamSlots.filter(s => s.role !== Role.COACH);

      const isRightAligned = alignment === 'right'; // Azure (Left Panel) aligns content to the right

      // Styling config based on side (Azure vs Crimson) - PLAYERS ONLY
      const mainColor = isRightAligned ? '#00d2ff' : '#ef4444'; // Cyan vs Red
      const borderColor = isRightAligned ? 'border-[#00d2ff]' : 'border-[#ef4444]';
      const bgColor = isRightAligned ? 'bg-[#00d2ff]/10' : 'bg-[#ef4444]/10';
      const textColor = isRightAligned ? 'text-[#00d2ff]' : 'text-[#ef4444]';
      const gradient = isRightAligned 
         ? 'bg-gradient-to-l from-[#00d2ff]/20 to-transparent' 
         : 'bg-gradient-to-r from-[#ef4444]/20 to-transparent';

      return (
        <div className={`flex flex-col ${isRightAligned ? 'items-end' : 'items-start'} relative`}>

            {/* COACH SECTION (TOP) */}
            {coachSlot && (
                <div className={`mb-6 relative flex flex-col ${isRightAligned ? 'items-end' : 'items-start'}`}>
                    {/* Connecting Line from Coach to Players */}
                    <div className={`
                        absolute top-full w-[2px] h-full bg-gradient-to-b from-white via-white/50 to-transparent z-0
                        ${isRightAligned ? 'right-8' : 'left-8'}
                        ${stage >= 2 ? 'opacity-50' : 'opacity-0'} transition-opacity duration-1000
                    `}></div>

                    <div 
                        className={`
                            flex items-center gap-4 transition-all duration-700 transform relative z-10
                            ${stage >= 2 ? 'translate-x-0 opacity-100' : (isRightAligned ? '-translate-x-10' : 'translate-x-10') + ' opacity-0'}
                            ${!isRightAligned ? 'flex-row-reverse' : ''}
                        `}
                    >
                         {/* Name Card - WHITE THEME */}
                         <div className={`
                            bg-white/10 border-white/50 py-3 px-6 clip-corner-sm relative group overflow-hidden min-w-[220px] 
                            ${isRightAligned ? 'text-right border-r-2' : 'text-left border-l-2'}
                            shadow-[0_0_15px_rgba(255,255,255,0.3)]
                         `}>
                            <div className={`absolute inset-0 ${isRightAligned ? 'bg-gradient-to-l' : 'bg-gradient-to-r'} from-white/20 to-transparent opacity-0 group-hover:opacity-100 transition-opacity`}></div>
                            <span className="block text-[9px] uppercase tracking-widest text-white/70 mb-0.5 font-bold">Team Coach</span>
                            <span className="relative z-10 text-white font-orbitron font-bold text-xl md:text-2xl drop-shadow-md tracking-wide">
                              {coachSlot.player.name}
                            </span>
                         </div>

                         {/* Coach Icon */}
                         <div className="relative">
                           <div className="px-2 py-2 flex items-center justify-center bg-[#0a1a2f] border border-white text-white clip-corner-sm shadow-[0_0_15px_white] min-w-[3.5rem] h-[3.5rem]">
                              <div className="scale-90">{RoleIcons[Role.COACH]}</div>
                           </div>
                         </div>
                    </div>
                </div>
            )}

            {/* PLAYERS SECTION */}
            <div className={`space-y-4 ${coachSlot ? 'mt-2' : ''}`}>
                {playerSlots.map((slot, idx) => (
                    <div 
                    key={idx} 
                    className={`
                        flex items-center gap-4 transition-all duration-500 transform
                        ${stage >= 2 ? 'translate-x-0 opacity-100' : (isRightAligned ? '-translate-x-10' : 'translate-x-10') + ' opacity-0'}
                        ${!isRightAligned ? 'flex-row-reverse' : ''}
                    `}
                    style={{ transitionDelay: `${800 + (idx * 100)}ms` }}
                    >
                        {/* Name Card */}
                        <div className={`
                            ${bgColor} ${isRightAligned ? 'border-r-2 pr-4 pl-8 text-right' : 'border-l-2 pl-4 pr-8 text-left'} 
                            ${borderColor} py-2 clip-corner-sm relative group overflow-hidden min-w-[200px]
                        `}>
                            <div className={`absolute inset-0 ${gradient} opacity-0 group-hover:opacity-100 transition-opacity`}></div>
                            <span className="relative z-10 text-white font-orbitron font-bold text-lg md:text-xl drop-shadow-md tracking-wide">
                                {slot.player.name}
                            </span>
                        </div>

                        {/* Role Icon/Badge */}
                        <div className="relative">
                            <div className={`px-2 py-2 flex items-center justify-center bg-[#0a1a2f] border ${borderColor} ${textColor} clip-corner-sm shadow-[0_0_10px_currentColor] min-w-[3rem]`}>
                                <div className="scale-75">{RoleIcons[slot.role]}</div>
                            </div>
                        </div>
                    </div>
                ))}
            </div>
        </div>
      );
  };

  return (
    <div className="fixed inset-0 z-[100] bg-black flex items-center justify-center overflow-hidden font-inter">

        {/* Background Flash on Impact */}
        <div className={`
            absolute inset-0 bg-white pointer-events-none z-50
            ${stage === 2 ? 'animate-[impact-flash_0.5s_ease-out_forwards]' : 'opacity-0'}
        `}></div>

        {/* Shake Container */}
        <div className={`
            absolute inset-0 flex items-center justify-center w-full h-full
            ${stage === 2 ? 'animate-[clash-shake_0.5s_ease-in-out]' : ''}
            transition-opacity duration-500
            ${stage === 3 ? 'opacity-0' : 'opacity-100'}
        `}>

            {/* LEFT SIDE - AZURE GOLEM */}
            <div className={`
                absolute left-0 top-0 bottom-0 w-1/2 
                bg-gradient-to-r from-[#0a1a2f] to-[#00d2ff]/30
                flex flex-col items-end justify-center
                border-r-4 border-[#00d2ff]
                pr-8 md:pr-48
                transform transition-all duration-700 ease-in
                ${stage >= 1 ? 'translate-x-0' : '-translate-x-full'}
            `}>
                <div className="text-right w-full max-w-xl">
                    <div className="text-[#00d2ff] font-cinzel font-black text-3xl md:text-5xl tracking-[0.1em] drop-shadow-[0_0_20px_#00d2ff] whitespace-nowrap mb-8 relative">
                        AZURE GOLEM
                        <div className="absolute -bottom-2 right-0 w-1/2 h-1 bg-[#00d2ff] shadow-[0_0_10px_#00d2ff]"></div>
                    </div>

                    {renderTeamSection(azureTeam, 'right')}
                </div>
            </div>

            {/* RIGHT SIDE - CRIMSON GOLEM */}
            <div className={`
                absolute right-0 top-0 bottom-0 w-1/2 
                bg-gradient-to-l from-[#1a0505] to-[#ef4444]/30
                flex flex-col items-start justify-center
                border-l-4 border-[#ef4444]
                pl-8 md:pl-48
                transform transition-all duration-700 ease-in
                ${stage >= 1 ? 'translate-x-0' : 'translate-x-full'}
            `}>
                <div className="text-left w-full max-w-xl">
                    <div className="text-[#ef4444] font-cinzel font-black text-3xl md:text-5xl tracking-[0.1em] drop-shadow-[0_0_20px_#ef4444] whitespace-nowrap mb-8 relative">
                        CRIMSON GOLEM
                        <div className="absolute -bottom-2 left-0 w-1/2 h-1 bg-[#ef4444] shadow-[0_0_10px_#ef4444]"></div>
                    </div>

                    {renderTeamSection(crimsonTeam, 'left')}
                </div>
            </div>

            {/* CENTER VS & Loading State */}
            <div className={`
                absolute z-40 flex flex-col items-center justify-center transform transition-all duration-300
                ${stage >= 2 ? 'scale-100 opacity-100' : 'scale-0 opacity-0'}
            `}>
                <div className="relative w-24 h-24 md:w-32 md:h-32 flex items-center justify-center mb-8">
                    <div className="absolute inset-0 bg-[#dcb06b] rotate-45 animate-pulse"></div>
                    <div className="absolute inset-1 bg-black rotate-45"></div>
                    <span className="relative z-10 text-[#dcb06b] font-orbitron font-black text-4xl md:text-5xl italic">VS</span>
                </div>

                {/* Loading / Timer UI */}
                <div className="flex flex-col items-center gap-2 mb-8 bg-black/50 p-4 rounded-lg backdrop-blur-sm border border-[#dcb06b]/30">
                    <div className="flex items-center gap-2">
                        <div className="w-4 h-4 border-2 border-[#dcb06b] border-t-transparent rounded-full animate-spin"></div>
                        <span className="text-[#dcb06b] text-xs font-orbitron tracking-widest uppercase animate-pulse">Match in Progress</span>
                    </div>
                    <div className="text-white font-mono text-2xl tracking-widest font-bold">
                       {formatTime(elapsedSeconds)}
                    </div>
                </div>

                <Button onClick={handleNext} className="px-8 border-[#dcb06b] shadow-[0_0_15px_#dcb06b] hover:scale-110">
                    ENTER BATTLEFIELD
                </Button>
            </div>

        </div>

        {/* Particles / Debris (Simple CSS) */}
        {stage >= 2 && (
            <div className="absolute inset-0 pointer-events-none overflow-hidden">
                <div className="absolute top-1/2 left-1/2 w-1 h-20 bg-[#dcb06b] rotate-45 animate-[fly-out_0.5s_ease-out_forwards]"></div>
            </div>
        )}
    </div>
  );
};

import React, { useState, useRef } from 'react';
import { Player, MatchResult, Role, MatchHistoryEntry } from './types';
import { PlayerForm } from './components/PlayerForm';
import { PlayerList } from './components/PlayerList';
import { MatchDisplay } from './components/MatchDisplay';
import { EditPlayerModal } from './components/EditPlayerModal';
import { HistoryList } from './components/HistoryList';
import { generateMatch } from './utils/matchmaker';
import { Button } from './components/Button';
import { BackgroundParticles } from './components/BackgroundParticles';

// Quick Fill Data: Honor of Kings Heroes
const HOK_HEROES = [
  { name: "Arthur", roles: [Role.CLASH] },
  { name: "Sun Ce", roles: [Role.CLASH, Role.JUNGLE] },
  { name: "Kaizer", roles: [Role.CLASH, Role.JUNGLE] },
  { name: "Biron", roles: [Role.CLASH] },
  { name: "Li Xin", roles: [Role.CLASH] },
  { name: "Charlotte", roles: [Role.CLASH] },
  { name: "Lam", roles: [Role.JUNGLE] },
  { name: "Prince of Lanling", roles: [Role.JUNGLE, Role.ROAM] },
  { name: "Wukong", roles: [Role.JUNGLE] },
  { name: "Li Bai", roles: [Role.JUNGLE] },
  { name: "Han Xin", roles: [Role.JUNGLE] },
  { name: "Luna", roles: [Role.JUNGLE, Role.MID] },
  { name: "Angela", roles: [Role.MID] },
  { name: "Diaochan", roles: [Role.MID] },
  { name: "Xiao Qiao", roles: [Role.MID] },
  { name: "Mai Shiranui", roles: [Role.MID, Role.JUNGLE] },
  { name: "Lady Zhen", roles: [Role.MID] },
  { name: "Milady", roles: [Role.MID] },
  { name: "Luban No.7", roles: [Role.FARM] },
  { name: "Marco Polo", roles: [Role.FARM] },
  { name: "Hou Yi", roles: [Role.FARM] },
  { name: "Consort Yu", roles: [Role.FARM] },
  { name: "Di Renjie", roles: [Role.FARM] },
  { name: "Arli", roles: [Role.FARM, Role.JUNGLE] },
  { name: "Dolia", roles: [Role.ROAM] },
  { name: "Kui", roles: [Role.ROAM] },
  { name: "Zhuangzi", roles: [Role.ROAM, Role.CLASH] },
  { name: "Zhang Fei", roles: [Role.ROAM] },
  { name: "Da Qiao", roles: [Role.ROAM, Role.MID] },
  { name: "Yaria", roles: [Role.ROAM] }
];

export default function App() {
  const [players, setPlayers] = useState<Player[]>([]);
  const [currentMatch, setCurrentMatch] = useState<MatchResult | null>(null);
  const [matchHistory, setMatchHistory] = useState<MatchHistoryEntry[]>([]);
  const [errorMsg, setErrorMsg] = useState<string | null>(null);
  const [roomId, setRoomId] = useState<string>('');
  const [isCoachMode, setIsCoachMode] = useState(false);
  const [isSidebarOpen, setIsSidebarOpen] = useState(true);

  // Edit State
  const [editingPlayer, setEditingPlayer] = useState<Player | null>(null);
  const [isEditModalOpen, setIsEditModalOpen] = useState(false);

  const rosterFileInputRef = useRef<HTMLInputElement>(null);
  const historyFileInputRef = useRef<HTMLInputElement>(null);

  const addPlayer = (newPlayer: Omit<Player, 'id' | 'isActive' | 'stats'>) => {
    setPlayers(prev => {
      // Check if player already exists (case-insensitive normalization)
      const normalizedName = newPlayer.name.trim().toLowerCase();
      const existingIndex = prev.findIndex(p => p.name.trim().toLowerCase() === normalizedName);

      if (existingIndex !== -1) {
        // UPDATE Existing Player Logic
        const updatedPlayers = [...prev];
        updatedPlayers[existingIndex] = {
          ...updatedPlayers[existingIndex],
          roles: newPlayer.roles,
          isAllRoles: newPlayer.isAllRoles,
          // We also ensure they are active if they are being updated/re-added
          isActive: true 
        };
        return updatedPlayers;
      }

      // CREATE New Player Logic
      const player: Player = { 
        ...newPlayer, 
        id: crypto.randomUUID(),
        isActive: true, // Default to active when added
        isLastMatchMvp: false,
        stats: {
          matchesPlayed: 0,
          wins: 0,
          currentStreak: 0,
          maxStreak: 0
        }
      };
      return [...prev, player];
    });
    setErrorMsg(null);
  };

  const removePlayer = (id: string) => {
    setPlayers(prev => prev.filter(p => p.id !== id));
  };

  const togglePlayerActive = (id: string) => {
    setPlayers(prev => prev.map(p => 
      p.id === id ? { ...p, isActive: !p.isActive } : p
    ));
  };

  // Edit Handlers
  const handleEditPlayer = (player: Player) => {
    setEditingPlayer(player);
    setIsEditModalOpen(true);
  };

  const handleUpdatePlayer = (updatedPlayer: Player) => {
    setPlayers(prev => prev.map(p => 
      p.id === updatedPlayer.id ? updatedPlayer : p
    ));
    setErrorMsg(null);
  };

  const activePlayers = players.filter(p => p.isActive);

  const handleGenerate = () => {
    if (!roomId.trim()) {
      setErrorMsg("Please enter a Room ID.");
      return;
    }

    const required = isCoachMode ? 12 : 10;
    if (activePlayers.length < required) {
      setErrorMsg(`Need ${required} ACTIVE players for ${isCoachMode ? 'Coach' : 'Standard'} Mode. Current Active: ${activePlayers.length}`);
      return;
    }

    // COACH MODE VALIDATION
    if (isCoachMode) {
       // STRICT: Only players with the explicit COACH role can be coach. 
       // All Roles/Fill does NOT count for coach slots.
       const coachCandidates = activePlayers.filter(p => p.roles.includes(Role.COACH));

       if (coachCandidates.length < 2) {
         setErrorMsg(`Coach Mode requires at least 2 players with the specific 'COACH' role. Found: ${coachCandidates.length}`);
         return;
       }
    }

    // Only pass active players to the matchmaker
    const result = generateMatch(activePlayers, roomId, isCoachMode);
    if (result) {
      setCurrentMatch(result);
      setErrorMsg(null);
    } else {
      setErrorMsg("Failed to find valid composition. Ensure role coverage.");
    }
  };

  const handleRerollSlot = (team: 'azure' | 'crimson', role: Role, newPlayer: Player) => {
    if (!currentMatch) return;

    // Update Match State with the new player chosen by the wheel
    setCurrentMatch(prev => {
       if (!prev) return null;

       const newAzure = prev.azureTeam.map(slot => {
          if (team === 'azure' && slot.role === role) {
             return { ...slot, player: newPlayer };
          }
          return slot;
       });

       const newCrimson = prev.crimsonTeam.map(slot => {
          if (team === 'crimson' && slot.role === role) {
             return { ...slot, player: newPlayer };
          }
          return slot;
       });

       return {
          ...prev,
          azureTeam: newAzure,
          crimsonTeam: newCrimson
       };
    });
  };

  const handleMatchFinish = (winner: 'azure' | 'crimson' | null, mvpId?: string) => {
    if (!currentMatch) return;

    // 1. Save History
    const historyEntry: MatchHistoryEntry = {
       ...currentMatch,
       id: crypto.randomUUID(),
       winningTeam: winner,
       mvpId: mvpId
    };
    setMatchHistory(prev => [historyEntry, ...prev]);

    // 2. Update Player Stats if there is a winner
    if (winner) {
      const azurePlayerIds = new Set(currentMatch.azureTeam.map(slot => slot.player.id));
      const crimsonPlayerIds = new Set(currentMatch.crimsonTeam.map(slot => slot.player.id));

      setPlayers(prevPlayers => prevPlayers.map(p => {
        let isLastMatchMvp = false;

        // If player matches the manually provided MVP ID, set flag
        if (mvpId && p.id === mvpId) {
          isLastMatchMvp = true;
        }

        if (!azurePlayerIds.has(p.id) && !crimsonPlayerIds.has(p.id)) {
          return { ...p, isLastMatchMvp: false }; // Clear old MVP if they didn't play
        }

        const isAzure = azurePlayerIds.has(p.id);
        const isWinner = (isAzure && winner === 'azure') || (!isAzure && winner === 'crimson');

        const newStats = { ...p.stats };
        newStats.matchesPlayed += 1;

        if (isWinner) {
           newStats.wins += 1;
           newStats.currentStreak += 1;
           if (newStats.currentStreak > newStats.maxStreak) {
             newStats.maxStreak = newStats.currentStreak;
           }
        } else {
           // Reset streak on loss
           newStats.currentStreak = 0;
        }

        return { ...p, stats: newStats, isLastMatchMvp };
      }));
    }

    // 3. Clear match and Room ID (Reset ID)
    setCurrentMatch(null);
    setRoomId(''); 
  };

  const handleAbortMatch = () => setCurrentMatch(null);

  const quickFill = () => {
     const shuffledHeroes = [...HOK_HEROES].sort(() => 0.5 - Math.random());
     const heroesToAdd = shuffledHeroes.slice(0, 15);
     const newPlayers: Player[] = heroesToAdd.map(hero => ({
        id: crypto.randomUUID(),
        name: hero.name,
        isAllRoles: false,
        roles: hero.roles,
        isActive: true,
        isLastMatchMvp: false,
        stats: { matchesPlayed: 0, wins: 0, currentStreak: 0, maxStreak: 0 }
     }));
     // Add some flexible minions/players if needed to ensure we have enough
     for(let i=0; i<5; i++) {
        newPlayers.push({
           id: crypto.randomUUID(),
           name: `Flex Player ${i+1}`,
           isAllRoles: true,
           roles: [],
           isActive: true,
           isLastMatchMvp: false,
           stats: { matchesPlayed: 0, wins: 0, currentStreak: 0, maxStreak: 0 }
        });
     }

     setPlayers(prev => {
        const existingNames = new Set(prev.map(p => p.name));
        const filteredNew = newPlayers.filter(p => !existingNames.has(p.name));
        return [...prev, ...filteredNew].slice(0, 30);
     });

     // NOTE: We do NOT set Room ID automatically anymore per user request.
  };

  // --- SAVE / LOAD FUNCTIONALITY ---

  const getFormattedTimestamp = () => {
    const date = new Date();
    const YYYY = date.getFullYear();
    const MM = String(date.getMonth() + 1).padStart(2, '0');
    const DD = String(date.getDate()).padStart(2, '0');
    const HH = String(date.getHours()).padStart(2, '0');
    const mm = String(date.getMinutes()).padStart(2, '0');
    return `${YYYY}-${MM}-${DD}_${HH}-${mm}`;
  };

  const handleExportRoster = () => {
    if (players.length === 0) return;
    const dataStr = "data:text/json;charset=utf-8," + encodeURIComponent(JSON.stringify(players, null, 2));
    const filename = `hok-squad-roster_${getFormattedTimestamp()}.json`;

    const downloadAnchorNode = document.createElement('a');
    downloadAnchorNode.setAttribute("href", dataStr);
    downloadAnchorNode.setAttribute("download", filename);
    document.body.appendChild(downloadAnchorNode);
    downloadAnchorNode.click();
    downloadAnchorNode.remove();
  };

  const handleExportHistory = () => {
    if (matchHistory.length === 0) return;
    const dataStr = "data:text/json;charset=utf-8," + encodeURIComponent(JSON.stringify(matchHistory, null, 2));
    const filename = `hok-match-history_${getFormattedTimestamp()}.json`;

    const downloadAnchorNode = document.createElement('a');
    downloadAnchorNode.setAttribute("href", dataStr);
    downloadAnchorNode.setAttribute("download", filename);
    document.body.appendChild(downloadAnchorNode);
    downloadAnchorNode.click();
    downloadAnchorNode.remove();
  };

  const handleRosterImportClick = () => {
    rosterFileInputRef.current?.click();
  };

  const handleHistoryImportClick = () => {
    historyFileInputRef.current?.click();
  };

  const handleRosterFileChange = (event: React.ChangeEvent<HTMLInputElement>) => {
    const fileObj = event.target.files && event.target.files[0];
    if (!fileObj) return;

    const reader = new FileReader();
    reader.onload = (e) => {
      try {
        const json = e.target?.result;
        if (typeof json === 'string') {
          const parsedData = JSON.parse(json);
          // Basic validation
          if (Array.isArray(parsedData) && parsedData.length > 0 && parsedData[0].name) {
             const importedPlayers: Player[] = parsedData.map((p: any) => ({
               ...p,
               id: crypto.randomUUID(),
               // Ensure properties exist for backward compatibility with old JSONs
               isActive: typeof p.isActive === 'boolean' ? p.isActive : true,
               isLastMatchMvp: typeof p.isLastMatchMvp === 'boolean' ? p.isLastMatchMvp : false,
               stats: p.stats || { matchesPlayed: 0, wins: 0, currentStreak: 0, maxStreak: 0 }
             }));
             setPlayers(importedPlayers);
             setErrorMsg(null);
          } else {
             setErrorMsg("Invalid Roster JSON file format.");
          }
        }
      } catch (err) {
        setErrorMsg("Failed to parse Roster JSON file.");
      }
    };
    reader.readAsText(fileObj);
    event.target.value = '';
  };

  const handleHistoryFileChange = (event: React.ChangeEvent<HTMLInputElement>) => {
    const fileObj = event.target.files && event.target.files[0];
    if (!fileObj) return;

    const reader = new FileReader();
    reader.onload = (e) => {
      try {
        const json = e.target?.result;
        if (typeof json === 'string') {
          const parsedData = JSON.parse(json);
          // Basic validation for match history
          if (Array.isArray(parsedData) && (parsedData.length === 0 || parsedData[0].roomId)) {
             setMatchHistory(parsedData);
             setErrorMsg(null);
          } else {
             setErrorMsg("Invalid History JSON file format.");
          }
        }
      } catch (err) {
        setErrorMsg("Failed to parse History JSON file.");
      }
    };
    reader.readAsText(fileObj);
    event.target.value = '';
  };

  const handleRoomIdChange = (e: React.ChangeEvent<HTMLInputElement>) => {
    const val = e.target.value;
    if (val.length <= 4) {
      setRoomId(val);
    }
  };

  return (
    <div className="min-h-screen text-slate-200 font-inter overflow-x-hidden relative">
      <BackgroundParticles />

      {/* New Background Image (HoK Global Launch) */}
      <div className="fixed inset-0 bg-black -z-10">
         <img 
           src="https://www.levelinfinite.com/wp-content/uploads/2024/03/honor-of-kings-global-launch-pc.jpg" 
           alt="Honor of Kings Background" 
           className="absolute inset-0 w-full h-full object-cover opacity-50"
         />
         <div className="absolute inset-0 bg-gradient-to-b from-[#05090f]/90 via-[#05090f]/60 to-[#05090f] mix-blend-multiply"></div>
         <div className="absolute inset-0 bg-gradient-to-t from-[#05090f] via-transparent to-[#05090f]/80"></div>
      </div>

      {/* Hidden File Inputs */}
      <input 
        type="file" 
        ref={rosterFileInputRef}
        onChange={handleRosterFileChange}
        accept=".json"
        className="hidden"
      />
      <input 
        type="file" 
        ref={historyFileInputRef}
        onChange={handleHistoryFileChange}
        accept=".json"
        className="hidden"
      />

      {/* Edit Modal */}
      {editingPlayer && (
        <EditPlayerModal 
          player={editingPlayer}
          isOpen={isEditModalOpen}
          onClose={() => setIsEditModalOpen(false)}
          onSave={handleUpdatePlayer}
        />
      )}

      {/* Cinematic Header - Sticky & Compact */}
      <header className="sticky top-0 z-50 h-16 flex items-center justify-center border-b border-[#dcb06b]/20 bg-[#05090f]/90 backdrop-blur-md shadow-lg transition-all">
        <div className="absolute inset-0 bg-gradient-to-r from-transparent via-[#dcb06b]/5 to-transparent"></div>
        <div className="flex items-center gap-2 animate-float">
           <div className="w-6 h-6 border border-[#dcb06b] rotate-45 flex items-center justify-center bg-[#0a1a2f]">
              <div className="w-3 h-3 bg-[#dcb06b]"></div>
           </div>
           <h1 className="text-xl font-cinzel font-black tracking-[0.2em] text-white flex flex-col md:flex-row md:items-center md:gap-2 leading-none">
             <span>
               <span className="hok-gold-text">HONOR</span> OF <span className="hok-gold-text">KINGS</span>
             </span>
             <span className="text-[7px] text-[#8a9db8] tracking-[0.3em] font-orbitron md:mt-0 mt-1">OPEN MABAR</span>
           </h1>
        </div>
      </header>

      <main className="relative z-10 pt-8 px-4 pb-20">
        {currentMatch ? (
          <MatchDisplay 
            match={currentMatch} 
            activePlayers={activePlayers} 
            onReset={handleAbortMatch}
            onCompleteMatch={handleMatchFinish}
            onReroll={handleRerollSlot}
          />
        ) : (
          <div className="max-w-7xl mx-auto">

            <div className="grid grid-cols-1 lg:grid-cols-12 gap-8 relative transition-all duration-500">

              {/* Left Panel: Controls (Collapsible) */}
              <div className={`
                 lg:col-span-4 space-y-6 transition-all duration-500 ease-in-out
                 ${isSidebarOpen ? 'opacity-100 translate-x-0' : 'hidden opacity-0 -translate-x-full lg:col-span-0'}
              `}>

                 {/* Room ID & Coach Mode Toggle */}
                 <div className="bg-[#0a1a2f]/80 p-1 clip-corner-sm border border-[#1e3a5f] shadow-[0_0_25px_rgba(220,176,107,0.15)] relative group space-y-2">
                    <div className="absolute -inset-1 bg-gradient-to-r from-transparent via-[#dcb06b]/30 to-transparent blur opacity-0 group-hover:opacity-100 transition-opacity duration-700"></div>

                    <div className="bg-[#05090f] p-4 flex items-center gap-4 clip-corner-sm relative z-10">
                       <label className="text-xs uppercase text-[#dcb06b] font-bold font-orbitron whitespace-nowrap tracking-widest">Room ID</label>
                       <div className="h-8 w-[1px] bg-[#1e3a5f]"></div>
                       <input 
                          type="text" 
                          value={roomId}
                          onChange={handleRoomIdChange}
                          maxLength={4}
                          placeholder="0000"
                          className="bg-transparent text-lg font-orbitron text-white w-full focus:outline-none tracking-widest placeholder-[#1e3a5f]"
                       />
                    </div>
                 </div>

                 <div className="flex items-center justify-between bg-[#0a1a2f]/60 p-4 border border-[#1e3a5f] clip-corner-sm">
                     <span className="text-[#dcb06b] font-cinzel font-bold text-sm tracking-widest flex items-center gap-2">
                        <svg xmlns="http://www.w3.org/2000/svg" className="h-4 w-4" fill="none" viewBox="0 0 24 24" stroke="currentColor">
                           <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M19 11H5m14 0a2 2 0 012 2v6a2 2 0 01-2 2H5a2 2 0 01-2-2v-6a2 2 0 012-2m14 0V9a2 2 0 00-2-2M5 11V9a2 2 0 012-2m0 0V5a2 2 0 012-2h6a2 2 0 012 2v2M7 7h10" />
                        </svg>
                        COACH MODE <span className="text-[8px] bg-[#dcb06b] text-black px-1.5 py-0.5 rounded font-orbitron font-bold ml-1">(BETA)</span>
                     </span>
                     <label className="relative inline-flex items-center cursor-pointer">
                        <input type="checkbox" className="sr-only peer" checked={isCoachMode} onChange={(e) => setIsCoachMode(e.target.checked)} />
                        <div className="w-11 h-6 bg-[#1e3a5f] peer-focus:outline-none rounded-full peer peer-checked:after:translate-x-full peer-checked:after:border-white after:content-[''] after:absolute after:top-[2px] after:left-[2px] after:bg-white after:border-gray-300 after:border after:rounded-full after:h-5 after:w-5 after:transition-all peer-checked:bg-[#dcb06b]"></div>
                     </label>
                 </div>

                 <PlayerForm onAddPlayer={addPlayer} isCoachMode={isCoachMode} />

                 {/* Status Panel */}
                 <div className="relative p-6 clip-corner-md bg-gradient-to-b from-[#1a2c42] to-[#05090f] border border-[#dcb06b]/20 group hover:border-[#dcb06b]/50 transition-colors duration-500">
                    <div className="absolute top-0 left-0 w-full h-1 bg-gradient-to-r from-transparent via-[#dcb06b] to-transparent opacity-50"></div>

                    <div className="flex justify-between items-end mb-6">
                       <div>
                          <div className="text-[#8a9db8] text-[10px] uppercase tracking-widest font-bold mb-1">Active Players</div>
                          <div className="text-5xl font-orbitron font-bold text-white relative">
                             {activePlayers.length}
                             <span className="text-lg text-[#4a5f78] absolute top-0 -right-12">/ {isCoachMode ? 12 : 10}</span>
                          </div>
                       </div>
                       <div className="text-right">
                          <button onClick={quickFill} className="text-[10px] text-[#dcb06b] border border-[#dcb06b] px-3 py-1 hover:bg-[#dcb06b] hover:text-black transition-colors uppercase tracking-wider">
                             Quick Fill
                          </button>
                       </div>
                    </div>

                    {errorMsg && (
                      <div className="mb-4 p-3 border-l-2 border-red-500 bg-red-900/20 text-red-200 text-xs">
                        {errorMsg}
                      </div>
                    )}

                    <Button 
                      onClick={handleGenerate} 
                      className="w-full text-lg shadow-[0_0_20px_rgba(220,176,107,0.3)]"
                      disabled={activePlayers.length < (isCoachMode ? 12 : 10)}
                    >
                       START MATCHMAKING
                    </Button>
                 </div>
              </div>

              {/* Right Panel: Player Grid & History */}
              <div className={`transition-all duration-500 ${isSidebarOpen ? 'lg:col-span-8' : 'lg:col-span-12'}`}>
                 <div className="flex flex-wrap items-center justify-between mb-6 gap-4">

                    {/* Header with Expand Button */}
                    <div className="flex items-center gap-4">
                        <button 
                           onClick={() => setIsSidebarOpen(!isSidebarOpen)} 
                           className="p-2 border border-[#1e3a5f] hover:border-[#dcb06b] text-[#dcb06b] clip-corner-sm transition-all bg-[#0a1a2f]/50"
                           title={isSidebarOpen ? "Maximize List" : "Show Controls"}
                        >
                           {isSidebarOpen ? (
                              <svg xmlns="http://www.w3.org/2000/svg" className="h-5 w-5" fill="none" viewBox="0 0 24 24" stroke="currentColor">
                                <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M4 8V4m0 0h4M4 4l5 5m11-1V4m0 0h-4m4 0l-5 5M4 16v4m0 0h4m-4 0l5-5m11 5l-5-5m5 5v-4m0 4h-4" />
                              </svg>
                           ) : (
                              <svg xmlns="http://www.w3.org/2000/svg" className="h-5 w-5" fill="none" viewBox="0 0 24 24" stroke="currentColor">
                                 <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M4 6h16M4 12h16M4 18h16" />
                              </svg>
                           )}
                        </button>

                        <h2 className="text-2xl font-cinzel font-black tracking-[0.2em] uppercase drop-shadow-sm text-[#dcb06b] flex items-center gap-3">
                           <span className="w-2 h-2 bg-[#dcb06b] rotate-45"></span>
                           SQUAD ROSTER
                        </h2>
                    </div>

                    <div className="flex items-center gap-2">
                       {/* Import/Export Controls */}
                       <button 
                         onClick={handleRosterImportClick}
                         className="flex items-center gap-2 px-3 py-1 text-[10px] uppercase font-bold tracking-wider text-[#4a5f78] border border-[#1e3a5f] hover:border-[#dcb06b] hover:text-[#dcb06b] transition-all clip-corner-sm"
                         title="Load Roster JSON"
                       >
                          <svg xmlns="http://www.w3.org/2000/svg" className="h-4 w-4" fill="none" viewBox="0 0 24 24" stroke="currentColor">
                            <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M4 16v1a3 3 0 003 3h10a3 3 0 003-3v-1m-4-8l-4-4m0 0L8 8m4-4v12" />
                          </svg>
                          Load
                       </button>

                       <button 
                         onClick={handleExportRoster}
                         disabled={players.length === 0}
                         className="flex items-center gap-2 px-3 py-1 text-[10px] uppercase font-bold tracking-wider text-[#4a5f78] border border-[#1e3a5f] hover:border-[#dcb06b] hover:text-[#dcb06b] transition-all clip-corner-sm disabled:opacity-30 disabled:cursor-not-allowed"
                         title="Save Roster JSON"
                       >
                          <svg xmlns="http://www.w3.org/2000/svg" className="h-4 w-4" fill="none" viewBox="0 0 24 24" stroke="currentColor">
                            <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M4 16v1a3 3 0 003 3h10a3 3 0 003-3v-1m-4-4l-4 4m0 0l-4-4m4 4V4" />
                          </svg>
                          Save
                       </button>

                       <div className="h-4 w-[1px] bg-[#1e3a5f] mx-2"></div>

                       <button onClick={() => setPlayers([])} className="text-xs text-[#4a5f78] hover:text-red-400 uppercase tracking-widest transition-colors">
                          Clear All
                       </button>
                    </div>
                 </div>

                 <div className="perspective-container tech-border p-6 bg-[#0a1a2f]/40 min-h-[400px] mb-8">
                    <PlayerList 
                      players={players} 
                      onRemove={removePlayer} 
                      onToggleActive={togglePlayerActive}
                      onEdit={handleEditPlayer}
                      isSidebarOpen={isSidebarOpen}
                    />
                 </div>

                 {/* MATCH HISTORY SECTION */}
                 <div className="mt-12">
                     <div className="flex items-center justify-between mb-6">
                        <h2 className="text-2xl font-cinzel font-black tracking-[0.2em] uppercase drop-shadow-sm text-[#dcb06b] flex items-center gap-3">
                           <span className="w-2 h-2 bg-[#dcb06b] rotate-45"></span>
                           BATTLE HISTORY
                        </h2>

                        <div className="flex items-center gap-2">
                           <button 
                             onClick={handleHistoryImportClick}
                             className="flex items-center gap-2 px-3 py-1 text-[10px] uppercase font-bold tracking-wider text-[#4a5f78] border border-[#1e3a5f] hover:border-[#dcb06b] hover:text-[#dcb06b] transition-all clip-corner-sm"
                           >
                              <svg xmlns="http://www.w3.org/2000/svg" className="h-4 w-4" fill="none" viewBox="0 0 24 24" stroke="currentColor">
                                <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M4 16v1a3 3 0 003 3h10a3 3 0 003-3v-1m-4-8l-4-4m0 0L8 8m4-4v12" />
                              </svg>
                              Import
                           </button>

                           <button 
                              onClick={handleExportHistory}
                              disabled={matchHistory.length === 0}
                              className="flex items-center gap-2 px-3 py-1 text-[10px] uppercase font-bold tracking-wider text-[#4a5f78] border border-[#1e3a5f] hover:border-[#dcb06b] hover:text-[#dcb06b] transition-all clip-corner-sm disabled:opacity-30 disabled:cursor-not-allowed"
                           >
                              <svg xmlns="http://www.w3.org/2000/svg" className="h-4 w-4" fill="none" viewBox="0 0 24 24" stroke="currentColor">
                                 <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M12 10v6m0 0l-3-3m3 3l3-3m2 8H7a2 2 0 01-2-2V5a2 2 0 012-2h5.586a1 1 0 01.707.293l5.414 5.414a1 1 0 01.293.707V19a2 2 0 01-2 2z" />
                              </svg>
                              Export
                           </button>
                        </div>
                     </div>

                     <div className="tech-border p-6 bg-[#0a1a2f]/40">
                        <HistoryList history={matchHistory} onClear={() => setMatchHistory([])} />
                     </div>
                 </div>
              </div>

            </div>
          </div>
        )}
      </main>
    </div>
  );
}

import React, { useState, useEffect } from 'react';
import { createPortal } from 'react-dom';
import { Player, Role } from '../types';
import { ROLES_ORDER } from '../constants';

interface PlayerListProps {
  players: Player[];
  onRemove: (id: string) => void;
  onToggleActive: (id: string) => void;
  onEdit: (player: Player) => void;
  isSidebarOpen?: boolean;
}

type FilterType = 'ALL' | 'ACTIVE' | 'BENCH' | Role;

export const PlayerList: React.FC<PlayerListProps> = ({ players, onRemove, onToggleActive, onEdit, isSidebarOpen = true }) => {
  const [filter, setFilter] = useState<FilterType>('ALL');
  const [searchQuery, setSearchQuery] = useState('');

  // Menu State (Only for Player Context Menu now)
  const [menuOpenId, setMenuOpenId] = useState<string | null>(null);
  const [menuPosition, setMenuPosition] = useState<{ top: number; left: number }>({ top: 0, left: 0 });

  // Close menu when clicking outside
  useEffect(() => {
    const handleClickOutside = (e: MouseEvent) => {
        setMenuOpenId(null);
    };
    const handleScroll = () => {
        setMenuOpenId(null);
    }; 

    if (menuOpenId) {
      document.addEventListener('click', handleClickOutside);
      window.addEventListener('scroll', handleScroll, true);
    }
    return () => {
      document.removeEventListener('click', handleClickOutside);
      window.removeEventListener('scroll', handleScroll, true);
    };
  }, [menuOpenId]);

  const toggleMenu = (e: React.MouseEvent, id: string) => {
    e.stopPropagation();
    if (menuOpenId === id) {
        setMenuOpenId(null);
    } else {
        const rect = e.currentTarget.getBoundingClientRect();
        setMenuPosition({
            top: rect.bottom + 5,
            left: rect.right - 128
        });
        setMenuOpenId(id);
    }
  };

  const filteredPlayers = players.filter(p => {
    let matchesCategory = true;
    if (filter === 'ACTIVE') matchesCategory = p.isActive;
    else if (filter === 'BENCH') matchesCategory = !p.isActive;
    else if (Object.values(Role).includes(filter as Role)) {
       matchesCategory = p.roles.includes(filter as Role);
    }
    const matchesSearch = p.name.toLowerCase().includes(searchQuery.toLowerCase());
    return matchesCategory && matchesSearch;
  });

  const filters: { label: string; value: FilterType; icon?: React.ReactNode }[] = [
    { label: 'All', value: 'ALL' },
    { label: 'Playing', value: 'ACTIVE' },
    { label: 'Benched', value: 'BENCH' },
    ...ROLES_ORDER.map(r => ({ label: r.split(' ')[0], value: r })),
    { label: 'Coach', value: Role.COACH }
  ];

  const getRoleBadgeStyle = (role: Role) => {
      switch (role) {
          case Role.COACH: return 'text-white border-white bg-white/10 shadow-[0_0_10px_rgba(255,255,255,0.5)]';
          case Role.CLASH: return 'text-orange-400 border-orange-500/50 bg-orange-900/20'; 
          case Role.JUNGLE: return 'text-emerald-400 border-emerald-500/50 bg-emerald-900/20'; 
          case Role.MID: return 'text-blue-400 border-blue-500/50 bg-blue-900/20'; 
          case Role.FARM: return 'text-yellow-400 border-yellow-500/50 bg-yellow-900/20'; 
          case Role.ROAM: return 'text-cyan-400 border-cyan-500/50 bg-cyan-900/20'; 
          default: return 'text-gray-400 border-gray-600 bg-gray-800/30';
      }
  };

  if (players.length === 0) {
    return (
      <div className="h-full min-h-[300px] flex flex-col items-center justify-center border border-dashed border-[#1e3a5f] rounded-lg bg-[#0a1a2f]/30 p-8">
        <div className="w-20 h-20 rounded-full bg-[#1e3a5f]/50 flex items-center justify-center mb-4 border border-[#dcb06b]/20">
           <svg xmlns="http://www.w3.org/2000/svg" className="h-8 w-8 text-[#dcb06b]/50" fill="none" viewBox="0 0 24 24" stroke="currentColor"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M12 4.354a4 4 0 110 5.292M15 21H3v-1a6 6 0 0112 0v1zm0 0h6v-1a6 6 0 00-9-5.197M13 7a4 4 0 11-8 0 4 4 0 018 0z" /></svg>
        </div>
        <p className="text-[#8a9db8] font-cinzel tracking-widest text-sm">Waiting for Challengers</p>
      </div>
    );
  }

  // Adjusted Grid Logic: 3xN when Sidebar Open
  const gridClasses = isSidebarOpen
      ? "grid-cols-1 md:grid-cols-2 lg:grid-cols-3" 
      : "grid-cols-1 md:grid-cols-3 lg:grid-cols-4 xl:grid-cols-5 2xl:grid-cols-6";

  return (
    <div>
      {/* FILTER & SEARCH BAR */}
      <div className="mb-6 flex flex-col xl:flex-row gap-4 items-start xl:items-center justify-between">

         {/* Filter Horizontal Scroll List (1x9) */}
         <div className="w-full xl:flex-1 overflow-x-auto pb-2">
             <div className="flex gap-2 min-w-max">
                {filters.map(f => (
                  <button
                    key={f.value}
                    onClick={() => setFilter(f.value)}
                    className={`
                      flex items-center justify-center px-4 py-2 text-[10px] uppercase font-bold tracking-wider clip-corner-sm border transition-all
                      ${filter === f.value 
                          ? 'bg-[#dcb06b] text-[#05090f] border-[#dcb06b] shadow-[0_0_10px_#dcb06b] scale-105' 
                          : 'bg-[#05090f] text-[#8a9db8] border-[#1e3a5f] hover:border-[#dcb06b] hover:text-white hover:bg-[#1e3a5f]/30'}
                    `}
                  >
                    {f.label}
                  </button>
                ))}
             </div>
         </div>

         <div className="relative w-full xl:w-64 shrink-0">
             <input 
               type="text" 
               placeholder="Find Player..." 
               value={searchQuery}
               onChange={(e) => setSearchQuery(e.target.value)}
               className="w-full bg-[#05090f] border border-[#1e3a5f] px-3 py-1.5 pl-8 text-xs text-[#f0f4f8] focus:outline-none focus:border-[#dcb06b] clip-corner-sm font-orbitron placeholder-[#4a5f78]"
             />
             <svg xmlns="http://www.w3.org/2000/svg" className="h-4 w-4 absolute left-2 top-1.5 text-[#4a5f78]" fill="none" viewBox="0 0 24 24" stroke="currentColor">
               <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M21 21l-6-6m2-5a7 7 0 11-14 0 7 7 0 0114 0z" />
             </svg>
         </div>
      </div>

      {/* PLAYER GRID */}
      <div className={`grid gap-3 transition-all duration-500 ${gridClasses}`}>
        {filteredPlayers.map(player => {
          const isActive = player.isActive;
          const stats = player.stats || { matchesPlayed: 0, wins: 0, currentStreak: 0, maxStreak: 0 };
          const winRate = stats.matchesPlayed > 0 
            ? Math.round((stats.wins / stats.matchesPlayed) * 100) 
            : 0;

          const streak = stats.currentStreak;
          const isHot = streak >= 3 && streak < 6; 
          const isGodlike = streak >= 6;
          const isMvp = player.isLastMatchMvp;
          const hasCoachRole = player.roles.includes(Role.COACH);

          // --- ANIMATED BORDER LOGIC ---
          let animationLayer = null;
          let glowClass = "";

          if (isActive) {
              if (isMvp) {
                  glowClass = "drop-shadow-[0_0_15px_rgba(251,191,36,0.6)]";
                  animationLayer = (
                      <div className="absolute inset-[-50%] bg-[conic-gradient(from_0deg,transparent_0deg,#fbbf24_90deg,transparent_180deg,#fbbf24_270deg,transparent_360deg)] animate-[spin_4s_linear_infinite] opacity-100"></div>
                  );
              } else if (hasCoachRole) {
                  glowClass = "drop-shadow-[0_0_10px_rgba(255,255,255,0.5)]";
                  animationLayer = (
                      <div className="absolute inset-[-50%] bg-[conic-gradient(from_0deg,transparent_0deg,#ffffff_90deg,transparent_180deg,#ffffff_270deg,transparent_360deg)] animate-[spin_6s_linear_infinite] opacity-80"></div>
                  );
              } else if (isGodlike) {
                  glowClass = "drop-shadow-[0_0_20px_rgba(239,68,68,0.8)]";
                  animationLayer = (
                      <div className="absolute inset-[-50%] bg-[conic-gradient(from_0deg,transparent_0deg,#ef4444_60deg,#7f1d1d_120deg,transparent_180deg,#ef4444_240deg,transparent_360deg)] animate-[spin_2s_linear_infinite] opacity-100"></div>
                  );
              } else if (isHot) {
                  glowClass = "drop-shadow-[0_0_10px_rgba(6,182,212,0.6)]";
                  animationLayer = (
                      <div className="absolute inset-[-50%] bg-[conic-gradient(from_0deg,transparent_0deg,#06b6d4_90deg,transparent_180deg,#06b6d4_270deg,transparent_360deg)] animate-[spin_3s_linear_infinite] opacity-100"></div>
                  );
              }
          }

          const cardBg = isActive && hasCoachRole ? 'bg-[#000000]' : 'bg-[#05090f]';

          return (
            <React.Fragment key={player.id}>
              {menuOpenId === player.id && createPortal(
                <div 
                   className="fixed z-[9999] w-32 bg-[#05090f] border border-[#dcb06b] shadow-[0_0_20px_rgba(0,0,0,0.9)] clip-corner-sm flex flex-col animate-slide-in"
                   style={{ 
                      top: menuPosition.top, 
                      left: menuPosition.left 
                   }}
                   onClick={(e) => e.stopPropagation()}
                >
                    <button 
                      onClick={(e) => { e.stopPropagation(); onToggleActive(player.id); setMenuOpenId(null); }}
                      className="px-3 py-3 text-left text-[10px] uppercase font-bold text-[#f0f4f8] hover:bg-[#dcb06b] hover:text-[#05090f] transition-colors"
                    >
                       {isActive ? 'Bench Player' : 'Activate'}
                    </button>
                    <button 
                      onClick={(e) => { e.stopPropagation(); onEdit(player); setMenuOpenId(null); }}
                      className="px-3 py-3 text-left text-[10px] uppercase font-bold text-[#f0f4f8] hover:bg-[#dcb06b] hover:text-[#05090f] transition-colors"
                    >
                       Edit Details
                    </button>
                    <div className="h-[1px] bg-[#1e3a5f] w-full"></div>
                    <button 
                      onClick={(e) => { e.stopPropagation(); onRemove(player.id); setMenuOpenId(null); }}
                      className="px-3 py-3 text-left text-[10px] uppercase font-bold text-red-500 hover:bg-red-500 hover:text-white transition-colors"
                    >
                       Remove
                    </button>
                 </div>,
                 document.body
              )}

              <div className={`relative group ${glowClass} tilt-card h-full transition-all duration-300`}>

                <div className="absolute inset-0 clip-corner-sm overflow-hidden z-0">
                    <div className="absolute inset-0 bg-[#1e3a5f]"></div>
                    {animationLayer}
                </div>

                <div 
                  className={`
                    absolute inset-[1px] clip-corner-sm z-10 flex flex-col gap-1 p-2
                    ${cardBg}
                    ${!isActive ? 'opacity-50 grayscale hover:opacity-80 transition-opacity' : ''}
                  `}
                >

                  <div className="flex justify-between items-start gap-2">

                     <div className="flex-1 min-w-0">
                        {/* Name */}
                        <div className="flex items-center gap-2 mb-1">
                            <div 
                                className={`text-lg font-bold font-orbitron tracking-wide leading-none truncate ${isMvp ? 'text-yellow-400' : 'text-[#e2e8f0]'}`}
                                title={player.name}
                            >
                                {player.name}
                            </div>

                            {/* Badges */}
                            {isMvp && <div className="text-[8px] font-black bg-gradient-to-r from-yellow-400 to-yellow-600 text-black px-1.5 py-0.5 rounded-sm shadow-[0_0_10px_#fbbf24] animate-pulse">MVP</div>}

                            {!isMvp && isGodlike && isActive && (
                               <span className="text-[8px] text-red-500 animate-pulse font-black">GODLIKE</span>
                            )}
                        </div>

                        <div className="flex flex-wrap gap-1">
                            {hasCoachRole ? (
                                // Exclusive Coach Badge - If player is Coach, ONLY show this.
                                <div className={`px-1.5 py-0.5 border clip-corner-sm ${getRoleBadgeStyle(Role.COACH)}`}>
                                    <span className="text-[7px] uppercase font-bold leading-none whitespace-nowrap opacity-100">
                                        COACH
                                    </span>
                                </div>
                            ) : (
                                // Standard Role Rendering
                                player.isAllRoles ? (
                                  <div className={`px-1.5 py-0.5 border clip-corner-sm bg-purple-900/20 text-purple-400 border-purple-500/30`}>
                                    <span className="text-[8px] font-bold uppercase whitespace-nowrap">All Roles</span>
                                  </div>
                                ) : (
                                  player.roles.map(role => (
                                      <div key={role} className={`px-1.5 py-0.5 border clip-corner-sm ${getRoleBadgeStyle(role)}`}>
                                          <span className="text-[7px] uppercase font-bold leading-none whitespace-nowrap opacity-100">
                                              {role.split(' ')[0]}
                                          </span>
                                      </div>
                                  ))
                                )
                            )}
                        </div>
                     </div>

                     <div className="relative shrink-0">
                        <button 
                           onClick={(e) => toggleMenu(e, player.id)}
                           className={`p-1 text-[#4a5f78] hover:text-[#dcb06b] hover:bg-white/5 transition-colors rounded`}
                        >
                           <svg xmlns="http://www.w3.org/2000/svg" className="h-4 w-4" fill="none" viewBox="0 0 24 24" stroke="currentColor">
                             <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M12 5v.01M12 12v.01M12 19v.01M12 6a1 1 0 110-2 1 1 0 010 2zm0 7a1 1 0 110-2 1 1 0 010 2zm0 7a1 1 0 110-2 1 1 0 010 2z" />
                           </svg>
                        </button>
                     </div>
                  </div>

                  {/* Stats - ALWAYS Visible */}
                  <div className={`flex flex-wrap items-center gap-x-3 gap-y-1 text-[9px] font-mono mt-auto pt-2 border-t border-white/5 ${isActive ? 'text-gray-400' : 'text-[#4a5f78]/50'}`}>
                      <div className="whitespace-nowrap">
                        Match: <span className="text-[#f0f4f8]">{stats.matchesPlayed}</span>
                      </div>
                      <div className="whitespace-nowrap">
                        WR: <span className={`${winRate >= 60 ? 'text-[#dcb06b]' : winRate >= 50 ? 'text-[#f0f4f8]' : 'text-red-400'}`}>{winRate}%</span>
                      </div>
                      {streak > 1 && (
                        <div className="whitespace-nowrap ml-auto">
                            <span className={`${isGodlike ? 'text-red-500 font-black animate-pulse' : isHot ? 'text-cyan-400 font-bold' : 'text-gray-400'}`}>
                                {streak} Win Streak
                            </span>
                        </div>
                      )}
                  </div>

                  {!isActive && (
                    <div className="absolute inset-0 flex items-center justify-center pointer-events-none z-10">
                      <span className="text-[#0a1a2f] font-black text-xl -rotate-12 opacity-40 uppercase tracking-widest select-none bg-[#dcb06b] px-1 mix-blend-screen">Benched</span>
                    </div>
                  )}
                </div>

                <div className="invisible p-2 flex flex-col gap-1 min-h-[72px]">
                   <div className="text-lg">Placeholder</div>
                   <div className="text-[7px]">Roles</div>
                </div>
              </div>
            </React.Fragment>
          );
        })}
      </div>
    </div>
  );
};

export enum Role {
  CLASH = 'Clash Lane',
  JUNGLE = 'Jungler',
  MID = 'Mid Lane',
  FARM = 'Farm Lane',
  ROAM = 'Roam',
  COACH = 'Coach',
}

export interface PlayerStats {
  matchesPlayed: number;
  wins: number;
  currentStreak: number;
  maxStreak: number;
}

export interface Player {
  id: string;
  name: string;
  roles: Role[]; 
  isAllRoles: boolean;
  isActive: boolean; // Menandakan apakah pemain ikut match kali ini
  isLastMatchMvp?: boolean; // New: Tracks if player was MVP in the specific last match
  stats: PlayerStats;
}

export interface TeamSlot {
  role: Role;
  player: Player;
}

export interface MatchResult {
  roomId: string;
  azureTeam: TeamSlot[];
  crimsonTeam: TeamSlot[];
  isCoachMode: boolean;
  timestamp: number;
}

export interface MatchHistoryEntry extends MatchResult {
  id: string;
  winningTeam: 'azure' | 'crimson' | null; // null means draw or abandoned
  mvpId?: string; // Track who was MVP in history
  ratings?: Record<string, number>; // 2 (Excellent), 1 (Good), -1 (Bad), -2 (Very Bad)
}

import React, { useState, useRef } from 'react';
import { Player, MatchResult, Role, MatchHistoryEntry } from './types';
import { PlayerForm } from './components/PlayerForm';
import { PlayerList } from './components/PlayerList';
import { MatchDisplay } from './components/MatchDisplay';
import { EditPlayerModal } from './components/EditPlayerModal';
import { HistoryList } from './components/HistoryList';
import { generateMatch } from './utils/matchmaker';
import { Button } from './components/Button';
import { BackgroundParticles } from './components/BackgroundParticles';

// Quick Fill Data: Honor of Kings Heroes
const HOK_HEROES = [
  { name: "Arthur", roles: [Role.CLASH] },
  { name: "Sun Ce", roles: [Role.CLASH, Role.JUNGLE] },
  { name: "Kaizer", roles: [Role.CLASH, Role.JUNGLE] },
  { name: "Biron", roles: [Role.CLASH] },
  { name: "Li Xin", roles: [Role.CLASH] },
  { name: "Charlotte", roles: [Role.CLASH] },
  { name: "Lam", roles: [Role.JUNGLE] },
  { name: "Prince of Lanling", roles: [Role.JUNGLE, Role.ROAM] },
  { name: "Wukong", roles: [Role.JUNGLE] },
  { name: "Li Bai", roles: [Role.JUNGLE] },
  { name: "Han Xin", roles: [Role.JUNGLE] },
  { name: "Luna", roles: [Role.JUNGLE, Role.MID] },
  { name: "Angela", roles: [Role.MID] },
  { name: "Diaochan", roles: [Role.MID] },
  { name: "Xiao Qiao", roles: [Role.MID] },
  { name: "Mai Shiranui", roles: [Role.MID, Role.JUNGLE] },
  { name: "Lady Zhen", roles: [Role.MID] },
  { name: "Milady", roles: [Role.MID] },
  { name: "Luban No.7", roles: [Role.FARM] },
  { name: "Marco Polo", roles: [Role.FARM] },
  { name: "Hou Yi", roles: [Role.FARM] },
  { name: "Consort Yu", roles: [Role.FARM] },
  { name: "Di Renjie", roles: [Role.FARM] },
  { name: "Arli", roles: [Role.FARM, Role.JUNGLE] },
  { name: "Dolia", roles: [Role.ROAM] },
  { name: "Kui", roles: [Role.ROAM] },
  { name: "Zhuangzi", roles: [Role.ROAM, Role.CLASH] },
  { name: "Zhang Fei", roles: [Role.ROAM] },
  { name: "Da Qiao", roles: [Role.ROAM, Role.MID] },
  { name: "Yaria", roles: [Role.ROAM] }
];

export default function App() {
  const [players, setPlayers] = useState<Player[]>([]);
  const [currentMatch, setCurrentMatch] = useState<MatchResult | null>(null);
  const [matchHistory, setMatchHistory] = useState<MatchHistoryEntry[]>([]);
  const [errorMsg, setErrorMsg] = useState<string | null>(null);
  const [roomId, setRoomId] = useState<string>('');
  const [isCoachMode, setIsCoachMode] = useState(false);
  const [isSidebarOpen, setIsSidebarOpen] = useState(true);

  // Edit State
  const [editingPlayer, setEditingPlayer] = useState<Player | null>(null);
  const [isEditModalOpen, setIsEditModalOpen] = useState(false);

  const rosterFileInputRef = useRef<HTMLInputElement>(null);
  const historyFileInputRef = useRef<HTMLInputElement>(null);

  const addPlayer = (newPlayer: Omit<Player, 'id' | 'isActive' | 'stats'>) => {
    setPlayers(prev => {
      // Check if player already exists (case-insensitive normalization)
      const normalizedName = newPlayer.name.trim().toLowerCase();
      const existingIndex = prev.findIndex(p => p.name.trim().toLowerCase() === normalizedName);

      if (existingIndex !== -1) {
        // UPDATE Existing Player Logic
        const updatedPlayers = [...prev];
        updatedPlayers[existingIndex] = {
          ...updatedPlayers[existingIndex],
          roles: newPlayer.roles,
          isAllRoles: newPlayer.isAllRoles,
          // We also ensure they are active if they are being updated/re-added
          isActive: true 
        };
        return updatedPlayers;
      }

      // CREATE New Player Logic
      const player: Player = { 
        ...newPlayer, 
        id: crypto.randomUUID(),
        isActive: true, // Default to active when added
        isLastMatchMvp: false,
        stats: {
          matchesPlayed: 0,
          wins: 0,
          currentStreak: 0,
          maxStreak: 0
        }
      };
      return [...prev, player];
    });
    setErrorMsg(null);
  };

  const removePlayer = (id: string) => {
    setPlayers(prev => prev.filter(p => p.id !== id));
  };

  const togglePlayerActive = (id: string) => {
    setPlayers(prev => prev.map(p => 
      p.id === id ? { ...p, isActive: !p.isActive } : p
    ));
  };

  // Edit Handlers
  const handleEditPlayer = (player: Player) => {
    setEditingPlayer(player);
    setIsEditModalOpen(true);
  };

  const handleUpdatePlayer = (updatedPlayer: Player) => {
    setPlayers(prev => prev.map(p => 
      p.id === updatedPlayer.id ? updatedPlayer : p
    ));
    setErrorMsg(null);
  };

  const activePlayers = players.filter(p => p.isActive);

  const handleGenerate = () => {
    if (!roomId.trim()) {
      setErrorMsg("Please enter a Room ID.");
      return;
    }

    const required = isCoachMode ? 12 : 10;
    if (activePlayers.length < required) {
      setErrorMsg(`Need ${required} ACTIVE players for ${isCoachMode ? 'Coach' : 'Standard'} Mode. Current Active: ${activePlayers.length}`);
      return;
    }

    // COACH MODE VALIDATION
    if (isCoachMode) {
       // STRICT: Only players with the explicit COACH role can be coach. 
       // All Roles/Fill does NOT count for coach slots.
       const coachCandidates = activePlayers.filter(p => p.roles.includes(Role.COACH));

       if (coachCandidates.length < 2) {
         setErrorMsg(`Coach Mode requires at least 2 players with the specific 'COACH' role. Found: ${coachCandidates.length}`);
         return;
       }
    }

    // Only pass active players to the matchmaker
    const result = generateMatch(activePlayers, roomId, isCoachMode);
    if (result) {
      setCurrentMatch(result);
      setErrorMsg(null);
    } else {
      setErrorMsg("Failed to find valid composition. Ensure role coverage.");
    }
  };

  const handleRerollSlot = (team: 'azure' | 'crimson', role: Role, newPlayer: Player) => {
    if (!currentMatch) return;

    // Update Match State with the new player chosen by the wheel
    setCurrentMatch(prev => {
       if (!prev) return null;

       const newAzure = prev.azureTeam.map(slot => {
          if (team === 'azure' && slot.role === role) {
             return { ...slot, player: newPlayer };
          }
          return slot;
       });

       const newCrimson = prev.crimsonTeam.map(slot => {
          if (team === 'crimson' && slot.role === role) {
             return { ...slot, player: newPlayer };
          }
          return slot;
       });

       return {
          ...prev,
          azureTeam: newAzure,
          crimsonTeam: newCrimson
       };
    });
  };

  const handleMatchFinish = (winner: 'azure' | 'crimson' | null, mvpId?: string, ratings?: Record<string, number>) => {
    if (!currentMatch) return;

    // 1. Save History with Ratings
    const historyEntry: MatchHistoryEntry = {
       ...currentMatch,
       id: crypto.randomUUID(),
       winningTeam: winner,
       mvpId: mvpId,
       ratings: ratings // Store the ratings
    };
    setMatchHistory(prev => [historyEntry, ...prev]);

    // 2. Update Player Stats if there is a winner
    if (winner) {
      const azurePlayerIds = new Set(currentMatch.azureTeam.map(slot => slot.player.id));
      const crimsonPlayerIds = new Set(currentMatch.crimsonTeam.map(slot => slot.player.id));

      setPlayers(prevPlayers => prevPlayers.map(p => {
        let isLastMatchMvp = false;

        // If player matches the manually provided MVP ID, set flag
        if (mvpId && p.id === mvpId) {
          isLastMatchMvp = true;
        }

        if (!azurePlayerIds.has(p.id) && !crimsonPlayerIds.has(p.id)) {
          return { ...p, isLastMatchMvp: false }; // Clear old MVP if they didn't play
        }

        const isAzure = azurePlayerIds.has(p.id);
        const isWinner = (isAzure && winner === 'azure') || (!isAzure && winner === 'crimson');

        const newStats = { ...p.stats };
        newStats.matchesPlayed += 1;

        if (isWinner) {
           newStats.wins += 1;
           newStats.currentStreak += 1;
           if (newStats.currentStreak > newStats.maxStreak) {
             newStats.maxStreak = newStats.currentStreak;
           }
        } else {
           // Reset streak on loss
           newStats.currentStreak = 0;
        }

        return { ...p, stats: newStats, isLastMatchMvp };
      }));
    }

    // 3. Clear match and Room ID (Reset ID)
    setCurrentMatch(null);
    setRoomId(''); 
  };

  const handleAbortMatch = () => setCurrentMatch(null);

  const quickFill = () => {
     const shuffledHeroes = [...HOK_HEROES].sort(() => 0.5 - Math.random());
     const heroesToAdd = shuffledHeroes.slice(0, 15);
     const newPlayers: Player[] = heroesToAdd.map(hero => ({
        id: crypto.randomUUID(),
        name: hero.name,
        isAllRoles: false,
        roles: hero.roles,
        isActive: true,
        isLastMatchMvp: false,
        stats: { matchesPlayed: 0, wins: 0, currentStreak: 0, maxStreak: 0 }
     }));
     // Add some flexible minions/players if needed to ensure we have enough
     for(let i=0; i<5; i++) {
        newPlayers.push({
           id: crypto.randomUUID(),
           name: `Flex Player ${i+1}`,
           isAllRoles: true,
           roles: [],
           isActive: true,
           isLastMatchMvp: false,
           stats: { matchesPlayed: 0, wins: 0, currentStreak: 0, maxStreak: 0 }
        });
     }

     setPlayers(prev => {
        const existingNames = new Set(prev.map(p => p.name));
        const filteredNew = newPlayers.filter(p => !existingNames.has(p.name));
        return [...prev, ...filteredNew].slice(0, 30);
     });

     // NOTE: We do NOT set Room ID automatically anymore per user request.
  };

  // --- SAVE / LOAD FUNCTIONALITY ---

  const getFormattedTimestamp = () => {
    const date = new Date();
    const YYYY = date.getFullYear();
    const MM = String(date.getMonth() + 1).padStart(2, '0');
    const DD = String(date.getDate()).padStart(2, '0');
    const HH = String(date.getHours()).padStart(2, '0');
    const mm = String(date.getMinutes()).padStart(2, '0');
    return `${YYYY}-${MM}-${DD}_${HH}-${mm}`;
  };

  const handleExportRoster = () => {
    if (players.length === 0) return;
    const dataStr = "data:text/json;charset=utf-8," + encodeURIComponent(JSON.stringify(players, null, 2));
    const filename = `hok-squad-roster_${getFormattedTimestamp()}.json`;

    const downloadAnchorNode = document.createElement('a');
    downloadAnchorNode.setAttribute("href", dataStr);
    downloadAnchorNode.setAttribute("download", filename);
    document.body.appendChild(downloadAnchorNode);
    downloadAnchorNode.click();
    downloadAnchorNode.remove();
  };

  const handleExportHistory = () => {
    if (matchHistory.length === 0) return;
    const dataStr = "data:text/json;charset=utf-8," + encodeURIComponent(JSON.stringify(matchHistory, null, 2));
    const filename = `hok-match-history_${getFormattedTimestamp()}.json`;

    const downloadAnchorNode = document.createElement('a');
    downloadAnchorNode.setAttribute("href", dataStr);
    downloadAnchorNode.setAttribute("download", filename);
    document.body.appendChild(downloadAnchorNode);
    downloadAnchorNode.click();
    downloadAnchorNode.remove();
  };

  const handleRosterImportClick = () => {
    rosterFileInputRef.current?.click();
  };

  const handleHistoryImportClick = () => {
    historyFileInputRef.current?.click();
  };

  const handleRosterFileChange = (event: React.ChangeEvent<HTMLInputElement>) => {
    const fileObj = event.target.files && event.target.files[0];
    if (!fileObj) return;

    const reader = new FileReader();
    reader.onload = (e) => {
      try {
        const json = e.target?.result;
        if (typeof json === 'string') {
          const parsedData = JSON.parse(json);
          // Basic validation
          if (Array.isArray(parsedData) && parsedData.length > 0 && parsedData[0].name) {
             const importedPlayers: Player[] = parsedData.map((p: any) => ({
               ...p,
               id: crypto.randomUUID(),
               // Ensure properties exist for backward compatibility with old JSONs
               isActive: typeof p.isActive === 'boolean' ? p.isActive : true,
               isLastMatchMvp: typeof p.isLastMatchMvp === 'boolean' ? p.isLastMatchMvp : false,
               stats: p.stats || { matchesPlayed: 0, wins: 0, currentStreak: 0, maxStreak: 0 }
             }));
             setPlayers(importedPlayers);
             setErrorMsg(null);
          } else {
             setErrorMsg("Invalid Roster JSON file format.");
          }
        }
      } catch (err) {
        setErrorMsg("Failed to parse Roster JSON file.");
      }
    };
    reader.readAsText(fileObj);
    event.target.value = '';
  };

  const handleHistoryFileChange = (event: React.ChangeEvent<HTMLInputElement>) => {
    const fileObj = event.target.files && event.target.files[0];
    if (!fileObj) return;

    const reader = new FileReader();
    reader.onload = (e) => {
      try {
        const json = e.target?.result;
        if (typeof json === 'string') {
          const parsedData = JSON.parse(json);
          // Basic validation for match history
          if (Array.isArray(parsedData) && (parsedData.length === 0 || parsedData[0].roomId)) {
             setMatchHistory(parsedData);
             setErrorMsg(null);
          } else {
             setErrorMsg("Invalid History JSON file format.");
          }
        }
      } catch (err) {
        setErrorMsg("Failed to parse History JSON file.");
      }
    };
    reader.readAsText(fileObj);
    event.target.value = '';
  };

  const handleRoomIdChange = (e: React.ChangeEvent<HTMLInputElement>) => {
    const val = e.target.value;
    if (val.length <= 4) {
      setRoomId(val);
    }
  };

  return (
    <div className="min-h-screen text-slate-200 font-inter overflow-x-hidden relative">
      <BackgroundParticles />

      {/* New Background Image (HoK Global Launch) */}
      <div className="fixed inset-0 bg-black -z-10">
         <img 
           src="https://www.levelinfinite.com/wp-content/uploads/2024/03/honor-of-kings-global-launch-pc.jpg" 
           alt="Honor of Kings Background" 
           className="absolute inset-0 w-full h-full object-cover opacity-50"
         />
         <div className="absolute inset-0 bg-gradient-to-b from-[#05090f]/90 via-[#05090f]/60 to-[#05090f] mix-blend-multiply"></div>
         <div className="absolute inset-0 bg-gradient-to-t from-[#05090f] via-transparent to-[#05090f]/80"></div>
      </div>

      {/* Hidden File Inputs */}
      <input 
        type="file" 
        ref={rosterFileInputRef}
        onChange={handleRosterFileChange}
        accept=".json"
        className="hidden"
      />
      <input 
        type="file" 
        ref={historyFileInputRef}
        onChange={handleHistoryFileChange}
        accept=".json"
        className="hidden"
      />

      {/* Edit Modal */}
      {editingPlayer && (
        <EditPlayerModal 
          player={editingPlayer}
          isOpen={isEditModalOpen}
          onClose={() => setIsEditModalOpen(false)}
          onSave={handleUpdatePlayer}
        />
      )}

      {/* Cinematic Header - Sticky & Compact */}
      <header className="sticky top-0 z-50 h-16 flex items-center justify-center border-b border-[#dcb06b]/20 bg-[#05090f]/90 backdrop-blur-md shadow-lg transition-all">
        <div className="absolute inset-0 bg-gradient-to-r from-transparent via-[#dcb06b]/5 to-transparent"></div>
        <div className="flex items-center gap-2 animate-float">
           <div className="w-6 h-6 border border-[#dcb06b] rotate-45 flex items-center justify-center bg-[#0a1a2f]">
              <div className="w-3 h-3 bg-[#dcb06b]"></div>
           </div>
           <h1 className="text-xl font-cinzel font-black tracking-[0.2em] text-white flex flex-col md:flex-row md:items-center md:gap-2 leading-none">
             <span>
               <span className="hok-gold-text">HONOR</span> OF <span className="hok-gold-text">KINGS</span>
             </span>
             <span className="text-[7px] text-[#8a9db8] tracking-[0.3em] font-orbitron md:mt-0 mt-1">OPEN MABAR</span>
           </h1>
        </div>
      </header>

      <main className="relative z-10 pt-8 px-4 pb-20">
        {currentMatch ? (
          <MatchDisplay 
            match={currentMatch} 
            activePlayers={activePlayers} 
            onReset={handleAbortMatch}
            onCompleteMatch={handleMatchFinish}
            onReroll={handleRerollSlot}
          />
        ) : (
          <div className="max-w-7xl mx-auto">

            <div className="grid grid-cols-1 lg:grid-cols-12 gap-8 relative transition-all duration-500">

              {/* Left Panel: Controls (Collapsible) */}
              <div className={`
                 lg:col-span-4 space-y-6 transition-all duration-500 ease-in-out
                 ${isSidebarOpen ? 'opacity-100 translate-x-0' : 'hidden opacity-0 -translate-x-full lg:col-span-0'}
              `}>

                 {/* Room ID & Coach Mode Toggle */}
                 <div className="bg-[#0a1a2f]/80 p-1 clip-corner-sm border border-[#1e3a5f] shadow-[0_0_25px_rgba(220,176,107,0.15)] relative group space-y-2">
                    <div className="absolute -inset-1 bg-gradient-to-r from-transparent via-[#dcb06b]/30 to-transparent blur opacity-0 group-hover:opacity-100 transition-opacity duration-700"></div>

                    <div className="bg-[#05090f] p-4 flex items-center gap-4 clip-corner-sm relative z-10">
                       <label className="text-xs uppercase text-[#dcb06b] font-bold font-orbitron whitespace-nowrap tracking-widest">Room ID</label>
                       <div className="h-8 w-[1px] bg-[#1e3a5f]"></div>
                       <input 
                          type="text" 
                          value={roomId}
                          onChange={handleRoomIdChange}
                          maxLength={4}
                          placeholder="0000"
                          className="bg-transparent text-lg font-orbitron text-white w-full focus:outline-none tracking-widest placeholder-[#1e3a5f]"
                       />
                    </div>
                 </div>

                 <div className="flex items-center justify-between bg-[#0a1a2f]/60 p-4 border border-[#1e3a5f] clip-corner-sm">
                     <span className="text-[#dcb06b] font-cinzel font-bold text-sm tracking-widest flex items-center gap-2">
                        <svg xmlns="http://www.w3.org/2000/svg" className="h-4 w-4" fill="none" viewBox="0 0 24 24" stroke="currentColor">
                           <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M19 11H5m14 0a2 2 0 012 2v6a2 2 0 01-2 2H5a2 2 0 01-2-2v-6a2 2 0 012-2m14 0V9a2 2 0 00-2-2M5 11V9a2 2 0 012-2m0 0V5a2 2 0 012-2h6a2 2 0 012 2v2M7 7h10" />
                        </svg>
                        COACH MODE <span className="text-[8px] bg-[#dcb06b] text-black px-1.5 py-0.5 rounded font-orbitron font-bold ml-1">(BETA)</span>
                     </span>
                     <label className="relative inline-flex items-center cursor-pointer">
                        <input type="checkbox" className="sr-only peer" checked={isCoachMode} onChange={(e) => setIsCoachMode(e.target.checked)} />
                        <div className="w-11 h-6 bg-[#1e3a5f] peer-focus:outline-none rounded-full peer peer-checked:after:translate-x-full peer-checked:after:border-white after:content-[''] after:absolute after:top-[2px] after:left-[2px] after:bg-white after:border-gray-300 after:border after:rounded-full after:h-5 after:w-5 after:transition-all peer-checked:bg-[#dcb06b]"></div>
                     </label>
                 </div>

                 <PlayerForm onAddPlayer={addPlayer} isCoachMode={isCoachMode} />

                 {/* Status Panel */}
                 <div className="relative p-6 clip-corner-md bg-gradient-to-b from-[#1a2c42] to-[#05090f] border border-[#dcb06b]/20 group hover:border-[#dcb06b]/50 transition-colors duration-500">
                    <div className="absolute top-0 left-0 w-full h-1 bg-gradient-to-r from-transparent via-[#dcb06b] to-transparent opacity-50"></div>

                    <div className="flex justify-between items-end mb-6">
                       <div>
                          <div className="text-[#8a9db8] text-[10px] uppercase tracking-widest font-bold mb-1">Active Players</div>
                          <div className="text-5xl font-orbitron font-bold text-white relative">
                             {activePlayers.length}
                             <span className="text-lg text-[#4a5f78] absolute top-0 -right-12">/ {isCoachMode ? 12 : 10}</span>
                          </div>
                       </div>
                       <div className="text-right">
                          <button onClick={quickFill} className="text-[10px] text-[#dcb06b] border border-[#dcb06b] px-3 py-1 hover:bg-[#dcb06b] hover:text-black transition-colors uppercase tracking-wider">
                             Quick Fill
                          </button>
                       </div>
                    </div>

                    {errorMsg && (
                      <div className="mb-4 p-3 border-l-2 border-red-500 bg-red-900/20 text-red-200 text-xs">
                        {errorMsg}
                      </div>
                    )}

                    <Button 
                      onClick={handleGenerate} 
                      className="w-full text-lg shadow-[0_0_20px_rgba(220,176,107,0.3)]"
                      disabled={activePlayers.length < (isCoachMode ? 12 : 10)}
                    >
                       START MATCHMAKING
                    </Button>
                 </div>
              </div>

              {/* Right Panel: Player Grid & History */}
              <div className={`transition-all duration-500 ${isSidebarOpen ? 'lg:col-span-8' : 'lg:col-span-12'}`}>
                 <div className="flex flex-wrap items-center justify-between mb-6 gap-4">

                    {/* Header with Expand Button */}
                    <div className="flex items-center gap-4">
                        <button 
                           onClick={() => setIsSidebarOpen(!isSidebarOpen)} 
                           className="p-2 border border-[#1e3a5f] hover:border-[#dcb06b] text-[#dcb06b] clip-corner-sm transition-all bg-[#0a1a2f]/50"
                           title={isSidebarOpen ? "Maximize List" : "Show Controls"}
                        >
                           {isSidebarOpen ? (
                              <svg xmlns="http://www.w3.org/2000/svg" className="h-5 w-5" fill="none" viewBox="0 0 24 24" stroke="currentColor">
                                <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M4 8V4m0 0h4M4 4l5 5m11-1V4m0 0h-4m4 0l-5 5M4 16v4m0 0h4m-4 0l5-5m11 5l-5-5m5 5v-4m0 4h-4" />
                              </svg>
                           ) : (
                              <svg xmlns="http://www.w3.org/2000/svg" className="h-5 w-5" fill="none" viewBox="0 0 24 24" stroke="currentColor">
                                 <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M4 6h16M4 12h16M4 18h16" />
                              </svg>
                           )}
                        </button>

                        <h2 className="text-2xl font-cinzel font-black tracking-[0.2em] uppercase drop-shadow-sm text-[#dcb06b] flex items-center gap-3">
                           <span className="w-2 h-2 bg-[#dcb06b] rotate-45"></span>
                           SQUAD ROSTER
                        </h2>
                    </div>

                    <div className="flex items-center gap-2">
                       {/* Import/Export Controls */}
                       <button 
                         onClick={handleRosterImportClick}
                         className="flex items-center gap-2 px-3 py-1 text-[10px] uppercase font-bold tracking-wider text-[#4a5f78] border border-[#1e3a5f] hover:border-[#dcb06b] hover:text-[#dcb06b] transition-all clip-corner-sm"
                         title="Load Roster JSON"
                       >
                          <svg xmlns="http://www.w3.org/2000/svg" className="h-4 w-4" fill="none" viewBox="0 0 24 24" stroke="currentColor">
                            <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M4 16v1a3 3 0 003 3h10a3 3 0 003-3v-1m-4-8l-4-4m0 0L8 8m4-4v12" />
                          </svg>
                          Load
                       </button>

                       <button 
                         onClick={handleExportRoster}
                         disabled={players.length === 0}
                         className="flex items-center gap-2 px-3 py-1 text-[10px] uppercase font-bold tracking-wider text-[#4a5f78] border border-[#1e3a5f] hover:border-[#dcb06b] hover:text-[#dcb06b] transition-all clip-corner-sm disabled:opacity-30 disabled:cursor-not-allowed"
                         title="Save Roster JSON"
                       >
                          <svg xmlns="http://www.w3.org/2000/svg" className="h-4 w-4" fill="none" viewBox="0 0 24 24" stroke="currentColor">
                            <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M4 16v1a3 3 0 003 3h10a3 3 0 003-3v-1m-4-4l-4 4m0 0l-4-4m4 4V4" />
                          </svg>
                          Save
                       </button>

                       <div className="h-4 w-[1px] bg-[#1e3a5f] mx-2"></div>

                       <button onClick={() => setPlayers([])} className="text-xs text-[#4a5f78] hover:text-red-400 uppercase tracking-widest transition-colors">
                          Clear All
                       </button>
                    </div>
                 </div>

                 <div className="perspective-container tech-border p-6 bg-[#0a1a2f]/40 min-h-[400px] mb-8">
                    <PlayerList 
                      players={players} 
                      onRemove={removePlayer} 
                      onToggleActive={togglePlayerActive}
                      onEdit={handleEditPlayer}
                      isSidebarOpen={isSidebarOpen}
                    />
                 </div>

                 {/* MATCH HISTORY SECTION */}
                 <div className="mt-12">
                     <div className="flex items-center justify-between mb-6">
                        <h2 className="text-2xl font-cinzel font-black tracking-[0.2em] uppercase drop-shadow-sm text-[#dcb06b] flex items-center gap-3">
                           <span className="w-2 h-2 bg-[#dcb06b] rotate-45"></span>
                           BATTLE HISTORY
                        </h2>

                        <div className="flex items-center gap-2">
                           <button 
                             onClick={handleHistoryImportClick}
                             className="flex items-center gap-2 px-3 py-1 text-[10px] uppercase font-bold tracking-wider text-[#4a5f78] border border-[#1e3a5f] hover:border-[#dcb06b] hover:text-[#dcb06b] transition-all clip-corner-sm"
                           >
                              <svg xmlns="http://www.w3.org/2000/svg" className="h-4 w-4" fill="none" viewBox="0 0 24 24" stroke="currentColor">
                                <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M4 16v1a3 3 0 003 3h10a3 3 0 003-3v-1m-4-8l-4-4m0 0L8 8m4-4v12" />
                              </svg>
                              Import
                           </button>

                           <button 
                              onClick={handleExportHistory}
                              disabled={matchHistory.length === 0}
                              className="flex items-center gap-2 px-3 py-1 text-[10px] uppercase font-bold tracking-wider text-[#4a5f78] border border-[#1e3a5f] hover:border-[#dcb06b] hover:text-[#dcb06b] transition-all clip-corner-sm disabled:opacity-30 disabled:cursor-not-allowed"
                           >
                              <svg xmlns="http://www.w3.org/2000/svg" className="h-4 w-4" fill="none" viewBox="0 0 24 24" stroke="currentColor">
                                 <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M12 10v6m0 0l-3-3m3 3l3-3m2 8H7a2 2 0 01-2-2V5a2 2 0 012-2h5.586a1 1 0 01.707.293l5.414 5.414a1 1 0 01.293.707V19a2 2 0 01-2 2z" />
                              </svg>
                              Export
                           </button>
                        </div>
                     </div>

                     <div className="tech-border p-6 bg-[#0a1a2f]/40">
                        <HistoryList history={matchHistory} onClear={() => setMatchHistory([])} />
                     </div>
                 </div>
              </div>

            </div>
          </div>
        )}
      </main>
    </div>
  );
}

import React, { useState } from 'react';
import { MatchResult, TeamSlot, Role, Player } from '../types';
import { RoleIcons, ROLES_ORDER } from '../constants';
import { Button } from './Button';
import { SpinWheel } from './SpinWheel';
import { PortalTransition } from './PortalTransition';
import { MatchSummary } from './MatchSummary';
import { VictoryCelebration } from './VictoryCelebration';
import { EvaluationScreen } from './EvaluationScreen';

interface MatchDisplayProps {
  match: MatchResult;
  activePlayers: Player[]; 
  onReset: () => void; // For Abort
  onCompleteMatch: (winner: 'azure' | 'crimson' | null, mvpId?: string, ratings?: Record<string, number>) => void; // For Finish
  onReroll: (team: 'azure' | 'crimson', role: Role, newPlayer: Player) => void;
}

type ViewState = 'drafting' | 'transition' | 'final' | 'celebration' | 'evaluation';

export const MatchDisplay: React.FC<MatchDisplayProps> = ({ match, activePlayers, onReset, onCompleteMatch, onReroll }) => {
  const [viewState, setViewState] = useState<ViewState>('drafting');
  const [winningTeam, setWinningTeam] = useState<'azure' | 'crimson' | null>(null);

  // Dynamic Role Order: If Coach mode, append Coach to standard order
  const displayRoles = match.isCoachMode ? [...ROLES_ORDER, Role.COACH] : ROLES_ORDER;

  // -1: Not started
  // 0-4: Revealing pairs (0=Clash, ... 4=Roam)
  // 5: Coach (if exists)
  const [currentRoleIndex, setCurrentRoleIndex] = useState(-1);

  // New State for the Modal Wheel
  const [wheelState, setWheelState] = useState<{
    isOpen: boolean;
    type: 'draft' | 'reroll'; // Differentiate between initial draft reveal and manual reroll
    team: 'azure' | 'crimson';
    role: Role;
    winnerName: string;
    winnerPlayer?: Player; // Needed for reroll
    candidates: string[];
  } | null>(null);

  // Tracks which individual cards are visible
  const [revealedCards, setRevealedCards] = useState<Set<string>>(new Set());

  const getPlayerForRole = (team: TeamSlot[], role: Role) => {
    return team.find(slot => slot.role === role);
  };

  const getCardId = (team: 'azure' | 'crimson', role: Role) => `${team}-${role}`;

  const handleNext = () => {
    const nextIndex = currentRoleIndex + 1;
    if (nextIndex >= displayRoles.length) return;

    const roleToReveal = displayRoles[nextIndex];

    // Step 1: Check if Azure is revealed
    const azureId = getCardId('azure', roleToReveal);
    if (!revealedCards.has(azureId)) {
      startWheel('azure', roleToReveal);
      return;
    }

    // Step 2: Check if Crimson is revealed
    const crimsonId = getCardId('crimson', roleToReveal);
    if (!revealedCards.has(crimsonId)) {
      startWheel('crimson', roleToReveal);
      return;
    }
  };

  const handleSkipAll = () => {
    // Debug: Instantly reveal everything
    const allCards = new Set<string>();
    displayRoles.forEach(r => {
      allCards.add(getCardId('azure', r));
      allCards.add(getCardId('crimson', r));
    });
    setRevealedCards(allCards);
    setCurrentRoleIndex(displayRoles.length); // Set to finished state
  };

  const startWheel = (team: 'azure' | 'crimson', role: Role) => {
    const teamSlots = team === 'azure' ? match.azureTeam : match.crimsonTeam;
    const winner = getPlayerForRole(teamSlots, role)?.player;
    if (!winner) return;

    // Get candidates for the wheel
    // STRICT COACH LOGIC: If role is Coach, ONLY allow players with Coach role.
    const candidates = activePlayers
      .filter(p => {
          if (role === Role.COACH) {
              return p.roles.includes(Role.COACH);
          }
          return p.isAllRoles || p.roles.includes(role);
      })
      .map(p => p.name);

    setWheelState({
      isOpen: true,
      type: 'draft',
      team,
      role,
      winnerName: winner.name,
      candidates
    });
  };

  // Triggered when user clicks the re-roll button on a card
  const handleRerollClick = (team: 'azure' | 'crimson', role: Role) => {
    const azureIds = new Set(match.azureTeam.map(s => s.player.id));
    const crimsonIds = new Set(match.crimsonTeam.map(s => s.player.id));

    const benchPlayers = activePlayers.filter(p => !azureIds.has(p.id) && !crimsonIds.has(p.id));

    if (benchPlayers.length === 0) {
      alert("No available bench players to re-roll with!");
      return;
    }

    const candidates = benchPlayers.filter(p => {
       if (role === Role.COACH) {
          return p.roles.includes(Role.COACH);
       }
       return p.isAllRoles || p.roles.includes(role);
    });

    if (candidates.length === 0) {
       alert(`No available bench players found for role: ${role}`);
       return;
    }

    const newPlayer = candidates[Math.floor(Math.random() * candidates.length)];
    const candidateNames = candidates.map(p => p.name);

    setWheelState({
        isOpen: true,
        type: 'reroll',
        team,
        role,
        winnerName: newPlayer.name,
        winnerPlayer: newPlayer,
        candidates: candidateNames
    });
  };

  const handleWheelComplete = () => {
    if (!wheelState) return;

    if (wheelState.type === 'draft') {
        const { team, role } = wheelState;
        setRevealedCards(prev => new Set(prev).add(getCardId(team, role)));
        if (team === 'crimson') {
           setCurrentRoleIndex(prev => prev + 1);
        }
    } else if (wheelState.type === 'reroll' && wheelState.winnerPlayer) {
        onReroll(wheelState.team, wheelState.role, wheelState.winnerPlayer);
    }

    setWheelState(null);
  };

  const handleWheelCancel = () => {
    setWheelState(null);
  };

  const handleInitializeBattle = () => {
    setViewState('transition');
  };

  const handleTransitionComplete = () => {
    setViewState('final');
  };

  const handleMatchDecided = (winner: 'azure' | 'crimson' | null) => {
    if (winner) {
      setWinningTeam(winner);
      setViewState('celebration');
    } else {
      onCompleteMatch(null);
    }
  };

  const handleCelebrationDismiss = () => {
    setViewState('evaluation');
  };

  const handleEvaluationComplete = (mvpId?: string, ratings?: Record<string, number>) => {
    onCompleteMatch(winningTeam, mvpId, ratings);
  }

  // --- RENDER LOGIC ---

  if (viewState === 'evaluation' && winningTeam) {
    return (
      <EvaluationScreen 
        match={match} 
        winner={winningTeam} 
        onComplete={handleEvaluationComplete} 
      />
    );
  }

  if (viewState === 'celebration' && winningTeam) {
    const winningTeamSlots = winningTeam === 'azure' ? match.azureTeam : match.crimsonTeam;
    return (
      <VictoryCelebration 
        winner={winningTeam} 
        teamSlots={winningTeamSlots}
        onDismiss={handleCelebrationDismiss} 
      />
    );
  }

  if (viewState === 'transition') {
    return (
      <PortalTransition 
        azureTeam={match.azureTeam} 
        crimsonTeam={match.crimsonTeam} 
        onComplete={handleTransitionComplete} 
      />
    );
  }

  if (viewState === 'final') {
    return <MatchSummary match={match} onReset={handleMatchDecided} />;
  }

  // --- DRAFTING VIEW ---

  const renderPlayerCard = (role: Role, roleIndex: number, team: 'azure' | 'crimson') => {
    const teamSlots = team === 'azure' ? match.azureTeam : match.crimsonTeam;
    const player = getPlayerForRole(teamSlots, role)?.player;
    const isRevealed = revealedCards.has(getCardId(team, role));
    const isCoach = role === Role.COACH;

    // HoK Color Palettes
    // If Coach, override with Special White/Silver Theme
    let theme;
    if (isCoach) {
        theme = {
            bg: 'bg-[#1a1a1a]',
            border: 'border-white',
            glow: 'shadow-[0_0_20px_rgba(255,255,255,0.8)]',
            text: 'text-white',
            gradient: 'from-white/20 to-transparent'
        };
    } else {
        theme = team === 'azure' 
          ? {
              bg: 'bg-[#0a1a2f]',
              border: 'border-hok-cyan',
              glow: 'shadow-[0_0_10px_#00d2ff]',
              text: 'text-hok-cyan',
              gradient: 'from-[#00d2ff]/20 to-transparent'
            } 
          : {
              bg: 'bg-[#1a0505]',
              border: 'border-hok-red',
              glow: 'shadow-[0_0_10px_#ef4444]',
              text: 'text-hok-red',
              gradient: 'from-[#c02d2d]/20 to-transparent'
            };
    }

    // State 1: Hidden
    if (!isRevealed) {
       return (
         <div className="h-16 w-full relative overflow-hidden clip-corner-md border border-[#1e3a5f] bg-[#05090f]/80 flex flex-col items-center justify-center opacity-40 group">
            <div className="text-[#1e3a5f] group-hover:text-[#dcb06b]/50 transition-colors duration-500 transform scale-90 opacity-50">
               {RoleIcons[role]}
            </div>
            {/* Tech Scanlines */}
            <div className="absolute inset-0 bg-[url('data:image/svg+xml;base64,PHN2ZyB4bWxucz0iaHR0cDovL3d3dy53My5vcmcvMjAwMC9zdmciIHdpZHRoPSI0IiBoZWlnaHQ9IjQiPgo8cmVjdCB3aWR0aD0iNCIgaGVpZ2h0PSI0IiBmaWxsPSIjZmZmIiBmaWxsLW9wYWNpdHk9IjAuMDUiLz4KPHBhdGggZD0iTTAgNEw0IDBaIiBzdHJva2U9IiMwMDAiIHN0cm9rZS13aWR0aD0iMSIvPgo8L3N2Zz4=')] opacity-20"></div>
         </div>
       );
    }

    // State 2: Revealed (UPDATED LAYOUT FOR TEXT ROLES & MIRRORING)
    return (
      <div className={`relative h-16 w-full animate-slide-in perspective-container group`}>
        <div className={`
            absolute inset-0 clip-corner-md border-l-4 tilt-card
            ${theme.bg} ${theme.border} 
            ${theme.glow}
            shadow-[0_0_15px_rgba(0,0,0,0.5)]
            transition-all duration-300 hover:brightness-110
        `}>
           <div className={`flex flex-col h-full relative z-10 px-4 py-1 justify-center ${team === 'crimson' ? 'items-end text-right' : 'items-start text-left'}`}>

             {/* Text Role Label (Top) */}
             <div className={`mb-0.5 px-2 py-0.5 rounded-sm bg-black/40 border border-white/10 ${theme.text} transform transition-transform duration-500 w-auto inline-block scale-90 origin-${team === 'crimson' ? 'right' : 'left'}`}>
                {RoleIcons[role]}
             </div>

             {/* Name Section */}
             <span className={`block text-lg md:text-xl font-bold text-white truncate font-orbitron drop-shadow-md w-full`}>
                {player?.name}
             </span>

             <div className={`absolute inset-0 bg-gradient-to-r ${theme.gradient} opacity-50 pointer-events-none`}></div>
           </div>

           {/* Decorative Tech Corners */}
           <div className={`absolute top-0 w-8 h-8 border-t border-${isCoach ? 'white' : (team === 'azure' ? 'cyan' : 'red')}-500/50 ${team === 'azure' ? 'left-0' : 'right-0'}`}></div>
           <div className={`absolute bottom-0 w-8 h-8 border-b border-${isCoach ? 'white' : (team === 'azure' ? 'cyan' : 'red')}-500/50 ${team === 'azure' ? 'right-0' : 'left-0'}`}></div>

           {/* Re-roll Button Overlay - Mirrored Position */}
           {/* If Azure (Left Align): Button on Right. If Crimson (Right Align): Button on Left */}
           <button 
             onClick={(e) => { e.stopPropagation(); handleRerollClick(team, role); }}
             className={`absolute top-1 p-1.5 bg-black/50 hover:bg-[#dcb06b] rounded-full transition-colors group-hover:opacity-100 opacity-0 text-white hover:text-black z-50 border border-white/20
                ${team === 'azure' ? 'right-2' : 'left-2'}
             `}
             title="Re-roll this specific slot"
           >
             <svg xmlns="http://www.w3.org/2000/svg" className="h-4 w-4" fill="none" viewBox="0 0 24 24" stroke="currentColor">
               <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M4 4v5h.582m15.356 2A8.001 8.001 0 004.582 9m0 0H9m11 11v-5h-.581m0 0a8.003 8.003 0 01-15.357-2m15.357 2H15" />
             </svg>
           </button>
        </div>
      </div>
    );
  };

  const nextRoleIndex = currentRoleIndex + 1;
  const nextRoleName = nextRoleIndex < displayRoles.length ? displayRoles[nextRoleIndex] : null;
  const isFinished = currentRoleIndex >= displayRoles.length - 1 && revealedCards.size === (match.isCoachMode ? 12 : 10);

  let buttonText = "START DRAFT";
  if (nextRoleName) {
     if (!revealedCards.has(getCardId('azure', nextRoleName))) {
        buttonText = `SELECT AZURE ${nextRoleName.split(' ')[0].toUpperCase()}`;
     } else if (!revealedCards.has(getCardId('crimson', nextRoleName))) {
        buttonText = `SELECT CRIMSON ${nextRoleName.split(' ')[0].toUpperCase()}`;
     } else {
        buttonText = "NEXT LANE";
     }
  }

  // Turret SVG Path
  const TurretIcon = (
    <svg viewBox="0 0 24 24" fill="currentColor" className="w-16 h-16 opacity-30 animate-pulse">
        <path d="M12,2 L2,22 L12,18 L22,22 L12,2 Z" />
        <path d="M12,5 L5,20 L12,17 L19,20 L12,5 Z" fillOpacity="0.5" />
    </svg>
  );

  return (
    <>
      {/* The Spin Wheel Overlay */}
      {wheelState && wheelState.isOpen && (
        <SpinWheel 
          candidates={wheelState.candidates}
          winnerName={wheelState.winnerName}
          team={wheelState.team}
          roleName={wheelState.role}
          onComplete={handleWheelComplete}
          onCancel={handleWheelCancel}
        />
      )}

      <div className="w-full max-w-7xl mx-auto px-4 py-8 pb-32 relative">

        {/* Top Controls: Abort & Instant Result */}
        <div className="absolute top-4 left-4 right-4 z-40 flex justify-between">
           <Button variant="outline" size="sm" onClick={() => onReset()} className="border-red-900/50 text-red-500 hover:bg-red-900/20 text-[10px] px-3">
              <span className="flex items-center gap-2">
                 <svg xmlns="http://www.w3.org/2000/svg" className="h-4 w-4" fill="none" viewBox="0 0 24 24" stroke="currentColor">
                   <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M11 15l-3-3m0 0l3-3m-3 3h8M3 12a9 9 0 1118 0 9 9 0 01-18 0z" />
                 </svg>
                 ABORT DRAFT
              </span>
           </Button>

           {/* Debug / Instant Result Button */}
           {!isFinished && (
             <Button variant="outline" size="sm" onClick={handleSkipAll} className="border-[#dcb06b]/50 text-[#dcb06b] hover:bg-[#dcb06b]/10 text-[10px] px-3">
                <span className="flex items-center gap-2">
                   INSTANT RESULT (DEBUG)
                   <svg xmlns="http://www.w3.org/2000/svg" className="h-4 w-4" fill="none" viewBox="0 0 24 24" stroke="currentColor">
                     <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M13 10V3L4 14h7v7l9-11h-7z" />
                   </svg>
                </span>
             </Button>
           )}
        </div>

        {/* Header Info - PERFECTLY CENTERED */}
        <div className="flex flex-col items-center mb-6 pt-8">
           <div className="flex justify-center w-full mb-4">
              <div className="bg-[#05090f] border border-[#dcb06b]/40 px-8 py-2 clip-diamond relative shadow-[0_0_15px_rgba(220,176,107,0.2)]">
                  <div className="absolute inset-0 bg-[#dcb06b]/5 pointer-events-none"></div>
                  <span className="text-[#dcb06b] font-cinzel font-bold text-xs tracking-widest uppercase block text-center">Room ID</span>
                  <span className="text-xl font-orbitron font-bold text-white tracking-widest text-center block">{match.roomId}</span>
              </div>
           </div>

           <div className="flex justify-between items-center w-full relative max-w-5xl">
              <div className="w-1/3 text-center relative group">
                 <div className="absolute -inset-4 bg-cyan-500/10 blur-xl rounded-full opacity-50 group-hover:opacity-100 transition-opacity"></div>
                 <div className="absolute -left-10 top-0 text-cyan-500/20">{TurretIcon}</div>
                 <h2 className="relative text-2xl md:text-4xl font-cinzel font-black text-transparent bg-clip-text bg-gradient-to-b from-cyan-200 to-cyan-600 drop-shadow-[0_0_15px_rgba(6,182,212,0.8)]">
                  AZURE
                 </h2>
                 <p className="text-[10px] md:text-xs text-cyan-400 font-orbitron tracking-[0.4em] mt-1 opacity-70">GOLEM TEAM</p>
                 <div className="h-1 w-24 bg-cyan-500 mx-auto mt-2 shadow-[0_0_10px_#00d2ff]"></div>
              </div>

              <div className="w-1/3 flex justify-center items-center z-10">
                <div className="relative w-20 h-20 md:w-28 md:h-28 flex items-center justify-center">
                  <div className="absolute inset-0 border-2 border-[#dcb06b] rotate-45 animate-spin-slow bg-[#05090f]"></div>
                  <div className="absolute inset-2 border border-[#dcb06b]/50 rotate-45"></div>
                  <span className="text-3xl font-black italic text-[#dcb06b] font-orbitron z-10 pr-2 pt-1 animate-pulse-fast">VS</span>
                </div>
              </div>

              <div className="w-1/3 text-center relative group">
                 <div className="absolute -inset-4 bg-red-500/10 blur-xl rounded-full opacity-50 group-hover:opacity-100 transition-opacity"></div>
                 <div className="absolute -right-10 top-0 text-red-500/20 transform scale-x-[-1]">{TurretIcon}</div>
                 <h2 className="relative text-2xl md:text-4xl font-cinzel font-black text-transparent bg-clip-text bg-gradient-to-b from-red-200 to-red-600 drop-shadow-[0_0_15px_rgba(220,45,45,0.8)]">
                  CRIMSON
                 </h2>
                 <p className="text-[10px] md:text-xs text-red-400 font-orbitron tracking-[0.4em] mt-1 opacity-70">GOLEM TEAM</p>
                 <div className="h-1 w-24 bg-red-500 mx-auto mt-2 shadow-[0_0_10px_#ef4444]"></div>
              </div>
           </div>
        </div>

        {/* Matchup Grid - Compact Gaps */}
        <div className="relative space-y-2 md:space-y-3">
          <div className="absolute left-1/2 top-0 bottom-0 w-[2px] bg-gradient-to-b from-transparent via-[#dcb06b]/30 to-transparent hidden md:block"></div>

          {displayRoles.map((role, idx) => (
            <div key={role} className="grid grid-cols-1 md:grid-cols-2 gap-2 md:gap-8 items-center">
               <div className="order-1 md:order-none">
