        </div>
      </div>
    </>
  );
};

import React, { useEffect, useState } from 'react';
import { MatchResult, Role } from '../types';
import { ROLES_ORDER, RoleIcons } from '../constants';
import { Button } from './Button';

interface EvaluationScreenProps {
  match: MatchResult;
  winner: 'azure' | 'crimson';
  onComplete: (mvpId?: string, ratings?: Record<string, number>) => void;
}

export const EvaluationScreen: React.FC<EvaluationScreenProps> = ({ match, winner, onComplete }) => {
  const [mvpId, setMvpId] = useState<string>('');
  const [isLoading, setIsLoading] = useState(true);

  // Rating State: Map of player ID to score: 2 (Excellent), 1 (Good), 0 (Neutral), -1 (Bad), -2 (Very Bad)
  const [ratings, setRatings] = useState<Record<string, number>>({});

  useEffect(() => {
    // Simulate Calculation Loading
    const timer = setTimeout(() => {
        setIsLoading(false);
    }, 2500); // 2.5s loading time

    return () => clearTimeout(timer);
  }, [match, winner]);

  // Handle Drag Start for MVP Badge
  const handleDragStart = (e: React.DragEvent) => {
    e.dataTransfer.setData("type", "mvp-token");
    e.dataTransfer.effectAllowed = "move";
  };

  const handleDragOver = (e: React.DragEvent) => {
    e.preventDefault(); // Necessary to allow dropping
    e.dataTransfer.dropEffect = "move";
  };

  const handleDrop = (e: React.DragEvent, playerId: string) => {
     e.preventDefault();
     const type = e.dataTransfer.getData("type");
     if (type === "mvp-token") {
        setMvpId(playerId);
     }
  };

  // Up Click: 0 -> 1 -> 2 -> 0
  const cycleRatingUp = (playerId: string) => {
      setRatings(prev => {
          const current = prev[playerId] || 0;
          let next = 0;
          if (current <= 0) next = 1;
          else if (current === 1) next = 2;
          else next = 0;

          const newState = { ...prev, [playerId]: next };
          if (next === 0) delete newState[playerId];
          return newState;
      });
  };

  // Down Click: 0 -> -1 -> -2 -> 0
  const cycleRatingDown = (playerId: string) => {
    setRatings(prev => {
        const current = prev[playerId] || 0;
        let next = 0;
        if (current >= 0) next = -1;
        else if (current === -1) next = -2;
        else next = 0;

        const newState = { ...prev, [playerId]: next };
        if (next === 0) delete newState[playerId];
        return newState;
    });
  };

  if (isLoading) {
    return (
        <div className="fixed inset-0 z-[100] bg-[#05090f] flex flex-col items-center justify-center">
            <div className="w-16 h-16 border-4 border-[#1e3a5f] border-t-[#dcb06b] rounded-full animate-spin mb-6"></div>
            <h2 className="text-[#dcb06b] font-orbitron text-xl tracking-[0.2em] animate-pulse">CALCULATING BATTLE DATA</h2>
            <div className="w-64 h-1 bg-[#1e3a5f] mt-4 rounded overflow-hidden">
                <div className="h-full bg-[#dcb06b] animate-[loading-bar_2s_ease-in-out_infinite]"></div>
            </div>
            <style>{`
                @keyframes loading-bar {
                    0% { width: 0%; transform: translateX(-100%); }
                    50% { width: 100%; transform: translateX(0); }
                    100% { width: 0%; transform: translateX(100%); }
                }
            `}</style>
        </div>
    );
  }

  // MVP Draggable Token Component
  const MVPToken = () => (
    <div 
      draggable 
      onDragStart={handleDragStart}
      className="cursor-grab active:cursor-grabbing hover:scale-110 transition-transform"
      title="Drag me to the MVP player!"
    >
       <div className="w-12 h-12 bg-gradient-to-br from-yellow-300 to-yellow-600 rounded-full flex items-center justify-center shadow-[0_0_15px_#fbbf24] border-2 border-white animate-pulse">
           <span className="font-black italic text-[#05090f] text-xs">MVP</span>
       </div>
    </div>
  );

  const winningTeam = winner === 'azure' ? match.azureTeam : match.crimsonTeam;
  const losingTeam = winner === 'azure' ? match.crimsonTeam : match.azureTeam;

  // Determine role display order (Coach at top if active)
  const rolesToRender = match.isCoachMode ? [Role.COACH, ...ROLES_ORDER] : ROLES_ORDER;

  const renderTeamColumn = (teamSlots: typeof winningTeam, teamName: string, isWinner: boolean, teamColor: 'cyan' | 'red') => {
      const borderColor = teamColor === 'cyan' ? 'border-[#00d2ff]' : 'border-[#ef4444]';
      const bgColor = teamColor === 'cyan' ? 'bg-[#00d2ff]/10' : 'bg-[#ef4444]/10';
      const textColor = teamColor === 'cyan' ? 'text-cyan-400' : 'text-red-500';

      return (
        <div className={`flex-1 w-full border ${borderColor} ${bgColor} p-0 clip-corner-md transition-all`}>
            <div className={`p-4 bg-opacity-30 border-b border-white/10 flex justify-between items-center ${teamColor === 'cyan' ? 'bg-[#00d2ff]' : 'bg-[#ef4444]'}`}>
                <div className="flex items-center gap-2">
                    <div className={`w-1 h-6 ${teamColor === 'cyan' ? 'bg-cyan-500' : 'bg-red-500'}`}></div>
                    <h3 className={`${textColor} font-cinzel font-bold text-xl`}>{teamName}</h3>
                </div>
                {isWinner && <span className="text-[#dcb06b] font-bold uppercase tracking-widest text-xs border border-[#dcb06b] px-2 py-1 rounded">Victory</span>}
            </div>

            <div className="p-4 space-y-2">
                {rolesToRender.map(role => {
                    const slot = teamSlots.find(s => s.role === role);
                    if(!slot) return null;
                    const isMvp = slot.player.id === mvpId;
                    const rating = ratings[slot.player.id] || 0;
                    const isCoach = role === Role.COACH;

                    return (
                        <div 
                            key={role} 
                            // Only allow drag drop if NOT Coach
                            onDragOver={!isCoach ? handleDragOver : undefined}
                            onDrop={!isCoach ? (e) => handleDrop(e, slot.player.id) : undefined}
                            className={`
                                flex items-center justify-between bg-[#0a1a2f]/50 p-3 rounded border relative overflow-hidden group transition-all
                                ${isMvp ? 'border-yellow-400 shadow-[0_0_15px_rgba(251,191,36,0.3)]' : isCoach ? 'border-white/20 bg-white/5' : 'border-white/5 hover:border-white/20'}
                            `}
                        >
                            {/* MVP Background Highlight */}
                            {isMvp && (
                                <div className="absolute inset-0 bg-gradient-to-r from-yellow-500/10 to-transparent pointer-events-none"></div>
                            )}

                            <div className="flex items-center gap-4 relative z-10 flex-1 min-w-0">
                                <div className={`shrink-0 ${isCoach ? 'text-white' : (teamColor === 'cyan' ? 'text-cyan-500/50' : 'text-red-500/50')}`}>
                                    {RoleIcons[role]}
                                </div>
                                <div className="min-w-0 flex-1">
                                    <div className={`text-lg font-orbitron truncate ${isMvp ? 'text-[#dcb06b]' : 'text-white'}`}>{slot.player.name}</div>
                                </div>
                            </div>

                            {/* Right Side: Arrows & MVP Status */}
                            <div className="flex items-center gap-4 relative z-10 shrink-0">

                                {/* Performance Arrows */}
                                <div className="flex flex-col gap-1 mr-2 items-center">
                                    <button 
                                        onClick={() => cycleRatingUp(slot.player.id)}
                                        className={`p-1 rounded hover:bg-white/10 transition-colors flex flex-col items-center leading-none ${rating > 0 ? 'text-green-400 drop-shadow-[0_0_5px_lime]' : 'text-gray-600'}`}
                                        title="Cycle: Good (1) -> Excellent (2) -> Neutral"
                                    >
                                        {/* Dynamic Arrow Icon based on rating level */}
                                        {rating === 2 && (
                                            <div className="flex flex-col -space-y-1">
                                                <svg xmlns="http://www.w3.org/2000/svg" className="h-3 w-3" fill="none" viewBox="0 0 24 24" stroke="currentColor" strokeWidth={4}>
                                                    <path strokeLinecap="round" strokeLinejoin="round" d="M5 15l7-7 7 7" />
                                                </svg>
                                                <svg xmlns="http://www.w3.org/2000/svg" className="h-3 w-3" fill="none" viewBox="0 0 24 24" stroke="currentColor" strokeWidth={4}>
                                                    <path strokeLinecap="round" strokeLinejoin="round" d="M5 15l7-7 7 7" />
                                                </svg>
                                            </div>
                                        )}
                                        {rating !== 2 && (
                                             <svg xmlns="http://www.w3.org/2000/svg" className="h-4 w-4" fill="none" viewBox="0 0 24 24" stroke="currentColor" strokeWidth={3}>
                                                <path strokeLinecap="round" strokeLinejoin="round" d="M5 15l7-7 7 7" />
                                            </svg>
                                        )}
                                    </button>

                                    <button 
                                        onClick={() => cycleRatingDown(slot.player.id)}
                                        className={`p-1 rounded hover:bg-white/10 transition-colors flex flex-col items-center leading-none ${rating < 0 ? 'text-red-500 drop-shadow-[0_0_5px_red]' : 'text-gray-600'}`}
                                        title="Cycle: Bad (-1) -> Very Bad (-2) -> Neutral"
                                    >
                                         {rating === -2 && (
                                            <div className="flex flex-col -space-y-1">
                                                <svg xmlns="http://www.w3.org/2000/svg" className="h-3 w-3" fill="none" viewBox="0 0 24 24" stroke="currentColor" strokeWidth={4}>
                                                    <path strokeLinecap="round" strokeLinejoin="round" d="M19 9l-7 7-7-7" />
                                                </svg>
                                                <svg xmlns="http://www.w3.org/2000/svg" className="h-3 w-3" fill="none" viewBox="0 0 24 24" stroke="currentColor" strokeWidth={4}>
                                                    <path strokeLinecap="round" strokeLinejoin="round" d="M19 9l-7 7-7-7" />
                                                </svg>
                                            </div>
                                        )}
                                        {rating !== -2 && (
                                            <svg xmlns="http://www.w3.org/2000/svg" className="h-4 w-4" fill="none" viewBox="0 0 24 24" stroke="currentColor" strokeWidth={3}>
                                                <path strokeLinecap="round" strokeLinejoin="round" d="M19 9l-7 7-7-7" />
                                            </svg>
                                        )}
                                    </button>
                                </div>

                                {/* MVP Badge Drop Zone / Display */}
                                {/* COACH CANNOT BE MVP */}
                                {!isCoach ? (
                                    <div className="w-12 h-12 flex items-center justify-center">
                                        {isMvp ? (
                                            <div className="w-10 h-10 bg-gradient-to-br from-yellow-300 to-yellow-600 rounded-full flex items-center justify-center shadow-[0_0_10px_#fbbf24] animate-[pop_0.3s_ease-out]">
                                                <span className="font-black italic text-[#05090f] text-[10px]">MVP</span>
                                            </div>
                                        ) : (
                                            <div className="w-10 h-10 border-2 border-dashed border-white/10 rounded-full flex items-center justify-center text-[8px] text-white/20 opacity-0 group-hover:opacity-100 transition-opacity">
                                                DROP
                                            </div>
                                        )}
                                    </div>
                                ) : (
                                     <div className="w-12 h-12 flex items-center justify-center opacity-30">
                                         <div className="text-[8px] text-white/50 uppercase tracking-tighter text-center leading-none">
                                            Coach
                                         </div>
                                     </div>
                                )}
                            </div>
                        </div>
                    );
                })}
            </div>
        </div>
      );
  }

  return (
    <div className="min-h-screen bg-[url('https://wallpaperaccess.com/full/3739268.jpg')] bg-cover bg-center fixed inset-0 z-[50] flex flex-col items-center justify-center p-4">
       <div className="absolute inset-0 bg-[#05090f]/90 backdrop-blur-md"></div>

       <div className="relative z-10 w-full max-w-6xl animate-slide-in h-full overflow-y-auto py-8">

          <div className="text-center mb-6">
             <div className="flex items-center justify-center gap-3 mb-2">
                 <div className="w-2 h-2 bg-[#dcb06b] rounded-full"></div>
                 <h2 className="text-[#dcb06b] font-cinzel font-bold text-xl tracking-[0.3em] uppercase">Battle Report</h2>
                 <div className="w-2 h-2 bg-[#dcb06b] rounded-full"></div>
             </div>
             <h1 className="text-3xl md:text-5xl font-orbitron font-black text-white uppercase drop-shadow-[0_0_15px_rgba(255,255,255,0.5)]">
                Evaluation
             </h1>
          </div>

          {/* MVP Drag Source Area */}
          <div className="flex flex-col items-center justify-center mb-8 p-4 bg-[#0a1a2f]/50 border border-[#dcb06b]/30 rounded-lg max-w-md mx-auto">
             <div className="text-[#8a9db8] text-[10px] uppercase tracking-widest mb-3 font-bold">
                 {!mvpId ? "Drag MVP Badge to Player" : "MVP Assigned"}
             </div>
             {!mvpId ? (
                <MVPToken />
             ) : (
                <div className="flex items-center gap-2">
                     <button onClick={() => setMvpId('')} className="text-xs text-red-400 underline">Reset Selection</button>
                </div>
             )}
          </div>

          <div className="flex flex-col md:flex-row gap-8 items-start justify-center">

             {/* Left Column (Azure) */}
             {renderTeamColumn(match.azureTeam, "AZURE GOLEM", winner === 'azure', 'cyan')}

             {/* Right Column (Crimson) */}
             {renderTeamColumn(match.crimsonTeam, "CRIMSON GOLEM", winner === 'crimson', 'red')}

          </div>

          <div className="mt-12 flex justify-center pb-8">
             <Button onClick={() => onComplete(mvpId, ratings)} className="px-16 py-4 text-xl shadow-[0_0_20px_#dcb06b]">
                CONTINUE TO LOBBY
             </Button>
          </div>
       </div>
    </div>
  );
};

import React, { useState } from 'react';
import { MatchHistoryEntry, Role } from '../types';
import { ROLES_ORDER, RoleIcons } from '../constants';

interface HistoryListProps {
  history: MatchHistoryEntry[];
  onClear: () => void;
}

export const HistoryList: React.FC<HistoryListProps> = ({ history, onClear }) => {
  const [expandedId, setExpandedId] = useState<string | null>(null);

  if (history.length === 0) {
    return (
      <div className="p-8 text-center border border-[#1e3a5f] bg-[#0a1a2f]/40 rounded">
        <p className="text-[#8a9db8] font-cinzel tracking-widest text-sm">No match history recorded yet.</p>
      </div>
    );
  }

  const toggleExpand = (id: string) => {
    setExpandedId(expandedId === id ? null : id);
  };

  const formatDate = (ts: number) => {
    return new Date(ts).toLocaleString();
  };

  const renderRatingArrow = (rating: number) => {
      if (!rating || rating === 0) return null;

      if (rating > 0) {
          // Positive
          return (
             <div className="flex flex-col -space-y-1 text-green-400 ml-2" title="Performance: Good">
                 <svg xmlns="http://www.w3.org/2000/svg" className="h-3 w-3" fill="none" viewBox="0 0 24 24" stroke="currentColor" strokeWidth={3}><path strokeLinecap="round" strokeLinejoin="round" d="M5 15l7-7 7 7" /></svg>
                 {rating === 2 && (
                    <svg xmlns="http://www.w3.org/2000/svg" className="h-3 w-3" fill="none" viewBox="0 0 24 24" stroke="currentColor" strokeWidth={3}><path strokeLinecap="round" strokeLinejoin="round" d="M5 15l7-7 7 7" /></svg>
                 )}
             </div>
          );
      } else {
          // Negative
          return (
             <div className="flex flex-col -space-y-1 text-red-500 ml-2" title="Performance: Bad">
                 {rating === -2 && (
                    <svg xmlns="http://www.w3.org/2000/svg" className="h-3 w-3" fill="none" viewBox="0 0 24 24" stroke="currentColor" strokeWidth={3}><path strokeLinecap="round" strokeLinejoin="round" d="M19 9l-7 7-7-7" /></svg>
                 )}
                 <svg xmlns="http://www.w3.org/2000/svg" className="h-3 w-3" fill="none" viewBox="0 0 24 24" stroke="currentColor" strokeWidth={3}><path strokeLinecap="round" strokeLinejoin="round" d="M19 9l-7 7-7-7" /></svg>
             </div>
          );
      }
  };

  return (
    <div className="space-y-4">
       <div className="flex justify-between items-center mb-4">
          <h3 className="text-[#dcb06b] font-cinzel text-lg tracking-widest">Recent Matches</h3>
          <button onClick={onClear} className="text-[10px] text-red-400 hover:text-red-200 uppercase tracking-wider">
             Clear History
          </button>
       </div>

       <div className="space-y-3">
         {history.map((match) => {
            const isAzureWin = match.winningTeam === 'azure';
            const isCrimsonWin = match.winningTeam === 'crimson';
            const isDraw = !match.winningTeam;

            // Determine display roles (Coach first if present in this match history)
            const displayRoles = match.isCoachMode ? [Role.COACH, ...ROLES_ORDER] : ROLES_ORDER;

            return (
              <div key={match.id} className="border border-[#1e3a5f] bg-[#05090f] clip-corner-sm transition-all hover:border-[#dcb06b]/30">
                {/* Header Summary */}
                <div 
                  className="p-4 flex items-center justify-between cursor-pointer hover:bg-[#1e3a5f]/20 transition-colors"
                  onClick={() => toggleExpand(match.id)}
                >
                   <div className="flex items-center gap-4">
                      <div className={`
                         w-2 h-12 skew-x-[-12deg]
                         ${isAzureWin ? 'bg-cyan-500 shadow-[0_0_10px_#06b6d4]' : isCrimsonWin ? 'bg-red-500 shadow-[0_0_10px_#ef4444]' : 'bg-gray-500'}
                      `}></div>
                      <div>
                         <div className="text-xs text-[#8a9db8] font-orbitron tracking-widest mb-1">
                            ROOM: {match.roomId}
                         </div>
                         <div className={`font-cinzel font-bold text-lg ${isAzureWin ? 'text-cyan-400' : isCrimsonWin ? 'text-red-500' : 'text-gray-400'}`}>
                            {isAzureWin ? 'AZURE VICTORY' : isCrimsonWin ? 'CRIMSON VICTORY' : 'MATCH ENDED'}
                         </div>
                         <div className="text-[10px] text-[#4a5f78]">{formatDate(match.timestamp)}</div>
                      </div>
                   </div>

                   <div className={`transform transition-transform duration-300 ${expandedId === match.id ? 'rotate-180' : ''}`}>
                      <svg xmlns="http://www.w3.org/2000/svg" className="h-5 w-5 text-[#dcb06b]" fill="none" viewBox="0 0 24 24" stroke="currentColor">
                        <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M19 9l-7 7-7-7" />
                      </svg>
                   </div>
                </div>

                {/* Details Accordion */}
                {expandedId === match.id && (
                  <div className="border-t border-[#1e3a5f] p-4 bg-[#0a1a2f]/30">
                     <div className="grid grid-cols-1 md:grid-cols-2 gap-8">
                        {/* Azure Roster */}
                        <div>
                           <h4 className="text-cyan-500 font-cinzel text-xs tracking-widest mb-3 border-b border-cyan-500/20 pb-1">AZURE TEAM</h4>
                           <div className="space-y-2">
                              {displayRoles.map(role => {
                                 const p = match.azureTeam.find(s => s.role === role)?.player;
                                 if (!p) return null;

                                 const isMvp = match.mvpId === p.id;
                                 const rating = match.ratings?.[p.id] || 0;

                                 return (
                                    <div key={role} className="flex items-center justify-between text-sm">
                                       <span className="flex items-center gap-2 text-[#8a9db8]">
                                          <div className={`scale-90 ${role === Role.COACH ? 'text-white' : 'text-cyan-500/70'}`}>{RoleIcons[role]}</div>
                                       </span>
                                       <div className="flex items-center gap-2">
                                           {isMvp && (
                                              <span className="text-[8px] font-black bg-yellow-500 text-black px-1 rounded shadow-[0_0_5px_gold]">MVP</span>
                                           )}
                                           <span className="text-white font-orbitron">{p.name}</span>
                                           {renderRatingArrow(rating)}
                                       </div>
                                    </div>
                                 );
                              })}
                           </div>
                        </div>

                        {/* Crimson Roster */}
                        <div>
                           <h4 className="text-red-500 font-cinzel text-xs tracking-widest mb-3 border-b border-red-500/20 pb-1">CRIMSON TEAM</h4>
                           <div className="space-y-2">
                              {displayRoles.map(role => {
                                 const p = match.crimsonTeam.find(s => s.role === role)?.player;
                                 if (!p) return null;

                                 const isMvp = match.mvpId === p.id;
                                 const rating = match.ratings?.[p.id] || 0;

                                 return (
                                    <div key={role} className="flex items-center justify-between text-sm">
                                       <span className="flex items-center gap-2 text-[#8a9db8]">
                                          <div className={`scale-90 ${role === Role.COACH ? 'text-white' : 'text-red-500/70'}`}>{RoleIcons[role]}</div>
                                       </span>
                                       <div className="flex items-center gap-2">
                                           {isMvp && (
                                              <span className="text-[8px] font-black bg-yellow-500 text-black px-1 rounded shadow-[0_0_5px_gold]">MVP</span>
                                           )}
                                           <span className="text-white font-orbitron">{p.name}</span>
                                           {renderRatingArrow(rating)}
                                       </div>
                                    </div>
                                 );
                              })}
                           </div>
                        </div>
                     </div>
                  </div>
                )}
              </div>
            );
         })}
       </div>
    </div>
  );
};

import React, { useState } from 'react';
import { Player, Role } from '../types';
import { Button } from './Button';
import { ROLES_ORDER } from '../constants';

interface PlayerFormProps {
  onAddPlayer: (player: Omit<Player, 'id' | 'isActive' | 'stats'>) => void;
  isCoachMode: boolean; // Received from App
}

export const PlayerForm: React.FC<PlayerFormProps> = ({ onAddPlayer, isCoachMode }) => {
  const [mode, setMode] = useState<'manual' | 'smart'>('manual');

  // Manual State
  const [name, setName] = useState('');
  const [isAllRoles, setIsAllRoles] = useState(false);
  const [selectedRoles, setSelectedRoles] = useState<Role[]>([]);

  // Smart State
  const [smartInput, setSmartInput] = useState('');

  const toggleRole = (role: Role) => {
    if (isAllRoles) return;

    // If selecting Coach, clear other roles as Coach is exclusive in this logic
    if (role === Role.COACH) {
        setSelectedRoles(prev => prev.includes(Role.COACH) ? [] : [Role.COACH]);
        return;
    }

    // If Coach was selected, remove it when selecting others
    let currentRoles = selectedRoles.filter(r => r !== Role.COACH);

    currentRoles = currentRoles.includes(role) 
        ? currentRoles.filter(r => r !== role) 
        : [...currentRoles, role];

    // Check if all 5 standard roles are selected
    const isFullSet = ROLES_ORDER.every(r => currentRoles.includes(r));

    if (isFullSet) {
        setIsAllRoles(true);
        setSelectedRoles([]);
    } else {
        setSelectedRoles(currentRoles);
    }
  };

  const handleManualSubmit = (e: React.FormEvent) => {
    e.preventDefault();
    if (!name.trim()) return;
    if (!isAllRoles && selectedRoles.length === 0) return;

    onAddPlayer({
      name: name.trim(),
      isAllRoles,
      roles: isAllRoles ? [] : selectedRoles
    });

    // Reset
    setName('');
    setIsAllRoles(false);
    setSelectedRoles([]);
  };

  const parseAndSubmitSmartInput = (e: React.FormEvent) => {
    e.preventDefault();
    if (!smartInput.trim()) return;

    const lines = smartInput.split(/\n/);
    let count = 0;

    lines.forEach(line => {
      // Clean line
      const cleanLine = line.trim();
      if (!cleanLine) return;

      // Split Name and Roles by ':' or '-'
      const parts = cleanLine.split(/[:|-]/);
      if (parts.length < 2) return;

      const pName = parts[0].trim();
      const pRoleStr = parts[1].toLowerCase();

      let pIsAllRoles = false;
      const pRoles: Role[] = [];

      // Detect All Role / Fill
      if (pRoleStr.includes('all') || pRoleStr.includes('fill') || pRoleStr.includes('any') || pRoleStr.includes('auto')) {
        pIsAllRoles = true;
      } else {
        // Detect Specific Roles
        if (pRoleStr.includes('clash') || pRoleStr.includes('exp') || pRoleStr.includes('fight')) pRoles.push(Role.CLASH);
        if (pRoleStr.includes('mid') || pRoleStr.includes('mage')) pRoles.push(Role.MID);
        if (pRoleStr.includes('jung') || pRoleStr.includes('jg') || pRoleStr.includes('assassin')) pRoles.push(Role.JUNGLE);
        if (pRoleStr.includes('farm') || pRoleStr.includes('gold') || pRoleStr.includes('mm') || pRoleStr.includes('adc') || pRoleStr.includes('archer')) pRoles.push(Role.FARM);
        if (pRoleStr.includes('roam') || pRoleStr.includes('supp') || pRoleStr.includes('tank')) pRoles.push(Role.ROAM);

        // Only allow Coach via smart paste if mode is enabled (optional strictness, but good for consistency)
        if (isCoachMode && pRoleStr.includes('coach')) pRoles.push(Role.COACH);
      }

      // Add if valid
      if (pName && (pIsAllRoles || pRoles.length > 0)) {
        onAddPlayer({
          name: pName,
          isAllRoles: pIsAllRoles,
          roles: pRoles
        });
        count++;
      }
    });

    if (count > 0) {
      setSmartInput('');
    }
  };

  // Combine standard roles with Coach for the manual selector IF mode is active
  const availableRolesForSelection = isCoachMode ? [...ROLES_ORDER, Role.COACH] : ROLES_ORDER;

  return (
    <div className="relative group">
      {/* Decorative Border Container */}
      <div className="absolute -inset-[1px] bg-gradient-to-b from-[#dcb06b]/50 to-transparent clip-corner-md opacity-50 pointer-events-none"></div>

      <div className="bg-[#0a1a2f]/90 backdrop-blur-md p-6 clip-corner-md relative overflow-hidden">

        {/* Header Decor & Mode Switch */}
        <div className="flex items-center justify-between mb-6 border-b border-[#dcb06b]/20 pb-4">
          <h3 className="text-xl text-[#dcb06b] font-cinzel font-bold tracking-widest flex items-center gap-2">
            <span className="w-1.5 h-6 bg-[#dcb06b] block skew-x-[-12deg]"></span>
            {mode === 'manual' ? 'New Challenger' : 'Smart Import'}
          </h3>

          {/* Mode Toggles */}
          <div className="flex bg-[#05090f] p-1 rounded clip-corner-sm border border-[#1e3a5f]">
             <button 
               onClick={() => setMode('manual')}
               className={`px-3 py-1 text-[10px] uppercase font-bold transition-all ${mode === 'manual' ? 'bg-[#dcb06b] text-[#05090f]' : 'text-[#4a5f78] hover:text-[#dcb06b]'}`}
             >
               Manual
             </button>
             <button 
               onClick={() => setMode('smart')}
               className={`px-3 py-1 text-[10px] uppercase font-bold transition-all ${mode === 'smart' ? 'bg-[#dcb06b] text-[#05090f]' : 'text-[#4a5f78] hover:text-[#dcb06b]'}`}
             >
               Smart Paste
             </button>
          </div>
        </div>

        {mode === 'manual' ? (
          <form onSubmit={handleManualSubmit}>
            <div className="mb-6">
              <label className="block text-[10px] uppercase tracking-[0.2em] text-[#8a9db8] mb-2 font-bold">Player Name</label>
              <div className="relative">
                 <input 
                  type="text" 
                  value={name}
                  onChange={e => setName(e.target.value)}
                  placeholder="ENTER IGN..."
                  className="w-full bg-[#05090f] border border-[#1e3a5f] p-4 text-[#f0f4f8] placeholder-[#2d4a6d] focus:outline-none focus:border-[#dcb06b] transition-all clip-corner-sm font-orbitron tracking-wide"
                />
                <div className="absolute right-0 bottom-0 h-2 w-2 border-b border-r border-[#dcb06b] pointer-events-none"></div>
              </div>
            </div>

            <div className="mb-8">
              <div className="flex justify-between items-end mb-4">
                 <label className="text-[10px] uppercase tracking-[0.2em] text-[#8a9db8] font-bold">Role Preference</label>
                 <label className="flex items-center cursor-pointer group/toggle">
                  <span className={`mr-3 text-xs font-bold font-orbitron transition-colors uppercase ${isAllRoles ? 'text-[#dcb06b]' : 'text-[#4a5f78] group-hover/toggle:text-[#dcb06b]/70'}`}>
                    Fill / All Roles
                  </span>
                  <div className={`w-10 h-5 rounded-full relative transition-colors ${isAllRoles ? 'bg-[#dcb06b]' : 'bg-[#1e3a5f]'}`}>
                     <div className={`absolute top-1 w-3 h-3 rounded-full bg-white shadow-sm transition-transform duration-300 ${isAllRoles ? 'left-6' : 'left-1'}`}></div>
                  </div>
                  <input 
                    type="checkbox" 
                    className="hidden"
                    checked={isAllRoles}
                    onChange={e => setIsAllRoles(e.target.checked)}
                  />
                </label>
              </div>

              {/* Roles Buttons */}
              <div className={`flex flex-wrap gap-2 transition-all duration-300 ${isAllRoles ? 'opacity-30 pointer-events-none' : 'opacity-100'}`}>
                {availableRolesForSelection.map(role => (
                  <button
                    key={role}
                    type="button"
                    onClick={() => toggleRole(role)}
                    className={`
                      relative px-4 py-2 flex-grow md:flex-grow-0
                      font-cinzel font-bold text-xs uppercase tracking-widest
                      transition-all duration-300
                      clip-corner-sm
                      ${selectedRoles.includes(role) 
                        ? 'bg-[#dcb06b] text-[#05090f] shadow-[0_0_15px_rgba(220,176,107,0.4)]' 
                        : 'bg-transparent text-[#8a9db8] border border-[#1e3a5f] hover:border-[#dcb06b] hover:text-[#dcb06b]'
                      }
                    `}
                  >
                    {role.replace(' Lane', '')}

                    {/* Small underline decoration for active */}
                    {selectedRoles.includes(role) && (
                      <div className="absolute bottom-0 left-0 right-0 h-[2px] bg-white/30"></div>
                    )}
                  </button>
                ))}
              </div>
            </div>

            <Button type="submit" className="w-full" disabled={!name || (!isAllRoles && selectedRoles.length === 0)}>
               <span className="text-base">Join Lobby</span>
            </Button>
          </form>
        ) : (
          <form onSubmit={parseAndSubmitSmartInput}>
            <div className="mb-4">
              <label className="block text-[10px] uppercase tracking-[0.2em] text-[#8a9db8] mb-2 font-bold">
                Paste Roster List
              </label>
              <div className="relative">
                 <textarea 
                  value={smartInput}
                  onChange={e => setSmartInput(e.target.value)}
                  placeholder={`Supported Formats:\n\nArthur : Clash Lane\nLam - Jungle, Roam\nDiaochan : Mid Lane\nMarco Polo : Farm / Gold\nDolia : Roam, Support\nKPL Coach : Coach\nFaker : All Role\n\n(Separators: : or -)`}
                  className="w-full h-48 bg-[#05090f] border border-[#1e3a5f] p-4 text-[#f0f4f8] placeholder-[#2d4a6d] focus:outline-none focus:border-[#dcb06b] transition-all clip-corner-sm font-orbitron tracking-wide text-sm resize-none"
                />
                <div className="absolute right-0 bottom-0 h-2 w-2 border-b border-r border-[#dcb06b] pointer-events-none"></div>
              </div>
              <p className="mt-2 text-[10px] text-[#4a5f78] italic">
                Supported: Clash/Exp, Mid, Farm/Gold/MM, Jungle/Jg, Roam/Tank, Coach, All Role/Fill.
              </p>
            </div>
            <Button type="submit" className="w-full" disabled={!smartInput.trim()}>
               <span className="text-base">Process Batch</span>
            </Button>
          </form>
        )}
      </div>
    </div>
  );
};

import React, { useState, useEffect } from 'react';
import { Player, Role } from '../types';
import { Button } from './Button';
import { ROLES_ORDER, RoleIcons } from '../constants';

interface EditPlayerModalProps {
  player: Player;
  isOpen: boolean;
  onClose: () => void;
  onSave: (updatedPlayer: Player) => void;
}

export const EditPlayerModal: React.FC<EditPlayerModalProps> = ({ player, isOpen, onClose, onSave }) => {
  const [name, setName] = useState(player.name);
  const [isAllRoles, setIsAllRoles] = useState(player.isAllRoles);
  const [selectedRoles, setSelectedRoles] = useState<Role[]>(player.roles);

  // Sync state when player prop changes or modal opens
  useEffect(() => {
    if (isOpen) {
      setName(player.name);
      setIsAllRoles(player.isAllRoles);
      setSelectedRoles(player.roles);
    }
  }, [player, isOpen]);

  if (!isOpen) return null;

  const toggleRole = (role: Role) => {
    if (isAllRoles) return;

    const nextRoles = selectedRoles.includes(role) 
        ? selectedRoles.filter(r => r !== role) 
        : [...selectedRoles, role];

    // Check if all 5 standard roles are selected
    const isFullSet = ROLES_ORDER.every(r => nextRoles.includes(r));

    if (isFullSet) {
        setIsAllRoles(true);
        setSelectedRoles([]);
    } else {
        setSelectedRoles(nextRoles);
    }
  };

  const handleSave = (e: React.FormEvent) => {
    e.preventDefault();
    onSave({
      ...player,
      name,
      isAllRoles,
      roles: isAllRoles ? [] : selectedRoles
    });
    onClose();
  };

  return (
    <div className="fixed inset-0 z-50 flex items-center justify-center p-4">
      {/* Backdrop */}
      <div className="absolute inset-0 bg-black/80 backdrop-blur-sm" onClick={onClose}></div>

      {/* Modal Content */}
      <div className="relative w-full max-w-lg bg-[#0a1a2f] border border-[#dcb06b] clip-corner-md shadow-[0_0_50px_rgba(0,0,0,0.8)] animate-slide-in">

        {/* Header */}
        <div className="bg-[#05090f] p-4 border-b border-[#1e3a5f] flex justify-between items-center">
          <h3 className="text-[#dcb06b] font-cinzel font-bold text-lg tracking-widest flex items-center gap-2">
            <span className="w-1.5 h-5 bg-[#dcb06b] skew-x-[-12deg]"></span>
            EDIT CHALLENGER
          </h3>
          <button onClick={onClose} className="text-[#4a5f78] hover:text-white transition-colors">
            <svg xmlns="http://www.w3.org/2000/svg" className="h-6 w-6" fill="none" viewBox="0 0 24 24" stroke="currentColor">
              <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M6 18L18 6M6 6l12 12" />
            </svg>
          </button>
        </div>

        {/* Body */}
        <div className="p-6">
          <form onSubmit={handleSave}>
            <div className="mb-6">
              <label className="block text-[10px] uppercase tracking-[0.2em] text-[#8a9db8] mb-2 font-bold">Player Name</label>
              <div className="relative">
                 <input 
                  type="text" 
                  value={name}
                  onChange={e => setName(e.target.value)}
                  className="w-full bg-[#05090f] border border-[#1e3a5f] p-3 text-[#f0f4f8] focus:outline-none focus:border-[#dcb06b] transition-all clip-corner-sm font-orbitron tracking-wide"
                />
                <div className="absolute right-0 bottom-0 h-2 w-2 border-b border-r border-[#dcb06b] pointer-events-none"></div>
              </div>
            </div>

            <div className="mb-8">
              <div className="flex justify-between items-center mb-3">
                 <label className="text-[10px] uppercase tracking-[0.2em] text-[#8a9db8] font-bold">Roles</label>
                 <label className="flex items-center cursor-pointer group/toggle">
                  <span className={`mr-3 text-xs font-bold transition-colors uppercase ${isAllRoles ? 'text-[#dcb06b]' : 'text-[#4a5f78]'}`}>
                    Fill / All Roles
                  </span>
                  <div className={`w-10 h-5 rounded-full relative transition-colors ${isAllRoles ? 'bg-[#dcb06b]' : 'bg-[#1e3a5f]'}`}>
                     <div className={`absolute top-1 w-3 h-3 rounded-full bg-white shadow-sm transition-transform duration-300 ${isAllRoles ? 'left-6' : 'left-1'}`}></div>
                  </div>
                  <input 
                    type="checkbox" 
                    className="hidden"
                    checked={isAllRoles}
                    onChange={e => setIsAllRoles(e.target.checked)}
                  />
                </label>
              </div>

              {/* Grid Updated for Flexible Widths */}
              <div className={`grid grid-cols-2 sm:grid-cols-3 gap-2 transition-all duration-300 ${isAllRoles ? 'opacity-40 pointer-events-none grayscale' : 'opacity-100'}`}>
                {ROLES_ORDER.map(role => (
                  <button
                    key={role}
                    type="button"
                    onClick={() => toggleRole(role)}
                    className={`group relative flex flex-col items-center justify-center p-2 h-auto py-3 clip-corner-sm transition-all duration-200 border border-transparent ${
                      selectedRoles.includes(role) 
                        ? 'bg-[#1e3a5f] border-[#dcb06b] shadow-[0_0_10px_rgba(220,176,107,0.2)]' 
                        : 'bg-[#05090f] hover:bg-[#0f223d] hover:border-[#1e3a5f]'
                    }`}
                  >
                    <div className={`transform ${selectedRoles.includes(role) ? 'text-[#dcb06b]' : 'text-[#4a5f78]'}`}>
                      {RoleIcons[role]}
                    </div>
                    {selectedRoles.includes(role) && (
                       <div className="absolute top-0 right-0 w-2 h-2 bg-[#dcb06b] clip-corner-sm"></div>
                    )}
                  </button>
                ))}
              </div>
            </div>

            <div className="flex gap-4">
               <Button type="button" variant="secondary" onClick={onClose} className="w-1/2">
                  Cancel
               </Button>
               <Button type="submit" className="w-1/2">
                  Save Changes
               </Button>
            </div>
          </form>
        </div>
      </div>
    </div>
  );
};

