// --- UTILS FOR HASHING ---
const encodeState = (data: any): string => {
  try {
    const json = JSON.stringify(data);
    // Handle Unicode strings (names) safely for btoa
    return btoa(encodeURIComponent(json).replace(/%([0-9A-F]{2})/g,
        function toSolidBytes(match, p1) {
            return String.fromCharCode(parseInt(p1, 16));
    }));
  } catch (e) {
    console.error("Encoding error", e);
    return "";
  }
};

const decodeState = (str: string): any => {
  try {
    const decodedStr = decodeURIComponent(Array.prototype.map.call(atob(str), function(c) {
        return '%' + ('00' + c.charCodeAt(0).toString(16)).slice(-2);
    }).join(''));
    return JSON.parse(decodedStr);
  } catch (e) {
    console.error("Decoding error", e);
    return null;
  }
};

type ViewMode = 'lobby' | 'match' | 'battle';

export default function App() {
  const [viewMode, setViewMode] = useState<ViewMode>('lobby');

  const [players, setPlayers] = useState<Player[]>([]);
  const [currentMatch, setCurrentMatch] = useState<MatchResult | null>(null);
  const [matchHistory, setMatchHistory] = useState<MatchHistoryEntry[]>([]);

  const [errorMsg, setErrorMsg] = useState<string | null>(null);
  const [roomId, setRoomId] = useState<string>('');
  const [isCoachMode, setIsCoachMode] = useState(false);
  const [isSidebarOpen, setIsSidebarOpen] = useState(true);

  // Edit State
  const [editingPlayer, setEditingPlayer] = useState<Player | null>(null);
  const [isEditModalOpen, setIsEditModalOpen] = useState(false);
  const [isFullscreen, setIsFullscreen] = useState(false);

  const rosterFileInputRef = useRef<HTMLInputElement>(null);
  const historyFileInputRef = useRef<HTMLInputElement>(null);

  // --- ROUTER & STATE SYNC ---

  // 1. Navigation Helper (Writes to URL)
  const navigate = useCallback((mode: ViewMode, data: any) => {
    const hash = encodeState(data);
    // Use replaceState to avoid cluttering history stack too much with every keystroke
    // But pushState is better for significant view changes.
    window.location.hash = `${mode}/${hash}`;
  }, []);

  // 2. Hash Listener (Reads from URL)
  useEffect(() => {
    const handleHashChange = () => {
      const hash = window.location.hash.substring(1); // Remove #
      if (!hash) {
         setViewMode('lobby');
         return;
      }

      // Format: mode/data
      const separatorIndex = hash.indexOf('/');
      if (separatorIndex === -1) return;

      const mode = hash.substring(0, separatorIndex) as ViewMode;
      const dataStr = hash.substring(separatorIndex + 1);
      const data = decodeState(dataStr);

      if (!data) return;

      if (mode === 'lobby') {
         setViewMode('lobby');
         if (Array.isArray(data)) {
            setPlayers(data);
            setCurrentMatch(null);
         }
      } else if (mode === 'match') {
         setViewMode('match');
         setCurrentMatch(data);
         // Restore players from match to keep context if needed, or rely on match data
         if (data.azureTeam && data.crimsonTeam) {
            // We don't strictly overwrite 'players' here to avoid losing bench players not in the match object
            // Ideally match object should contain bench, but for now we just render the match.
         }
      } else if (mode === 'battle') {
         setViewMode('battle');
         setCurrentMatch(data);
      }
    };

    window.addEventListener('hashchange', handleHashChange);
    handleHashChange(); // Run on mount

    return () => window.removeEventListener('hashchange', handleHashChange);
  }, []);

  // 3. Auto-Save Lobby State (Debounced)
  // Only runs when we are strictly in LOBBY mode to avoid overwriting Match URL
  useEffect(() => {
    if (viewMode === 'lobby') {
       const timer = setTimeout(() => {
          navigate('lobby', players);
       }, 500);
       return () => clearTimeout(timer);
    }
  }, [players, viewMode, navigate]);

  // --- ACTIONS ---

  const handleBatchProcess = (batchData: { name: string; roles: Role[]; isAllRoles: boolean; action?: 'add' | 'bench' }[]) => {
    setPlayers(prev => {
      let updatedPlayers = [...prev];
      batchData.forEach(item => {
        const normalizedName = item.name.trim().toLowerCase();
        const existingIndex = updatedPlayers.findIndex(p => p.name.trim().toLowerCase() === normalizedName);

        if (item.action === 'bench') {
           if (existingIndex !== -1) {
              updatedPlayers[existingIndex] = { ...updatedPlayers[existingIndex], isActive: false };
           }
        } else {
           if (existingIndex !== -1) {
              updatedPlayers[existingIndex] = {
                 ...updatedPlayers[existingIndex],
                 roles: item.roles,
                 isAllRoles: item.isAllRoles,
                 isActive: true
              };
           } else {
              updatedPlayers.push({
                 id: crypto.randomUUID(),
                 name: item.name,
                 roles: item.roles,
                 isAllRoles: item.isAllRoles,
                 isActive: true,
                 isLastMatchMvp: false,
                 stats: { matchesPlayed: 0, wins: 0, currentStreak: 0, maxStreak: 0 }
              });
           }
        }
      });
      return updatedPlayers;
    });
    setErrorMsg(null);
  };

  const removePlayer = (id: string) => {
    setPlayers(prev => prev.filter(p => p.id !== id));
  };

  const handleClearAll = () => {
    if (window.confirm("Are you sure you want to clear the entire roster? This cannot be undone.")) {
       setPlayers([]);
       setRoomId('');
       setErrorMsg(null);
       navigate('lobby', []);
    }
  };

  const togglePlayerActive = (id: string) => {
    setPlayers(prev => prev.map(p => p.id === id ? { ...p, isActive: !p.isActive } : p));
  };

  const handleEditPlayer = (player: Player) => {
    setEditingPlayer(player);
    setIsEditModalOpen(true);
  };

  const handleUpdatePlayer = (updatedPlayer: Player) => {
    setPlayers(prev => prev.map(p => p.id === updatedPlayer.id ? updatedPlayer : p));
    setErrorMsg(null);
  };

  const activePlayers = players.filter(p => p.isActive);

  // --- MATCH ACTIONS ---

  const handleGenerate = () => {
    if (!roomId.trim()) {
      setErrorMsg("Please enter a Room ID.");
      return;
    }
    const required = isCoachMode ? 12 : 10;
    if (activePlayers.length < required) {
      setErrorMsg(`Need ${required} ACTIVE players for ${isCoachMode ? 'Coach' : 'Standard'} Mode. Current: ${activePlayers.length}`);
      return;
    }
    if (isCoachMode) {
       const coachCandidates = activePlayers.filter(p => p.roles.includes(Role.COACH));
       if (coachCandidates.length < 2) {
         setErrorMsg(`Coach Mode requires 2 players with 'COACH' role. Found: ${coachCandidates.length}`);
         return;
       }
    }

    const result = generateMatch(activePlayers, roomId, isCoachMode);
    if (result) {
      setCurrentMatch(result);
      setErrorMsg(null);
      // Change View to Match
      navigate('match', result);
    } else {
      setErrorMsg("Failed to find valid composition.");
    }
  };

  const handleRerollSlot = (team: 'azure' | 'crimson', role: Role, newPlayer: Player) => {
    if (!currentMatch) return;

    const updatedMatch = {
        ...currentMatch,
        azureTeam: currentMatch.azureTeam.map(slot => 
            (team === 'azure' && slot.role === role) ? { ...slot, player: newPlayer } : slot
        ),
        crimsonTeam: currentMatch.crimsonTeam.map(slot => 
            (team === 'crimson' && slot.role === role) ? { ...slot, player: newPlayer } : slot
        )
    };

    setCurrentMatch(updatedMatch);
    // Sync Reroll to URL
    navigate('match', updatedMatch);
  };

  const handleStartBattle = () => {
     if (!currentMatch) return;
     // Move to Battle Mode
     navigate('battle', currentMatch);
  };

  const handleMatchFinish = (winner: 'azure' | 'crimson' | null, mvpId?: string, ratings?: Record<string, number>) => {
    if (!currentMatch) return;

    // Save History
    const historyEntry: MatchHistoryEntry = {
       ...currentMatch,
       id: crypto.randomUUID(),
       winningTeam: winner,
       mvpId: mvpId,
       ratings: ratings 
    };
    setMatchHistory(prev => [historyEntry, ...prev]);

    // Update Player Stats
    if (winner) {
      const azureIds = new Set(currentMatch.azureTeam.map(slot => slot.player.id));
      const crimsonIds = new Set(currentMatch.crimsonTeam.map(slot => slot.player.id));

      const updatedPlayers = players.map(p => {
        let isLastMatchMvp = false;
        if (mvpId && p.id === mvpId) isLastMatchMvp = true;

        if (!azureIds.has(p.id) && !crimsonIds.has(p.id)) return { ...p, isLastMatchMvp: false };

        const isAzure = azureIds.has(p.id);
        const isWinner = (isAzure && winner === 'azure') || (!isAzure && winner === 'crimson');

        const newStats = { ...p.stats };
        newStats.matchesPlayed += 1;

        if (isWinner) {
           newStats.wins += 1;
           newStats.currentStreak += 1;
           if (newStats.currentStreak > newStats.maxStreak) newStats.maxStreak = newStats.currentStreak;
        } else {
           newStats.currentStreak = 0;
        }
        return { ...p, stats: newStats, isLastMatchMvp };
      });

      setPlayers(updatedPlayers);
      // Navigate back to Lobby with updated stats
      navigate('lobby', updatedPlayers);
    } else {
      // Draw/Abandon
      navigate('lobby', players);
    }

    setCurrentMatch(null);
    setRoomId(''); 
  };

  const handleAbortMatch = () => {
      setCurrentMatch(null);
      navigate('lobby', players);
  };

  // --- UTILS ---

  const quickFill = () => {
     const shuffledHeroes = [...HOK_HEROES].sort(() => 0.5 - Math.random());
     const heroesToAdd = shuffledHeroes.slice(0, 15);
     const batchData = heroesToAdd.map(hero => ({
        name: hero.name,
        roles: hero.roles,
        isAllRoles: false,
        action: 'add' as const
     }));
     for(let i=0; i<5; i++) {
        batchData.push({ name: `Flex Player ${i+1}`, roles: [], isAllRoles: true, action: 'add' });
     }
     if (isCoachMode) {
        batchData.push({ name: "Coach Gemik", roles: [Role.COACH], isAllRoles: false, action: 'add' });
        batchData.push({ name: "Coach KPL", roles: [Role.COACH], isAllRoles: false, action: 'add' });
     }
     handleBatchProcess(batchData);
  };

  // Fullscreen
  useEffect(() => {
    const handleFsChange = () => setIsFullscreen(!!document.fullscreenElement);
    document.addEventListener('fullscreenchange', handleFsChange);
    return () => document.removeEventListener('fullscreenchange', handleFsChange);
  }, []);

  const toggleFullScreen = () => {
    if (!document.fullscreenElement) {
      document.documentElement.requestFullscreen().catch((err) => console.error(err));
    } else {
      if (document.exitFullscreen) document.exitFullscreen();
    }
  };

  // --- RENDER ---

  // Determine Main Content based on View Mode
  let mainContent;
  if (viewMode === 'lobby') {
     mainContent = (
        <div className="max-w-7xl mx-auto">
            <div className="grid grid-cols-1 lg:grid-cols-12 gap-8 relative transition-all duration-500">
              {/* Left Panel */}
              <div className={`lg:col-span-4 space-y-6 transition-all duration-500 ease-in-out ${isSidebarOpen ? 'opacity-100 translate-x-0' : 'hidden opacity-0 -translate-x-full lg:col-span-0'}`}>

                 {/* Room ID - HIGHLY VISIBLE UPDATE */}
                 <div className="relative group p-[2px] rounded clip-corner-sm">
                    {/* Animated Gold/Yellow Gradient Border/Glow */}
                    <div className="absolute inset-0 bg-gradient-to-r from-[#dcb06b] via-[#8a6d3b] to-[#dcb06b] animate-[spin-slow_4s_linear_infinite] opacity-80 blur-sm"></div>

                    <div className="bg-[#05090f] p-5 flex items-center gap-4 relative z-10 clip-corner-sm border border-[#dcb06b] shadow-[inset_0_0_20px_rgba(220,176,107,0.2)]">
                       <label className="text-sm uppercase text-[#dcb06b] font-black font-orbitron whitespace-nowrap tracking-widest drop-shadow-[0_2px_2px_rgba(0,0,0,0.8)]">
                          Room ID
                       </label>
                       <div className="h-8 w-[2px] bg-[#dcb06b] shadow-[0_0_10px_#dcb06b]"></div>
                       <input 
                          type="text" 
                          value={roomId}
                          onChange={(e) => { if (/^\d*$/.test(e.target.value) && e.target.value.length <= 4) setRoomId(e.target.value); }}
                          maxLength={4}
                          placeholder="0000"
                          className="bg-transparent text-2xl font-orbitron font-bold text-[#f3dcb1] w-full focus:outline-none tracking-[0.2em] placeholder-[#1e3a5f] drop-shadow-[0_0_5px_#dcb06b]"
                       />
                    </div>
                 </div>

                 {/* Coach Mode */}
                 <div className="flex items-center justify-between bg-[#0a1a2f]/60 p-4 border border-[#1e3a5f] clip-corner-sm">
                     <span className="text-[#dcb06b] font-cinzel font-bold text-sm tracking-widest flex items-center gap-2">
                        <svg xmlns="http://www.w3.org/2000/svg" className="h-4 w-4" fill="none" viewBox="0 0 24 24" stroke="currentColor">
                           <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M19 11H5m14 0a2 2 0 012 2v6a2 2 0 01-2 2H5a2 2 0 01-2-2v-6a2 2 0 012-2m14 0V9a2 2 0 00-2-2M5 11V9a2 2 0 012-2m0 0V5a2 2 0 012-2h6a2 2 0 012 2v2M7 7h10" />
                        </svg>
                        COACH MODE <span className="text-[8px] bg-[#dcb06b] text-black px-1.5 py-0.5 rounded font-orbitron font-bold ml-1">(BETA)</span>
                     </span>
                     <label className="relative inline-flex items-center cursor-pointer">
                        <input type="checkbox" className="sr-only peer" checked={isCoachMode} onChange={(e) => setIsCoachMode(e.target.checked)} />
                        <div className="w-11 h-6 bg-[#1e3a5f] peer-focus:outline-none rounded-full peer peer-checked:after:translate-x-full peer-checked:after:border-white after:content-[''] after:absolute after:top-[2px] after:left-[2px] after:bg-white after:border-gray-300 after:border after:rounded-full after:h-5 after:w-5 after:transition-all peer-checked:bg-[#dcb06b]"></div>
                     </label>
                 </div>

                 <PlayerForm onBatchProcess={handleBatchProcess} isCoachMode={isCoachMode} />

                 <div className="relative p-6 clip-corner-md bg-gradient-to-b from-[#1a2c42] to-[#05090f] border border-[#dcb06b]/20 group hover:border-[#dcb06b]/50 transition-colors duration-500">
                    <div className="absolute top-0 left-0 w-full h-1 bg-gradient-to-r from-transparent via-[#dcb06b] to-transparent opacity-50"></div>
                    <div className="flex justify-between items-end mb-6">
                       <div>
                          <div className="text-[#8a9db8] text-[10px] uppercase tracking-widest font-bold mb-1">Active Players</div>
                          <div className="text-5xl font-orbitron font-bold text-white relative">
                             {activePlayers.length}
                             <span className="text-lg text-[#4a5f78] absolute top-0 -right-12">/ {isCoachMode ? 12 : 10}</span>
                          </div>
                       </div>
                       <div className="text-right">
                          <button onClick={quickFill} className="text-[10px] text-[#dcb06b] border border-[#dcb06b] px-3 py-1 hover:bg-[#dcb06b] hover:text-black transition-colors uppercase tracking-wider">
                             Quick Fill
                          </button>
                       </div>
                    </div>
                    {errorMsg && <div className="mb-4 p-3 border-l-2 border-red-500 bg-red-900/20 text-red-200 text-xs">{errorMsg}</div>}
                    <Button onClick={handleGenerate} className="w-full text-lg shadow-[0_0_20px_rgba(220,176,107,0.3)]" disabled={activePlayers.length < (isCoachMode ? 12 : 10)}>
                       START MATCHMAKING
                    </Button>
                 </div>
              </div>

              {/* Right Panel */}
              <div className={`transition-all duration-500 ${isSidebarOpen ? 'lg:col-span-8' : 'lg:col-span-12'}`}>
                 <div className="flex flex-wrap items-center justify-between mb-6 gap-4">
                    <div className="flex items-center gap-4">
                        <button onClick={() => setIsSidebarOpen(!isSidebarOpen)} className="p-2 border border-[#1e3a5f] hover:border-[#dcb06b] text-[#dcb06b] clip-corner-sm transition-all bg-[#0a1a2f]/50">
                           {isSidebarOpen ? (
                              <svg xmlns="http://www.w3.org/2000/svg" className="h-5 w-5" fill="none" viewBox="0 0 24 24" stroke="currentColor"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M4 8V4m0 0h4M4 4l5 5m11-1V4m0 0h-4m4 0l-5 5M4 16v4m0 0h4m-4 0l5-5m11 5l-5-5m5 5v-4m0 4h-4" /></svg>
                           ) : (
                              <svg xmlns="http://www.w3.org/2000/svg" className="h-5 w-5" fill="none" viewBox="0 0 24 24" stroke="currentColor"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M4 6h16M4 12h16M4 18h16" /></svg>
                           )}
                        </button>
                        <h2 className="text-2xl font-cinzel font-black tracking-[0.2em] uppercase drop-shadow-sm text-[#dcb06b] flex items-center gap-3">
                           <span className="w-2 h-2 bg-[#dcb06b] rotate-45"></span> SQUAD ROSTER
                        </h2>
                    </div>
                    <div className="flex items-center gap-2">
                       <button onClick={() => rosterFileInputRef.current?.click()} className="flex items-center gap-2 px-3 py-1 text-[10px] uppercase font-bold tracking-wider text-[#4a5f78] border border-[#1e3a5f] hover:border-[#dcb06b] hover:text-[#dcb06b] transition-all clip-corner-sm">
                          Load
                       </button>
                       <div className="h-4 w-[1px] bg-[#1e3a5f] mx-2"></div>
                       <button onClick={handleClearAll} className="text-xs text-[#4a5f78] hover:text-red-400 uppercase tracking-widest transition-colors">Clear All</button>
                    </div>
                 </div>

                 <div className="perspective-container tech-border p-6 bg-[#0a1a2f]/40 min-h-[400px] mb-8">
                    <PlayerList players={players} onRemove={removePlayer} onToggleActive={togglePlayerActive} onEdit={handleEditPlayer} isSidebarOpen={isSidebarOpen} />
                 </div>

                 <div className="mt-12">
                     <div className="flex items-center justify-between mb-6">
                        <h2 className="text-2xl font-cinzel font-black tracking-[0.2em] uppercase drop-shadow-sm text-[#dcb06b] flex items-center gap-3">
                           <span className="w-2 h-2 bg-[#dcb06b] rotate-45"></span> BATTLE HISTORY
                        </h2>
                     </div>
                     <div className="tech-border p-6 bg-[#0a1a2f]/40">
                        <HistoryList history={matchHistory} onClear={() => setMatchHistory([])} />
                     </div>
                 </div>
              </div>
            </div>
        </div>
     );
  } else if (currentMatch) {
     // Match or Battle Mode
     mainContent = (
        <MatchDisplay 
          match={currentMatch} 
          activePlayers={activePlayers} // Used for reroll pool
          initialMode={viewMode === 'battle' ? 'battle' : 'draft'}
          onReset={handleAbortMatch}
          onCompleteMatch={handleMatchFinish}
          onReroll={handleRerollSlot}
          onStartBattle={handleStartBattle}
        />
     );
  }

  return (
    <div className="min-h-screen text-slate-200 font-inter overflow-x-hidden relative flex flex-col">
      <BackgroundParticles />
      <div className="fixed inset-0 bg-black -z-10">
         <img src="https://www.levelinfinite.com/wp-content/uploads/2024/03/honor-of-kings-global-launch-pc.jpg" alt="HoK" className="absolute inset-0 w-full h-full object-cover opacity-50" />
         <div className="absolute inset-0 bg-gradient-to-b from-[#05090f]/90 via-[#05090f]/60 to-[#05090f] mix-blend-multiply"></div>
      </div>

      {/* Hidden File Inputs */}
      <input type="file" ref={rosterFileInputRef} onChange={(e) => {}} accept=".json" className="hidden" />
      <input type="file" ref={historyFileInputRef} onChange={(e) => {}} accept=".json" className="hidden" />

      {/* Edit Modal */}
      {editingPlayer && (
        <EditPlayerModal player={editingPlayer} isOpen={isEditModalOpen} onClose={() => setIsEditModalOpen(false)} onSave={handleUpdatePlayer} />
      )}

      {/* Header - Only Show in Lobby */}
      {viewMode === 'lobby' && (
        <header className="sticky top-0 z-50 h-16 flex items-center justify-center border-b border-[#dcb06b]/20 bg-[#05090f]/90 backdrop-blur-md shadow-lg transition-all">
          <div className="absolute inset-0 bg-gradient-to-r from-transparent via-[#dcb06b]/5 to-transparent"></div>

          <div className="flex items-center gap-3 animate-float">
             <div className="w-8 h-8 border-2 border-[#dcb06b] rotate-45 flex items-center justify-center bg-[#0a1a2f] shadow-[0_0_10px_#dcb06b]">
                <div className="w-4 h-4 bg-[#dcb06b] shadow-inner"></div>
             </div>

             <h1 className="text-2xl font-cinzel font-black tracking-[0.2em] text-white flex flex-col leading-none drop-shadow-[0_0_10px_rgba(220,176,107,0.5)]">
               <span><span className="hok-gold-text">HONOR</span> OF <span className="hok-gold-text">KINGS</span></span>
             </h1>
          </div>

          <button onClick={toggleFullScreen} className="absolute right-4 sm:right-8 p-2 text-[#4a5f78] hover:text-[#dcb06b] transition-colors">
             {isFullscreen ? <svg xmlns="http://www.w3.org/2000/svg" className="h-5 w-5" fill="none" viewBox="0 0 24 24" stroke="currentColor"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M6 18L18 6M6 6l12 12" /></svg> : <svg xmlns="http://www.w3.org/2000/svg" className="h-5 w-5" fill="none" viewBox="0 0 24 24" stroke="currentColor"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M4 8V4m0 0h4M4 4l5 5m11-1V4m0 0h-4m4 0l-5 5M4 16v4m0 0h4m-4 0l5-5m11 5l-5-5m5 5v-4m0 4h-4" /></svg>}
          </button>
        </header>
      )}

      <main className="relative z-10 pt-8 px-4 flex-grow">
         {mainContent}
      </main>

      {/* Footer - Only in Lobby */}
      {viewMode === 'lobby' && (
        <footer className="relative z-10 py-4 mt-8 text-center border-t border-[#dcb06b]/10 bg-[#05090f] w-full">
            <div className="max-w-4xl mx-auto px-4 text-[#4a5f78] font-orbitron text-[9px] tracking-widest leading-relaxed uppercase opacity-80">
                <span className="block mb-1 text-[#dcb06b] font-bold">APPLICATION DEVELOPED BY KAZEHUNT</span>
                <span className="block mb-1">DESIGNED EXCLUSIVELY FOR HONOR OF KINGS CUSTOM FUN MATCHES ON THE OFFICIAL DISCORD.</span>
                <span className="block opacity-50 text-[8px]">THE DEVELOPER ASSUMES NO RESPONSIBILITY FOR USAGE OUTSIDE THIS INTENDED SCOPE.</span>
            </div>
        </footer>
      )}
    </div>
  );
}

import React, { useState, useEffect } from 'react';
import { MatchResult, TeamSlot, Role, Player } from '../types';
import { RoleIcons, ROLES_ORDER } from '../constants';
import { Button } from './Button';
import { SpinWheel } from './SpinWheel';
import { PortalTransition } from './PortalTransition';
import { MatchSummary } from './MatchSummary';
import { VictoryCelebration } from './VictoryCelebration';
import { EvaluationScreen } from './EvaluationScreen';

interface MatchDisplayProps {
  match: MatchResult;
  activePlayers: Player[]; 
  initialMode: 'draft' | 'battle';
  onReset: () => void; // For Abort
  onCompleteMatch: (winner: 'azure' | 'crimson' | null, mvpId?: string, ratings?: Record<string, number>) => void; // For Finish
  onReroll: (team: 'azure' | 'crimson', role: Role, newPlayer: Player) => void;
  onStartBattle: () => void; // Triggered when draft is done
}

type ViewState = 'drafting' | 'transition' | 'final' | 'celebration' | 'evaluation';

export const MatchDisplay: React.FC<MatchDisplayProps> = ({ 
  match, activePlayers, initialMode, 
  onReset, onCompleteMatch, onReroll, onStartBattle 
}) => {
  const [viewState, setViewState] = useState<ViewState>('drafting');
  const [winningTeam, setWinningTeam] = useState<'azure' | 'crimson' | null>(null);

  // Set initial state based on props (URL)
  useEffect(() => {
     if (initialMode === 'battle') {
        setViewState('final');
     } else {
        setViewState('drafting');
     }
  }, [initialMode]);

  // Dynamic Role Order: If Coach mode, append Coach to standard order
  const displayRoles = match.isCoachMode ? [...ROLES_ORDER, Role.COACH] : ROLES_ORDER;

  // -1: Not started
  // 0-4: Revealing pairs (0=Clash, ... 4=Roam)
  // 5: Coach (if exists)
  const [currentRoleIndex, setCurrentRoleIndex] = useState(-1);

  // New State for the Modal Wheel
  const [wheelState, setWheelState] = useState<{
    isOpen: boolean;
    type: 'draft' | 'reroll'; // Differentiate between initial draft reveal and manual reroll
    team: 'azure' | 'crimson';
    role: Role;
    winnerName: string;
    winnerPlayer?: Player; // Needed for reroll
    candidates: string[];
  } | null>(null);

  // Tracks which individual cards are visible
  const [revealedCards, setRevealedCards] = useState<Set<string>>(new Set());

  // If loading directly into battle, ensure revealedCards is full? 
  // No need, because Battle View (MatchSummary) doesn't use revealedCards.
  // But if we are in draft mode, we start clean.

  const getPlayerForRole = (team: TeamSlot[], role: Role) => {
    return team.find(slot => slot.role === role);
  };

  const getCardId = (team: 'azure' | 'crimson', role: Role) => `${team}-${role}`;

  const handleNext = () => {
    const nextIndex = currentRoleIndex + 1;
    if (nextIndex >= displayRoles.length) return;

    const roleToReveal = displayRoles[nextIndex];

    // Step 1: Check if Azure is revealed
    const azureId = getCardId('azure', roleToReveal);
    if (!revealedCards.has(azureId)) {
      startWheel('azure', roleToReveal);
      return;
    }

    // Step 2: Check if Crimson is revealed
    const crimsonId = getCardId('crimson', roleToReveal);
    if (!revealedCards.has(crimsonId)) {
      startWheel('crimson', roleToReveal);
      return;
    }
  };

  const handleSkipAll = () => {
    // Debug: Instantly reveal everything
    const allCards = new Set<string>();
    displayRoles.forEach(r => {
      allCards.add(getCardId('azure', r));
      allCards.add(getCardId('crimson', r));
    });
    setRevealedCards(allCards);
    setCurrentRoleIndex(displayRoles.length); // Set to finished state
  };

  const startWheel = (team: 'azure' | 'crimson', role: Role) => {
    const teamSlots = team === 'azure' ? match.azureTeam : match.crimsonTeam;
    const winner = getPlayerForRole(teamSlots, role)?.player;
    if (!winner) return;

    // Get candidates for the wheel
    // STRICT COACH LOGIC: If role is Coach, ONLY allow players with Coach role.
    const candidates = activePlayers
      .filter(p => {
          if (role === Role.COACH) {
              return p.roles.includes(Role.COACH);
          }
          return p.isAllRoles || p.roles.includes(role);
      })
      .map(p => p.name);

    setWheelState({
      isOpen: true,
      type: 'draft',
      team,
      role,
      winnerName: winner.name,
      candidates
    });
  };

  // Triggered when user clicks the re-roll button on a card
  const handleRerollClick = (team: 'azure' | 'crimson', role: Role) => {
    const azureIds = new Set(match.azureTeam.map(s => s.player.id));
    const crimsonIds = new Set(match.crimsonTeam.map(s => s.player.id));

    const benchPlayers = activePlayers.filter(p => !azureIds.has(p.id) && !crimsonIds.has(p.id));

    if (benchPlayers.length === 0) {
      alert("No available bench players to re-roll with!");
      return;
    }

    const candidates = benchPlayers.filter(p => {
       if (role === Role.COACH) {
          return p.roles.includes(Role.COACH);
       }
       return p.isAllRoles || p.roles.includes(role);
    });

    if (candidates.length === 0) {
       alert(`No available bench players found for role: ${role}`);
       return;
    }

    const newPlayer = candidates[Math.floor(Math.random() * candidates.length)];
    const candidateNames = candidates.map(p => p.name);

    setWheelState({
        isOpen: true,
        type: 'reroll',
        team,
        role,
        winnerName: newPlayer.name,
        winnerPlayer: newPlayer,
        candidates: candidateNames
    });
  };

  const handleWheelComplete = () => {
    if (!wheelState) return;

    if (wheelState.type === 'draft') {
        const { team, role } = wheelState;
        setRevealedCards(prev => new Set(prev).add(getCardId(team, role)));
        if (team === 'crimson') {
           setCurrentRoleIndex(prev => prev + 1);
        }
    } else if (wheelState.type === 'reroll' && wheelState.winnerPlayer) {
        onReroll(wheelState.team, wheelState.role, wheelState.winnerPlayer);
    }

    setWheelState(null);
  };

  const handleWheelCancel = () => {
    setWheelState(null);
  };

  const handleInitializeBattle = () => {
    setViewState('transition');
  };

  const handleTransitionComplete = () => {
    // This function tells parent to update URL to /#battle/...
    onStartBattle();
    // Local state follows
    setViewState('final');
  };

  const handleMatchDecided = (winner: 'azure' | 'crimson' | null) => {
    if (winner) {
      setWinningTeam(winner);
      setViewState('celebration');
    } else {
      onCompleteMatch(null);
    }
  };

  const handleCelebrationDismiss = () => {
    setViewState('evaluation');
  };

  const handleEvaluationComplete = (mvpId?: string, ratings?: Record<string, number>) => {
    onCompleteMatch(winningTeam, mvpId, ratings);
  }

  // --- RENDER LOGIC ---

  if (viewState === 'evaluation' && winningTeam) {
    return (
      <EvaluationScreen 
        match={match} 
        winner={winningTeam} 
        onComplete={handleEvaluationComplete} 
      />
    );
  }

  if (viewState === 'celebration' && winningTeam) {
    const winningTeamSlots = winningTeam === 'azure' ? match.azureTeam : match.crimsonTeam;
    return (
      <VictoryCelebration 
        winner={winningTeam} 
        teamSlots={winningTeamSlots}
        onDismiss={handleCelebrationDismiss} 
      />
    );
  }

  if (viewState === 'transition') {
    return (
      <PortalTransition 
        azureTeam={match.azureTeam} 
        crimsonTeam={match.crimsonTeam} 
        onComplete={handleTransitionComplete} 
      />
    );
  }

  if (viewState === 'final') {
    return <MatchSummary match={match} onReset={handleMatchDecided} />;
  }

  // --- DRAFTING VIEW ---

  const renderPlayerCard = (role: Role, roleIndex: number, team: 'azure' | 'crimson') => {
    const teamSlots = team === 'azure' ? match.azureTeam : match.crimsonTeam;
    const player = getPlayerForRole(teamSlots, role)?.player;
    const isRevealed = revealedCards.has(getCardId(team, role));
    const isCoach = role === Role.COACH;

    // HoK Color Palettes
    // If Coach, override with Special White/Silver Theme
    let theme;
    if (isCoach) {
        theme = {
            bg: 'bg-[#1a1a1a]',
            border: 'border-white',
            glow: 'shadow-[0_0_20px_rgba(255,255,255,0.8)]',
            text: 'text-white',
            gradient: 'from-white/20 to-transparent'
        };
    } else {
        theme = team === 'azure' 
          ? {
              bg: 'bg-[#0a1a2f]',
              border: 'border-hok-cyan',
              glow: 'shadow-[0_0_10px_#00d2ff]',
              text: 'text-hok-cyan',
              gradient: 'from-[#00d2ff]/20 to-transparent'
            } 
          : {
              bg: 'bg-[#1a0505]',
              border: 'border-hok-red',
              glow: 'shadow-[0_0_10px_#ef4444]',
              text: 'text-hok-red',
              gradient: 'from-[#c02d2d]/20 to-transparent'
            };
    }

    // State 1: Hidden
    if (!isRevealed) {
       return (
         <div className="h-16 w-full relative overflow-hidden clip-corner-md border border-[#1e3a5f] bg-[#05090f]/80 flex flex-col items-center justify-center opacity-40 group">
            <div className="text-[#1e3a5f] group-hover:text-[#dcb06b]/50 transition-colors duration-500 transform scale-90 opacity-50">
               {RoleIcons[role]}
            </div>
            {/* Tech Scanlines */}
            <div className="absolute inset-0 bg-[url('data:image/svg+xml;base64,PHN2ZyB4bWxucz0iaHR0cDovL3d3dy53My5vcmcvMjAwMC9zdmciIHdpZHRoPSI0IiBoZWlnaHQ9IjQiPgo8cmVjdCB3aWR0aD0iNCIgaGVpZ2h0PSI0IiBmaWxsPSIjZmZmIiBmaWxsLW9wYWNpdHk9IjAuMDUiLz4KPHBhdGggZD0iTTAgNEw0IDBaIiBzdHJva2U9IiMwMDAiIHN0cm9rZS13aWR0aD0iMSIvPgo8L3N2Zz4=')] opacity-20"></div>
         </div>
       );
    }

    // State 2: Revealed (UPDATED LAYOUT FOR TEXT ROLES & MIRRORING)
    return (
      <div className={`relative h-16 w-full animate-slide-in perspective-container group`}>
        <div className={`
            absolute inset-0 clip-corner-md border-l-4 tilt-card
            ${theme.bg} ${theme.border} 
            ${theme.glow}
            shadow-[0_0_15px_rgba(0,0,0,0.5)]
            transition-all duration-300 hover:brightness-110
        `}>
           <div className={`flex flex-col h-full relative z-10 px-4 py-1 justify-center ${team === 'crimson' ? 'items-end text-right' : 'items-start text-left'}`}>

             {/* Text Role Label (Top) */}
             <div className={`mb-0.5 px-2 py-0.5 rounded-sm bg-black/40 border border-white/10 ${theme.text} transform transition-transform duration-500 w-auto inline-block scale-90 origin-${team === 'crimson' ? 'right' : 'left'}`}>
                {RoleIcons[role]}
             </div>

             {/* Name Section */}
             <span className={`block text-lg md:text-xl font-bold text-white truncate font-orbitron drop-shadow-md w-full`}>
                {player?.name}
             </span>

             <div className={`absolute inset-0 bg-gradient-to-r ${theme.gradient} opacity-50 pointer-events-none`}></div>
           </div>

           {/* Decorative Tech Corners */}
           <div className={`absolute top-0 w-8 h-8 border-t border-${isCoach ? 'white' : (team === 'azure' ? 'cyan' : 'red')}-500/50 ${team === 'azure' ? 'left-0' : 'right-0'}`}></div>
           <div className={`absolute bottom-0 w-8 h-8 border-b border-${isCoach ? 'white' : (team === 'azure' ? 'cyan' : 'red')}-500/50 ${team === 'azure' ? 'right-0' : 'left-0'}`}></div>

           {/* Re-roll Button Overlay - Mirrored Position */}
           {/* If Azure (Left Align): Button on Right. If Crimson (Right Align): Button on Left */}
           <button 
             onClick={(e) => { e.stopPropagation(); handleRerollClick(team, role); }}
             className={`absolute top-1 p-1.5 bg-black/50 hover:bg-[#dcb06b] rounded-full transition-colors group-hover:opacity-100 opacity-0 text-white hover:text-black z-50 border border-white/20
                ${team === 'azure' ? 'right-2' : 'left-2'}
             `}
             title="Re-roll this specific slot"
           >
             <svg xmlns="http://www.w3.org/2000/svg" className="h-4 w-4" fill="none" viewBox="0 0 24 24" stroke="currentColor">
               <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M4 4v5h.582m15.356 2A8.001 8.001 0 004.582 9m0 0H9m11 11v-5h-.581m0 0a8.003 8.003 0 01-15.357-2m15.357 2H15" />
             </svg>
           </button>
        </div>
      </div>
    );
  };

  const nextRoleIndex = currentRoleIndex + 1;
  const nextRoleName = nextRoleIndex < displayRoles.length ? displayRoles[nextRoleIndex] : null;
  const isFinished = currentRoleIndex >= displayRoles.length - 1 && revealedCards.size === (match.isCoachMode ? 12 : 10);

  let buttonText = "START DRAFT";
  if (nextRoleName) {
     if (!revealedCards.has(getCardId('azure', nextRoleName))) {
        buttonText = `SELECT AZURE ${nextRoleName.split(' ')[0].toUpperCase()}`;
     } else if (!revealedCards.has(getCardId('crimson', nextRoleName))) {
        buttonText = `SELECT CRIMSON ${nextRoleName.split(' ')[0].toUpperCase()}`;
     } else {
        buttonText = "NEXT LANE";
     }
  }

  // Turret SVG Path
  const TurretIcon = (
    <svg viewBox="0 0 24 24" fill="currentColor" className="w-16 h-16 opacity-30 animate-pulse">
        <path d="M12,2 L2,22 L12,18 L22,22 L12,2 Z" />
        <path d="M12,5 L5,20 L12,17 L19,20 L12,5 Z" fillOpacity="0.5" />
    </svg>
  );

  return (
    <>
      {/* The Spin Wheel Overlay */}
      {wheelState && wheelState.isOpen && (
        <SpinWheel 
          candidates={wheelState.candidates}
          winnerName={wheelState.winnerName}
          team={wheelState.team}
          roleName={wheelState.role}
          roomId={match.roomId}
          onComplete={handleWheelComplete}
          onCancel={handleWheelCancel}
        />
      )}

      <div className="w-full max-w-7xl mx-auto px-4 py-8 pb-32 relative">

        {/* Top Controls: Abort & Instant Result */}
        <div className="absolute top-4 left-4 right-4 z-40 flex justify-between">
           <Button variant="outline" size="sm" onClick={() => onReset()} className="border-red-900/50 text-red-500 hover:bg-red-900/20 text-[10px] px-3">
              <span className="flex items-center gap-2">
                 <svg xmlns="http://www.w3.org/2000/svg" className="h-4 w-4" fill="none" viewBox="0 0 24 24" stroke="currentColor">
                   <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M11 15l-3-3m0 0l3-3m-3 3h8M3 12a9 9 0 1118 0 9 9 0 01-18 0z" />
                 </svg>
                 ABORT DRAFT
              </span>
           </Button>

           {/* Debug / Instant Result Button */}
           {!isFinished && (
             <Button variant="outline" size="sm" onClick={handleSkipAll} className="border-[#dcb06b]/50 text-[#dcb06b] hover:bg-[#dcb06b]/10 text-[10px] px-3">
                <span className="flex items-center gap-2">
                   INSTANT RESULT (DEBUG)
                   <svg xmlns="http://www.w3.org/2000/svg" className="h-4 w-4" fill="none" viewBox="0 0 24 24" stroke="currentColor">
                     <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M13 10V3L4 14h7v7l9-11h-7z" />
                   </svg>
                </span>
             </Button>
           )}
        </div>

        {/* Header Info - PERFECTLY CENTERED */}
        <div className="flex flex-col items-center mb-6 pt-8">
           <div className="flex justify-center w-full mb-4">
              {/* HIGHLIGHTED ROOM ID - GLOWING EFFECT */}
              <div className="relative group p-[2px] rounded clip-corner-sm">
                 <div className="absolute inset-0 bg-gradient-to-r from-[#dcb06b] via-[#8a6d3b] to-[#dcb06b] animate-[spin-slow_4s_linear_infinite] opacity-80 blur-sm"></div>
                 <div className="bg-[#05090f] px-10 py-3 relative z-10 clip-corner-sm border border-[#dcb06b] shadow-[inset_0_0_20px_rgba(220,176,107,0.2)] flex flex-col items-center">
                    <span className="text-[#dcb06b] font-cinzel font-bold text-xs tracking-widest uppercase block text-center drop-shadow-[0_2px_2px_rgba(0,0,0,0.8)]">Room ID</span>
                    <span className="text-2xl font-orbitron font-bold text-[#f3dcb1] tracking-[0.2em] text-center block drop-shadow-[0_0_5px_#dcb06b]">{match.roomId}</span>
                 </div>
              </div>
           </div>

           <div className="flex justify-between items-center w-full relative max-w-5xl">
              <div className="w-1/3 text-center relative group">
                 <div className="absolute -inset-4 bg-cyan-500/10 blur-xl rounded-full opacity-50 group-hover:opacity-100 transition-opacity"></div>
                 <div className="absolute -left-10 top-0 text-cyan-500/20">{TurretIcon}</div>
                 <h2 className="relative text-2xl md:text-4xl font-cinzel font-black text-transparent bg-clip-text bg-gradient-to-b from-cyan-200 to-cyan-600 drop-shadow-[0_0_15px_rgba(6,182,212,0.8)]">
                  AZURE
                 </h2>
                 <p className="text-[10px] md:text-xs text-cyan-400 font-orbitron tracking-[0.4em] mt-1 opacity-70">GOLEM TEAM</p>
                 <div className="h-1 w-24 bg-cyan-500 mx-auto mt-2 shadow-[0_0_10px_#00d2ff]"></div>
              </div>

              <div className="w-1/3 flex justify-center items-center z-10">
                <div className="relative w-20 h-20 md:w-28 md:h-28 flex items-center justify-center">
                  <div className="absolute inset-0 border-2 border-[#dcb06b] rotate-45 animate-spin-slow bg-[#05090f]"></div>
                  <div className="absolute inset-2 border border-[#dcb06b]/50 rotate-45"></div>
                  <span className="text-3xl font-black italic text-[#dcb06b] font-orbitron z-10 pr-2 pt-1 animate-pulse-fast">VS</span>
                </div>
              </div>

              <div className="w-1/3 text-center relative group">
                 <div className="absolute -inset-4 bg-red-500/10 blur-xl rounded-full opacity-50 group-hover:opacity-100 transition-opacity"></div>
                 <div className="absolute -right-10 top-0 text-red-500/20 transform scale-x-[-1]">{TurretIcon}</div>
                 <h2 className="relative text-2xl md:text-4xl font-cinzel font-black text-transparent bg-clip-text bg-gradient-to-b from-red-200 to-red-600 drop-shadow-[0_0_15px_rgba(220,45,45,0.8)]">
                  CRIMSON
                 </h2>
                 <p className="text-[10px] md:text-xs text-red-400 font-orbitron tracking-[0.4em] mt-1 opacity-70">GOLEM TEAM</p>
                 <div className="h-1 w-24 bg-red-500 mx-auto mt-2 shadow-[0_0_10px_#ef4444]"></div>
              </div>
           </div>
        </div>

        {/* Matchup Grid - Compact Gaps */}
        <div className="relative space-y-2 md:space-y-3">
          <div className="absolute left-1/2 top-0 bottom-0 w-[2px] bg-gradient-to-b from-transparent via-[#dcb06b]/30 to-transparent hidden md:block"></div>

          {displayRoles.map((role, idx) => (
            <div key={role} className="grid grid-cols-1 md:grid-cols-2 gap-2 md:gap-8 items-center">
               <div className="order-1 md:order-none">
                  {renderPlayerCard(role, idx, 'azure')}
               </div>
               <div className="order-2 md:order-none">
                  {renderPlayerCard(role, idx, 'crimson')}
               </div>
            </div>
          ))}
        </div>

        {/* Control Bar */}
        <div className="fixed bottom-0 left-0 right-0 p-8 z-50 flex justify-center items-end bg-gradient-to-t from-[#05090f] via-[#05090f]/90 to-transparent pointer-events-none h-48">
           <div className="pointer-events-auto transform transition-all hover:scale-105">
              {!isFinished ? (
                 <div className="flex flex-col items-center">
                    <button 
                      onClick={handleNext}
                      className="
                        group relative w-72 h-16
                        bg-[#0a1a2f] border border-[#dcb06b] 
                        clip-corner-md
                        flex items-center justify-center
                        text-[#dcb06b] font-cinzel font-bold text-xl tracking-widest
                        overflow-hidden
                        hover:bg-[#dcb06b] hover:text-[#05090f]
                        transition-all duration-300
                        shadow-[0_0_20px_rgba(220,176,107,0.2)]
                      "
                    >
                       <span className="relative z-10">
                         {buttonText}
                       </span>
                       <div className="absolute inset-0 w-full h-full bg-white/20 -translate-x-full group-hover:animate-[shimmer_1s_infinite]"></div>
                    </button>
                 </div>
              ) : (
                 <div className="flex flex-col items-center animate-slide-in">
                    <p className="text-[#00d2ff] font-bold mb-4 uppercase tracking-[0.3em] text-sm font-orbitron drop-shadow-[0_0_5px_rgba(0,210,255,0.8)]">
                       Draft Completed
                    </p>
                    <Button 
                      onClick={handleInitializeBattle} 
                      className="px-12 border-[#dcb06b] shadow-[0_0_20px_#dcb06b] animate-pulse"
                    >
                       INITIALIZE BATTLE
                    </Button>
                 </div>
              )}
           </div>
        </div>
      </div>
    </>
  );
};

import React, { useState, useEffect, useRef } from 'react';
import { Button } from './Button';

interface SpinWheelProps {
  candidates: string[];
  winnerName: string;
  onComplete: () => void;
  onCancel: () => void;
  team: 'azure' | 'crimson';
  roleName: string;
  roomId: string;
}

export const SpinWheel: React.FC<SpinWheelProps> = ({ candidates, winnerName, onComplete, onCancel, team, roleName, roomId }) => {
  const [status, setStatus] = useState<'idle' | 'scrolling' | 'completed'>('idle');
  const [scrollPosition, setScrollPosition] = useState(0);

  // Ref for the scroll container
  const reelRef = useRef<HTMLDivElement>(null);

  // Configuration
  const ITEM_HEIGHT = 80; 
  const VISIBLE_ITEMS = 5; 
  const TOTAL_DURATION = 8000; 
  const WINNER_INDEX = 150; 

  const [reelItems, setReelItems] = useState<string[]>([]);

  useEffect(() => {
    const items: string[] = [];
    const uniqueCandidates = Array.from(new Set(candidates)) as string[];

    // If we only have 1 candidate (or 0), we can't avoid duplicates
    if (uniqueCandidates.length <= 1) {
       for (let i = 0; i < WINNER_INDEX + VISIBLE_ITEMS + 5; i++) {
          if (i === WINNER_INDEX) {
            items.push(winnerName);
          } else {
            items.push(uniqueCandidates[0] || winnerName);
          }
       }
       setReelItems(items);
       return;
    }

    let previousName = '';

    for (let i = 0; i < WINNER_INDEX + VISIBLE_ITEMS + 5; i++) {
       if (i === WINNER_INDEX) {
         items.push(winnerName);
         previousName = winnerName;
       } else {
         // Filter available candidates to exclude the one we just added (previousName)
         // This guarantees no immediate duplicates (e.g. A, B, A, C, B) instead of (A, A, B, B)
         const availableCandidates = uniqueCandidates.filter(name => name !== previousName);

         // Fallback if filter empties list (shouldn't happen if uniqueCandidates > 1)
         const pool = availableCandidates.length > 0 ? availableCandidates : uniqueCandidates;

         const randomName = pool[Math.floor(Math.random() * pool.length)];
         items.push(randomName);
         previousName = randomName;
       }
    }
    setReelItems(items);
  }, [candidates, winnerName]);

  const handleLock = () => {
    if (status !== 'idle') return;
    setStatus('scrolling');

    const containerHeight = ITEM_HEIGHT * VISIBLE_ITEMS;
    const centerOffset = (containerHeight / 2) - (ITEM_HEIGHT / 2);
    const targetY = -(WINNER_INDEX * ITEM_HEIGHT) + centerOffset;

    setScrollPosition(targetY);

    setTimeout(() => {
       setStatus('completed');
       setTimeout(() => {
         onComplete();
       }, 1000);
    }, TOTAL_DURATION);
  };

  const handleSkip = () => {
     // Instantly jump to end
     setStatus('completed');
     const containerHeight = ITEM_HEIGHT * VISIBLE_ITEMS;
     const centerOffset = (containerHeight / 2) - (ITEM_HEIGHT / 2);
     const targetY = -(WINNER_INDEX * ITEM_HEIGHT) + centerOffset;
     setScrollPosition(targetY);
     setTimeout(() => {
         onComplete();
     }, 500);
  };

  const themeColor = team === 'azure' ? '#00d2ff' : '#ef4444';

  return (
    <div className="fixed inset-0 z-[60] flex flex-col items-center justify-center bg-black/90 backdrop-blur-xl animate-slide-in">

      {/* Controls: Skip & Abort */}
      <div className="absolute top-6 right-6 z-50 flex gap-4">
        {/* Skip Animation (Debug) */}
        {status === 'scrolling' && (
           <button 
             onClick={handleSkip}
             className="px-4 py-2 bg-[#dcb06b]/20 border border-[#dcb06b] text-[#dcb06b] font-orbitron font-bold text-xs uppercase tracking-widest hover:bg-[#dcb06b] hover:text-black transition-colors"
           >
             Fast Forward
           </button>
        )}

        {/* Cancel Button */}
        {status === 'idle' && (
          <button 
            onClick={onCancel}
            className="group flex items-center gap-2 text-[#4a5f78] hover:text-white transition-colors"
          >
            <span className="text-xs uppercase tracking-widest font-bold opacity-0 group-hover:opacity-100 transition-opacity">Abort</span>
            <div className="w-10 h-10 rounded-full border border-[#1e3a5f] group-hover:border-red-500 flex items-center justify-center bg-[#05090f]">
              <svg xmlns="http://www.w3.org/2000/svg" className="h-5 w-5" fill="none" viewBox="0 0 24 24" stroke="currentColor">
                <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M6 18L18 6M6 6l12 12" />
              </svg>
            </div>
          </button>
        )}
      </div>

      <div className="mb-8 text-center relative z-10 pointer-events-none select-none flex flex-col items-center">
        {/* HIGHLIGHTED ROOM ID */}
        <div className="relative group p-[1px] rounded clip-corner-sm mb-4">
            <div className="absolute inset-0 bg-gradient-to-r from-[#dcb06b] via-[#8a6d3b] to-[#dcb06b] animate-[spin-slow_4s_linear_infinite] opacity-80 blur-sm"></div>
            <div className="bg-[#05090f] px-6 py-2 relative z-10 clip-corner-sm border border-[#dcb06b] shadow-[inset_0_0_15px_rgba(220,176,107,0.2)]">
                <span className="text-[#f3dcb1] font-orbitron text-sm tracking-[0.2em] font-bold drop-shadow-[0_0_5px_#dcb06b]">ROOM: {roomId}</span>
            </div>
        </div>

        <h3 className="text-[#8a9db8] font-cinzel text-lg tracking-[0.3em] uppercase mb-1">
          Targeting Candidate
        </h3>
        <h2 className="text-4xl md:text-5xl font-black font-orbitron text-white uppercase drop-shadow-[0_0_15px_rgba(255,255,255,0.5)]">
          <span style={{ color: themeColor }}>{team}</span> {roleName}
        </h2>
      </div>

      {/* Scroller Container */}
      <div className="relative">

         <div 
            className="relative overflow-hidden bg-[#05090f] border-x-2 border-[#dcb06b]/30 shadow-[0_0_50px_rgba(0,0,0,0.8)]"
            style={{ 
              width: '320px', 
              height: `${ITEM_HEIGHT * VISIBLE_ITEMS}px`
            }}
         >
            <div 
              ref={reelRef}
