          <h2 className="text-[#dcb06b] font-cinzel font-black text-2xl mt-8 mb-2">TICKET READY!</h2>
          <p className="text-[#8a9db8] text-xs mb-6 uppercase tracking-widest">Sent this to your admin in Chat</p>

          <div className="bg-black/50 p-4 rounded mb-6 border border-white/10 font-orbitron text-[#dcb06b] text-sm break-all select-all">
             {name} : {isAllRoles ? 'All Role' : selectedRoles.map(r => r.split(' ')[0]).join(', ')} [{ticket}]
