import React, { useState } from 'react';
import { Player, Role } from '../types';
import { Button } from './Button';
import { ROLES_ORDER } from '../constants';

interface BatchItem {
  name: string;
  roles: Role[];
  isAllRoles: boolean;
  action: 'add' | 'bench';
}

interface PlayerFormProps {
  onBatchProcess: (items: BatchItem[]) => void;
  isCoachMode: boolean;
}

export const PlayerForm: React.FC<PlayerFormProps> = ({ onBatchProcess, isCoachMode }) => {
  const [mode, setMode] = useState<'manual' | 'smart'>('manual');
  const [name, setName] = useState('');
  const [isAllRoles, setIsAllRoles] = useState(false);
  const [selectedRoles, setSelectedRoles] = useState<Role[]>([]);
  const [smartInput, setSmartInput] = useState('');

  const toggleRole = (role: Role) => {
    if (isAllRoles) return;
    if (role === Role.COACH) {
        setSelectedRoles(prev => prev.includes(Role.COACH) ? [] : [Role.COACH]);
        return;
    }
    let currentRoles = selectedRoles.filter(r => r !== Role.COACH);
    currentRoles = currentRoles.includes(role) ? currentRoles.filter(r => r !== role) : [...currentRoles, role];
    const isFullSet = ROLES_ORDER.every(r => currentRoles.includes(r));
    if (isFullSet) { setIsAllRoles(true); setSelectedRoles([]); } 
    else { setSelectedRoles(currentRoles); }
  };

  const handleManualSubmit = (e: React.FormEvent) => {
    e.preventDefault();
    if (!name.trim()) return;
    onBatchProcess([{ name: name.trim(), isAllRoles, roles: isAllRoles ? [] : selectedRoles, action: 'add' }]);
    setName(''); setIsAllRoles(false); setSelectedRoles([]);
  };

  const parseAndSubmitSmartInput = (e: React.FormEvent) => {
    e.preventDefault();
    if (!smartInput.trim()) return;

    const lines = smartInput.split(/\n/);
    const batchItems: BatchItem[] = [];

    lines.forEach(line => {
      const cleanLine = line.trim();
      if (!cleanLine) return;

      // New: Ticket Extraction Logic
      // Matches "Name : Roles [HOK-CODE]" or traditional "Name : Roles"
      const parts = cleanLine.split(/[:|-]/);
      if (parts.length < 2) return;

      const pName = parts[0].trim();
      const pRoleStr = parts[1].toLowerCase();

      let pIsAllRoles = false;
      const pRoles: Role[] = [];
      let pAction: 'add' | 'bench' = 'add';

      if (pRoleStr.includes('stop') || pRoleStr.includes('bench') || pRoleStr.includes('out')) {
         pAction = 'bench';
      } else {
         if (pRoleStr.includes('all') || pRoleStr.includes('fill')) pIsAllRoles = true;
         else {
            if (pRoleStr.includes('clash') || pRoleStr.includes('exp')) pRoles.push(Role.CLASH);
            if (pRoleStr.includes('mid') || pRoleStr.includes('mage')) pRoles.push(Role.MID);
            if (pRoleStr.includes('jung') || pRoleStr.includes('jg')) pRoles.push(Role.JUNGLE);
            if (pRoleStr.includes('farm') || pRoleStr.includes('gold')) pRoles.push(Role.FARM);
            if (pRoleStr.includes('roam') || pRoleStr.includes('supp')) pRoles.push(Role.ROAM);
            if (isCoachMode && pRoleStr.includes('coach')) pRoles.push(Role.COACH);
         }
      }

      if (pName && (pAction === 'bench' || pIsAllRoles || pRoles.length > 0)) {
        batchItems.push({ name: pName, isAllRoles: pIsAllRoles, roles: pRoles, action: pAction });
      }
    });

    if (batchItems.length > 0) {
      onBatchProcess(batchItems);
      setSmartInput('');
      setMode('manual');
    }
  };

  return (
    <div className="relative group">
      <div className="bg-[#0a1a2f]/90 backdrop-blur-md p-6 clip-corner-md relative overflow-hidden border border-[#dcb06b]/20">
        <div className="flex items-center justify-between mb-6">
          <h3 className="text-xl text-[#dcb06b] font-cinzel font-bold tracking-widest">{mode === 'manual' ? 'Add Player' : 'Bulk Importer'}</h3>
          <div className="flex bg-[#05090f] p-1 rounded border border-[#1e3a5f]">
             <button onClick={() => setMode('manual')} className={`px-3 py-1 text-[10px] uppercase font-bold ${mode === 'manual' ? 'bg-[#dcb06b] text-black' : 'text-[#4a5f78]'}`}>Manual</button>
             <button onClick={() => setMode('smart')} className={`px-3 py-1 text-[10px] uppercase font-bold ${mode === 'smart' ? 'bg-[#dcb06b] text-black' : 'text-[#4a5f78]'}`}>Smart</button>
          </div>
        </div>

        {mode === 'manual' ? (
          <form onSubmit={handleManualSubmit}>
            <input type="text" value={name} onChange={e => setName(e.target.value)} placeholder="ENTER IGN..." className="w-full bg-[#05090f] border border-[#1e3a5f] p-4 text-white mb-4 clip-corner-sm" />
            <div className="flex flex-wrap gap-2 mb-6">
               { (isCoachMode ? [...ROLES_ORDER, Role.COACH] : ROLES_ORDER).map(role => (
                 <button key={role} type="button" onClick={() => toggleRole(role)} className={`px-3 py-2 text-[9px] font-bold border clip-corner-sm ${selectedRoles.includes(role) ? 'bg-[#dcb06b] text-black border-[#dcb06b]' : 'text-[#8a9db8] border-[#1e3a5f]'}`}>
                   {role.split(' ')[0]}
                 </button>
               ))}
            </div>
            <Button type="submit" className="w-full" disabled={!name}>ADD TO LOBBY</Button>
          </form>
        ) : (
          <form onSubmit={parseAndSubmitSmartInput}>
            <textarea value={smartInput} onChange={e => setSmartInput(e.target.value)} placeholder="Paste chat log or Join Tickets here..." className="w-full h-48 bg-[#05090f] border border-[#1e3a5f] p-4 text-white text-xs resize-none mb-4" />
            <Button type="submit" className="w-full">PROCESS ALL TICKETS</Button>
          </form>
        )}
      </div>
    </div>
  );
};
